{
  "name": "SparkPlan AI",
  "description": "An intelligent anti-procrastination calendar that uses AI to break down large tasks into manageable work sessions based on your difficulty preferences and schedule availability."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum EventType {
  IMPORTED = 'IMPORTED', // From ICS or external
  MANUAL = 'MANUAL',     // User manually added
  AI_WORK_SESSION = 'AI_WORK_SESSION' // Generated by Gemini
}

export interface CalendarEvent {
  id: string;
  title: string;
  start: Date;
  end: Date;
  type: EventType;
  description?: string;
  relatedTaskId?: string; // If it's a work session for a specific task
  color?: string;
}

export interface TaskFile {
  name: string;
  size: number;
  type: string;
  url?: string; // For preview purposes
}

export interface Task {
  id: string;
  title: string;
  description: string;
  difficulty: number; // 1-10
  totalHoursNeeded: number;
  deadline: Date;
  preferredDays: string[]; // e.g., ["Monday", "Wednesday"]
  files: TaskFile[];
  isScheduled: boolean;
}

// Helper type for the Gemini response
export interface AIScheduleSuggestion {
  sessions: {
    startISO: string;
    endISO: string;
    summary: string;
    reasoning: string;
  }[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { CalendarEvent, Task, EventType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateWorkSessions = async (
  currentEvents: CalendarEvent[],
  task: Task
): Promise<CalendarEvent[]> => {
  const model = "gemini-3-flash-preview";

  // 1. Prepare context for the AI
  const eventContext = currentEvents.map(e => ({
    title: e.title,
    start: e.start.toISOString(),
    end: e.end.toISOString()
  }));

  const taskContext = {
    title: task.title,
    description: task.description,
    difficulty: task.difficulty,
    totalHours: task.totalHoursNeeded,
    deadline: task.deadline.toISOString(),
    preferredDays: task.preferredDays.join(", ")
  };

  const today = new Date();

  const prompt = `
    I am a student trying to prevent procrastination. 
    Today is ${today.toDateString()}.

    I have a task: "${taskContext.title}".
    Difficulty (1-10): ${taskContext.difficulty}.
    Total Estimated Work Hours Needed: ${taskContext.totalHours}.
    Deadline: ${taskContext.deadline}.
    I prefer to work on these days: ${taskContext.preferredDays}.

    Here is my current existing schedule (busy times):
    ${JSON.stringify(eventContext)}

    Please generate a list of "Work Sessions" to fit into my schedule between now and the deadline.

    Rules:
    1. Break the total hours into smaller, manageable chunks (e.g., 30 mins to 90 mins). 
    2. Higher difficulty tasks should have more breaks or shorter sessions.
    3. Do NOT overlap with existing events.
    4. Try to respect preferred days, but prioritize finishing before the deadline.
    5. Spread them out to avoid burnout.

    Return a JSON object containing an array of sessions.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sessions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  startISO: { type: Type.STRING, description: "ISO date string for start time" },
                  endISO: { type: Type.STRING, description: "ISO date string for end time" },
                  summary: { type: Type.STRING, description: "Title of the session, e.g. 'Research for History Paper'" },
                  reasoning: { type: Type.STRING, description: "Why this time was chosen" }
                },
                required: ["startISO", "endISO", "summary"]
              }
            }
          }
        }
      }
    });

    const result = JSON.parse(response.text || "{ \"sessions\": [] }");

    // Map response back to application domain objects
    const newEvents: CalendarEvent[] = result.sessions.map((session: any) => ({
      id: crypto.randomUUID(),
      title: session.summary,
      start: new Date(session.startISO),
      end: new Date(session.endISO),
      type: EventType.AI_WORK_SESSION,
      description: session.reasoning,
      relatedTaskId: task.id,
      color: "bg-indigo-600" // Visual distinction
    }));

    return newEvents;

  } catch (error) {
    console.error("Gemini scheduling failed:", error);
    throw new Error("Failed to generate schedule. Please try again.");
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  disabled, 
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center px-4 py-2 border text-sm font-medium rounded-md shadow-sm focus:outline-none focus:ring-2 focus:ring-offset-2 transition-colors";

  const variants = {
    primary: "border-transparent text-white bg-indigo-600 hover:bg-indigo-700 focus:ring-indigo-500",
    secondary: "border-gray-300 text-gray-700 bg-white hover:bg-gray-50 focus:ring-indigo-500",
    danger: "border-transparent text-white bg-red-600 hover:bg-red-700 focus:ring-red-500",
    ghost: "border-transparent text-indigo-600 bg-transparent hover:bg-indigo-50 focus:ring-indigo-500 shadow-none"
  };

  return (
    <button
      disabled={disabled || isLoading}
      className={`${baseStyles} ${variants[variant]} ${className} ${isLoading ? 'opacity-70 cursor-not-allowed' : ''}`}
      {...props}
    >
      {isLoading ? (
        <>
          <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Processing...
        </>
      ) : children}
    </button>
  );
};

import React, { useState } from 'react';
import { Button } from './Button';
import { CalendarEvent, EventType } from '../types';

interface ImportModalProps {
  isOpen: boolean;
  onClose: () => void;
  onImport: (events: CalendarEvent[]) => void;
}

export const ImportModal: React.FC<ImportModalProps> = ({ isOpen, onClose, onImport }) => {
  const [icsContent, setIcsContent] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  if (!isOpen) return null;

  const handleSimulateImport = () => {
    setIsProcessing(true);
    // Simulate a delay and mock data usually found in an ICS
    setTimeout(() => {
      const today = new Date();
      const mockEvents: CalendarEvent[] = [
        {
          id: crypto.randomUUID(),
          title: "CS101 Lecture",
          start: new Date(today.getFullYear(), today.getMonth(), today.getDate(), 9, 0),
          end: new Date(today.getFullYear(), today.getMonth(), today.getDate(), 10, 30),
          type: EventType.IMPORTED,
          color: "bg-blue-500"
        },
        {
          id: crypto.randomUUID(),
          title: "Team Meeting",
          start: new Date(today.getFullYear(), today.getMonth(), today.getDate(), 14, 0),
          end: new Date(today.getFullYear(), today.getMonth(), today.getDate(), 15, 0),
          type: EventType.IMPORTED,
          color: "bg-blue-500"
        },
        {
          id: crypto.randomUUID(),
          title: "Gym",
          start: new Date(today.getFullYear(), today.getMonth(), today.getDate() + 1, 18, 0),
          end: new Date(today.getFullYear(), today.getMonth(), today.getDate() + 1, 19, 30),
          type: EventType.IMPORTED,
          color: "bg-green-500"
        }
      ];
      onImport(mockEvents);
      setIsProcessing(false);
      onClose();
    }, 800);
  };

  const handleManualParse = () => {
    // Basic ICS parser logic
    setIsProcessing(true);
    try {
      const events: CalendarEvent[] = [];
      const lines = icsContent.split('\n');
      let currentEvent: Partial<CalendarEvent> = {};
      let inEvent = false;

      for (const line of lines) {
        if (line.includes('BEGIN:VEVENT')) {
          inEvent = true;
          currentEvent = { id: crypto.randomUUID(), type: EventType.IMPORTED, color: "bg-gray-500" };
        } else if (line.includes('END:VEVENT')) {
          inEvent = false;
          if (currentEvent.title && currentEvent.start && currentEvent.end) {
            events.push(currentEvent as CalendarEvent);
          }
        } else if (inEvent) {
          if (line.startsWith('SUMMARY:')) currentEvent.title = line.substring(8).trim();
          // Very basic date parsing, assuming standard ICS format (YYYYMMDDTHHMMSS)
          // In production, use a library like 'ical.js'
          if (line.startsWith('DTSTART:')) {
             const dateStr = line.substring(8).trim();
             currentEvent.start = parseICSDate(dateStr);
          }
          if (line.startsWith('DTEND:')) {
            const dateStr = line.substring(6).trim();
            currentEvent.end = parseICSDate(dateStr);
          }
        }
      }

      onImport(events);
      setIcsContent('');
      onClose();
    } catch (e) {
      alert("Failed to parse ICS text. Please try using the Sample Import instead.");
    } finally {
      setIsProcessing(false);
    }
  };

  const parseICSDate = (str: string): Date => {
    // Minimal parser for 20231024T103000Z format
    const year = parseInt(str.substring(0, 4));
    const month = parseInt(str.substring(4, 6)) - 1;
    const day = parseInt(str.substring(6, 8));
    const hour = parseInt(str.substring(9, 11));
    const min = parseInt(str.substring(11, 13));
    return new Date(year, month, day, hour, min);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 p-4">
      <div className="bg-white rounded-lg shadow-xl w-full max-w-md p-6">
        <h2 className="text-xl font-bold mb-4 text-gray-800">Import Calendar</h2>

        <div className="mb-6">
          <p className="text-sm text-gray-600 mb-2">
            Paste .ICS file content below to import events.
          </p>
          <textarea 
            className="w-full h-32 p-2 border border-gray-300 rounded focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm"
            placeholder="BEGIN:VCALENDAR..."
            value={icsContent}
            onChange={(e) => setIcsContent(e.target.value)}
          />
          <div className="mt-2 flex justify-end">
            <Button onClick={handleManualParse} disabled={!icsContent} variant="secondary" className="mr-2">Parse Text</Button>
          </div>
        </div>

        <div className="relative flex py-2 items-center">
            <div className="flex-grow border-t border-gray-300"></div>
            <span className="flex-shrink-0 mx-4 text-gray-400 text-xs">OR</span>
            <div className="flex-grow border-t border-gray-300"></div>
        </div>

        <div className="mt-4">
          <Button onClick={handleSimulateImport} isLoading={isProcessing} className="w-full">
            Load Sample University Schedule
          </Button>
        </div>

        <div className="mt-6 flex justify-end">
          <Button variant="ghost" onClick={onClose}>Cancel</Button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Task, TaskFile } from '../types';
import { Button } from './Button';

interface TaskFormProps {
  onSubmit: (task: Task) => Promise<void>;
  onCancel: () => void;
}

const DAYS_OF_WEEK = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"];

export const TaskForm: React.FC<TaskFormProps> = ({ onSubmit, onCancel }) => {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [difficulty, setDifficulty] = useState(5);
  const [totalHours, setTotalHours] = useState(2);
  const [deadline, setDeadline] = useState("");
  const [selectedDays, setSelectedDays] = useState<string[]>([]);
  const [files, setFiles] = useState<TaskFile[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: TaskFile[] = Array.from(e.target.files).map(f => ({
        name: f.name,
        size: f.size,
        type: f.type,
        // In a real app, you'd upload to S3/Cloud storage here. 
        // We create a local URL for demo purposes.
        url: URL.createObjectURL(f) 
      }));
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const toggleDay = (day: string) => {
    setSelectedDays(prev => 
      prev.includes(day) ? prev.filter(d => d !== day) : [...prev, day]
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!deadline) {
        alert("Please select a deadline.");
        return;
    }

    setIsSubmitting(true);

    const newTask: Task = {
      id: crypto.randomUUID(),
      title,
      description,
      difficulty,
      totalHoursNeeded: totalHours,
      deadline: new Date(deadline),
      preferredDays: selectedDays.length > 0 ? selectedDays : DAYS_OF_WEEK,
      files,
      isScheduled: false
    };

    try {
      await onSubmit(newTask);
    } catch (err) {
      console.error(err);
      alert("Failed to schedule task. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-lg max-w-2xl mx-auto border border-gray-100">
      <h2 className="text-2xl font-bold text-gray-800 mb-6 flex items-center">
        <span className="bg-indigo-100 text-indigo-600 p-2 rounded-lg mr-3">
            ✨
        </span>
        Create Smart Task
      </h2>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Basic Info */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="col-span-2">
            <label className="block text-sm font-medium text-gray-700">Task Title</label>
            <input 
              required
              type="text" 
              value={title}
              onChange={e => setTitle(e.target.value)}
              className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-indigo-500 focus:border-indigo-500"
              placeholder="e.g. Write History Term Paper"
            />
          </div>

          <div className="col-span-2">
            <label className="block text-sm font-medium text-gray-700">Description</label>
            <textarea 
              value={description}
              onChange={e => setDescription(e.target.value)}
              rows={2}
              className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-indigo-500 focus:border-indigo-500"
              placeholder="What needs to be done?"
            />
          </div>

          <div>
             <label className="block text-sm font-medium text-gray-700">Deadline</label>
             <input 
                required
                type="datetime-local"
                value={deadline}
                onChange={e => setDeadline(e.target.value)}
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-indigo-500 focus:border-indigo-500"
             />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700">Total Hours Needed</label>
            <input 
              type="number" 
              min="0.5"
              step="0.5"
              value={totalHours}
              onChange={e => setTotalHours(parseFloat(e.target.value))}
              className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-indigo-500 focus:border-indigo-500"
            />
          </div>
        </div>

        {/* Difficulty Slider */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Difficulty Level (1-10)
            <span className="ml-2 text-xs text-gray-500 font-normal">Higher difficulty results in more frequent breaks.</span>
          </label>
          <div className="flex items-center gap-4">
            <span className="text-sm text-gray-500">Easy</span>
            <input 
              type="range" 
              min="1" 
              max="10" 
              value={difficulty}
              onChange={e => setDifficulty(parseInt(e.target.value))}
              className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
            />
            <span className="text-sm text-gray-500">Hard</span>
            <span className="text-lg font-bold text-indigo-600 w-8 text-center">{difficulty}</span>
          </div>
        </div>

        {/* Preferred Days */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">Days willing to work</label>
          <div className="flex flex-wrap gap-2">
            {DAYS_OF_WEEK.map(day => (
              <button
                key={day}
                type="button"
                onClick={() => toggleDay(day)}
                className={`px-3 py-1 rounded-full text-xs font-medium border transition-colors ${
                  selectedDays.includes(day)
                    ? 'bg-indigo-600 text-white border-indigo-600'
                    : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'
                }`}
              >
                {day}
              </button>
            ))}
          </div>
          {selectedDays.length === 0 && <p className="text-xs text-gray-500 mt-1">If none selected, all days are considered.</p>}
        </div>

        {/* File Upload */}
        <div className="border-t pt-4">
          <label className="block text-sm font-medium text-gray-700 mb-2">Attach Materials/Files</label>
          <div className="flex items-center justify-center w-full">
            <label className="flex flex-col items-center justify-center w-full h-24 border-2 border-gray-300 border-dashed rounded-lg cursor-pointer bg-gray-50 hover:bg-gray-100">
                <div className="flex flex-col items-center justify-center pt-5 pb-6">
                    <p className="mb-2 text-sm text-gray-500"><span className="font-semibold">Click to upload</span> or drag and drop</p>
                </div>
                <input type="file" className="hidden" multiple onChange={handleFileChange} />
            </label>
          </div>

          {/* File List */}
          {files.length > 0 && (
            <ul className="mt-4 space-y-2">
              {files.map((file, idx) => (
                <li key={idx} className="flex items-center justify-between bg-gray-50 p-2 rounded border border-gray-200 text-sm">
                  <span className="truncate max-w-xs">{file.name} ({(file.size / 1024).toFixed(1)} KB)</span>
                  <button type="button" onClick={() => removeFile(idx)} className="text-red-500 hover:text-red-700">
                    ✕
                  </button>
                </li>
              ))}
            </ul>
          )}
        </div>

        {/* Actions */}
        <div className="flex justify-end gap-3 pt-4 border-t">
          <Button type="button" variant="secondary" onClick={onCancel}>Cancel</Button>
          <Button type="submit" isLoading={isSubmitting}>
             Generate Schedule with AI
          </Button>
        </div>
      </form>
    </div>
  );
};

import React from 'react';
import { CalendarEvent, EventType } from '../types';

interface CalendarProps {
  events: CalendarEvent[];
  currentDate: Date;
  onEventClick: (event: CalendarEvent) => void;
}

export const Calendar: React.FC<CalendarProps> = ({ events, currentDate, onEventClick }) => {
  const daysOfWeek = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const hours = Array.from({ length: 15 }, (_, i) => i + 7); // 7 AM to 9 PM

  const getDayDates = () => {
    const dates = [];
    const startOfWeek = new Date(currentDate);
    const day = startOfWeek.getDay();
    // Adjust to make Monday first if preferred, keeping Sunday first for now
    startOfWeek.setDate(startOfWeek.getDate() - day);

    for (let i = 0; i < 7; i++) {
      const date = new Date(startOfWeek);
      date.setDate(startOfWeek.getDate() + i);
      dates.push(date);
    }
    return dates;
  };

  const weekDates = getDayDates();

  const getEventStyle = (event: CalendarEvent, colIndex: number) => {
    const startHour = event.start.getHours() + event.start.getMinutes() / 60;
    const endHour = event.end.getHours() + event.end.getMinutes() / 60;
    const duration = endHour - startHour;

    // 7 AM is start, so subtract 7
    const top = (startHour - 7) * 60; // 60px per hour
    const height = duration * 60;

    return {
      top: `${top}px`,
      height: `${height}px`,
      left: '2px',
      right: '2px'
    };
  };

  const isSameDay = (d1: Date, d2: Date) => {
    return d1.getDate() === d2.getDate() && 
           d1.getMonth() === d2.getMonth() && 
           d1.getFullYear() === d2.getFullYear();
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-lg shadow overflow-hidden">
      {/* Header */}
      <div className="grid grid-cols-8 border-b border-gray-200">
        <div className="p-4 border-r border-gray-100 text-xs font-semibold text-gray-500 uppercase tracking-wide text-center pt-8">
           GMT{(new Date().getTimezoneOffset() / 60) * -1}
        </div>
        {weekDates.map((date, i) => (
          <div key={i} className={`p-4 text-center border-r border-gray-100 ${isSameDay(date, new Date()) ? 'bg-indigo-50' : ''}`}>
            <div className="text-xs font-semibold text-gray-500 uppercase tracking-wide">{daysOfWeek[date.getDay()]}</div>
            <div className={`mt-1 text-xl font-bold ${isSameDay(date, new Date()) ? 'text-indigo-600' : 'text-gray-900'}`}>
              {date.getDate()}
            </div>
          </div>
        ))}
      </div>

      {/* Grid */}
      <div className="flex-1 overflow-y-auto relative" style={{ maxHeight: '600px' }}>
        <div className="grid grid-cols-8 min-h-[900px]">
          {/* Time Sidebar */}
          <div className="border-r border-gray-100 bg-gray-50">
            {hours.map(hour => (
              <div key={hour} className="h-[60px] border-b border-gray-200 text-xs text-gray-500 text-right pr-2 pt-2 relative">
                 {hour > 12 ? `${hour - 12} PM` : `${hour} ${hour === 12 ? 'PM' : 'AM'}`}
              </div>
            ))}
          </div>

          {/* Days Columns */}
          {weekDates.map((date, colIndex) => {
            const dayEvents = events.filter(e => isSameDay(e.start, date));

            return (
              <div key={colIndex} className="relative border-r border-gray-100">
                 {/* Grid lines */}
                {hours.map(hour => (
                  <div key={hour} className="h-[60px] border-b border-gray-100"></div>
                ))}

                {/* Events */}
                {dayEvents.map(event => (
                  <div
                    key={event.id}
                    onClick={() => onEventClick(event)}
                    className={`absolute rounded px-2 py-1 text-xs cursor-pointer shadow-sm transition-all hover:scale-[1.02] hover:z-10 overflow-hidden ${
                      event.type === EventType.AI_WORK_SESSION 
                        ? 'bg-indigo-600 text-white border-indigo-700' 
                        : event.color || 'bg-blue-500 text-white'
                    }`}
                    style={getEventStyle(event, colIndex)}
                  >
                    <div className="font-semibold truncate">{event.title}</div>
                    <div className="opacity-90 text-[10px]">
                      {event.start.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - 
                      {event.end.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                    </div>
                  </div>
                ))}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { CalendarEvent, Task, EventType } from '../types';
import { Button } from './Button';

interface EventDetailsModalProps {
  event: CalendarEvent | null;
  relatedTask?: Task; // If it's an AI session, we pass the parent task
  onClose: () => void;
  onDelete: (id: string) => void;
}

export const EventDetailsModal: React.FC<EventDetailsModalProps> = ({ event, relatedTask, onClose, onDelete }) => {
  if (!event) return null;

