import React, { useState, useEffect } from 'react';
import { Calendar } from './components/Calendar';
import { TaskForm } from './components/TaskForm';
import { ImportModal } from './components/ImportModal';
import { EventDetailsModal } from './components/EventDetailsModal';
import { Button } from './components/Button';
import { generateWorkSessions } from './services/geminiService';
import { CalendarEvent, Task, EventType } from './types';

function App() {
  const [view, setView] = useState<'calendar' | 'newTask'>('calendar');
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);

  // Initialize with today's date
  const [currentDate] = useState(new Date());

  const handleImport = (importedEvents: CalendarEvent[]) => {
    setEvents(prev => [...prev, ...importedEvents]);
  };

  const handleCreateTask = async (task: Task) => {
    try {
      // Call AI Service
      const workSessions = await generateWorkSessions(events, task);

      // Update State
      setTasks(prev => [...prev, { ...task, isScheduled: true }]);
      setEvents(prev => [...prev, ...workSessions]);
      setView('calendar');
    } catch (error) {
      console.error(error);
      alert("Error generating schedule. Ensure you have a valid API Key set in the environment.");
    }
  };

  const handleDeleteEvent = (id: string) => {
    setEvents(prev => prev.filter(e => e.id !== id));
  };

  // Find the task related to the selected event if it exists
  const selectedTask = selectedEvent?.relatedTaskId 
    ? tasks.find(t => t.id === selectedEvent.relatedTaskId) 
    : undefined;

  return (
    <div className="min-h-screen flex flex-col">
      {/* Navbar */}
      <nav className="bg-white border-b border-gray-200 shadow-sm sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <span className="bg-indigo-600 text-white p-1.5 rounded-lg mr-2">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
              </span>
              <h1 className="text-xl font-bold text-gray-900">SparkPlan AI</h1>
            </div>
            <div className="flex items-center space-x-4">
              <Button variant="secondary" onClick={() => setIsImportModalOpen(true)}>
                Import Calendar
              </Button>
              <Button onClick={() => setView('newTask')} disabled={view === 'newTask'}>
                + New Smart Task
              </Button>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {view === 'calendar' ? (
          <>
            <div className="mb-6 flex items-center justify-between">
              <div>
                <h2 className="text-lg font-medium text-gray-900">Your Schedule</h2>
                <p className="text-sm text-gray-500">
                  {events.filter(e => e.type === EventType.AI_WORK_SESSION).length} AI sessions scheduled
                </p>
              </div>
              <div className="flex gap-2 text-sm">
                 <div className="flex items-center"><div className="w-3 h-3 bg-indigo-600 rounded mr-1"></div> Work Session</div>
                 <div className="flex items-center"><div className="w-3 h-3 bg-blue-500 rounded mr-1"></div> Class/Meeting</div>
              </div>
            </div>

            <div className="h-[calc(100vh-200px)]">
               <Calendar 
                  events={events} 
                  currentDate={currentDate} 
                  onEventClick={setSelectedEvent}
               />
            </div>
          </>
        ) : (
          <div className="py-8">
            <TaskForm 
              onSubmit={handleCreateTask} 
              onCancel={() => setView('calendar')} 
            />
          </div>
        )}
      </main>

      {/* Modals */}
      <ImportModal 
        isOpen={isImportModalOpen} 
        onClose={() => setIsImportModalOpen(false)} 
        onImport={handleImport} 
      />

      <EventDetailsModal 
        event={selectedEvent} 
        relatedTask={selectedTask}
        onClose={() => setSelectedEvent(null)}
        onDelete={handleDeleteEvent}
      />

    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { Button } from './Button';
import { CalendarEvent, EventType } from '../types';

interface ImportModalProps {
  isOpen: boolean;
  onClose: () => void;
  onImport: (events: CalendarEvent[]) => void;
}

type TabType = 'upload' | 'url' | 'text';

export const ImportModal: React.FC<ImportModalProps> = ({ isOpen, onClose, onImport }) => {
  const [activeTab, setActiveTab] = useState<TabType>('upload');
  const [icsContent, setIcsContent] = useState('');
  const [urlInput, setUrlInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  if (!isOpen) return null;

  const parseICSDate = (str: string): Date => {
    // Minimal parser for 20231024T103000Z format
    // Handle YYYYMMDD format (all day events) as well if possible, or just standard
    try {
        if (str.length === 8) {
             const year = parseInt(str.substring(0, 4));
             const month = parseInt(str.substring(4, 6)) - 1;
             const day = parseInt(str.substring(6, 8));
             return new Date(year, month, day);
        }
        const year = parseInt(str.substring(0, 4));
        const month = parseInt(str.substring(4, 6)) - 1;
        const day = parseInt(str.substring(6, 8));
        const hour = parseInt(str.substring(9, 11));
        const min = parseInt(str.substring(11, 13));
        return new Date(year, month, day, hour, min);
    } catch (e) {
        return new Date();
    }
  };

  const processICSContent = (content: string) => {
    try {
      const events: CalendarEvent[] = [];
      const lines = content.split(/\r\n|\n|\r/);
      let currentEvent: Partial<CalendarEvent> = {};
      let inEvent = false;

      for (const line of lines) {
        if (line.includes('BEGIN:VEVENT')) {
          inEvent = true;
          currentEvent = { id: crypto.randomUUID(), type: EventType.IMPORTED, color: "bg-blue-500" };
        } else if (line.includes('END:VEVENT')) {
          inEvent = false;
          if (currentEvent.title && currentEvent.start && currentEvent.end) {
            events.push(currentEvent as CalendarEvent);
          }
        } else if (inEvent) {
          if (line.startsWith('SUMMARY:')) currentEvent.title = line.substring(8).trim();

          if (line.startsWith('DTSTART:')) {
             const dateStr = line.substring(8).trim();
             currentEvent.start = parseICSDate(dateStr);
          } else if (line.startsWith('DTSTART;')) {
             // Handle parameters like DTSTART;VALUE=DATE:20230505
             const parts = line.split(':');
             if (parts.length > 1) currentEvent.start = parseICSDate(parts[1].trim());
          }

          if (line.startsWith('DTEND:')) {
            const dateStr = line.substring(6).trim();
            currentEvent.end = parseICSDate(dateStr);
          } else if (line.startsWith('DTEND;')) {
             const parts = line.split(':');
             if (parts.length > 1) currentEvent.end = parseICSDate(parts[1].trim());
          }
        }
      }

      if (events.length === 0) {
        alert("No events found in the provided data.");
        return;
      }

      onImport(events);
      setIcsContent('');
      setUrlInput('');
      onClose();
    } catch (e) {
      console.error(e);
      alert("Failed to parse ICS data.");
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      processICSContent(text);
      setIsProcessing(false);
    };
    reader.onerror = () => {
        alert("Failed to read file.");
        setIsProcessing(false);
    };
    reader.readAsText(file);
  };

  const handleUrlImport = async () => {
    if (!urlInput) return;
    setIsProcessing(true);
    try {
        // Note: Simple fetch may fail due to CORS. 
        // In a real app, use a backend proxy.
        // For this demo, we try direct fetch.
        const response = await fetch(urlInput);
        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }
        const text = await response.text();
        processICSContent(text);
    } catch (e) {
        console.error(e);
        alert("Could not fetch from URL. This is likely due to CORS restrictions on the calendar server. Please download the .ics file manually and use the 'Upload File' option.");
    } finally {
        setIsProcessing(false);
    }
  };

  const handleManualPasteImport = () => {
      if (!icsContent) return;
      processICSContent(icsContent);
  };

  const handleSimulateImport = () => {
    setIsProcessing(true);
    setTimeout(() => {
      const today = new Date();
      const mockEvents: CalendarEvent[] = [
        {
          id: crypto.randomUUID(),
          title: "CS101 Lecture",
          start: new Date(today.getFullYear(), today.getMonth(), today.getDate(), 9, 0),
          end: new Date(today.getFullYear(), today.getMonth(), today.getDate(), 10, 30),
          type: EventType.IMPORTED,
          color: "bg-blue-500"
        },
        {
          id: crypto.randomUUID(),
          title: "Team Meeting",
          start: new Date(today.getFullYear(), today.getMonth(), today.getDate(), 14, 0),
          end: new Date(today.getFullYear(), today.getMonth(), today.getDate(), 15, 0),
          type: EventType.IMPORTED,
          color: "bg-blue-500"
        },
        {
          id: crypto.randomUUID(),
          title: "Gym",
          start: new Date(today.getFullYear(), today.getMonth(), today.getDate() + 1, 18, 0),
          end: new Date(today.getFullYear(), today.getMonth(), today.getDate() + 1, 19, 30),
          type: EventType.IMPORTED,
          color: "bg-green-500"
        }
      ];
      onImport(mockEvents);
      setIsProcessing(false);
      onClose();
    }, 800);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 p-4">
      <div className="bg-white rounded-lg shadow-xl w-full max-w-md p-6">
        <h2 className="text-xl font-bold mb-4 text-gray-800">Import Calendar</h2>

        {/* Tabs */}
        <div className="flex border-b border-gray-200 mb-6">
            <button 
                onClick={() => setActiveTab('upload')}
                className={`flex-1 py-2 text-sm font-medium border-b-2 ${activeTab === 'upload' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
            >
                Upload File
            </button>
            <button 
                onClick={() => setActiveTab('url')}
                className={`flex-1 py-2 text-sm font-medium border-b-2 ${activeTab === 'url' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
            >
                From URL
            </button>
            <button 
                onClick={() => setActiveTab('text')}
                className={`flex-1 py-2 text-sm font-medium border-b-2 ${activeTab === 'text' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
            >
                Paste Text
            </button>
        </div>

        <div className="min-h-[160px]">
            {activeTab === 'upload' && (
                <div className="text-center py-4">
                    <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-gray-300 border-dashed rounded-lg cursor-pointer bg-gray-50 hover:bg-gray-100">
                        <div className="flex flex-col items-center justify-center pt-5 pb-6">
                            <svg className="w-8 h-8 mb-4 text-gray-500" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 20 16">
                                <path stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 13h3a3 3 0 0 0 0-6h-.025A5.56 5.56 0 0 0 16 6.5 5.5 5.5 0 0 0 5.207 5.021C5.137 5.017 5.071 5 5 5a4 4 0 0 0 0 8h2.167M10 15V6m0 0L8 8m2-2 2 2"/>
                            </svg>
                            <p className="mb-2 text-sm text-gray-500"><span className="font-semibold">Click to upload .ics file</span></p>
                        </div>
                        <input type="file" accept=".ics,text/calendar" className="hidden" onChange={handleFileUpload} />
                    </label>
                    <p className="text-xs text-gray-500 mt-2">Supports .ics files exported from Google Calendar, Apple Calendar, Outlook, etc.</p>
                </div>
            )}

            {activeTab === 'url' && (
                <div className="py-2">
                    <label className="block text-sm font-medium text-gray-700 mb-2">Calendar Address (URL)</label>
                    <input 
                        type="url"
                        placeholder="https://calendar.google.com/calendar/ical/.../basic.ics"
                        value={urlInput}
                        onChange={(e) => setUrlInput(e.target.value)}
                        className="w-full p-2 border border-gray-300 rounded focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm"
                    />
                    <div className="mt-4 flex justify-end">
                        <Button onClick={handleUrlImport} isLoading={isProcessing} disabled={!urlInput}>
                            Fetch & Import
                        </Button>
                    </div>
                    <p className="text-xs text-gray-500 mt-4 bg-yellow-50 p-2 rounded border border-yellow-100">
                        Note: This must be a direct link to the .ics file. If the server blocks cross-origin requests (CORS), you may need to download the file and use the "Upload File" tab instead.
                    </p>
                </div>
            )}

            {activeTab === 'text' && (
                <div className="py-2">
                    <textarea 
                        className="w-full h-32 p-2 border border-gray-300 rounded focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 text-sm font-mono"
                        placeholder="BEGIN:VCALENDAR&#10;..."
                        value={icsContent}
                        onChange={(e) => setIcsContent(e.target.value)}
                    />
                    <div className="mt-2 flex justify-end">
                        <Button onClick={handleManualPasteImport} disabled={!icsContent} variant="primary">
                            Parse & Import
                        </Button>
                    </div>
                </div>
            )}
        </div>

        <div className="relative flex py-4 items-center">
            <div className="flex-grow border-t border-gray-300"></div>
            <span className="flex-shrink-0 mx-4 text-gray-400 text-xs">OR</span>
            <div className="flex-grow border-t border-gray-300"></div>
        </div>

        <div>
          <Button onClick={handleSimulateImport} isLoading={isProcessing} variant="secondary" className="w-full text-xs">
            Load Sample University Schedule
          </Button>
        </div>

        <div className="mt-6 flex justify-end">
          <Button variant="ghost" onClick={onClose}>Cancel</Button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Button } from './Button';
import { CalendarEvent, EventType } from '../types';

interface ImportModalProps {
  isOpen: boolean;
  onClose: () => void;
  onImport: (events: CalendarEvent[]) => void;
}

type TabType = 'upload' | 'url' | 'text';

export const ImportModal: React.FC<ImportModalProps> = ({ isOpen, onClose, onImport }) => {
  const [activeTab, setActiveTab] = useState<TabType>('upload');
  const [icsContent, setIcsContent] = useState('');
  const [urlInput, setUrlInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  if (!isOpen) return null;

  // Safe ID generator
  const generateId = () => {
    return Date.now().toString(36) + Math.random().toString(36).substring(2);
  };

  const parseICSDate = (str: string): Date | null => {
    try {
        if (!str) return null;

        // Handle basic format: 20231024T103000Z or 20231024
        const isUTC = str.endsWith('Z');
        const cleanStr = str.replace('Z', '');

        if (cleanStr.length < 8) return null;

        const year = parseInt(cleanStr.substring(0, 4));
        const month = parseInt(cleanStr.substring(4, 6)) - 1;
        const day = parseInt(cleanStr.substring(6, 8));

        if (isNaN(year) || isNaN(month) || isNaN(day)) return null;

        // All day event (YYYYMMDD)
        if (cleanStr.length === 8) {
             return new Date(year, month, day);
        }

        // With time (YYYYMMDDTHHMMSS)
        // T is at index 8
        const hour = parseInt(cleanStr.substring(9, 11));
        const min = parseInt(cleanStr.substring(11, 13));
        const sec = cleanStr.length >= 15 ? parseInt(cleanStr.substring(13, 15)) : 0;

        if (isNaN(hour) || isNaN(min)) return null;

        if (isUTC) {
            return new Date(Date.UTC(year, month, day, hour, min, sec));
        }

        return new Date(year, month, day, hour, min, sec);
    } catch (e) {
        console.warn("Date parse error for:", str);
        return null;
    }
  };

  const processICSContent = (content: string) => {
    try {
      if (!content.trim()) {
        alert("Content is empty.");
        return;
      }

      const events: CalendarEvent[] = [];
      const lines = content.split(/\r\n|\n|\r/);
      let currentEvent: Partial<CalendarEvent> | null = null;
      let inEvent = false;

      for (let i = 0; i < lines.length; i++) {
        const line = lines[i].trim();
        if (!line) continue;

        if (line === 'BEGIN:VEVENT') {
          inEvent = true;
          currentEvent = { id: generateId(), type: EventType.IMPORTED, color: "bg-blue-500" };
          continue;
        } 

        if (line === 'END:VEVENT') {
          inEvent = false;
          if (currentEvent && currentEvent.title && currentEvent.start && currentEvent.end) {
            // Check for valid dates
            if (!isNaN(currentEvent.start.getTime()) && !isNaN(currentEvent.end.getTime())) {
                events.push(currentEvent as CalendarEvent);
            }
          }
          currentEvent = null;
          continue;
        }

        if (inEvent && currentEvent) {
          if (line.startsWith('SUMMARY:')) {
            currentEvent.title = line.substring(8).trim();
          }

          // Handle Date Fields
          // They can be DTSTART:2023... or DTSTART;TZID=...:2023...
          if (line.startsWith('DTSTART')) {
             const parts = line.split(':');
             // The value is the last part usually, but to be safe with timezone params that might contain colons (unlikely but possible), 
             // we assume the date is after the last colon if it's a standard property. 
             // Actually, property values in ICS follow PROPERTY;PARAM=VALUE:CONTENT. content is everything after the first colon that isn't inside a quoted param.
             // Simplification: Split by first colon to separate Prop+Params from Value
             const firstColonIndex = line.indexOf(':');
             if (firstColonIndex > -1) {
                 const value = line.substring(firstColonIndex + 1).trim();
                 const date = parseICSDate(value);
                 if (date) currentEvent.start = date;
             }
          }

          if (line.startsWith('DTEND')) {
            const firstColonIndex = line.indexOf(':');
            if (firstColonIndex > -1) {
                const value = line.substring(firstColonIndex + 1).trim();
                const date = parseICSDate(value);
                if (date) currentEvent.end = date;
            }
          }
        }
      }

      if (events.length === 0) {
        alert("No valid events found. Please ensure the content is a valid ICS format.");
        return;
      }

      onImport(events);
      setIcsContent('');
      setUrlInput('');
      onClose();
    } catch (e) {
      console.error("Import processing error:", e);
      alert("An error occurred while processing the calendar data.");
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      processICSContent(text);
      setIsProcessing(false);
    };
    reader.onerror = () => {
        alert("Failed to read file.");
        setIsProcessing(false);
    };
    reader.readAsText(file);
  };

  const handleUrlImport = async () => {
    if (!urlInput) return;
    setIsProcessing(true);
    try {
        const response = await fetch(urlInput);
        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }
        const text = await response.text();
        processICSContent(text);
    } catch (e) {
        console.error(e);
        alert("Could not fetch from URL. Possible CORS issue. Please download the .ics file and upload it instead.");
    } finally {
        setIsProcessing(false);
    }
  };

  const handleManualPasteImport = () => {
      if (!icsContent) return;
      processICSContent(icsContent);
  };

  const handleSimulateImport = () => {
    setIsProcessing(true);
    setTimeout(() => {
      const today = new Date();
      const mockEvents: CalendarEvent[] = [
        {
          id: generateId(),
          title: "CS101 Lecture",
          start: new Date(today.getFullYear(), today.getMonth(), today.getDate(), 9, 0),
          end: new Date(today.getFullYear(), today.getMonth(), today.getDate(), 10, 30),
          type: EventType.IMPORTED,
          color: "bg-blue-500"
        },
        {
          id: generateId(),
          title: "Team Meeting",
          start: new Date(today.getFullYear(), today.getMonth(), today.getDate(), 14, 0),
          end: new Date(today.getFullYear(), today.getMonth(), today.getDate(), 15, 0),
          type: EventType.IMPORTED,
          color: "bg-blue-500"
        },
        {
          id: generateId(),
          title: "Gym",
          start: new Date(today.getFullYear(), today.getMonth(), today.getDate() + 1, 18, 0),
          end: new Date(today.getFullYear(), today.getMonth(), today.getDate() + 1, 19, 30),
          type: EventType.IMPORTED,
          color: "bg-green-500"
        }
      ];
      onImport(mockEvents);
      setIsProcessing(false);
      onClose();
    }, 800);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 p-4">
