import React, { useState } from 'react';
import { Task, TaskFile } from '../types';
import { Button } from './Button';

interface TaskFormProps {
  onSubmit: (task: Task) => Promise<void>;
  onCancel: () => void;
}

const DAYS_OF_WEEK = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"];

export const TaskForm: React.FC<TaskFormProps> = ({ onSubmit, onCancel }) => {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [difficulty, setDifficulty] = useState(5);
  const [totalHours, setTotalHours] = useState(2);
  const [deadline, setDeadline] = useState("");
  const [selectedDays, setSelectedDays] = useState<string[]>([]);
  const [files, setFiles] = useState<TaskFile[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Safe ID generator
  const generateId = () => {
    return Date.now().toString(36) + Math.random().toString(36).substring(2);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: TaskFile[] = Array.from(e.target.files).map(f => ({
        name: f.name,
        size: f.size,
        type: f.type,
        // In a real app, you'd upload to S3/Cloud storage here. 
        // We create a local URL for demo purposes.
        url: URL.createObjectURL(f) 
      }));
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const toggleDay = (day: string) => {
    setSelectedDays(prev => 
      prev.includes(day) ? prev.filter(d => d !== day) : [...prev, day]
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!deadline) {
        alert("Please select a deadline.");
        return;
    }

    setIsSubmitting(true);

    const newTask: Task = {
      id: generateId(),
      title,
      description,
      difficulty,
      totalHoursNeeded: totalHours,
      deadline: new Date(deadline),
      preferredDays: selectedDays.length > 0 ? selectedDays : DAYS_OF_WEEK,
      files,
      isScheduled: false
    };

    try {
      await onSubmit(newTask);
    } catch (err) {
      console.error(err);
      alert("Failed to schedule task. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-lg max-w-2xl mx-auto border border-gray-100">
      <h2 className="text-2xl font-bold text-gray-800 mb-6 flex items-center">
        <span className="bg-indigo-100 text-indigo-600 p-2 rounded-lg mr-3">
            ✨
        </span>
        Create Smart Task
      </h2>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Basic Info */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="col-span-2">
            <label className="block text-sm font-medium text-gray-700">Task Title</label>
            <input 
              required
              type="text" 
              value={title}
              onChange={e => setTitle(e.target.value)}
              className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-indigo-500 focus:border-indigo-500"
              placeholder="e.g. Write History Term Paper"
            />
          </div>

          <div className="col-span-2">
            <label className="block text-sm font-medium text-gray-700">Description</label>
            <textarea 
              value={description}
              onChange={e => setDescription(e.target.value)}
              rows={2}
              className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-indigo-500 focus:border-indigo-500"
              placeholder="What needs to be done?"
            />
          </div>

          <div>
             <label className="block text-sm font-medium text-gray-700">Deadline</label>
             <input 
                required
                type="datetime-local"
                value={deadline}
                onChange={e => setDeadline(e.target.value)}
                className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-indigo-500 focus:border-indigo-500"
             />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700">Total Hours Needed</label>
            <input 
              type="number" 
              min="0.5"
              step="0.5"
              value={totalHours}
              onChange={e => setTotalHours(parseFloat(e.target.value))}
              className="mt-1 block w-full rounded-md border-gray-300 shadow-sm border p-2 focus:ring-indigo-500 focus:border-indigo-500"
            />
          </div>
        </div>

        {/* Difficulty Slider */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Difficulty Level (1-10)
            <span className="ml-2 text-xs text-gray-500 font-normal">Higher difficulty results in more frequent breaks.</span>
          </label>
          <div className="flex items-center gap-4">
            <span className="text-sm text-gray-500">Easy</span>
            <input 
              type="range" 
              min="1" 
              max="10" 
              value={difficulty}
              onChange={e => setDifficulty(parseInt(e.target.value))}
              className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
            />
            <span className="text-sm text-gray-500">Hard</span>
            <span className="text-lg font-bold text-indigo-600 w-8 text-center">{difficulty}</span>
          </div>
        </div>

        {/* Preferred Days */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">Days willing to work</label>
          <div className="flex flex-wrap gap-2">
            {DAYS_OF_WEEK.map(day => (
              <button
                key={day}
                type="button"
                onClick={() => toggleDay(day)}
                className={`px-3 py-1 rounded-full text-xs font-medium border transition-colors ${
                  selectedDays.includes(day)
                    ? 'bg-indigo-600 text-white border-indigo-600'
                    : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'
                }`}
              >
                {day}
              </button>
            ))}
          </div>
          {selectedDays.length === 0 && <p className="text-xs text-gray-500 mt-1">If none selected, all days are considered.</p>}
        </div>

        {/* File Upload */}
        <div className="border-t pt-4">
          <label className="block text-sm font-medium text-gray-700 mb-2">Attach Materials/Files</label>
          <div className="flex items-center justify-center w-full">
            <label className="flex flex-col items-center justify-center w-full h-24 border-2 border-gray-300 border-dashed rounded-lg cursor-pointer bg-gray-50 hover:bg-gray-100">
                <div className="flex flex-col items-center justify-center pt-5 pb-6">
                    <p className="mb-2 text-sm text-gray-500"><span className="font-semibold">Click to upload</span> or drag and drop</p>
                </div>
                <input type="file" className="hidden" multiple onChange={handleFileChange} />
            </label>
          </div>

          {/* File List */}
          {files.length > 0 && (
            <ul className="mt-4 space-y-2">
              {files.map((file, idx) => (
                <li key={idx} className="flex items-center justify-between bg-gray-50 p-2 rounded border border-gray-200 text-sm">
                  <span className="truncate max-w-xs">{file.name} ({(file.size / 1024).toFixed(1)} KB)</span>
                  <button type="button" onClick={() => removeFile(idx)} className="text-red-500 hover:text-red-700">
                    ✕
                  </button>
                </li>
              ))}
            </ul>
          )}
        </div>

        {/* Actions */}
        <div className="flex justify-end gap-3 pt-4 border-t">
          <Button type="button" variant="secondary" onClick={onCancel}>Cancel</Button>
          <Button type="submit" isLoading={isSubmitting}>
             Generate Schedule with AI
          </Button>
        </div>
      </form>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { CalendarEvent, Task, EventType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Safe ID generator
const generateId = () => {
  return Date.now().toString(36) + Math.random().toString(36).substring(2);
};

export const generateWorkSessions = async (
  currentEvents: CalendarEvent[],
  task: Task
): Promise<CalendarEvent[]> => {
  const model = "gemini-3-flash-preview";

  // 1. Prepare context for the AI
  const eventContext = currentEvents.map(e => ({
    title: e.title,
    start: e.start.toISOString(),
    end: e.end.toISOString()
  }));

  const taskContext = {
    title: task.title,
    description: task.description,
    difficulty: task.difficulty,
    totalHours: task.totalHoursNeeded,
    deadline: task.deadline.toISOString(),
    preferredDays: task.preferredDays.join(", ")
  };

  const today = new Date();

  const prompt = `
    I am a student trying to prevent procrastination. 
    Today is ${today.toDateString()}.

    I have a task: "${taskContext.title}".
    Difficulty (1-10): ${taskContext.difficulty}.
    Total Estimated Work Hours Needed: ${taskContext.totalHours}.
    Deadline: ${taskContext.deadline}.
    I prefer to work on these days: ${taskContext.preferredDays}.

    Here is my current existing schedule (busy times):
    ${JSON.stringify(eventContext)}

    Please generate a list of "Work Sessions" to fit into my schedule between now and the deadline.

    Rules:
    1. Break the total hours into smaller, manageable chunks (e.g., 30 mins to 90 mins). 
    2. Higher difficulty tasks should have more breaks or shorter sessions.
    3. Do NOT overlap with existing events.
    4. Try to respect preferred days, but prioritize finishing before the deadline.
    5. Spread them out to avoid burnout.

    Return a JSON object containing an array of sessions.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            sessions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  startISO: { type: Type.STRING, description: "ISO date string for start time" },
                  endISO: { type: Type.STRING, description: "ISO date string for end time" },
                  summary: { type: Type.STRING, description: "Title of the session, e.g. 'Research for History Paper'" },
                  reasoning: { type: Type.STRING, description: "Why this time was chosen" }
                },
                required: ["startISO", "endISO", "summary"]
              }
            }
          }
        }
      }
    });

    const result = JSON.parse(response.text || "{ \"sessions\": [] }");

    // Map response back to application domain objects
    const newEvents: CalendarEvent[] = result.sessions.map((session: any) => ({
      id: generateId(),
      title: session.summary,
      start: new Date(session.startISO),
      end: new Date(session.endISO),
      type: EventType.AI_WORK_SESSION,
      description: session.reasoning,
      relatedTaskId: task.id,
      color: "bg-indigo-600" // Visual distinction
    }));

    return newEvents;

  } catch (error) {
    console.error("Gemini scheduling failed:", error);
    throw new Error("Failed to generate schedule. Please try again.");
  }
};

