};

export enum EventType {
  IMPORTED = 'IMPORTED', // From ICS or external
  MANUAL = 'MANUAL',     // User manually added
  AI_WORK_SESSION = 'AI_WORK_SESSION' // Generated by Gemini
}

export interface CalendarEvent {
  id: string;
  title: string;
  start: Date;
  end: Date;
  type: EventType;
  description?: string;
  relatedTaskId?: string; // If it's a work session for a specific task
  color?: string;
}

export interface TaskFile {
  name: string;
  size: number;
  type: string;
  url?: string; // For preview purposes
}

export interface Task {
  id: string;
  title: string;
  description: string;
  difficulty: number; // 1-10
  totalHoursNeeded: number;
  deadline: Date;
  preferredDays: string[]; // e.g., ["Monday", "Wednesday"]
  preferredTimeStart: string; // "09:00"
  preferredTimeEnd: string;   // "22:00"
  files: TaskFile[];
  isScheduled: boolean;
}

// Helper type for the Gemini response
export interface AIScheduleSuggestion {
  sessions: {
    startISO: string;
    endISO: string;
    summary: string;
    reasoning: string;
  }[];
}

import React, { useState, useEffect } from 'react';
