function App() {
  const [view, setView] = useState<'calendar' | 'newTask'>('calendar');
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);

  // Initialize with today's date
  const [currentDate, setCurrentDate] = useState(new Date());

  const handleNavigate = (direction: 'prev' | 'next' | 'today') => {
    const newDate = new Date(currentDate);
    if (direction === 'today') {
      setCurrentDate(new Date());
    } else if (direction === 'next') {
      newDate.setDate(newDate.getDate() + 7);
      setCurrentDate(newDate);
    } else {
      newDate.setDate(newDate.getDate() - 7);
      setCurrentDate(newDate);
    }
  };

  const handleImport = (importedEvents: CalendarEvent[]) => {
    setEvents(prev => [...prev, ...importedEvents]);
  };

  const handleCreateTask = async (task: Task) => {
    try {
      // Call AI Service
      const workSessions = await generateWorkSessions(events, task);

      // Update State
      setTasks(prev => [...prev, { ...task, isScheduled: true }]);
      setEvents(prev => [...prev, ...workSessions]);
      setView('calendar');
    } catch (error) {
      console.error(error);
      alert("Error generating schedule. Ensure you have a valid API Key set in the environment.");
    }
  };

  const handleDeleteEvent = (id: string) => {
    setEvents(prev => prev.filter(e => e.id !== id));
  };

  // Find the task related to the selected event if it exists
  const selectedTask = selectedEvent?.relatedTaskId 
    ? tasks.find(t => t.id === selectedEvent.relatedTaskId) 
    : undefined;

  return (
    <div className="min-h-screen flex flex-col">
      {/* Navbar */}
      <nav className="bg-white border-b border-gray-200 shadow-sm sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <span className="bg-indigo-600 text-white p-1.5 rounded-lg mr-2">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
              </span>
              <h1 className="text-xl font-bold text-gray-900">SparkPlan AI</h1>
            </div>
            <div className="flex items-center space-x-4">
              <Button variant="secondary" onClick={() => setIsImportModalOpen(true)}>
                Import Calendar
              </Button>
              <Button onClick={() => setView('newTask')} disabled={view === 'newTask'}>
                + New Smart Task
              </Button>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {view === 'calendar' ? (
          <>
            <div className="mb-6 flex items-center justify-between">
              <div>
                <h2 className="text-lg font-medium text-gray-900">Your Schedule</h2>
                <p className="text-sm text-gray-500">
                  {events.filter(e => e.type === EventType.AI_WORK_SESSION).length} AI sessions scheduled
                </p>
              </div>
              <div className="flex gap-2 text-sm">
                 <div className="flex items-center"><div className="w-3 h-3 bg-indigo-600 rounded mr-1"></div> Work Session</div>
                 <div className="flex items-center"><div className="w-3 h-3 bg-blue-500 rounded mr-1"></div> Class/Meeting</div>
              </div>
            </div>

            <div className="h-[calc(100vh-200px)]">
               <Calendar 
                  events={events} 
                  currentDate={currentDate} 
                  onEventClick={setSelectedEvent}
                  onNavigate={handleNavigate}
               />
            </div>
          </>
        ) : (
          <div className="py-8">
            <TaskForm 
              onSubmit={handleCreateTask} 
              onCancel={() => setView('calendar')} 
            />
          </div>
        )}
      </main>

      {/* Modals */}
      <ImportModal 
        isOpen={isImportModalOpen} 
        onClose={() => setIsImportModalOpen(false)} 
        onImport={handleImport} 
      />

      <EventDetailsModal 
        event={selectedEvent} 
        relatedTask={selectedTask}
        onClose={() => setSelectedEvent(null)}
        onDelete={handleDeleteEvent}
      />

    </div>
  );
}

