import React from 'react';
import { CalendarEvent, EventType } from '../types';

interface CalendarProps {
  events: CalendarEvent[];
  currentDate: Date;
  onEventClick: (event: CalendarEvent) => void;
  onNavigate: (direction: 'prev' | 'next' | 'today') => void;
}

export const Calendar: React.FC<CalendarProps> = ({ events, currentDate, onEventClick, onNavigate }) => {
  const daysOfWeek = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  // Extended hours: 6 AM to Midnight (18 hours)
  const startHour = 6;
  const hours = Array.from({ length: 18 }, (_, i) => i + startHour); 

  const getDayDates = () => {
    const dates = [];
    const startOfWeek = new Date(currentDate);
    const day = startOfWeek.getDay();
    // Adjust to make Sunday first
    startOfWeek.setDate(startOfWeek.getDate() - day);

    for (let i = 0; i < 7; i++) {
      const date = new Date(startOfWeek);
      date.setDate(startOfWeek.getDate() + i);
      dates.push(date);
    }
    return dates;
  };

  const weekDates = getDayDates();

  const getEventStyle = (event: CalendarEvent, colIndex: number) => {
    const eventStartHour = event.start.getHours() + event.start.getMinutes() / 60;
    const eventEndHour = event.end.getHours() + event.end.getMinutes() / 60;

    // Calculate duration
    const duration = eventEndHour - eventStartHour;

    // Calculate top position relative to the calendar start time
    const top = (eventStartHour - startHour) * 60; // 60px per hour
    const height = duration * 60;

    return {
      top: `${top}px`,
      height: `${height}px`,
      left: '2px',
      right: '2px'
    };
  };

  const isSameDay = (d1: Date, d2: Date) => {
    return d1.getDate() === d2.getDate() && 
           d1.getMonth() === d2.getMonth() && 
           d1.getFullYear() === d2.getFullYear();
  };

  const formatMonthYear = (date: Date) => {
    return date.toLocaleString('default', { month: 'long', year: 'numeric' });
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-lg shadow overflow-hidden border border-gray-200">

      {/* Navigation Header */}
      <div className="flex items-center justify-between px-6 py-4 border-b border-gray-200 bg-gray-50">
        <div className="flex items-center gap-4">
            <h2 className="text-xl font-bold text-gray-800">
                {formatMonthYear(weekDates[0])}
                {weekDates[0].getMonth() !== weekDates[6].getMonth() && ` - ${formatMonthYear(weekDates[6])}`}
            </h2>
            <div className="flex items-center bg-white rounded-md border border-gray-300 shadow-sm">
                <button 
                    onClick={() => onNavigate('prev')} 
                    className="px-3 py-1.5 hover:bg-gray-50 text-gray-600 border-r border-gray-300"
                    title="Previous Week"
                >
                    &lt;
                </button>
                <button 
                    onClick={() => onNavigate('today')} 
                    className="px-4 py-1.5 hover:bg-gray-50 text-sm font-medium text-gray-700"
                >
                    Today
                </button>
                <button 
                    onClick={() => onNavigate('next')} 
                    className="px-3 py-1.5 hover:bg-gray-50 text-gray-600 border-l border-gray-300"
                    title="Next Week"
                >
                    &gt;
                </button>
            </div>
        </div>
      </div>

      {/* Days Header */}
      <div className="grid grid-cols-8 border-b border-gray-200 bg-white">
        <div className="p-2 border-r border-gray-100 text-xs font-semibold text-gray-500 uppercase tracking-wide text-center pt-8">
           Time
        </div>
        {weekDates.map((date, i) => (
          <div key={i} className={`p-2 text-center border-r border-gray-100 ${isSameDay(date, new Date()) ? 'bg-indigo-50' : ''}`}>
            <div className="text-xs font-semibold text-gray-500 uppercase tracking-wide">{daysOfWeek[date.getDay()]}</div>
            <div className={`mt-1 text-lg font-bold ${isSameDay(date, new Date()) ? 'text-indigo-600' : 'text-gray-900'}`}>
              {date.getDate()}
            </div>
          </div>
        ))}
      </div>

      {/* Grid */}
      <div className="flex-1 overflow-y-auto relative" style={{ maxHeight: '600px' }}>
        <div className="grid grid-cols-8 min-h-[1080px]">
          {/* Time Sidebar */}
          <div className="border-r border-gray-100 bg-gray-50">
            {hours.map(hour => (
              <div key={hour} className="h-[60px] border-b border-gray-200 text-xs text-gray-500 text-right pr-2 pt-2 relative">
                 {hour > 12 ? `${hour - 12} PM` : `${hour} ${hour === 12 ? 'PM' : 'AM'}`}
                 {hour === 24 && '12 AM'}
              </div>
            ))}
          </div>

          {/* Days Columns */}
          {weekDates.map((date, colIndex) => {
            const dayEvents = events.filter(e => isSameDay(e.start, date));

            return (
              <div key={colIndex} className="relative border-r border-gray-100 hover:bg-gray-50 transition-colors">
                 {/* Grid lines */}
                {hours.map(hour => (
                  <div key={hour} className="h-[60px] border-b border-gray-100"></div>
                ))}

                {/* Events */}
                {dayEvents.map(event => {
                    const styles = getEventStyle(event, colIndex);
                    // Filter out events that are completely outside of renderable hours (e.g. 2AM if start is 6AM)
                    // Simple check: if top is negative and height + top < 0
                    if (parseInt(styles.top) + parseInt(styles.height) < 0) return null;

                    return (
                      <div
                        key={event.id}
                        onClick={(e) => { e.stopPropagation(); onEventClick(event); }}
                        className={`absolute rounded px-2 py-1 text-xs cursor-pointer shadow-sm transition-all hover:scale-[1.02] hover:z-10 overflow-hidden ${
                          event.type === EventType.AI_WORK_SESSION 
                            ? 'bg-indigo-600 text-white border-indigo-700' 
                            : event.color || 'bg-blue-500 text-white'
                        }`}
                        style={styles}
                      >
                        <div className="font-semibold truncate">{event.title}</div>
                        <div className="opacity-90 text-[10px] hidden sm:block">
                          {event.start.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - 
                          {event.end.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                        </div>
                      </div>
                    );
                })}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Task, TaskFile } from '../types';
