              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { CalendarEvent, EventType } from '../types';

interface CalendarProps {
  events: CalendarEvent[];
  currentDate: Date;
  onEventClick: (event: CalendarEvent) => void;
  onNavigate: (direction: 'prev' | 'next' | 'today') => void;
}

export const Calendar: React.FC<CalendarProps> = ({ events, currentDate, onEventClick, onNavigate }) => {
  const daysOfWeek = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  // Extended hours: 6 AM to Midnight (18 hours)
  const startHour = 6;
  const hours = Array.from({ length: 18 }, (_, i) => i + startHour); 

  const getDayDates = () => {
    const dates = [];
    const startOfWeek = new Date(currentDate);
    const day = startOfWeek.getDay();
    // Adjust to make Sunday first
    startOfWeek.setDate(startOfWeek.getDate() - day);

    for (let i = 0; i < 7; i++) {
      const date = new Date(startOfWeek);
      // Create a new date object for each day to avoid reference issues
      date.setDate(startOfWeek.getDate() + i);
      dates.push(date);
    }
    return dates;
  };

  const weekDates = getDayDates();

  const getEventStyle = (event: CalendarEvent, colIndex: number) => {
    const eventStartHour = event.start.getHours() + event.start.getMinutes() / 60;
    const eventEndHour = event.end.getHours() + event.end.getMinutes() / 60;

    // Calculate duration
    const duration = eventEndHour - eventStartHour;

    // Calculate top position relative to the calendar start time
    const top = (eventStartHour - startHour) * 60; // 60px per hour
    const height = duration * 60;

    return {
      top: `${top}px`,
      height: `${height}px`,
      left: '2px',
      right: '2px'
    };
  };

  const isSameDay = (d1: Date, d2: Date) => {
    return d1.getDate() === d2.getDate() && 
           d1.getMonth() === d2.getMonth() && 
           d1.getFullYear() === d2.getFullYear();
  };

  const formatWeekRange = (start: Date, end: Date) => {
    const startMonth = start.toLocaleString('default', { month: 'short' });
    const endMonth = end.toLocaleString('default', { month: 'short' });
    const startYear = start.getFullYear();
    const endYear = end.getFullYear();

    // Same month, same year: "Oct 22 - 28, 2023"
    if (startMonth === endMonth && startYear === endYear) {
        return `${startMonth} ${start.getDate()} - ${end.getDate()}, ${startYear}`;
    }

    // Different month, same year: "Oct 29 - Nov 4, 2023"
    if (startYear === endYear) {
        return `${startMonth} ${start.getDate()} - ${endMonth} ${end.getDate()}, ${startYear}`;
    }

    // Different year: "Dec 31, 2023 - Jan 6, 2024"
    return `${startMonth} ${start.getDate()}, ${startYear} - ${endMonth} ${end.getDate()}, ${endYear}`;
  };

  const formatMonthYear = (date: Date) => {
    return date.toLocaleString('default', { month: 'long', year: 'numeric' });
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-lg shadow overflow-hidden border border-gray-200">

      {/* Navigation Header */}
      <div className="flex items-center justify-between px-6 py-4 border-b border-gray-200 bg-gray-50">
        <div className="flex items-center gap-4">
            <h2 className="text-xl font-bold text-gray-800 w-48">
                {formatMonthYear(weekDates[0])}
            </h2>
            <div className="flex items-center gap-3">
                <div className="flex items-center bg-white rounded-md border border-gray-300 shadow-sm">
                    <button 
                        onClick={() => onNavigate('prev')} 
                        className="px-3 py-2 hover:bg-gray-50 text-gray-600 border-r border-gray-300 transition-colors"
                        title="Previous Week"
                    >
                        &lt;
                    </button>
                    <div className="px-4 py-2 text-sm font-medium text-gray-700 min-w-[160px] text-center bg-gray-50">
                        {formatWeekRange(weekDates[0], weekDates[6])}
                    </div>
                    <button 
                        onClick={() => onNavigate('next')} 
                        className="px-3 py-2 hover:bg-gray-50 text-gray-600 border-l border-gray-300 transition-colors"
                        title="Next Week"
                    >
                        &gt;
                    </button>
                </div>
                <button 
                    onClick={() => onNavigate('today')} 
                    className="px-3 py-2 bg-white border border-gray-300 rounded-md text-sm font-medium text-gray-700 hover:bg-gray-50 transition-colors"
                >
                    Today
                </button>
            </div>
        </div>
      </div>

      {/* Days Header */}
      <div className="grid grid-cols-8 border-b border-gray-200 bg-white">
        <div className="p-2 border-r border-gray-100 text-xs font-semibold text-gray-500 uppercase tracking-wide text-center pt-8">
           Time
        </div>
        {weekDates.map((date, i) => (
          <div key={i} className={`p-2 text-center border-r border-gray-100 ${isSameDay(date, new Date()) ? 'bg-indigo-50' : ''}`}>
            <div className="text-xs font-semibold text-gray-500 uppercase tracking-wide">{daysOfWeek[date.getDay()]}</div>
            <div className={`mt-1 text-lg font-bold ${isSameDay(date, new Date()) ? 'text-indigo-600' : 'text-gray-900'}`}>
              {date.getDate()}
            </div>
          </div>
        ))}
      </div>

      {/* Grid */}
      <div className="flex-1 overflow-y-auto relative" style={{ maxHeight: '600px' }}>
        <div className="grid grid-cols-8 min-h-[1080px]">
          {/* Time Sidebar */}
          <div className="border-r border-gray-100 bg-gray-50">
            {hours.map(hour => (
              <div key={hour} className="h-[60px] border-b border-gray-200 text-xs text-gray-500 text-right pr-2 pt-2 relative">
                 {hour > 12 ? `${hour - 12} PM` : `${hour} ${hour === 12 ? 'PM' : 'AM'}`}
                 {hour === 24 && '12 AM'}
              </div>
            ))}
          </div>

          {/* Days Columns */}
          {weekDates.map((date, colIndex) => {
            const dayEvents = events.filter(e => isSameDay(e.start, date));

            return (
              <div key={colIndex} className="relative border-r border-gray-100 hover:bg-gray-50 transition-colors">
                 {/* Grid lines */}
                {hours.map(hour => (
                  <div key={hour} className="h-[60px] border-b border-gray-100"></div>
                ))}

                {/* Events */}
                {dayEvents.map(event => {
                    const styles = getEventStyle(event, colIndex);
                    // Filter out events that are completely outside of renderable hours (e.g. 2AM if start is 6AM)
                    // Simple check: if top is negative and height + top < 0
                    if (parseInt(styles.top) + parseInt(styles.height) < 0) return null;

                    return (
                      <div
                        key={event.id}
                        onClick={(e) => { e.stopPropagation(); onEventClick(event); }}
                        className={`absolute rounded px-2 py-1 text-xs cursor-pointer shadow-sm transition-all hover:scale-[1.02] hover:z-10 overflow-hidden ${
                          event.type === EventType.AI_WORK_SESSION 
                            ? 'bg-indigo-600 text-white border-indigo-700' 
                            : event.color || 'bg-blue-500 text-white'
                        }`}
                        style={styles}
                      >
                        <div className="font-semibold truncate">{event.title}</div>
                        <div className="opacity-90 text-[10px] hidden sm:block">
                          {event.start.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - 
                          {event.end.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                        </div>
                      </div>
                    );
                })}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { CalendarEvent, Task, EventType, AIScheduleSuggestion } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateWorkSessions = async (
  currentEvents: CalendarEvent[],
  task: Task
): Promise<CalendarEvent[]> => {
  // Use gemini-3-flash-preview for fast, logical reasoning
  const model = "gemini-3-flash-preview";

  // 1. Prepare context for the AI
  const eventContext = currentEvents.map(e => ({
    title: e.title,
    start: e.start.toLocaleString(), // Use local string to help AI understand user's time context
    end: e.end.toLocaleString()
  }));

  const taskContext = {
    title: task.title,
    description: task.description,
    difficulty: task.difficulty,
    totalHours: task.totalHoursNeeded,
    deadline: task.deadline.toLocaleString(),
    preferredDays: task.preferredDays.join(", "),
    preferredTimeStart: task.preferredTimeStart,
    preferredTimeEnd: task.preferredTimeEnd
  };

  const today = new Date();

  const prompt = `
    I am a student trying to prevent procrastination. 
    Current Date/Time: ${today.toLocaleString()}.

    I have a task: "${taskContext.title}".
    Difficulty (1-10): ${taskContext.difficulty}.
    Total Estimated Work Hours Needed: ${taskContext.totalHours}.
    Deadline: ${taskContext.deadline}.
    I prefer to work on these days: ${taskContext.preferredDays}.

    CRITICAL CONSTRAINTS (MUST FOLLOW):
    1. My working hours are STRICTLY between ${taskContext.preferredTimeStart} and ${taskContext.preferredTimeEnd}.
    2. ABSOLUTELY NO sessions starting before ${taskContext.preferredTimeStart}.
    3. ABSOLUTELY NO sessions ending after ${taskContext.preferredTimeEnd}.
    4. Do NOT overlap with existing busy events provided below.

    Here is my current existing schedule (busy times):
    ${JSON.stringify(eventContext)}

    Please generate a list of "Work Sessions" to fit into my schedule between now and the deadline.

    Planning Rules:
    1. Break the total hours into smaller, manageable chunks (e.g., 45 mins to 90 mins). 
    2. Higher difficulty tasks should have more breaks or shorter sessions.
    3. If the deadline is very close, prioritize finding any available slot within working hours, even if it's not a "preferred day".
  `;

  // 2. Define Output Schema
  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      sessions: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            startISO: { type: Type.STRING, description: "The ISO 8601 date string for the start of the session" },
            endISO: { type: Type.STRING, description: "The ISO 8601 date string for the end of the session" },
            summary: { type: Type.STRING, description: "A short title for this session (e.g. 'Research Phase')" },
            reasoning: { type: Type.STRING, description: "Brief explanation of why this slot was chosen (e.g. 'Morning slot for high focus')" }
          },
          required: ["startISO", "endISO", "summary", "reasoning"]
        }
      }
    }
  };

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        // Lower temperature to make the model stricter about following constraints
        temperature: 0.1, 
      },
    });

    const outputText = response.text;
    if (!outputText) {
      throw new Error("No response received from AI");
    }

    const result = JSON.parse(outputText) as AIScheduleSuggestion;

    // 3. Map to CalendarEvent objects
    const newEvents: CalendarEvent[] = result.sessions.map((session, index) => ({
      id: crypto.randomUUID(),
      title: `${task.title} (${index + 1}/${result.sessions.length})`,
      start: new Date(session.startISO),
      end: new Date(session.endISO),
      type: EventType.AI_WORK_SESSION,
      description: session.reasoning,
      relatedTaskId: task.id,
      color: "bg-indigo-600"
    }));

    return newEvents;

  } catch (error) {
    console.error("Error generating work sessions:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { Calendar } from './components/Calendar';
