import { CalendarEvent, Task, EventType } from './types';

function App() {
  const [view, setView] = useState<'calendar' | 'newTask'>('calendar');
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  // Initialize with today's date
  const [currentDate, setCurrentDate] = useState(new Date());

  const handleNavigate = (direction: 'prev' | 'next' | 'today') => {
    const newDate = new Date(currentDate);
    if (direction === 'today') {
      setCurrentDate(new Date());
    } else if (direction === 'next') {
      newDate.setDate(newDate.getDate() + 7);
      setCurrentDate(newDate);
    } else {
      newDate.setDate(newDate.getDate() - 7);
      setCurrentDate(newDate);
    }
  };

  // Helper to run the scheduler globally
  const runGlobalScheduler = (fixedEvents: CalendarEvent[], currentTasks: Task[]) => {
    // 1. Filter out old generated sessions from the base events
    // (Assuming 'fixedEvents' passed in are already clean of AI sessions, but double check)
    const cleanFixedEvents = fixedEvents.filter(e => e.type !== EventType.AI_WORK_SESSION);

    // 2. Run EDF Scheduler
    const newSessions = scheduleTasks(cleanFixedEvents, currentTasks);

    // 3. Merge
    return [...cleanFixedEvents, ...newSessions];
  };

  const handleImport = async (importedEvents: CalendarEvent[]) => {
    setIsImportModalOpen(false);
    setIsProcessing(true);

    try {
      // 1. Get existing fixed events (Manual + previously Imported)
      const existingFixed = events.filter(e => e.type !== EventType.AI_WORK_SESSION);

      // 2. Combine with new imports
      const allFixedEvents = [...existingFixed, ...importedEvents];

      // 3. Re-run scheduler for ALL tasks against the new constraints
      const optimizedSchedule = runGlobalScheduler(allFixedEvents, tasks);

      setEvents(optimizedSchedule);
    } catch (error) {
      console.error("Import error:", error);
      alert("An error occurred while processing the schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCreateTask = async (task: Task) => {
    setIsProcessing(true);
    try {
      // 1. Add new task to list
      const updatedTasks = [...tasks, { ...task, isScheduled: true }];
      setTasks(updatedTasks);

      // 2. Get current fixed events
      const fixedEvents = events.filter(e => e.type !== EventType.AI_WORK_SESSION);

      // 3. Re-run scheduler
      const optimizedSchedule = runGlobalScheduler(fixedEvents, updatedTasks);

      setEvents(optimizedSchedule);
      setView('calendar');
    } catch (error) {
      console.error(error);
      alert("Error generating schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDeleteEvent = (id: string) => {
    const eventToDelete = events.find(e => e.id === id);
    if (!eventToDelete) return;

    if (eventToDelete.type === EventType.AI_WORK_SESSION) {
        // If deleting a work session, we might want to just remove that specific block
        // OR optionally remove the task? For now, just remove the event.
        setEvents(prev => prev.filter(e => e.id !== id));
    } else {
        // If deleting a fixed event (manual/imported), we should technically reschedule tasks
        // to fill the gap.
        const remainingFixed = events.filter(e => e.id !== id && e.type !== EventType.AI_WORK_SESSION);

        // Re-run scheduler to potentially use the newly freed time
        const optimizedSchedule = runGlobalScheduler(remainingFixed, tasks);
        setEvents(optimizedSchedule);
    }
  };

  // Find the task related to the selected event if it exists
  const selectedTask = selectedEvent?.relatedTaskId 
    ? tasks.find(t => t.id === selectedEvent.relatedTaskId) 
    : undefined;

  return (
    <div className="min-h-screen flex flex-col relative">
      {/* Navbar */}
      <nav className="bg-white border-b border-gray-200 shadow-sm sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <span className="bg-indigo-600 text-white p-1.5 rounded-lg mr-2">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
              </span>
              <h1 className="text-xl font-bold text-gray-900">SparkPlan AI</h1>
            </div>
            <div className="flex items-center space-x-4">
              <Button variant="secondary" onClick={() => setIsImportModalOpen(true)}>
                Import Calendar
              </Button>
              <Button onClick={() => setView('newTask')} disabled={view === 'newTask'}>
                + New Smart Task
              </Button>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {view === 'calendar' ? (
          <>
            <div className="mb-6 flex items-center justify-between">
              <div>
                <h2 className="text-lg font-medium text-gray-900">Your Schedule</h2>
                <p className="text-sm text-gray-500">
                  {events.filter(e => e.type === EventType.AI_WORK_SESSION).length} Work sessions scheduled
                </p>
              </div>
              <div className="flex gap-2 text-sm">
                 <div className="flex items-center"><div className="w-3 h-3 bg-indigo-600 rounded mr-1"></div> Work Session</div>
                 <div className="flex items-center"><div className="w-3 h-3 bg-blue-500 rounded mr-1"></div> Class/Meeting</div>
              </div>
            </div>

            <div className="h-[calc(100vh-200px)]">
               <Calendar 
                  events={events} 
                  currentDate={currentDate} 
                  onEventClick={setSelectedEvent}
                  onNavigate={handleNavigate}
               />
            </div>
          </>
        ) : (
          <div className="py-8">
            <TaskForm 
              onSubmit={handleCreateTask} 
              onCancel={() => setView('calendar')} 
            />
          </div>
        )}
      </main>

      {/* Modals */}
      <ImportModal 
        isOpen={isImportModalOpen} 
        onClose={() => setIsImportModalOpen(false)} 
        onImport={handleImport} 
      />

      <EventDetailsModal 
        event={selectedEvent} 
        relatedTask={selectedTask}
        onClose={() => setSelectedEvent(null)}
        onDelete={handleDeleteEvent}
      />

      {/* Loading Overlay */}
      {isProcessing && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 backdrop-blur-sm transition-opacity">
            <div className="bg-white p-8 rounded-lg shadow-xl flex flex-col items-center max-w-sm text-center">
                <div className="animate-spin rounded-full h-12 w-12 border-4 border-indigo-100 border-t-indigo-600 mb-4"></div>
                <h3 className="text-lg font-bold text-gray-900">Optimizing Schedule...</h3>
                <p className="text-sm text-gray-500 mt-2">Re-calculating the best slots for your deadlines using EDF algorithm.</p>
            </div>
        </div>
      )}

    </div>
  );
}

export default App;

import { CalendarEvent, Task, EventType } from '../types';

/**
 * Parses a time string (e.g. "14:30") and sets it on the given date object.
 */
const parseTimeOnDate = (timeStr: string, date: Date): Date => {
    const [hours, minutes] = timeStr.split(':').map(Number);
    const newDate = new Date(date);
    newDate.setHours(hours, minutes, 0, 0);
    return newDate;
};

/**
 * Checks if two date ranges overlap
 */
const isOverlapping = (start1: Date, end1: Date, start2: Date, end2: Date): boolean => {
    return start1 < end2 && end1 > start2;
};

interface TimeRange {
    start: Date;
    end: Date;
}

/**
 * Subtracts busy intervals from a time range to find free bins.
 */
const calculateFreeBins = (
    rangeStart: Date,
    rangeEnd: Date,
    busyEvents: CalendarEvent[]
): TimeRange[] => {
    // Sort busy events by start time
    const sortedBusy = [...busyEvents]
        .filter(e => isOverlapping(e.start, e.end, rangeStart, rangeEnd))
        .sort((a, b) => a.start.getTime() - b.start.getTime());

    const freeBins: TimeRange[] = [];
    let currentStart = new Date(rangeStart);

    for (const event of sortedBusy) {
        // Clamp event start/end to the range
        const eventStart = event.start < rangeStart ? rangeStart : event.start;
        const eventEnd = event.end > rangeEnd ? rangeEnd : event.end;

        if (eventStart > currentStart) {
            // We have a gap
            freeBins.push({ start: new Date(currentStart), end: new Date(eventStart) });
        }

        // Move currentStart to the end of this blocking event if it's further ahead
        if (eventEnd > currentStart) {
            currentStart = new Date(eventEnd);
        }
    }

    // Add remaining time after last event
    if (currentStart < rangeEnd) {
        freeBins.push({ start: new Date(currentStart), end: new Date(rangeEnd) });
    }

    return freeBins;
};

/**
 * Distributed Earliest Deadline First (EDF) Scheduler
 * - Sorts by Deadline
 * - Spreads work over multiple days (Load Balancing)
 * - Enforces max session lengths
 */
export const scheduleTasks = (
    fixedEvents: CalendarEvent[],
    tasks: Task[]
): CalendarEvent[] => {
    // 1. Sort tasks by deadline (EDF) - Ascending
    const sortedTasks = [...tasks].sort((a, b) => a.deadline.getTime() - b.deadline.getTime());

    const scheduledEvents: CalendarEvent[] = [];

    // Helper to get all currently occupied slots
    const getOccupiedSlots = () => {
        return [...fixedEvents, ...scheduledEvents];
    };

    const now = new Date();
    // Round 'now' up to the next 15 minute mark to avoid scheduling in the past few minutes
    const startOfScheduling = new Date(now);
    const remainder = 15 - (startOfScheduling.getMinutes() % 15);
    startOfScheduling.setMinutes(startOfScheduling.getMinutes() + remainder, 0, 0);

    const MAX_SESSION_DURATION_HOURS = 1.5; // Max 90 mins per block
    const MIN_SESSION_DURATION_HOURS = 0.5; // Min 30 mins per block

    for (const task of sortedTasks) {
        if (!task.isScheduled) continue;

        let hoursRemaining = task.totalHoursNeeded;
        let currentDate = new Date(startOfScheduling);

        // Safety break
        let dayCount = 0;
        const maxDays = 365;

        // Calculate total available days until deadline to determine spread
        const timeUntilDeadline = task.deadline.getTime() - now.getTime();
        const daysUntilDeadline = Math.max(1, Math.ceil(timeUntilDeadline / (1000 * 60 * 60 * 24)));

        // Ideal Daily Limit: Spread the work! 
        // If 10 hours needed in 5 days, aim for ~2 hours/day.
        // We add a slight buffer (1.2x) to be flexible, but cap it so we don't do it all at once.
        // Base Cap is usually 2 hours/day unless the math says we need more.
        const averageHoursPerDay = hoursRemaining / daysUntilDeadline;
        const dynamicDailyLimitBase = Math.max(2.0, averageHoursPerDay * 1.2); 

        while (hoursRemaining > 0 && currentDate < task.deadline && dayCount < maxDays) {
            dayCount++;

            const dayName = currentDate.toLocaleDateString('en-US', { weekday: 'long' });

            // Check if day is preferred
            if (task.preferredDays.includes(dayName)) {

                // Recalculate urgency on the fly
                // If we are getting closer to deadline and still have lots of work, increase the daily cap
                const currentDiffMs = task.deadline.getTime() - currentDate.getTime();
                const currentDaysLeft = Math.max(0.5, currentDiffMs / (1000 * 60 * 60 * 24));

                // If it's the last day(s), panic mode: Unlimited daily cap.
                // Otherwise, use the spread logic.
                let effectiveDailyLimit = (currentDaysLeft < 1.5) 
                    ? 24 // "Panic mode": Take all available time
                    : dynamicDailyLimitBase;

                let hoursScheduledToday = 0;

                // Define the working window for this day
                const windowStart = parseTimeOnDate(task.preferredTimeStart, currentDate);
                const windowEnd = parseTimeOnDate(task.preferredTimeEnd, currentDate);

                // Adjust windowStart if it's today and 'startOfScheduling' is later
                const effectiveStart = (windowStart < startOfScheduling) ? startOfScheduling : windowStart;

                if (effectiveStart < windowEnd) {
                    // Get all busy events that could overlap with this day's window
                    const busyEvents = getOccupiedSlots();

                    // Get Free Bins
                    const freeBins = calculateFreeBins(effectiveStart, windowEnd, busyEvents);

                    for (const bin of freeBins) {
                        if (hoursRemaining <= 0) break;
                        if (hoursScheduledToday >= effectiveDailyLimit) break;

                        const binDurationMs = bin.end.getTime() - bin.start.getTime();
                        const binDurationHours = binDurationMs / (1000 * 60 * 60);

                        if (binDurationHours < MIN_SESSION_DURATION_HOURS) continue;

                        // Calculate how much we can fit in this bin
                        // Constrained by:
                        // 1. Total task work remaining
                        // 2. The bin size
                        // 3. Max session length (force a break)
                        // 4. Daily limit remaining
                        const maxForThisSession = Math.min(
                            MAX_SESSION_DURATION_HOURS, 
                            effectiveDailyLimit - hoursScheduledToday
                        );

                        const timeToTake = Math.min(hoursRemaining, binDurationHours, maxForThisSession);

                        // Don't schedule tiny fragments unless it finishes the task
                        if (timeToTake < MIN_SESSION_DURATION_HOURS && timeToTake < hoursRemaining) continue;

                        const sessionEnd = new Date(bin.start.getTime() + timeToTake * 60 * 60 * 1000);

                        scheduledEvents.push({
                            id: crypto.randomUUID(),
                            title: `${task.title}`,
                            start: new Date(bin.start),
                            end: sessionEnd,
                            type: EventType.AI_WORK_SESSION,
                            relatedTaskId: task.id,
                            description: `Focus Session (${timeToTake.toFixed(1)}h). Deadline: ${task.deadline.toLocaleDateString()}`,
                            color: 'bg-indigo-600'
                        });

                        hoursRemaining -= timeToTake;
                        hoursScheduledToday += timeToTake;
                    }
                }
            }

            // Move to next day
            currentDate.setDate(currentDate.getDate() + 1);
            currentDate.setHours(0, 0, 0, 0);
        }

        // If loop finished and hoursRemaining > 0, it means we couldn't fit it in with "Nice" constraints.
        // In a real app, we would notify the user. For now, we leave it partially unscheduled or 
        // relies on "Panic Mode" (last 1.5 days) to catch most of it.
    }

    return scheduledEvents;
};

export enum EventType {
  IMPORTED = 'IMPORTED', // From ICS or external
  MANUAL = 'MANUAL',     // User manually added
  AI_WORK_SESSION = 'AI_WORK_SESSION' // Generated by Engine
}

export type Priority = 'High' | 'Medium' | 'Low';
export type EnergyLevel = 'High' | 'Low';

export interface CalendarEvent {
  id: string;
  title: string;
  start: Date;
  end: Date;
  type: EventType;
  description?: string;
  relatedTaskId?: string; 
  color?: string;
  priority?: Priority;
}

export interface TaskFile {
  name: string;
  size: number;
  type: string;
  url?: string; 
}

export interface Task {
  id: string;
  title: string;
  description: string;
  difficulty: number; 
  totalHoursNeeded: number;
  deadline: Date;
  preferredDays: string[]; 
  preferredTimeStart: string; 
  preferredTimeEnd: string;
  files: TaskFile[];
  isScheduled: boolean;
  priority: Priority;
  energyLevel: EnergyLevel;
}

import { CalendarEvent, Task, EventType, Priority } from '../types';

/**
 * Parses a time string (e.g. "14:30") and sets it on the given date object.
 */
const parseTimeOnDate = (timeStr: string, date: Date): Date => {
    const [hours, minutes] = timeStr.split(':').map(Number);
    const newDate = new Date(date);
    newDate.setHours(hours, minutes, 0, 0);
    return newDate;
};

/**
 * Checks if two date ranges overlap
 */
const isOverlapping = (start1: Date, end1: Date, start2: Date, end2: Date): boolean => {
    return start1 < end2 && end1 > start2;
};

interface TimeRange {
    start: Date;
    end: Date;
}

/**
 * Subtracts busy intervals from a time range to find free bins.
 */
const calculateFreeBins = (
    rangeStart: Date,
    rangeEnd: Date,
    busyEvents: CalendarEvent[]
): TimeRange[] => {
    // Sort busy events by start time
    const sortedBusy = [...busyEvents]
        .filter(e => isOverlapping(e.start, e.end, rangeStart, rangeEnd))
        .sort((a, b) => a.start.getTime() - b.start.getTime());

    const freeBins: TimeRange[] = [];
    let currentStart = new Date(rangeStart);

    for (const event of sortedBusy) {
        // Clamp event start/end to the range
        const eventStart = event.start < rangeStart ? rangeStart : event.start;
        const eventEnd = event.end > rangeEnd ? rangeEnd : event.end;

        if (eventStart > currentStart) {
            freeBins.push({ start: new Date(currentStart), end: new Date(eventStart) });
        }

        if (eventEnd > currentStart) {
            currentStart = new Date(eventEnd);
        }
    }

    if (currentStart < rangeEnd) {
        freeBins.push({ start: new Date(currentStart), end: new Date(rangeEnd) });
    }

    return freeBins;
};

const getEventColorByPriority = (priority: Priority) => {
    switch(priority) {
        case 'High': return 'bg-red-900 border-red-700 text-red-100';
        case 'Medium': return 'bg-yellow-900 border-yellow-700 text-yellow-100';
        case 'Low': return 'bg-emerald-900 border-emerald-700 text-emerald-100';
        default: return 'bg-neutral-800 border-neutral-600 text-neutral-200';
    }
};

/**
 * Deterministic Scheduler Engine
 * 1. Earliest Deadline First (EDF)
 * 2. Energy Level Heuristics (Morning vs Evening preference)
 * 3. Preemptive Splitting
 */
export const scheduleTasks = (
    fixedEvents: CalendarEvent[],
    tasks: Task[]
): CalendarEvent[] => {
    // 1. Sort tasks by deadline (EDF)
    const sortedTasks = [...tasks].sort((a, b) => a.deadline.getTime() - b.deadline.getTime());

    const scheduledEvents: CalendarEvent[] = [];

    const getOccupiedSlots = () => [...fixedEvents, ...scheduledEvents];

    const now = new Date();
    const startOfScheduling = new Date(now);
    // Align to next 15 min slot
    const remainder = 15 - (startOfScheduling.getMinutes() % 15);
    startOfScheduling.setMinutes(startOfScheduling.getMinutes() + remainder, 0, 0);

    const MIN_SESSION_DURATION_HOURS = 0.5; 

    for (const task of sortedTasks) {
        if (!task.isScheduled) continue;

        let hoursRemaining = task.totalHoursNeeded;
        let currentDate = new Date(startOfScheduling);

        let dayCount = 0;
        const maxDays = 365; // Safety break

        while (hoursRemaining > 0 && currentDate < task.deadline && dayCount < maxDays) {
            dayCount++;

            const dayName = currentDate.toLocaleDateString('en-US', { weekday: 'long' });

            if (task.preferredDays.includes(dayName)) {
                // Determine Day Window
                const windowStart = parseTimeOnDate(task.preferredTimeStart, currentDate);
                const windowEnd = parseTimeOnDate(task.preferredTimeEnd, currentDate);
                const effectiveStart = (windowStart < startOfScheduling) ? startOfScheduling : windowStart;

                if (effectiveStart < windowEnd) {
                    const busyEvents = getOccupiedSlots();

                    // Get Free Bins
                    let freeBins = calculateFreeBins(effectiveStart, windowEnd, busyEvents);

                    // --- Weighted Heuristic: Energy Level Sorting ---
                    // If High Energy: Prefer bins earlier in the day
                    // If Low Energy: Prefer bins later in the day
                    freeBins.sort((a, b) => {
                        const midA = (a.start.getHours() + a.end.getHours()) / 2;
                        const midB = (b.start.getHours() + b.end.getHours()) / 2;

                        if (task.energyLevel === 'High') {
                            return midA - midB; // Ascending (Morning first)
                        } else {
                            return midB - midA; // Descending (Evening first)
                        }
                    });

                    for (const bin of freeBins) {
                        if (hoursRemaining <= 0) break;

                        const binDurationMs = bin.end.getTime() - bin.start.getTime();
                        const binDurationHours = binDurationMs / (1000 * 60 * 60);

                        if (binDurationHours < MIN_SESSION_DURATION_HOURS) continue;

                        // Max session length to prevent burnout (e.g., 2 hours max per block)
                        const MAX_BLOCK_HOURS = 2;
                        const timeToTake = Math.min(hoursRemaining, binDurationHours, MAX_BLOCK_HOURS);

                        // Don't leave tiny slivers unless finishing task
                        if (timeToTake < MIN_SESSION_DURATION_HOURS && timeToTake < hoursRemaining) continue;

                        const sessionEnd = new Date(bin.start.getTime() + timeToTake * 60 * 60 * 1000);

                        scheduledEvents.push({
                            id: crypto.randomUUID(),
                            title: task.title,
                            start: new Date(bin.start),
                            end: sessionEnd,
                            type: EventType.AI_WORK_SESSION,
                            relatedTaskId: task.id,
                            description: `Priority: ${task.priority} | Energy: ${task.energyLevel}`,
                            color: getEventColorByPriority(task.priority),
                            priority: task.priority
                        });

                        hoursRemaining -= timeToTake;
                    }
                }
            }
            // Next day
            currentDate.setDate(currentDate.getDate() + 1);
            currentDate.setHours(0, 0, 0, 0);
        }
    }

    return scheduledEvents;
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  disabled, 
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center px-4 py-2 border text-sm font-medium rounded-md shadow-sm focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-black transition-all";

  const variants = {
    primary: "border-transparent text-black bg-white hover:bg-gray-200 focus:ring-white",
    secondary: "border-gray-700 text-gray-200 bg-black hover:bg-gray-900 focus:ring-gray-500",
    danger: "border-transparent text-white bg-red-900 hover:bg-red-800 focus:ring-red-900",
    ghost: "border-transparent text-gray-400 bg-transparent hover:text-white hover:bg-gray-900 focus:ring-gray-500 shadow-none"
  };

  return (
    <button
      disabled={disabled || isLoading}
      className={`${baseStyles} ${variants[variant]} ${className} ${isLoading ? 'opacity-70 cursor-not-allowed' : ''}`}
      {...props}
    >
      {isLoading ? (
        <>
          <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          ...
        </>
      ) : children}
    </button>
  );
};

import React, { useState } from 'react';
import { Task, TaskFile, Priority, EnergyLevel } from '../types';
import { Button } from './Button';

interface TaskFormProps {
  onSubmit: (task: Task) => Promise<void>;
  onCancel: () => void;
}

const DAYS_OF_WEEK = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"];

export const TaskForm: React.FC<TaskFormProps> = ({ onSubmit, onCancel }) => {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [priority, setPriority] = useState<Priority>('Medium');
  const [energyLevel, setEnergyLevel] = useState<EnergyLevel>('High');
  const [totalHours, setTotalHours] = useState(2);
  const [deadline, setDeadline] = useState("");
  const [selectedDays, setSelectedDays] = useState<string[]>([]);
  const [preferredTimeStart, setPreferredTimeStart] = useState("09:00");
  const [preferredTimeEnd, setPreferredTimeEnd] = useState("22:00");
  const [files, setFiles] = useState<TaskFile[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: TaskFile[] = Array.from(e.target.files).map(f => ({
        name: f.name,
        size: f.size,
        type: f.type,
        url: URL.createObjectURL(f) 
      }));
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const toggleDay = (day: string) => {
    setSelectedDays(prev => 
      prev.includes(day) ? prev.filter(d => d !== day) : [...prev, day]
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!deadline) {
        alert("Please select a deadline.");
        return;
    }

    setIsSubmitting(true);

    const newTask: Task = {
      id: crypto.randomUUID(),
      title,
      description,
      difficulty: 5, // Deprecated in UI but kept for type compatibility if needed
