import { CalendarEvent, Task, EventType } from './types';

function App() {
  const [view, setView] = useState<'calendar' | 'newTask'>('calendar');
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const [currentDate, setCurrentDate] = useState(new Date());

  const handleNavigate = (direction: 'prev' | 'next' | 'today') => {
    const newDate = new Date(currentDate);
    if (direction === 'today') {
      setCurrentDate(new Date());
    } else if (direction === 'next') {
      newDate.setDate(newDate.getDate() + 7);
      setCurrentDate(newDate);
    } else {
      newDate.setDate(newDate.getDate() - 7);
      setCurrentDate(newDate);
    }
  };

  const runGlobalScheduler = (fixedEvents: CalendarEvent[], currentTasks: Task[]) => {
    const cleanFixedEvents = fixedEvents.filter(e => e.type !== EventType.AI_WORK_SESSION);
    const newSessions = scheduleTasks(cleanFixedEvents, currentTasks);
    return [...cleanFixedEvents, ...newSessions];
  };

  const handleImport = async (importedEvents: CalendarEvent[]) => {
    setIsImportModalOpen(false);
    setIsProcessing(true);
    try {
      const existingFixed = events.filter(e => e.type !== EventType.AI_WORK_SESSION);
      const allFixedEvents = [...existingFixed, ...importedEvents];
      const optimizedSchedule = runGlobalScheduler(allFixedEvents, tasks);
      setEvents(optimizedSchedule);
    } catch (error) {
      console.error("Import error:", error);
      alert("Error processing schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCreateTask = async (task: Task) => {
    setIsProcessing(true);
    try {
      const updatedTasks = [...tasks, { ...task, isScheduled: true }];
      setTasks(updatedTasks);
      const fixedEvents = events.filter(e => e.type !== EventType.AI_WORK_SESSION);
      const optimizedSchedule = runGlobalScheduler(fixedEvents, updatedTasks);
      setEvents(optimizedSchedule);
      setView('calendar');
    } catch (error) {
      console.error(error);
      alert("Error generating schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDeleteEvent = (id: string) => {
    const eventToDelete = events.find(e => e.id === id);
    if (!eventToDelete) return;

    if (eventToDelete.type === EventType.AI_WORK_SESSION) {
        setEvents(prev => prev.filter(e => e.id !== id));
    } else {
        const remainingFixed = events.filter(e => e.id !== id && e.type !== EventType.AI_WORK_SESSION);
        const optimizedSchedule = runGlobalScheduler(remainingFixed, tasks);
        setEvents(optimizedSchedule);
    }
  };

  const selectedTask = selectedEvent?.relatedTaskId 
    ? tasks.find(t => t.id === selectedEvent.relatedTaskId) 
    : undefined;

  return (
    <div className="min-h-screen flex flex-col relative bg-gray-50 text-gray-900 font-sans">
      {/* Navbar */}
      <nav className="border-b border-gray-200 bg-white sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <span className="bg-indigo-600 text-white p-1.5 rounded mr-3 font-bold">
                 SP
              </span>
              <h1 className="text-xl font-bold tracking-tight text-gray-900">SparkPlan AI</h1>
            </div>
            <div className="flex items-center space-x-4">
              <Button variant="ghost" onClick={() => setIsImportModalOpen(true)}>
                Import
              </Button>
              <Button onClick={() => setView('newTask')} disabled={view === 'newTask'}>
                + New Task
              </Button>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {view === 'calendar' ? (
          <>
            <div className="mb-6 flex items-center justify-between">
              <div>
                <h2 className="text-xl font-bold text-gray-900 tracking-tight">Dashboard</h2>
                <p className="text-sm text-gray-500 mt-1">
                  {events.filter(e => e.type === EventType.AI_WORK_SESSION).length} active work sessions.
                </p>
              </div>
              <div className="flex gap-4 text-xs font-medium text-gray-600">
                 <div className="flex items-center"><div className="w-2 h-2 bg-gray-300 rounded-full mr-2"></div> Manual Block</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-red-400 rounded-full mr-2"></div> High Prio</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-emerald-400 rounded-full mr-2"></div> Low Prio</div>
              </div>
            </div>

            <div className="h-[calc(100vh-200px)]">
               <Calendar 
                  events={events} 
                  currentDate={currentDate} 
                  onEventClick={setSelectedEvent}
                  onNavigate={handleNavigate}
               />
            </div>
          </>
        ) : (
          <div className="py-8">
            <TaskForm 
              onSubmit={handleCreateTask} 
              onCancel={() => setView('calendar')} 
            />
          </div>
        )}
      </main>

      {/* Modals */}
      <ImportModal 
        isOpen={isImportModalOpen} 
        onClose={() => setIsImportModalOpen(false)} 
        onImport={handleImport} 
      />

      <EventDetailsModal 
        event={selectedEvent} 
        relatedTask={selectedTask}
        onClose={() => setSelectedEvent(null)}
        onDelete={handleDeleteEvent}
      />

      {/* Loading Overlay */}
      {isProcessing && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-900 bg-opacity-50 backdrop-blur-sm transition-opacity">
            <div className="flex flex-col items-center p-6 bg-white rounded-lg shadow-xl">
                <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
                <h3 className="text-lg font-bold text-gray-900 tracking-widest uppercase">Optimizing</h3>
            </div>
        </div>
      )}

    </div>
  );
}

export default App;

import { CalendarEvent, Task, EventType, Priority } from '../types';

/**
 * Parses a time string (e.g. "14:30") and sets it on the given date object.
 */
const parseTimeOnDate = (timeStr: string, date: Date): Date => {
    const [hours, minutes] = timeStr.split(':').map(Number);
    const newDate = new Date(date);
    newDate.setHours(hours, minutes, 0, 0);
    return newDate;
};

/**
 * Checks if two date ranges overlap
 */
const isOverlapping = (start1: Date, end1: Date, start2: Date, end2: Date): boolean => {
    return start1 < end2 && end1 > start2;
};

interface TimeRange {
    start: Date;
    end: Date;
}

/**
 * Subtracts busy intervals from a time range to find free bins.
 */
const calculateFreeBins = (
    rangeStart: Date,
    rangeEnd: Date,
    busyEvents: CalendarEvent[]
): TimeRange[] => {
    // Sort busy events by start time
    const sortedBusy = [...busyEvents]
        .filter(e => isOverlapping(e.start, e.end, rangeStart, rangeEnd))
        .sort((a, b) => a.start.getTime() - b.start.getTime());

    const freeBins: TimeRange[] = [];
    let currentStart = new Date(rangeStart);

    for (const event of sortedBusy) {
        // Clamp event start/end to the range
        const eventStart = event.start < rangeStart ? rangeStart : event.start;
        const eventEnd = event.end > rangeEnd ? rangeEnd : event.end;

        if (eventStart > currentStart) {
            freeBins.push({ start: new Date(currentStart), end: new Date(eventStart) });
        }

        if (eventEnd > currentStart) {
            currentStart = new Date(eventEnd);
        }
    }

    if (currentStart < rangeEnd) {
        freeBins.push({ start: new Date(currentStart), end: new Date(rangeEnd) });
    }

    return freeBins;
};

const getEventColorByPriority = (priority: Priority) => {
    switch(priority) {
        case 'High': return 'bg-red-50 border-red-200 text-red-700';
        case 'Medium': return 'bg-amber-50 border-amber-200 text-amber-700';
        case 'Low': return 'bg-emerald-50 border-emerald-200 text-emerald-700';
        default: return 'bg-gray-50 border-gray-200 text-gray-700';
    }
};

/**
 * Deterministic Scheduler Engine
 * 1. Earliest Deadline First (EDF)
 * 2. Energy Level Heuristics (Morning vs Evening preference)
 * 3. Preemptive Splitting
 */
export const scheduleTasks = (
    fixedEvents: CalendarEvent[],
    tasks: Task[]
): CalendarEvent[] => {
    // 1. Sort tasks by deadline (EDF)
    const sortedTasks = [...tasks].sort((a, b) => a.deadline.getTime() - b.deadline.getTime());

    const scheduledEvents: CalendarEvent[] = [];

    const getOccupiedSlots = () => [...fixedEvents, ...scheduledEvents];

    const now = new Date();
    const startOfScheduling = new Date(now);
    // Align to next 15 min slot
    const remainder = 15 - (startOfScheduling.getMinutes() % 15);
    startOfScheduling.setMinutes(startOfScheduling.getMinutes() + remainder, 0, 0);

    const MIN_SESSION_DURATION_HOURS = 0.5; 

    for (const task of sortedTasks) {
        if (!task.isScheduled) continue;

        let hoursRemaining = task.totalHoursNeeded;
        let currentDate = new Date(startOfScheduling);

        let dayCount = 0;
        const maxDays = 365; // Safety break

        while (hoursRemaining > 0 && currentDate < task.deadline && dayCount < maxDays) {
            dayCount++;

            const dayName = currentDate.toLocaleDateString('en-US', { weekday: 'long' });

            if (task.preferredDays.includes(dayName)) {
                // Determine Day Window
                const windowStart = parseTimeOnDate(task.preferredTimeStart, currentDate);
                const windowEnd = parseTimeOnDate(task.preferredTimeEnd, currentDate);
                const effectiveStart = (windowStart < startOfScheduling) ? startOfScheduling : windowStart;

                if (effectiveStart < windowEnd) {
                    const busyEvents = getOccupiedSlots();

                    // Get Free Bins
                    let freeBins = calculateFreeBins(effectiveStart, windowEnd, busyEvents);

                    // --- Weighted Heuristic: Energy Level Sorting ---
                    // If High Energy: Prefer bins earlier in the day
                    // If Low Energy: Prefer bins later in the day
                    freeBins.sort((a, b) => {
                        const midA = (a.start.getHours() + a.end.getHours()) / 2;
                        const midB = (b.start.getHours() + b.end.getHours()) / 2;

                        if (task.energyLevel === 'High') {
                            return midA - midB; // Ascending (Morning first)
                        } else {
                            return midB - midA; // Descending (Evening first)
                        }
                    });

                    for (const bin of freeBins) {
                        if (hoursRemaining <= 0) break;

                        const binDurationMs = bin.end.getTime() - bin.start.getTime();
                        const binDurationHours = binDurationMs / (1000 * 60 * 60);

                        if (binDurationHours < MIN_SESSION_DURATION_HOURS) continue;

                        // Max session length to prevent burnout (e.g., 2 hours max per block)
                        const MAX_BLOCK_HOURS = 2;
                        const timeToTake = Math.min(hoursRemaining, binDurationHours, MAX_BLOCK_HOURS);

                        // Don't leave tiny slivers unless finishing task
                        if (timeToTake < MIN_SESSION_DURATION_HOURS && timeToTake < hoursRemaining) continue;

                        const sessionEnd = new Date(bin.start.getTime() + timeToTake * 60 * 60 * 1000);

                        scheduledEvents.push({
                            id: crypto.randomUUID(),
                            title: task.title,
                            start: new Date(bin.start),
                            end: sessionEnd,
                            type: EventType.AI_WORK_SESSION,
                            relatedTaskId: task.id,
                            description: `Priority: ${task.priority} | Energy: ${task.energyLevel}`,
                            color: getEventColorByPriority(task.priority),
                            priority: task.priority
                        });

                        hoursRemaining -= timeToTake;
                    }
                }
            }
            // Next day
            currentDate.setDate(currentDate.getDate() + 1);
            currentDate.setHours(0, 0, 0, 0);
        }
    }

    return scheduledEvents;
};

export enum EventType {
  IMPORTED = 'IMPORTED', // From ICS or external
  MANUAL = 'MANUAL',     // User manually added
  AI_WORK_SESSION = 'AI_WORK_SESSION' // Generated by Engine
}

export type Priority = 'High' | 'Medium' | 'Low';
export type EnergyLevel = 'High' | 'Low';

export interface CalendarEvent {
  id: string;
  title: string;
  start: Date;
  end: Date;
  type: EventType;
  description?: string;
  relatedTaskId?: string; 
  color?: string;
  priority?: Priority;
  isClass?: boolean; // New property to identify classes
}

export interface TaskFile {
  name: string;
  size: number;
  type: string;
  url?: string; 
}

export interface Task {
  id: string;
  title: string;
  description: string;
  difficulty: number; 
  totalHoursNeeded: number;
  deadline: Date;
  preferredDays: string[]; 
  preferredTimeStart: string; 
  preferredTimeEnd: string;
  files: TaskFile[];
  isScheduled: boolean;
  priority: Priority;
  energyLevel: EnergyLevel;
}

export interface AIScheduleSuggestion {
  sessions: {
    startISO: string;
    endISO: string;
    summary: string;
    reasoning: string;
  }[];
}

export interface AIClassClassification {
  classEventIds: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { CalendarEvent, Task, EventType, AIScheduleSuggestion, AIClassClassification } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = "gemini-3-flash-preview";

export const identifyClasses = async (events: CalendarEvent[]): Promise<string[]> => {
  if (events.length === 0) return [];

  const eventSummaries = events.map(e => ({
    id: e.id,
    title: e.title,
    description: e.description || ""
  }));

  const prompt = `
    Analyze the following calendar events and identify which ones are likely University Classes, Lectures, Labs, or Recitations.
    Return a list of IDs for the events that ARE classes.
    Ignore social events, work, or general reminders.

    Events:
    ${JSON.stringify(eventSummaries)}
  `;

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      classEventIds: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "List of Event IDs that are identified as academic classes."
      }
    }
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.1,
      },
    });

    const outputText = response.text;
    if (!outputText) return [];

    const result = JSON.parse(outputText) as AIClassClassification;
    return result.classEventIds || [];
  } catch (error) {
    console.error("Error identifying classes:", error);
    return []; // Fail gracefully by returning no classes
  }
};

export const generateWorkSessions = async (
  currentEvents: CalendarEvent[],
  task: Task
): Promise<CalendarEvent[]> => {

  // 1. Prepare context for the AI
  const eventContext = currentEvents.map(e => ({
    title: e.title,
    start: e.start.toLocaleString(), 
    end: e.end.toLocaleString()
  }));

  const taskContext = {
    title: task.title,
    description: task.description,
    difficulty: task.difficulty,
    totalHours: task.totalHoursNeeded,
    deadline: task.deadline.toLocaleString(),
    preferredDays: task.preferredDays.join(", "),
    preferredTimeStart: task.preferredTimeStart,
    preferredTimeEnd: task.preferredTimeEnd
  };

  const today = new Date();

  const prompt = `
    I am a student trying to prevent procrastination. 
    Current Date/Time: ${today.toLocaleString()}.

    I have a task: "${taskContext.title}".
    Difficulty (1-10): ${taskContext.difficulty}.
    Total Estimated Work Hours Needed: ${taskContext.totalHours}.
    Deadline: ${taskContext.deadline}.
    I prefer to work on these days: ${taskContext.preferredDays}.

    CRITICAL CONSTRAINTS (MUST FOLLOW):
    1. My working hours are STRICTLY between ${taskContext.preferredTimeStart} and ${taskContext.preferredTimeEnd}.
    2. ABSOLUTELY NO sessions starting before ${taskContext.preferredTimeStart}.
    3. ABSOLUTELY NO sessions ending after ${taskContext.preferredTimeEnd}.
    4. Do NOT overlap with existing busy events provided below.

    Here is my current existing schedule (busy times):
    ${JSON.stringify(eventContext)}

    Please generate a list of "Work Sessions" to fit into my schedule between now and the deadline.

    Planning Rules:
    1. Break the total hours into smaller, manageable chunks (e.g., 45 mins to 90 mins). 
    2. Higher difficulty tasks should have more breaks or shorter sessions.
    3. If the deadline is very close, prioritize finding any available slot within working hours, even if it's not a "preferred day".
  `;

  // 2. Define Output Schema
  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      sessions: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            startISO: { type: Type.STRING, description: "The ISO 8601 date string for the start of the session" },
            endISO: { type: Type.STRING, description: "The ISO 8601 date string for the end of the session" },
            summary: { type: Type.STRING, description: "A short title for this session (e.g. 'Research Phase')" },
            reasoning: { type: Type.STRING, description: "Brief explanation of why this slot was chosen (e.g. 'Morning slot for high focus')" }
          },
          required: ["startISO", "endISO", "summary", "reasoning"]
        }
      }
    }
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.1, 
      },
    });

    const outputText = response.text;
    if (!outputText) {
      throw new Error("No response received from AI");
    }

    const result = JSON.parse(outputText) as AIScheduleSuggestion;

    // 3. Map to CalendarEvent objects
    const newEvents: CalendarEvent[] = result.sessions.map((session, index) => ({
      id: crypto.randomUUID(),
      title: `${task.title} (${index + 1}/${result.sessions.length})`,
      start: new Date(session.startISO),
      end: new Date(session.endISO),
      type: EventType.AI_WORK_SESSION,
      description: session.reasoning,
      relatedTaskId: task.id,
      color: "bg-indigo-600"
    }));

    return newEvents;

  } catch (error) {
    console.error("Error generating work sessions:", error);
    throw error;
  }
};

