/**
 * Deterministic Scheduler Engine
 * 1. Earliest Deadline First (EDF)
 * 2. Energy Level Heuristics (Morning vs Evening preference)
 * 3. Preemptive Splitting
 * 4. Class Buffering (30 mins before/after)
 */
export const scheduleTasks = (
    fixedEvents: CalendarEvent[],
    tasks: Task[]
): CalendarEvent[] => {
    // 1. Sort tasks by deadline (EDF)
    const sortedTasks = [...tasks].sort((a, b) => a.deadline.getTime() - b.deadline.getTime());

    const scheduledEvents: CalendarEvent[] = [];

    // Helper: Apply buffers to classes for collision detection
    const getOccupiedSlots = () => {
        // Create a buffer around "Class" events
        const bufferedFixed = fixedEvents.map(e => {
            if (e.isClass) {
                const bufferedStart = new Date(e.start);
                bufferedStart.setMinutes(bufferedStart.getMinutes() - 30);
                const bufferedEnd = new Date(e.end);
                bufferedEnd.setMinutes(bufferedEnd.getMinutes() + 30);
                return { ...e, start: bufferedStart, end: bufferedEnd };
            }
            return e;
        });
        return [...bufferedFixed, ...scheduledEvents];
    };

    const now = new Date();
    const startOfScheduling = new Date(now);
    // Align to next 15 min slot
    const remainder = 15 - (startOfScheduling.getMinutes() % 15);
    startOfScheduling.setMinutes(startOfScheduling.getMinutes() + remainder, 0, 0);

    const MIN_SESSION_DURATION_HOURS = 0.5; 

    for (const task of sortedTasks) {
        if (!task.isScheduled) continue;

        let hoursRemaining = task.totalHoursNeeded;

        // Sanity check to prevent "20 hours" bug if input is bad
        if (typeof hoursRemaining !== 'number' || isNaN(hoursRemaining) || hoursRemaining <= 0) {
            continue; 
        }

        let currentDate = new Date(startOfScheduling);

        let dayCount = 0;
        const maxDays = 365; // Safety break

        while (hoursRemaining > 0.05 && currentDate < task.deadline && dayCount < maxDays) {
            dayCount++;

            const dayName = currentDate.toLocaleDateString('en-US', { weekday: 'long' });

            if (task.preferredDays.includes(dayName)) {
                // Determine Day Window
                const windowStart = parseTimeOnDate(task.preferredTimeStart, currentDate);
                const windowEnd = parseTimeOnDate(task.preferredTimeEnd, currentDate);
                const effectiveStart = (windowStart < startOfScheduling) ? startOfScheduling : windowStart;

                if (effectiveStart < windowEnd) {
                    const busyEvents = getOccupiedSlots();

                    // Get Free Bins
                    let freeBins = calculateFreeBins(effectiveStart, windowEnd, busyEvents);

                    // --- Weighted Heuristic: Energy Level Sorting ---
                    freeBins.sort((a, b) => {
                        const midA = (a.start.getHours() + a.end.getHours()) / 2;
                        const midB = (b.start.getHours() + b.end.getHours()) / 2;

                        if (task.energyLevel === 'High') {
                            return midA - midB; // Ascending (Morning first)
                        } else {
                            return midB - midA; // Descending (Evening first)
                        }
                    });

                    for (const bin of freeBins) {
                        if (hoursRemaining <= 0.05) break;

                        const binDurationMs = bin.end.getTime() - bin.start.getTime();
                        const binDurationHours = binDurationMs / (1000 * 60 * 60);

                        if (binDurationHours < MIN_SESSION_DURATION_HOURS) continue;

                        // Max session length to prevent burnout
                        const MAX_BLOCK_HOURS = 2;
                        const timeToTake = Math.min(hoursRemaining, binDurationHours, MAX_BLOCK_HOURS);

                        // Don't leave tiny slivers unless finishing task
                        if (timeToTake < MIN_SESSION_DURATION_HOURS && Math.abs(timeToTake - hoursRemaining) > 0.05) continue;

                        const sessionEnd = new Date(bin.start.getTime() + timeToTake * 60 * 60 * 1000);

                        scheduledEvents.push({
                            id: crypto.randomUUID(),
                            title: task.title,
                            start: new Date(bin.start),
                            end: sessionEnd,
                            type: EventType.AI_WORK_SESSION,
                            relatedTaskId: task.id,
                            description: `Priority: ${task.priority} | Energy: ${task.energyLevel}`,
                            color: getEventColorByPriority(task.priority),
                            priority: task.priority
                        });

                        hoursRemaining -= timeToTake;
                    }
                }
            }
            // Next day
            currentDate.setDate(currentDate.getDate() + 1);
            currentDate.setHours(0, 0, 0, 0);
        }
    }

    return scheduledEvents;
};

import React, { useState } from 'react';
import { Calendar } from './components/Calendar';
import { TaskForm } from './components/TaskForm';
import { ImportModal } from './components/ImportModal';
import { EventDetailsModal } from './components/EventDetailsModal';
import { Button } from './components/Button';
import { scheduleTasks } from './services/scheduler';
import { identifyClasses } from './services/geminiService';
import { CalendarEvent, Task, EventType } from './types';

function App() {
  const [view, setView] = useState<'calendar' | 'newTask'>('calendar');
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const [currentDate, setCurrentDate] = useState(new Date());

  const handleNavigate = (direction: 'prev' | 'next' | 'today') => {
    const newDate = new Date(currentDate);
    if (direction === 'today') {
      setCurrentDate(new Date());
    } else if (direction === 'next') {
      newDate.setDate(newDate.getDate() + 7);
      setCurrentDate(newDate);
    } else {
      newDate.setDate(newDate.getDate() - 7);
      setCurrentDate(newDate);
    }
  };

  const runGlobalScheduler = (fixedEvents: CalendarEvent[], currentTasks: Task[]) => {
    const cleanFixedEvents = fixedEvents.filter(e => e.type !== EventType.AI_WORK_SESSION);
    const newSessions = scheduleTasks(cleanFixedEvents, currentTasks);
    return [...cleanFixedEvents, ...newSessions];
  };

  const handleImport = async (importedEvents: CalendarEvent[]) => {
    setIsImportModalOpen(false);
    setIsProcessing(true);
    try {
      // 1. Identify which events are classes using AI
      const classIds = await identifyClasses(importedEvents);

      // 2. Tag events
      const taggedEvents = importedEvents.map(e => ({
        ...e,
        isClass: classIds.includes(e.id),
        // If it's a class, maybe give it a specific color if not set?
        color: classIds.includes(e.id) ? "bg-blue-50 border-blue-200 text-blue-700" : e.color
      }));

      const existingFixed = events.filter(e => e.type !== EventType.AI_WORK_SESSION);
      const allFixedEvents = [...existingFixed, ...taggedEvents];
      const optimizedSchedule = runGlobalScheduler(allFixedEvents, tasks);
      setEvents(optimizedSchedule);
    } catch (error) {
      console.error("Import error:", error);
      alert("Error processing schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCreateTask = async (task: Task) => {
    setIsProcessing(true);
    try {
      const updatedTasks = [...tasks, { ...task, isScheduled: true }];
      setTasks(updatedTasks);
      const fixedEvents = events.filter(e => e.type !== EventType.AI_WORK_SESSION);
      const optimizedSchedule = runGlobalScheduler(fixedEvents, updatedTasks);
      setEvents(optimizedSchedule);
      setView('calendar');
    } catch (error) {
      console.error(error);
      alert("Error generating schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDeleteEvent = (id: string) => {
    const eventToDelete = events.find(e => e.id === id);
    if (!eventToDelete) return;

    if (eventToDelete.type === EventType.AI_WORK_SESSION) {
        setEvents(prev => prev.filter(e => e.id !== id));
    } else {
        const remainingFixed = events.filter(e => e.id !== id && e.type !== EventType.AI_WORK_SESSION);
        const optimizedSchedule = runGlobalScheduler(remainingFixed, tasks);
        setEvents(optimizedSchedule);
    }
  };

  const selectedTask = selectedEvent?.relatedTaskId 
    ? tasks.find(t => t.id === selectedEvent.relatedTaskId) 
    : undefined;

  return (
    <div className="min-h-screen flex flex-col relative bg-gray-50 text-gray-900 font-sans">
      {/* Navbar */}
      <nav className="border-b border-gray-200 bg-white sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <span className="bg-indigo-600 text-white p-1.5 rounded mr-3 font-bold">
                 SP
              </span>
              <h1 className="text-xl font-bold tracking-tight text-gray-900">SparkPlan AI</h1>
            </div>
            <div className="flex items-center space-x-4">
              <Button variant="ghost" onClick={() => setIsImportModalOpen(true)}>
                Import
              </Button>
              <Button onClick={() => setView('newTask')} disabled={view === 'newTask'}>
                + New Task
              </Button>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {view === 'calendar' ? (
          <>
            <div className="mb-6 flex items-center justify-between">
              <div>
                <h2 className="text-xl font-bold text-gray-900 tracking-tight">Dashboard</h2>
                <p className="text-sm text-gray-500 mt-1">
                  {events.filter(e => e.type === EventType.AI_WORK_SESSION).length} active work sessions.
                </p>
              </div>
              <div className="flex gap-4 text-xs font-medium text-gray-600">
                 <div className="flex items-center"><div className="w-2 h-2 bg-gray-300 rounded-full mr-2"></div> Manual Block</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-blue-400 rounded-full mr-2"></div> Class (+30m Buffer)</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-indigo-600 rounded-full mr-2"></div> Work Session</div>
              </div>
            </div>

            <div className="h-[calc(100vh-200px)]">
               <Calendar 
                  events={events} 
                  currentDate={currentDate} 
                  onEventClick={setSelectedEvent}
                  onNavigate={handleNavigate}
               />
            </div>
          </>
        ) : (
          <div className="py-8">
            <TaskForm 
              onSubmit={handleCreateTask} 
              onCancel={() => setView('calendar')} 
            />
          </div>
        )}
      </main>

      {/* Modals */}
      <ImportModal 
        isOpen={isImportModalOpen} 
        onClose={() => setIsImportModalOpen(false)} 
        onImport={handleImport} 
      />

      <EventDetailsModal 
        event={selectedEvent} 
        relatedTask={selectedTask}
        onClose={() => setSelectedEvent(null)}
        onDelete={handleDeleteEvent}
      />

      {/* Loading Overlay */}
      {isProcessing && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-900 bg-opacity-50 backdrop-blur-sm transition-opacity">
            <div className="flex flex-col items-center p-6 bg-white rounded-lg shadow-xl">
                <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
                <h3 className="text-lg font-bold text-gray-900 tracking-widest uppercase">Optimizing</h3>
                <p className="text-xs text-gray-500 mt-2">Classifying events & scheduling...</p>
            </div>
        </div>
      )}

    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { Task, TaskFile, Priority, EnergyLevel } from '../types';
import { Button } from './Button';

interface TaskFormProps {
  onSubmit: (task: Task) => Promise<void>;
  onCancel: () => void;
}

const DAYS_OF_WEEK = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"];

export const TaskForm: React.FC<TaskFormProps> = ({ onSubmit, onCancel }) => {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [priority, setPriority] = useState<Priority>('Medium');
  const [energyLevel, setEnergyLevel] = useState<EnergyLevel>('High');
  const [totalHours, setTotalHours] = useState(2);
  const [deadline, setDeadline] = useState("");
  const [selectedDays, setSelectedDays] = useState<string[]>([]);
  const [preferredTimeStart, setPreferredTimeStart] = useState("09:00");
  const [preferredTimeEnd, setPreferredTimeEnd] = useState("22:00");
  const [files, setFiles] = useState<TaskFile[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: TaskFile[] = Array.from(e.target.files).map(f => ({
        name: f.name,
        size: f.size,
        type: f.type,
        url: URL.createObjectURL(f) 
      }));
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const toggleDay = (day: string) => {
    setSelectedDays(prev => 
      prev.includes(day) ? prev.filter(d => d !== day) : [...prev, day]
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!deadline) {
        alert("Please select a deadline.");
        return;
    }

    setIsSubmitting(true);

    const newTask: Task = {
      id: crypto.randomUUID(),
      title,
      description,
      difficulty: 5,
      priority,
      energyLevel,
      totalHoursNeeded: totalHours,
      deadline: new Date(deadline),
      preferredDays: selectedDays.length > 0 ? selectedDays : DAYS_OF_WEEK,
      preferredTimeStart,
      preferredTimeEnd,
      files,
      isScheduled: false
    };

    try {
      await onSubmit(newTask);
    } catch (err) {
      console.error(err);
      alert("Failed to schedule task.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-xl max-w-2xl mx-auto border border-gray-200">
      <h2 className="text-2xl font-bold text-gray-900 mb-6 flex items-center">
        <span className="bg-indigo-50 text-indigo-600 p-2 rounded-lg mr-3 border border-indigo-100">
            ✦
        </span>
        New Task
      </h2>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Basic Info */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="col-span-2">
            <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Title</label>
            <input 
              required
              type="text" 
              value={title}
              onChange={e => setTitle(e.target.value)}
              className="block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2.5 border bg-white text-gray-900 placeholder-gray-400"
              placeholder="e.g. Final Project"
            />
          </div>

          <div className="col-span-2">
            <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Description</label>
            <textarea 
              value={description}
              onChange={e => setDescription(e.target.value)}
              rows={2}
              className="block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2.5 border bg-white text-gray-900 placeholder-gray-400"
              placeholder="Task details..."
            />
          </div>

          <div>
             <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Deadline</label>
             <input 
                required
                type="datetime-local"
                value={deadline}
                onChange={e => setDeadline(e.target.value)}
                className="block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2.5 border bg-white text-gray-900"
             />
          </div>

          <div>
                 <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Hours Needed</label>
                 <input 
                    type="number" 
                    min="0.5" 
                    step="0.5"
                    value={totalHours}
                    onChange={e => setTotalHours(parseFloat(e.target.value))}
                    className="block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2.5 border bg-white text-gray-900"
                 />
          </div>

          <div>
             <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Priority</label>
             <div className="flex rounded-md shadow-sm bg-gray-50 border border-gray-200 p-1">
                {(['High', 'Medium', 'Low'] as Priority[]).map((p) => (
                    <button
                        key={p}
                        type="button"
                        onClick={() => setPriority(p)}
                        className={`flex-1 py-1 text-xs font-medium rounded transition-colors ${priority === p ? 'bg-white text-indigo-600 shadow-sm border border-gray-100' : 'text-gray-500 hover:text-gray-700'}`}
                    >
                        {p}
                    </button>
                ))}
             </div>
          </div>

          <div>
             <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Energy Level</label>
             <div className="flex rounded-md shadow-sm bg-gray-50 border border-gray-200 p-1">
                {(['High', 'Low'] as EnergyLevel[]).map((e) => (
                    <button
                        key={e}
                        type="button"
                        onClick={() => setEnergyLevel(e)}
                        className={`flex-1 py-1 text-xs font-medium rounded transition-colors ${energyLevel === e ? 'bg-white text-indigo-600 shadow-sm border border-gray-100' : 'text-gray-500 hover:text-gray-700'}`}
                    >
                        {e}
                    </button>
                ))}
             </div>
             <p className="text-[10px] text-gray-500 mt-1">High = Morning prefer. Low = Evening prefer.</p>
          </div>
        </div>

        <div className="border-t border-gray-200 pt-6">
            <h3 className="text-sm font-semibold text-gray-900 mb-4">Availability</h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-4">
                <div>
                    <label className="block text-xs text-gray-500 mb-1">Work Start</label>
                    <input 
                        type="time" 
                        value={preferredTimeStart}
                        onChange={e => setPreferredTimeStart(e.target.value)}
                        className="block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2 border bg-white text-gray-900"
                    />
                </div>
                <div>
                    <label className="block text-xs text-gray-500 mb-1">Work End</label>
                    <input 
                        type="time" 
                        value={preferredTimeEnd}
                        onChange={e => setPreferredTimeEnd(e.target.value)}
                        className="block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2 border bg-white text-gray-900"
                    />
                </div>
            </div>

            <div className="flex flex-wrap gap-2">
                {DAYS_OF_WEEK.map(day => (
                    <button
                        key={day}
                        type="button"
                        onClick={() => toggleDay(day)}
                        className={`px-3 py-1.5 rounded text-xs font-medium border transition-colors ${
                            selectedDays.includes(day) 
                                ? 'bg-indigo-600 text-white border-indigo-600' 
                                : 'bg-white text-gray-500 border-gray-300 hover:border-gray-400'
                        }`}
                    >
                        {day.substring(0, 3)}
                    </button>
                ))}
            </div>
        </div>

        <div className="border-t border-gray-200 pt-6">
            <label className="flex flex-col items-center justify-center w-full h-20 border-2 border-gray-300 border-dashed rounded-lg cursor-pointer hover:bg-gray-50 transition-colors bg-white">
                <span className="text-xs text-gray-500">Upload Materials</span>
                <input type="file" className="hidden" multiple onChange={handleFileChange} />
            </label>

            {files.length > 0 && (
                <ul className="mt-4 space-y-2">
                    {files.map((file, idx) => (
                        <li key={idx} className="flex justify-between items-center p-2 bg-gray-50 border border-gray-200 rounded text-xs text-gray-700">
                            <span className="truncate flex-1 mr-2">{file.name}</span>
                            <button type="button" onClick={() => removeFile(idx)} className="text-red-500 hover:text-red-700">×</button>
                        </li>
                    ))}
                </ul>
            )}
        </div>

        <div className="flex justify-end gap-3 pt-4">
            <Button variant="ghost" type="button" onClick={onCancel}>Cancel</Button>
            <Button type="submit" isLoading={isSubmitting}>Schedule Task</Button>
        </div>
      </form>
    </div>
  );
};

import React from 'react';
import { CalendarEvent, EventType } from '../types';

interface CalendarProps {
  events: CalendarEvent[];
  currentDate: Date;
  onEventClick: (event: CalendarEvent) => void;
  onNavigate: (direction: 'prev' | 'next' | 'today') => void;
}

export const Calendar: React.FC<CalendarProps> = ({ events, currentDate, onEventClick, onNavigate }) => {
  const daysOfWeek = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const startHour = 6;
  const hours = Array.from({ length: 18 }, (_, i) => i + startHour); 

  const getDayDates = () => {
    const dates = [];
    const startOfWeek = new Date(currentDate);
    const day = startOfWeek.getDay();
    startOfWeek.setDate(startOfWeek.getDate() - day);

    for (let i = 0; i < 7; i++) {
      const date = new Date(startOfWeek);
      date.setDate(startOfWeek.getDate() + i);
      dates.push(date);
    }
    return dates;
  };

  const weekDates = getDayDates();

  const formatHour = (h: number) => {
    const ampm = h >= 12 ? 'PM' : 'AM';
    const h12 = h % 12 || 12;
    return `${h12} ${ampm}`;
  };

  const getEventStyle = (event: CalendarEvent, colIndex: number) => {
    const eventStartHour = event.start.getHours() + event.start.getMinutes() / 60;
    const eventEndHour = event.end.getHours() + event.end.getMinutes() / 60;
    const duration = eventEndHour - eventStartHour;
    const top = (eventStartHour - startHour) * 60; 
    const height = duration * 60;

    return {
      top: `${top}px`,
      height: `${height}px`,
      left: '2px',
      right: '2px'
    };
  };

  const isSameDay = (d1: Date, d2: Date) => {
    return d1.getDate() === d2.getDate() && 
           d1.getMonth() === d2.getMonth() && 
           d1.getFullYear() === d2.getFullYear();
  };

  const formatWeekRange = (start: Date, end: Date) => {
    return `${start.toLocaleDateString('default', {month:'short', day:'numeric'})} - ${end.toLocaleDateString('default', {month:'short', day:'numeric'})}`;
  };

  // --- Heatmap Logic: Calculate Constraint Density ---
  // Returns a color string based on hours filled
  const getHeatmapColor = (date: Date) => {
      const dayEvents = events.filter(e => isSameDay(e.start, date));
      let totalHours = 0;
      dayEvents.forEach(e => {
          totalHours += (e.end.getTime() - e.start.getTime()) / (1000 * 60 * 60);
      });

      const ratio = Math.min(totalHours / 12, 1);

      // Light mode specific tints (very subtle)
      if (ratio < 0.2) return 'bg-emerald-50/50'; // Low
      if (ratio < 0.5) return 'bg-amber-50/50'; // Med
      return 'bg-red-50/50'; // High density
  };

  // Returns height percentage for the heatmap bar
  const getHeatmapHeight = (date: Date) => {
      const dayEvents = events.filter(e => isSameDay(e.start, date));
      let totalHours = 0;
      dayEvents.forEach(e => {
          totalHours += (e.end.getTime() - e.start.getTime()) / (1000 * 60 * 60);
      });
      const ratio = Math.min(totalHours / 14, 1);
      return `${ratio * 100}%`;
  }

  return (
    <div className="flex flex-col h-full bg-white rounded-xl border border-gray-200 overflow-hidden shadow-sm">

      {/* Navigation Header */}
      <div className="flex items-center justify-between px-6 py-4 border-b border-gray-200 bg-white">
        <div className="flex items-center gap-6">
            <h2 className="text-lg font-bold text-gray-900 w-48 tracking-tight">
                {weekDates[0].toLocaleString('default', { month: 'long', year: 'numeric' })}
            </h2>
            <div className="flex items-center gap-2">
                <button onClick={() => onNavigate('prev')} className="p-2 text-gray-500 hover:text-gray-900 transition-colors">←</button>
                <span className="text-sm font-medium text-gray-600 w-32 text-center">
                    {formatWeekRange(weekDates[0], weekDates[6])}
                </span>
                <button onClick={() => onNavigate('next')} className="p-2 text-gray-500 hover:text-gray-900 transition-colors">→</button>

                <button 
                    onClick={() => onNavigate('today')} 
                    className="ml-4 px-3 py-1 text-xs font-medium text-gray-700 bg-gray-100 rounded hover:bg-gray-200 transition-colors border border-gray-200"
                >
                    Today
                </button>
            </div>
        </div>
      </div>

      {/* Days Header with Heatmap Indicator */}
      <div className="grid grid-cols-8 border-b border-gray-200 bg-gray-50">
        <div className="p-4 border-r border-gray-200 text-xs font-mono text-gray-500 uppercase text-center pt-8">
           GMT
        </div>
        {weekDates.map((date, i) => (
          <div key={i} className={`relative p-2 text-center border-r border-gray-200 ${isSameDay(date, new Date()) ? 'bg-blue-50' : ''}`}>
             {/* Heatmap Bar Overlay */}
             <div className="absolute top-0 left-0 w-full opacity-30 pointer-events-none" 
                  style={{ 
                      height: '4px', 
                      background: `linear-gradient(90deg, transparent, ${getHeatmapHeight(date)} === '0%' ? 'transparent' : '#ef4444')`
                  }}>
             </div>
             {/* Constraint Density Background Tint */}
             <div className={`absolute inset-0 pointer-events-none ${getHeatmapColor(date)}`}></div>

            <div className="relative z-10">
                <div className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1">{daysOfWeek[date.getDay()]}</div>
                <div className={`text-xl font-medium ${isSameDay(date, new Date()) ? 'text-indigo-600' : 'text-gray-900'}`}>
                {date.getDate()}
                </div>
            </div>
          </div>
        ))}
      </div>

      {/* Grid */}
      <div className="flex-1 overflow-y-auto relative custom-scrollbar">
        <div className="grid grid-cols-8 min-h-[1080px]">
          {/* Time Sidebar */}
          <div className="border-r border-gray-200 bg-white">
            {hours.map(hour => (
              <div key={hour} className="h-[60px] border-b border-gray-100 text-[10px] text-gray-400 text-right pr-3 pt-2 font-mono">
                 {formatHour(hour)}
              </div>
            ))}
          </div>

          {/* Days Columns */}
          {weekDates.map((date, colIndex) => {
            const dayEvents = events.filter(e => isSameDay(e.start, date));

            return (
              <div key={colIndex} className="relative border-r border-gray-200 bg-white hover:bg-gray-50 transition-colors">
                {hours.map(hour => (
                  <div key={hour} className="h-[60px] border-b border-gray-100"></div>
                ))}

                {dayEvents.map(event => {
                    const styles = getEventStyle(event, colIndex);
                    if (parseInt(styles.top) + parseInt(styles.height) < 0) return null;

                    return (
                      <div
                        key={event.id}
                        onClick={(e) => { e.stopPropagation(); onEventClick(event); }}
                        className={`absolute rounded px-3 py-2 text-xs cursor-pointer border-l-4 shadow-sm transition-all hover:shadow-md hover:z-20 overflow-hidden group
                            ${event.color || 'bg-gray-100 border-gray-400 text-gray-700'}`}
                        style={styles}
                      >
                        <div className="font-semibold truncate tracking-tight">{event.title}</div>
                        <div className="opacity-0 group-hover:opacity-100 transition-opacity text-[9px] mt-1 font-mono">
                          {event.start.toLocaleTimeString([], {hour: 'numeric', minute:'2-digit', hour12: true})}
                        </div>
                      </div>
                    );
                })}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { CalendarEvent, Task, EventType } from '../types';
import { Button } from './Button';

interface EventDetailsModalProps {
  event: CalendarEvent | null;
  relatedTask?: Task;
  onClose: () => void;
  onDelete: (id: string) => void;
}

export const EventDetailsModal: React.FC<EventDetailsModalProps> = ({ event, relatedTask, onClose, onDelete }) => {
  if (!event) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-500 bg-opacity-75 backdrop-blur-sm p-4">
      <div className="bg-white rounded-lg shadow-2xl w-full max-w-lg p-6 border border-gray-200">
        <div className="flex justify-between items-start mb-6">
            <h2 className="text-xl font-bold text-gray-900">{event.title}</h2>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-600">✕</button>
        </div>

        <div className="space-y-6">
            <div>
                <span className={`inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider ${
                    event.type === EventType.AI_WORK_SESSION ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-700'
                }`}>
                    {event.type === EventType.AI_WORK_SESSION ? 'Work Session' : 'Event'}
                </span>
                <p className="mt-2 text-sm text-gray-700 font-mono">
                    {event.start.toLocaleTimeString([], {hour:'numeric', minute:'2-digit', hour12: true})} - {event.end.toLocaleTimeString([], {hour:'numeric', minute:'2-digit', hour12: true})}
                </p>
                <p className="text-sm text-gray-500 mt-1">
                    {event.start.toLocaleDateString(undefined, {weekday:'long', month:'long', day:'numeric'})}
                </p>
            </div>

            {event.description && (
                <div className="bg-gray-50 p-4 rounded border border-gray-200 text-sm text-gray-700">
                    <p className="text-xs text-gray-400 uppercase font-bold mb-2">Details</p>
                    {event.description}
                </div>
            )}

            {event.type === EventType.AI_WORK_SESSION && relatedTask && relatedTask.files.length > 0 && (
                <div className="border-t border-gray-100 pt-4">
                    <h3 className="text-xs text-gray-500 uppercase font-bold mb-3">Materials</h3>
                    <ul className="space-y-2">
                        {relatedTask.files.map((file, idx) => (
                            <li key={idx} className="flex items-center justify-between p-2 bg-gray-50 rounded border border-gray-200">
                                <span className="text-xs text-gray-700 truncate flex-1 mr-2">{file.name}</span>
                                {file.url && (
                                    <a 
                                        href={file.url} 
                                        target="_blank" 
                                        rel="noopener noreferrer"
                                        className="text-[10px] bg-white border border-gray-300 text-gray-700 px-2 py-1 rounded hover:bg-gray-100"
                                    >
                                        Open
                                    </a>
                                )}
                            </li>
                        ))}
                    </ul>
                </div>
            )}
        </div>

        <div className="mt-8 flex justify-end gap-3">
          <Button variant="danger" onClick={() => { onDelete(event.id); onClose(); }}>Delete</Button>
          <Button variant="secondary" onClick={onClose}>Close</Button>
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { CalendarEvent, Task, EventType, AIScheduleSuggestion } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = "gemini-3-flash-preview";

export const identifyClasses = async (events: CalendarEvent[]): Promise<string[]> => {
  if (events.length === 0) return [];

  // Optimization: Deduplicate events by Title to reduce token usage and latency.
  // We only send unique titles/descriptions to the AI.
  const uniqueEvents = new Map<string, { title: string; description: string }>();

  events.forEach(e => {
    // Optional: Only look at events that are recurring or look like classes (e.g. have a description or specific length?)
    // For now, just dedup all by title.
    if (!uniqueEvents.has(e.title)) {
        uniqueEvents.set(e.title, {
            title: e.title,
            description: e.description || ""
        });
    }
  });

  const distinctEventList = Array.from(uniqueEvents.values());

  // If we still have too many distinct events, maybe slice it? 
  // Gemini Flash has huge context so 100-200 distinct titles is fine.
  // But let's limit to 150 to be safe and fast.
  const slicedContext = distinctEventList.slice(0, 150);

  const prompt = `
    Analyze the following list of unique event titles and descriptions.
    Identify which ones represent University Classes, Lectures, Labs, or Recitations.
    Return a list of the *Exact Titles* that are classes.
    Ignore social events, work, clubs, or general reminders.

    Unique Events:
    ${JSON.stringify(slicedContext)}
  `;

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      classTitles: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "List of exact titles identified as academic classes."
      }
    }
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.1,
      },
    });

    const outputText = response.text;
    if (!outputText) return [];

    const result = JSON.parse(outputText) as { classTitles: string[] };
    const classTitles = new Set(result.classTitles || []);

    // Map back to Event IDs
    const classEventIds = events
        .filter(e => classTitles.has(e.title))
        .map(e => e.id);

    return classEventIds;

  } catch (error) {
    console.error("Error identifying classes:", error);
    return []; // Fail gracefully
  }
};

export const generateWorkSessions = async (
  currentEvents: CalendarEvent[],
  task: Task
): Promise<CalendarEvent[]> => {

  // 1. Prepare context for the AI
  // Limit context to relevant events (next 2 weeks or up to deadline) to save tokens
  const relevantEvents = currentEvents.filter(e => {
      const now = new Date();
      return e.start > now && e.start < task.deadline;
  });

  const eventContext = relevantEvents.map(e => ({
    title: e.title,
    start: e.start.toLocaleString(), 
    end: e.end.toLocaleString()
  }));

  const taskContext = {
    title: task.title,
    description: task.description,
    difficulty: task.difficulty,
    totalHours: task.totalHoursNeeded,
    deadline: task.deadline.toLocaleString(),
    preferredDays: task.preferredDays.join(", "),
    preferredTimeStart: task.preferredTimeStart,
    preferredTimeEnd: task.preferredTimeEnd
  };

  const today = new Date();

  const prompt = `
    I am a student trying to prevent procrastination. 
    Current Date/Time: ${today.toLocaleString()}.

    I have a task: "${taskContext.title}".
    Difficulty (1-10): ${taskContext.difficulty}.
    Total Estimated Work Hours Needed: ${taskContext.totalHours}.
    Deadline: ${taskContext.deadline}.
    I prefer to work on these days: ${taskContext.preferredDays}.

    CRITICAL CONSTRAINTS (MUST FOLLOW):
    1. My working hours are STRICTLY between ${taskContext.preferredTimeStart} and ${taskContext.preferredTimeEnd}.
    2. ABSOLUTELY NO sessions starting before ${taskContext.preferredTimeStart}.
    3. ABSOLUTELY NO sessions ending after ${taskContext.preferredTimeEnd}.
    4. Do NOT overlap with existing busy events provided below.

    Here is my current existing schedule (busy times):
    ${JSON.stringify(eventContext)}

    Please generate a list of "Work Sessions" to fit into my schedule between now and the deadline.

    Planning Rules:
    1. Break the total hours into smaller, manageable chunks (e.g., 45 mins to 90 mins). 
    2. Higher difficulty tasks should have more breaks or shorter sessions.
    3. If the deadline is very close, prioritize finding any available slot within working hours, even if it's not a "preferred day".
  `;

  // 2. Define Output Schema
  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      sessions: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            startISO: { type: Type.STRING, description: "The ISO 8601 date string for the start of the session" },
            endISO: { type: Type.STRING, description: "The ISO 8601 date string for the end of the session" },
            summary: { type: Type.STRING, description: "A short title for this session (e.g. 'Research Phase')" },
            reasoning: { type: Type.STRING, description: "Brief explanation of why this slot was chosen (e.g. 'Morning slot for high focus')" }
          },
          required: ["startISO", "endISO", "summary", "reasoning"]
        }
      }
    }
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.1, 
      },
    });

    const outputText = response.text;
    if (!outputText) {
      throw new Error("No response received from AI");
    }

    const result = JSON.parse(outputText) as AIScheduleSuggestion;

    // 3. Map to CalendarEvent objects
    const newEvents: CalendarEvent[] = result.sessions.map((session, index) => ({
      id: crypto.randomUUID(),
      title: `${task.title} (${index + 1}/${result.sessions.length})`,
      start: new Date(session.startISO),
      end: new Date(session.endISO),
      type: EventType.AI_WORK_SESSION,
      description: session.reasoning,
      relatedTaskId: task.id,
      color: "bg-indigo-600"
    }));

    return newEvents;

  } catch (error) {
    console.error("Error generating work sessions:", error);
    throw error;
  }
};

import React from 'react';
import { CalendarEvent, EventType } from '../types';

interface CalendarProps {
  events: CalendarEvent[];
  currentDate: Date;
  onEventClick: (event: CalendarEvent) => void;
  onNavigate: (direction: 'prev' | 'next' | 'today') => void;
  onEventUpdate: (updatedEvent: CalendarEvent) => void;
}

export const Calendar: React.FC<CalendarProps> = ({ events, currentDate, onEventClick, onNavigate, onEventUpdate }) => {
  const daysOfWeek = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const startHour = 6;
  const hours = Array.from({ length: 18 }, (_, i) => i + startHour); 

  const getDayDates = () => {
    const dates = [];
    const startOfWeek = new Date(currentDate);
    const day = startOfWeek.getDay();
    startOfWeek.setDate(startOfWeek.getDate() - day);

    for (let i = 0; i < 7; i++) {
      const date = new Date(startOfWeek);
      date.setDate(startOfWeek.getDate() + i);
      dates.push(date);
    }
    return dates;
  };

  const weekDates = getDayDates();

  const formatHour = (h: number) => {
    const ampm = h >= 12 ? 'PM' : 'AM';
    const h12 = h % 12 || 12;
    return `${h12} ${ampm}`;
  };

  const getEventStyle = (event: CalendarEvent, colIndex: number) => {
    const eventStartHour = event.start.getHours() + event.start.getMinutes() / 60;
    const eventEndHour = event.end.getHours() + event.end.getMinutes() / 60;
    const duration = eventEndHour - eventStartHour;
    const top = (eventStartHour - startHour) * 60; 
    const height = duration * 60;

    return {
      top: `${top}px`,
      height: `${height}px`,
      left: '2px',
      right: '2px'
    };
  };

  const isSameDay = (d1: Date, d2: Date) => {
    return d1.getDate() === d2.getDate() && 
           d1.getMonth() === d2.getMonth() && 
           d1.getFullYear() === d2.getFullYear();
  };

  const formatWeekRange = (start: Date, end: Date) => {
    return `${start.toLocaleDateString('default', {month:'short', day:'numeric'})} - ${end.toLocaleDateString('default', {month:'short', day:'numeric'})}`;
  };

  // --- Heatmap Logic: Calculate Constraint Density ---
  const getHeatmapColor = (date: Date) => {
      const dayEvents = events.filter(e => isSameDay(e.start, date));
      let totalHours = 0;
      dayEvents.forEach(e => {
          totalHours += (e.end.getTime() - e.start.getTime()) / (1000 * 60 * 60);
      });

      const ratio = Math.min(totalHours / 12, 1);

      if (ratio < 0.2) return 'bg-emerald-50/50'; 
      if (ratio < 0.5) return 'bg-amber-50/50'; 
      return 'bg-red-50/50'; 
  };

  const getHeatmapHeight = (date: Date) => {
      const dayEvents = events.filter(e => isSameDay(e.start, date));
      let totalHours = 0;
      dayEvents.forEach(e => {
          totalHours += (e.end.getTime() - e.start.getTime()) / (1000 * 60 * 60);
      });
      const ratio = Math.min(totalHours / 14, 1);
      return `${ratio * 100}%`;
  }

  // --- Drag and Drop Handlers ---

  const handleDragStart = (e: React.DragEvent, event: CalendarEvent) => {
    e.dataTransfer.setData('text/plain', event.id);
    e.dataTransfer.effectAllowed = 'move';

    // Calculate offset to prevent "jumping" when dragging starts
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const offsetY = e.clientY - rect.top;
    e.dataTransfer.setData('offsetY', offsetY.toString());
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault(); // Necessary to allow dropping
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, date: Date) => {
    e.preventDefault();
    const eventId = e.dataTransfer.getData('text/plain');
    const offsetY = parseFloat(e.dataTransfer.getData('offsetY'));

    const event = events.find(ev => ev.id === eventId);
    if (!event) return;

    const colRect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const dropY = e.clientY - colRect.top - offsetY; 

    // Snap to 15 min slots (15px)
    const snappedY = Math.round(dropY / 15) * 15;

    // Calculate new start time
    const hoursFromStart = snappedY / 60;
    const totalMinutes = (startHour * 60) + (hoursFromStart * 60);

    const newStart = new Date(date);
    newStart.setHours(Math.floor(totalMinutes / 60), Math.floor(totalMinutes % 60), 0, 0);

    // Calculate new end time (preserve duration)
    const durationMs = event.end.getTime() - event.start.getTime();
    const newEnd = new Date(newStart.getTime() + durationMs);

    onEventUpdate({ ...event, start: newStart, end: newEnd });
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-xl border border-gray-200 overflow-hidden shadow-sm">

      {/* Navigation Header */}
      <div className="flex items-center justify-between px-6 py-4 border-b border-gray-200 bg-white">
        <div className="flex items-center gap-6">
            <h2 className="text-lg font-bold text-gray-900 w-48 tracking-tight">
                {weekDates[0].toLocaleString('default', { month: 'long', year: 'numeric' })}
            </h2>
            <div className="flex items-center gap-2">
                <button onClick={() => onNavigate('prev')} className="p-2 text-gray-500 hover:text-gray-900 transition-colors">←</button>
                <span className="text-sm font-medium text-gray-600 w-32 text-center">
                    {formatWeekRange(weekDates[0], weekDates[6])}
                </span>
                <button onClick={() => onNavigate('next')} className="p-2 text-gray-500 hover:text-gray-900 transition-colors">→</button>

                <button 
                    onClick={() => onNavigate('today')} 
                    className="ml-4 px-3 py-1 text-xs font-medium text-gray-700 bg-gray-100 rounded hover:bg-gray-200 transition-colors border border-gray-200"
                >
                    Today
                </button>
            </div>
        </div>
      </div>

      {/* Days Header */}
      <div className="grid grid-cols-8 border-b border-gray-200 bg-gray-50">
        <div className="p-4 border-r border-gray-200 text-xs font-mono text-gray-500 uppercase text-center pt-8">
           GMT
        </div>
        {weekDates.map((date, i) => (
          <div key={i} className={`relative p-2 text-center border-r border-gray-200 ${isSameDay(date, new Date()) ? 'bg-blue-50' : ''}`}>
             <div className="absolute top-0 left-0 w-full opacity-30 pointer-events-none" 
                  style={{ 
                      height: '4px', 
                      background: `linear-gradient(90deg, transparent, ${getHeatmapHeight(date)} === '0%' ? 'transparent' : '#ef4444')`
                  }}>
             </div>
             <div className={`absolute inset-0 pointer-events-none ${getHeatmapColor(date)}`}></div>

            <div className="relative z-10">
                <div className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1">{daysOfWeek[date.getDay()]}</div>
                <div className={`text-xl font-medium ${isSameDay(date, new Date()) ? 'text-indigo-600' : 'text-gray-900'}`}>
                {date.getDate()}
                </div>
            </div>
          </div>
        ))}
      </div>

      {/* Grid */}
      <div className="flex-1 overflow-y-auto relative custom-scrollbar">
        <div className="grid grid-cols-8 min-h-[1080px]">
          {/* Time Sidebar */}
          <div className="border-r border-gray-200 bg-white">
            {hours.map(hour => (
              <div key={hour} className="h-[60px] border-b border-gray-100 text-[10px] text-gray-400 text-right pr-3 pt-2 font-mono">
                 {formatHour(hour)}
              </div>
            ))}
          </div>

          {/* Days Columns */}
          {weekDates.map((date, colIndex) => {
            const dayEvents = events.filter(e => isSameDay(e.start, date));

            return (
              <div 
                key={colIndex} 
                className="relative border-r border-gray-200 bg-white hover:bg-gray-50 transition-colors"
                onDragOver={handleDragOver}
                onDrop={(e) => handleDrop(e, date)}
              >
                {hours.map(hour => (
                  <div key={hour} className="h-[60px] border-b border-gray-100 pointer-events-none"></div>
                ))}

                {dayEvents.map(event => {
                    const styles = getEventStyle(event, colIndex);
                    if (parseInt(styles.top) + parseInt(styles.height) < 0) return null;

                    return (
                      <div
                        key={event.id}
                        draggable
                        onDragStart={(e) => handleDragStart(e, event)}
                        onClick={(e) => { e.stopPropagation(); onEventClick(event); }}
                        className={`absolute rounded px-3 py-2 text-xs cursor-pointer border-l-4 shadow-sm transition-all hover:shadow-md hover:z-20 overflow-hidden group
                            ${event.color || 'bg-gray-100 border-gray-400 text-gray-700'}`}
                        style={styles}
                      >
                        <div className="font-semibold truncate tracking-tight">{event.title}</div>
                        <div className="opacity-0 group-hover:opacity-100 transition-opacity text-[9px] mt-1 font-mono">
                          {event.start.toLocaleTimeString([], {hour: 'numeric', minute:'2-digit', hour12: true})}
                        </div>
                      </div>
                    );
                })}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { CalendarEvent, Task, EventType } from '../types';
import { Button } from './Button';

interface EventDetailsModalProps {
  event: CalendarEvent | null;
  relatedTask?: Task;
  onClose: () => void;
  onDelete: (id: string) => void;
  onUpdate: (event: CalendarEvent) => void;
}

export const EventDetailsModal: React.FC<EventDetailsModalProps> = ({ event, relatedTask, onClose, onDelete, onUpdate }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState('');
  const [editStart, setEditStart] = useState('');
  const [editEnd, setEditEnd] = useState('');

  // Reset state when event changes
  useEffect(() => {
    if (event) {
        setIsEditing(false);
        setEditTitle(event.title);
        // Format for datetime-local input (YYYY-MM-DDTHH:mm)
        const formatForInput = (d: Date) => {
            const pad = (n: number) => n < 10 ? '0'+n : n;
            return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
        };
        setEditStart(formatForInput(event.start));
        setEditEnd(formatForInput(event.end));
    }
  }, [event]);

  if (!event) return null;

  const handleSave = () => {
    if (!editTitle || !editStart || !editEnd) return;

    const newStart = new Date(editStart);
    const newEnd = new Date(editEnd);

    if (newEnd <= newStart) {
        alert("End time must be after start time");
        return;
    }

    onUpdate({
        ...event,
        title: editTitle,
        start: newStart,
        end: newEnd
    });
    setIsEditing(false);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-500 bg-opacity-75 backdrop-blur-sm p-4">
      <div className="bg-white rounded-lg shadow-2xl w-full max-w-lg p-6 border border-gray-200">

        {/* Header */}
        <div className="flex justify-between items-start mb-6">
            {isEditing ? (
                 <input 
                    type="text" 
                    value={editTitle}
                    onChange={(e) => setEditTitle(e.target.value)}
                    className="text-xl font-bold text-gray-900 border-b-2 border-indigo-500 focus:outline-none w-full"
                 />
            ) : (
                <h2 className="text-xl font-bold text-gray-900">{event.title}</h2>
            )}
            <button onClick={onClose} className="text-gray-400 hover:text-gray-600 ml-4">✕</button>
        </div>

        <div className="space-y-6">
            <div>
                <span className={`inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider ${
                    event.type === EventType.AI_WORK_SESSION ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-700'
                }`}>
                    {event.type === EventType.AI_WORK_SESSION ? 'Work Session' : 'Event'}
                </span>

                {isEditing ? (
                    <div className="mt-4 grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-xs text-gray-500 mb-1">Start</label>
                            <input 
                                type="datetime-local" 
                                value={editStart}
                                onChange={(e) => setEditStart(e.target.value)}
                                className="block w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-indigo-500 focus:border-indigo-500 border p-2 bg-white text-gray-900"
                            />
                        </div>
                        <div>
                            <label className="block text-xs text-gray-500 mb-1">End</label>
                            <input 
                                type="datetime-local" 
                                value={editEnd}
                                onChange={(e) => setEditEnd(e.target.value)}
                                className="block w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-indigo-500 focus:border-indigo-500 border p-2 bg-white text-gray-900"
                            />
                        </div>
                    </div>
                ) : (
                    <>
                        <p className="mt-2 text-sm text-gray-700 font-mono">
                            {event.start.toLocaleTimeString([], {hour:'numeric', minute:'2-digit', hour12: true})} - {event.end.toLocaleTimeString([], {hour:'numeric', minute:'2-digit', hour12: true})}
                        </p>
                        <p className="text-sm text-gray-500 mt-1">
                            {event.start.toLocaleDateString(undefined, {weekday:'long', month:'long', day:'numeric'})}
                        </p>
                    </>
                )}
            </div>

            {!isEditing && event.description && (
                <div className="bg-gray-50 p-4 rounded border border-gray-200 text-sm text-gray-700">
                    <p className="text-xs text-gray-400 uppercase font-bold mb-2">Details</p>
                    {event.description}
                </div>
            )}

            {!isEditing && event.type === EventType.AI_WORK_SESSION && relatedTask && relatedTask.files.length > 0 && (
                <div className="border-t border-gray-100 pt-4">
                    <h3 className="text-xs text-gray-500 uppercase font-bold mb-3">Materials</h3>
                    <ul className="space-y-2">
                        {relatedTask.files.map((file, idx) => (
                            <li key={idx} className="flex items-center justify-between p-2 bg-gray-50 rounded border border-gray-200">
                                <span className="text-xs text-gray-700 truncate flex-1 mr-2">{file.name}</span>
                                {file.url && (
                                    <a 
                                        href={file.url} 
                                        target="_blank" 
                                        rel="noopener noreferrer"
                                        className="text-[10px] bg-white border border-gray-300 text-gray-700 px-2 py-1 rounded hover:bg-gray-100"
                                    >
                                        Open
                                    </a>
                                )}
                            </li>
                        ))}
                    </ul>
                </div>
            )}
        </div>

        <div className="mt-8 flex justify-end gap-3 pt-4 border-t border-gray-100">
          {isEditing ? (
            <>
                <Button variant="ghost" onClick={() => setIsEditing(false)}>Cancel</Button>
                <Button onClick={handleSave}>Save Changes</Button>
            </>
          ) : (
            <>
                <Button variant="danger" onClick={() => { onDelete(event.id); onClose(); }}>Delete</Button>
                <Button variant="secondary" onClick={() => setIsEditing(true)}>Edit</Button>
                <Button variant="primary" onClick={onClose}>Close</Button>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Calendar } from './components/Calendar';
import { TaskForm } from './components/TaskForm';
import { ImportModal } from './components/ImportModal';
import { EventDetailsModal } from './components/EventDetailsModal';
import { Button } from './components/Button';
import { scheduleTasks } from './services/scheduler';
import { identifyClasses } from './services/geminiService';
import { CalendarEvent, Task, EventType } from './types';

function App() {
  const [view, setView] = useState<'calendar' | 'newTask'>('calendar');
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const [currentDate, setCurrentDate] = useState(new Date());

  const handleNavigate = (direction: 'prev' | 'next' | 'today') => {
    const newDate = new Date(currentDate);
    if (direction === 'today') {
      setCurrentDate(new Date());
    } else if (direction === 'next') {
      newDate.setDate(newDate.getDate() + 7);
      setCurrentDate(newDate);
    } else {
      newDate.setDate(newDate.getDate() - 7);
      setCurrentDate(newDate);
    }
  };

  const runGlobalScheduler = (fixedEvents: CalendarEvent[], currentTasks: Task[]) => {
    // Only AI Work Sessions that haven't been manually moved (conceptually) are re-scheduled.
    // However, if we just exclude all AI sessions, we lose the ones we want to keep.
    // For now, simpler: Wipe all AI sessions and re-generate. 
    // BUT, if user manually updated an AI session, we should convert it to 'MANUAL' so it sticks.

    const cleanFixedEvents = fixedEvents.filter(e => e.type !== EventType.AI_WORK_SESSION);
    const newSessions = scheduleTasks(cleanFixedEvents, currentTasks);
    return [...cleanFixedEvents, ...newSessions];
  };

  const handleImport = async (importedEvents: CalendarEvent[]) => {
    setIsImportModalOpen(false);
    setIsProcessing(true);
    try {
      // 1. Identify which events are classes using AI
      const classIds = await identifyClasses(importedEvents);

      // 2. Tag events
      const taggedEvents = importedEvents.map(e => ({
        ...e,
        isClass: classIds.includes(e.id),
        // If it's a class, maybe give it a specific color if not set?
        color: classIds.includes(e.id) ? "bg-blue-50 border-blue-200 text-blue-700" : e.color
      }));

      const existingFixed = events.filter(e => e.type !== EventType.AI_WORK_SESSION);
      const allFixedEvents = [...existingFixed, ...taggedEvents];
      const optimizedSchedule = runGlobalScheduler(allFixedEvents, tasks);
      setEvents(optimizedSchedule);
    } catch (error) {
      console.error("Import error:", error);
      alert("Error processing schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCreateTask = async (task: Task) => {
    setIsProcessing(true);
    try {
      const updatedTasks = [...tasks, { ...task, isScheduled: true }];
      setTasks(updatedTasks);
      const fixedEvents = events.filter(e => e.type !== EventType.AI_WORK_SESSION);
      const optimizedSchedule = runGlobalScheduler(fixedEvents, updatedTasks);
      setEvents(optimizedSchedule);
      setView('calendar');
    } catch (error) {
      console.error(error);
      alert("Error generating schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDeleteEvent = (id: string) => {
    const eventToDelete = events.find(e => e.id === id);
    if (!eventToDelete) return;

    if (eventToDelete.type === EventType.AI_WORK_SESSION) {
        setEvents(prev => prev.filter(e => e.id !== id));
    } else {
        const remainingFixed = events.filter(e => e.id !== id && e.type !== EventType.AI_WORK_SESSION);
        const optimizedSchedule = runGlobalScheduler(remainingFixed, tasks);
        setEvents(optimizedSchedule);
    }
  };

  const handleUpdateEvent = (updatedEvent: CalendarEvent) => {
    // If the user manually updates an AI session (Drag or Edit), it should become 'fixed' 
    // so it doesn't get overwritten by the scheduler next time.
    // We change its type to MANUAL.
    const finalEvent = {
        ...updatedEvent,
        type: updatedEvent.type === EventType.AI_WORK_SESSION ? EventType.MANUAL : updatedEvent.type,
        // Optional: Change color to indicate it's now manual? 
        // color: updatedEvent.type === EventType.AI_WORK_SESSION ? 'bg-indigo-100 border-indigo-400 text-indigo-900' : updatedEvent.color
    };

    setEvents(prevEvents => {
        const otherEvents = prevEvents.filter(e => e.id !== updatedEvent.id);
        const newEventList = [...otherEvents, finalEvent];
        return newEventList;
    });

    // Optionally re-run scheduler for OTHER tasks to work around this new fixed block?
    // We can do this asynchronously or immediately.
    // For now, let's just update the event. If they want to re-optimize, they might need a button or we do it here.
    // If we do it here, it feels very "integrated".

    // NOTE: If we re-run scheduler here, we must ensure 'finalEvent' is treated as fixed.
    // runGlobalScheduler filters out AI_WORK_SESSION. Since we changed type to MANUAL, it is now fixed. Perfect.

    // const optimizedSchedule = runGlobalScheduler([...otherFixed, finalEvent], tasks);
    // setEvents(optimizedSchedule);
  };

  const selectedTask = selectedEvent?.relatedTaskId 
    ? tasks.find(t => t.id === selectedEvent.relatedTaskId) 
    : undefined;

  return (
    <div className="min-h-screen flex flex-col relative bg-gray-50 text-gray-900 font-sans">
      {/* Navbar */}
      <nav className="border-b border-gray-200 bg-white sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <span className="bg-indigo-600 text-white p-1.5 rounded mr-3 font-bold">
                 SP
              </span>
              <h1 className="text-xl font-bold tracking-tight text-gray-900">SparkPlan AI</h1>
            </div>
            <div className="flex items-center space-x-4">
              <Button variant="ghost" onClick={() => setIsImportModalOpen(true)}>
                Import
              </Button>
              <Button onClick={() => setView('newTask')} disabled={view === 'newTask'}>
                + New Task
              </Button>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {view === 'calendar' ? (
          <>
            <div className="mb-6 flex items-center justify-between">
              <div>
                <h2 className="text-xl font-bold text-gray-900 tracking-tight">Dashboard</h2>
                <p className="text-sm text-gray-500 mt-1">
                  {events.filter(e => e.type === EventType.AI_WORK_SESSION).length} active work sessions.
                </p>
              </div>
              <div className="flex gap-4 text-xs font-medium text-gray-600">
                 <div className="flex items-center"><div className="w-2 h-2 bg-gray-300 rounded-full mr-2"></div> Manual Block</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-blue-400 rounded-full mr-2"></div> Class (+30m Buffer)</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-indigo-600 rounded-full mr-2"></div> Work Session</div>
              </div>
            </div>

            <div className="h-[calc(100vh-200px)]">
               <Calendar 
                  events={events} 
                  currentDate={currentDate} 
                  onEventClick={setSelectedEvent}
                  onNavigate={handleNavigate}
                  onEventUpdate={handleUpdateEvent}
               />
            </div>
          </>
        ) : (
          <div className="py-8">
            <TaskForm 
              onSubmit={handleCreateTask} 
              onCancel={() => setView('calendar')} 
            />
          </div>
        )}
      </main>

      {/* Modals */}
      <ImportModal 
        isOpen={isImportModalOpen} 
        onClose={() => setIsImportModalOpen(false)} 
        onImport={handleImport} 
      />

      <EventDetailsModal 
        event={selectedEvent} 
        relatedTask={selectedTask}
        onClose={() => setSelectedEvent(null)}
        onDelete={handleDeleteEvent}
        onUpdate={handleUpdateEvent}
      />

      {/* Loading Overlay */}
      {isProcessing && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-900 bg-opacity-50 backdrop-blur-sm transition-opacity">
            <div className="flex flex-col items-center p-6 bg-white rounded-lg shadow-xl">
                <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
                <h3 className="text-lg font-bold text-gray-900 tracking-widest uppercase">Optimizing</h3>
                <p className="text-xs text-gray-500 mt-2">Classifying events & scheduling...</p>
            </div>
        </div>
      )}

    </div>
  );
}

export default App;

import { CalendarEvent, Task, EventType, Priority } from '../types';

/**
 * Parses a time string (e.g. "14:30") and sets it on the given date object.
 */
const parseTimeOnDate = (timeStr: string, date: Date): Date => {
    const [hours, minutes] = timeStr.split(':').map(Number);
    const newDate = new Date(date);
    newDate.setHours(hours, minutes, 0, 0);
    return newDate;
};

/**
 * Checks if two date ranges overlap
 */
const isOverlapping = (start1: Date, end1: Date, start2: Date, end2: Date): boolean => {
    return start1 < end2 && end1 > start2;
};

interface TimeRange {
    start: Date;
    end: Date;
}

/**
 * Subtracts busy intervals from a time range to find free bins.
 */
const calculateFreeBins = (
    rangeStart: Date,
    rangeEnd: Date,
    busyEvents: CalendarEvent[]
): TimeRange[] => {
    // Sort busy events by start time
    const sortedBusy = [...busyEvents]
        .filter(e => isOverlapping(e.start, e.end, rangeStart, rangeEnd))
        .sort((a, b) => a.start.getTime() - b.start.getTime());

    const freeBins: TimeRange[] = [];
    let currentStart = new Date(rangeStart);

    for (const event of sortedBusy) {
        // Clamp event start/end to the range
        const eventStart = event.start < rangeStart ? rangeStart : event.start;
        const eventEnd = event.end > rangeEnd ? rangeEnd : event.end;

        if (eventStart > currentStart) {
            freeBins.push({ start: new Date(currentStart), end: new Date(eventStart) });
        }

        if (eventEnd > currentStart) {
            currentStart = new Date(eventEnd);
        }
    }

    if (currentStart < rangeEnd) {
        freeBins.push({ start: new Date(currentStart), end: new Date(rangeEnd) });
    }

    return freeBins;
};

const getEventColorByPriority = (priority: Priority) => {
    switch(priority) {
        case 'High': return 'bg-red-50 border-red-200 text-red-700';
        case 'Medium': return 'bg-amber-50 border-amber-200 text-amber-700';
        case 'Low': return 'bg-emerald-50 border-emerald-200 text-emerald-700';
        default: return 'bg-gray-50 border-gray-200 text-gray-700';
    }
};

/**
 * Deterministic Scheduler Engine
 * 1. Earliest Deadline First (EDF)
 * 2. Energy Level Heuristics (Morning vs Evening preference)
 * 3. Preemptive Splitting
 * 4. Class Buffering (30 mins) & Task Buffering (15 mins)
 */
export const scheduleTasks = (
    fixedEvents: CalendarEvent[],
    tasks: Task[]
): CalendarEvent[] => {
    // 1. Sort tasks by deadline (EDF)
    const sortedTasks = [...tasks].sort((a, b) => a.deadline.getTime() - b.deadline.getTime());

    const scheduledEvents: CalendarEvent[] = [];

    // Helper: Apply buffers to all events to ensure breaks
    const getAllBusySlots = () => {
        const allEvents = [...fixedEvents, ...scheduledEvents];

        return allEvents.map(e => {
            const start = new Date(e.start);
            const end = new Date(e.end);

            if (e.isClass) {
                // Classes get 30 mins buffer before/after (commute/prep time)
                start.setMinutes(start.getMinutes() - 30);
                end.setMinutes(end.getMinutes() + 30);
            } else {
                // All other tasks (Manual or AI) get 15 mins buffer before/after
                // This ensures at least a 15 min break between ANY two items.
                start.setMinutes(start.getMinutes() - 15);
                end.setMinutes(end.getMinutes() + 15);
            }
            return { ...e, start, end };
        });
    };

    const now = new Date();
    const startOfScheduling = new Date(now);
    // Align to next 15 min slot
    const remainder = 15 - (startOfScheduling.getMinutes() % 15);
    startOfScheduling.setMinutes(startOfScheduling.getMinutes() + remainder, 0, 0);

    const MIN_SESSION_DURATION_HOURS = 0.5; 

    for (const task of sortedTasks) {
        if (!task.isScheduled) continue;

        let hoursRemaining = task.totalHoursNeeded;

        // Sanity check to prevent "20 hours" bug if input is bad
        if (typeof hoursRemaining !== 'number' || isNaN(hoursRemaining) || hoursRemaining <= 0) {
            continue; 
        }

        let currentDate = new Date(startOfScheduling);

        let dayCount = 0;
        const maxDays = 365; // Safety break

        while (hoursRemaining > 0.05 && currentDate < task.deadline && dayCount < maxDays) {
            dayCount++;

            const dayName = currentDate.toLocaleDateString('en-US', { weekday: 'long' });

            if (task.preferredDays.includes(dayName)) {
                // Determine Day Window
                const windowStart = parseTimeOnDate(task.preferredTimeStart, currentDate);
                const windowEnd = parseTimeOnDate(task.preferredTimeEnd, currentDate);
                const effectiveStart = (windowStart < startOfScheduling) ? startOfScheduling : windowStart;

                if (effectiveStart < windowEnd) {
                    const busyEvents = getAllBusySlots();

                    // Get Free Bins
                    let freeBins = calculateFreeBins(effectiveStart, windowEnd, busyEvents);

                    // --- Weighted Heuristic: Energy Level Sorting ---
                    freeBins.sort((a, b) => {
                        const midA = (a.start.getHours() + a.end.getHours()) / 2;
                        const midB = (b.start.getHours() + b.end.getHours()) / 2;

                        if (task.energyLevel === 'High') {
                            return midA - midB; // Ascending (Morning first)
                        } else {
                            return midB - midA; // Descending (Evening first)
                        }
                    });

                    for (const bin of freeBins) {
                        if (hoursRemaining <= 0.05) break;

                        const binDurationMs = bin.end.getTime() - bin.start.getTime();
                        const binDurationHours = binDurationMs / (1000 * 60 * 60);

                        if (binDurationHours < MIN_SESSION_DURATION_HOURS) continue;

                        // Max session length to prevent burnout
                        const MAX_BLOCK_HOURS = 2;
                        const timeToTake = Math.min(hoursRemaining, binDurationHours, MAX_BLOCK_HOURS);

                        // Don't leave tiny slivers unless finishing task
                        if (timeToTake < MIN_SESSION_DURATION_HOURS && Math.abs(timeToTake - hoursRemaining) > 0.05) continue;

                        const sessionEnd = new Date(bin.start.getTime() + timeToTake * 60 * 60 * 1000);

                        scheduledEvents.push({
                            id: crypto.randomUUID(),
                            title: task.title,
                            start: new Date(bin.start),
                            end: sessionEnd,
                            type: EventType.AI_WORK_SESSION,
                            relatedTaskId: task.id,
                            description: `Priority: ${task.priority} | Energy: ${task.energyLevel}`,
                            color: getEventColorByPriority(task.priority),
                            priority: task.priority
                        });

                        hoursRemaining -= timeToTake;
                    }
                }
            }
            // Next day
            currentDate.setDate(currentDate.getDate() + 1);
            currentDate.setHours(0, 0, 0, 0);
        }
    }

    return scheduledEvents;
};

import React, { useState } from 'react';
import { Button } from './Button';
import { CalendarEvent, EventType } from '../types';

interface ImportModalProps {
  isOpen: boolean;
  onClose: () => void;
  onImport: (events: CalendarEvent[]) => void;
}

type TabType = 'upload' | 'url' | 'text';

export const ImportModal: React.FC<ImportModalProps> = ({ isOpen, onClose, onImport }) => {
  const [activeTab, setActiveTab] = useState<TabType>('upload');
  const [icsContent, setIcsContent] = useState('');
  const [urlInput, setUrlInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  if (!isOpen) return null;

  const generateId = () => Date.now().toString(36) + Math.random().toString(36).substring(2);

  const parseICSDate = (str: string): Date | null => {
    try {
        if (!str) return null;
        const isUTC = str.endsWith('Z');
        const cleanStr = str.replace('Z', '');
        if (cleanStr.length < 8) return null;
        const year = parseInt(cleanStr.substring(0, 4));
        const month = parseInt(cleanStr.substring(4, 6)) - 1;
        const day = parseInt(cleanStr.substring(6, 8));
        if (isNaN(year) || isNaN(month) || isNaN(day)) return null;
        if (cleanStr.length === 8) return new Date(year, month, day);
        const hour = parseInt(cleanStr.substring(9, 11));
        const min = parseInt(cleanStr.substring(11, 13));
        const sec = cleanStr.length >= 15 ? parseInt(cleanStr.substring(13, 15)) : 0;
        if (isNaN(hour) || isNaN(min)) return null;
        if (isUTC) return new Date(Date.UTC(year, month, day, hour, min, sec));
        return new Date(year, month, day, hour, min, sec);
    } catch (e) { return null; }
  };

  const expandRecurringEvent = (originalEvent: CalendarEvent, rruleStr: string): CalendarEvent[] => {
      try {
        const rules: any = {};
        rruleStr.split(';').forEach(part => {
            const [key, val] = part.split('=');
            rules[key] = val;
        });
        if (rules.FREQ !== 'WEEKLY') return [originalEvent]; 
        const expanded: CalendarEvent[] = [];
        const duration = originalEvent.end.getTime() - originalEvent.start.getTime();
        let until = rules.UNTIL ? parseICSDate(rules.UNTIL) : null;
        const count = rules.COUNT ? parseInt(rules.COUNT) : Infinity;
        const interval = rules.INTERVAL ? parseInt(rules.INTERVAL) : 1;
        if (!until && count === Infinity) {
            const d = new Date(originalEvent.start);
            d.setMonth(d.getMonth() + 4);
            until = d;
        }
        const dayMap: {[key: string]: number} = { 'SU': 0, 'MO': 1, 'TU': 2, 'WE': 3, 'TH': 4, 'FR': 5, 'SA': 6 };
        const byDay = rules.BYDAY ? rules.BYDAY.split(',').map((d: string) => dayMap[d.length > 2 ? d.slice(-2) : d]) : null;
        const anchor = new Date(originalEvent.start);
        anchor.setDate(anchor.getDate() - anchor.getDay()); 
        anchor.setHours(originalEvent.start.getHours(), originalEvent.start.getMinutes(), 0, 0);
        let addedCount = 0;
        for (let w = 0; w < 52; w++) { 
            if (addedCount >= count) break;
            if (!byDay) {
                const date = new Date(originalEvent.start);
                date.setDate(date.getDate() + (w * 7 * interval));
                if (until && date > until) break;
                expanded.push({ ...originalEvent, id: `${originalEvent.id}_${w}`, start: date, end: new Date(date.getTime() + duration) });
                addedCount++;
                continue;
            }
            if (w % interval !== 0) continue;
            for (const dayIdx of byDay) {
                if (dayIdx === undefined) continue;
                const date = new Date(anchor);
                date.setDate(date.getDate() + (w * 7) + dayIdx);
                date.setHours(originalEvent.start.getHours(), originalEvent.start.getMinutes(), originalEvent.start.getSeconds(), 0);
                if (date < originalEvent.start) continue; 
                if (until && date > until) { } else {
                    expanded.push({ ...originalEvent, id: `${originalEvent.id}_${w}_${dayIdx}`, start: date, end: new Date(date.getTime() + duration) });
                    addedCount++;
                }
            }
            if (until && expanded.length > 0 && expanded[expanded.length-1].start > until) break;
        }
        return expanded.length > 0 ? expanded : [originalEvent];
    } catch (e) { return [originalEvent]; }
  };

  const processICSContent = (content: string) => {
      try {
      if (!content.trim()) return;
      const events: CalendarEvent[] = [];
      const lines = content.split(/\r\n|\n|\r/);
      let currentEvent: Partial<CalendarEvent> | null = null;
      let currentEventRRule: string | null = null;
      let inEvent = false;

      for (let i = 0; i < lines.length; i++) {
        const line = lines[i].trim();
        if (!line) continue;
        if (line === 'BEGIN:VEVENT') {
          inEvent = true;
          currentEvent = { id: generateId(), type: EventType.IMPORTED, color: "bg-gray-100 border-gray-300 text-gray-700" }; 
          currentEventRRule = null;
          continue;
        } 
        if (line === 'END:VEVENT') {
          inEvent = false;
          if (currentEvent && currentEvent.title && currentEvent.start && currentEvent.end) {
            if (!isNaN(currentEvent.start.getTime()) && !isNaN(currentEvent.end.getTime())) {
                if (currentEventRRule) {
                    events.push(...expandRecurringEvent(currentEvent as CalendarEvent, currentEventRRule));
                } else {
                    events.push(currentEvent as CalendarEvent);
                }
            }
          }
          currentEvent = null; continue;
        }
        if (inEvent && currentEvent) {
          if (line.startsWith('SUMMARY:')) currentEvent.title = line.substring(8).trim();
          if (line.startsWith('RRULE:')) currentEventRRule = line.substring(6).trim();
          if (line.startsWith('DTSTART')) {
             const val = line.substring(line.indexOf(':') + 1).trim();
             const date = parseICSDate(val);
             if (date) currentEvent.start = date;
          }
          if (line.startsWith('DTEND')) {
             const val = line.substring(line.indexOf(':') + 1).trim();
             const date = parseICSDate(val);
             if (date) currentEvent.end = date;
          }
        }
      }
      onImport(events);
      setIcsContent(''); setUrlInput(''); onClose();
    } catch (e) { console.error(e); }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      processICSContent(event.target?.result as string);
      setIsProcessing(false);
    };
    reader.readAsText(file);
  };

  const handleUrlImport = async () => {
    if (!urlInput) return;
    setIsProcessing(true);
    try {
        // Use a CORS proxy to bypass browser restrictions on external ICS files (e.g. Google Calendar)
        const proxyUrl = `https://corsproxy.io/?${encodeURIComponent(urlInput)}`;
        const response = await fetch(proxyUrl);
        if (!response.ok) throw new Error("Fetch failed");
        const text = await response.text();
        processICSContent(text);
    } catch (e) { 
        console.error(e);
        alert("Import failed. If using Google Calendar, ensure you are using the 'Secret address in iCal format' found in your calendar settings."); 
    } finally { setIsProcessing(false); }
  };

  const handleSimulateImport = () => {
    setIsProcessing(true);
    setTimeout(() => {
      const today = new Date();
      const mockEvents: CalendarEvent[] = [];
      for(let i=0; i<4; i++) { 
         [1, 3, 5].forEach(dayOffset => { 
             const start = new Date(today);
             start.setDate(today.getDate() - today.getDay() + dayOffset + (i*7));
             start.setHours(10, 0, 0, 0);
             const end = new Date(start);
             end.setHours(11, 30, 0, 0);
             mockEvents.push({
                id: generateId(),
                title: "Calculus II",
                start: start,
                end: end,
                type: EventType.IMPORTED,
                color: "bg-gray-100 border-gray-300 text-gray-700"
             });
         });
      }
      onImport(mockEvents);
      setIsProcessing(false);
      onClose();
    }, 800);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-500 bg-opacity-75 backdrop-blur-sm p-4">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6 border border-gray-200">
        <h2 className="text-xl font-bold mb-6 text-gray-900 tracking-tight">Import Calendar</h2>

        <div className="flex border-b border-gray-200 mb-6">
            {(['upload', 'url', 'text'] as TabType[]).map(tab => (
                 <button 
                    key={tab}
                    onClick={() => setActiveTab(tab)}
                    className={`flex-1 py-2 text-xs font-medium border-b-2 uppercase tracking-wide transition-colors ${activeTab === tab ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
                >
                    {tab}
                </button>
            ))}
        </div>

        <div className="min-h-[160px]">
            {activeTab === 'upload' && (
                <div className="text-center py-4">
                    <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-gray-300 border-dashed rounded-lg cursor-pointer bg-gray-50 hover:bg-gray-100 transition-colors">
                        <span className="text-sm text-gray-500">Click to upload .ics file</span>
                        <input type="file" accept=".ics,text/calendar" className="hidden" onChange={handleFileUpload} />
                    </label>
                </div>
            )}
            {activeTab === 'url' && (
                <div className="py-2">
                    <input 
