        <div className="flex justify-end gap-3 pt-4">
            <Button variant="ghost" type="button" onClick={onCancel}>Cancel</Button>
            <Button type="submit" isLoading={isSubmitting}>
                {initialTask ? 'Update Schedule' : 'Schedule Task'}
            </Button>
        </div>
      </form>
    </div>
  );
};

import { CalendarEvent, Task, EventType, Priority } from '../types';

/**
 * Parses a time string (e.g. "14:30") and sets it on the given date object.
 */
const parseTimeOnDate = (timeStr: string, date: Date): Date => {
    const [hours, minutes] = timeStr.split(':').map(Number);
    const newDate = new Date(date);
    newDate.setHours(hours, minutes, 0, 0);
    return newDate;
};

/**
 * Checks if two date ranges overlap
 */
const isOverlapping = (start1: Date, end1: Date, start2: Date, end2: Date): boolean => {
    return start1 < end2 && end1 > start2;
};

interface TimeRange {
    start: Date;
    end: Date;
}

/**
 * Subtracts busy intervals from a time range to find free bins.
 */
const calculateFreeBins = (
    rangeStart: Date,
    rangeEnd: Date,
    busyEvents: CalendarEvent[]
): TimeRange[] => {
    // Sort busy events by start time
    const sortedBusy = [...busyEvents]
        .filter(e => isOverlapping(e.start, e.end, rangeStart, rangeEnd))
        .sort((a, b) => a.start.getTime() - b.start.getTime());

    const freeBins: TimeRange[] = [];
    let currentStart = new Date(rangeStart);

    for (const event of sortedBusy) {
        // Clamp event start/end to the range
        const eventStart = event.start < rangeStart ? rangeStart : event.start;
        const eventEnd = event.end > rangeEnd ? rangeEnd : event.end;

        if (eventStart > currentStart) {
            freeBins.push({ start: new Date(currentStart), end: new Date(eventStart) });
        }

        if (eventEnd > currentStart) {
            currentStart = new Date(eventEnd);
        }
    }

    if (currentStart < rangeEnd) {
        freeBins.push({ start: new Date(currentStart), end: new Date(rangeEnd) });
    }

    return freeBins;
};

const getEventColorByPriority = (priority: Priority) => {
    switch(priority) {
        case 'High': return 'bg-red-50 border-red-200 text-red-700';
        case 'Medium': return 'bg-amber-50 border-amber-200 text-amber-700';
        case 'Low': return 'bg-emerald-50 border-emerald-200 text-emerald-700';
        default: return 'bg-gray-50 border-gray-200 text-gray-700';
    }
};

/**
 * Deterministic Scheduler Engine
 * 1. Earliest Deadline First (EDF)
 * 2. Energy Level Heuristics (Morning vs Evening preference)
 * 3. Preemptive Splitting
 * 4. Class Buffering (30 mins) & Task Buffering (15 mins)
 */
export const scheduleTasks = (
    fixedEvents: CalendarEvent[],
    tasks: Task[]
): CalendarEvent[] => {
    // 1. Sort tasks by deadline (EDF)
    const sortedTasks = [...tasks].sort((a, b) => a.deadline.getTime() - b.deadline.getTime());

    const scheduledEvents: CalendarEvent[] = [];

    // Helper: Apply buffers to all events to ensure breaks
    const getAllBusySlots = () => {
        const allEvents = [...fixedEvents, ...scheduledEvents];

        return allEvents.map(e => {
            const start = new Date(e.start);
            const end = new Date(e.end);

            if (e.isClass) {
                // Classes get 30 mins buffer before/after (commute/prep time)
                start.setMinutes(start.getMinutes() - 30);
                end.setMinutes(end.getMinutes() + 30);
            } else {
                // All other tasks (Manual or AI) get 15 mins buffer before/after
                // This ensures at least a 15 min break between ANY two items.
                start.setMinutes(start.getMinutes() - 15);
                end.setMinutes(end.getMinutes() + 15);
            }
            return { ...e, start, end };
        });
    };

    const now = new Date();
    const startOfScheduling = new Date(now);
    // Align to next 15 min slot
    const remainder = 15 - (startOfScheduling.getMinutes() % 15);
    startOfScheduling.setMinutes(startOfScheduling.getMinutes() + remainder, 0, 0);

    const MIN_SESSION_DURATION_HOURS = 0.5; 

    for (const task of sortedTasks) {
        if (!task.isScheduled) continue;

        let hoursRemaining = task.totalHoursNeeded;

        // Sanity check to prevent "20 hours" bug if input is bad
        if (typeof hoursRemaining !== 'number' || isNaN(hoursRemaining) || hoursRemaining <= 0) {
            continue; 
        }

        let currentDate = new Date(startOfScheduling);

        let dayCount = 0;
        const maxDays = 365; // Safety break

        while (hoursRemaining > 0.05 && currentDate < task.deadline && dayCount < maxDays) {
            dayCount++;

            const dayName = currentDate.toLocaleDateString('en-US', { weekday: 'long' });

            if (task.preferredDays.includes(dayName)) {
                // Determine Day Window
                const windowStart = parseTimeOnDate(task.preferredTimeStart, currentDate);
                const windowEnd = parseTimeOnDate(task.preferredTimeEnd, currentDate);
                const effectiveStart = (windowStart < startOfScheduling) ? startOfScheduling : windowStart;

                if (effectiveStart < windowEnd) {
                    const busyEvents = getAllBusySlots();

                    // Get Free Bins
                    let freeBins = calculateFreeBins(effectiveStart, windowEnd, busyEvents);

                    // --- Weighted Heuristic: Energy Level Sorting ---
                    freeBins.sort((a, b) => {
                        const midA = (a.start.getHours() + a.end.getHours()) / 2;
                        const midB = (b.start.getHours() + b.end.getHours()) / 2;

                        if (task.energyLevel === 'High') {
                            return midA - midB; // Ascending (Morning first)
                        } else {
                            return midB - midA; // Descending (Evening first)
                        }
                    });

                    for (const bin of freeBins) {
                        if (hoursRemaining <= 0.05) break;

                        const binDurationMs = bin.end.getTime() - bin.start.getTime();
                        const binDurationHours = binDurationMs / (1000 * 60 * 60);

                        if (binDurationHours < MIN_SESSION_DURATION_HOURS) continue;

                        // Use user preference for max block size, fallback to 2h if not set.
                        const maxBlockSize = task.preferredSessionDuration || 2.0;

                        const timeToTake = Math.min(hoursRemaining, binDurationHours, maxBlockSize);

                        // Don't leave tiny slivers unless finishing task
                        if (timeToTake < MIN_SESSION_DURATION_HOURS && Math.abs(timeToTake - hoursRemaining) > 0.05) continue;

                        const sessionEnd = new Date(bin.start.getTime() + timeToTake * 60 * 60 * 1000);

                        scheduledEvents.push({
                            id: crypto.randomUUID(),
                            title: task.title,
                            start: new Date(bin.start),
                            end: sessionEnd,
                            type: EventType.AI_WORK_SESSION,
                            relatedTaskId: task.id,
                            description: `Priority: ${task.priority} | Energy: ${task.energyLevel}`,
                            color: getEventColorByPriority(task.priority),
                            priority: task.priority
                        });

                        hoursRemaining -= timeToTake;
                    }
                }
            }
            // Next day
            currentDate.setDate(currentDate.getDate() + 1);
            currentDate.setHours(0, 0, 0, 0);
        }
    }

    return scheduledEvents;
};

import React, { useState, useEffect } from 'react';
import { Task, CalendarEvent, EventType, Priority } from '../types';
import { Button } from './Button';

interface TasksViewProps {
  tasks: Task[];
  events: CalendarEvent[];
  onEditTask: (task: Task) => void;
  onDeleteTask: (taskId: string) => void;
}

export const TasksView: React.FC<TasksViewProps> = ({ tasks, events, onEditTask, onDeleteTask }) => {
  // Use current time to calculate live progress
  const [now, setNow] = useState(new Date());

  useEffect(() => {
    // Update 'now' every minute to keep progress bars fresh
    const interval = setInterval(() => {
        setNow(new Date());
    }, 60000); // 60s
    return () => clearInterval(interval);
  }, []);

  const getProgress = (task: Task) => {
    const taskEvents = events.filter(e => e.relatedTaskId === task.id);

    let totalScheduledHours = 0;
    let completedHours = 0;

    taskEvents.forEach(e => {
        const durationHours = (e.end.getTime() - e.start.getTime()) / (1000 * 60 * 60);
        totalScheduledHours += durationHours;

        // Calculate portion of event that has passed
        if (now >= e.end) {
            completedHours += durationHours;
        } else if (now > e.start) {
            // Currently in progress
            const passedMs = now.getTime() - e.start.getTime();
            completedHours += passedMs / (1000 * 60 * 60);
        }
    });

    return {
        completed: completedHours,
        scheduledFuture: Math.max(0, totalScheduledHours - completedHours),
        totalNeeded: task.totalHoursNeeded,
        // Percentages for the bar
        percentCompleted: Math.min(100, (completedHours / task.totalHoursNeeded) * 100),
        percentScheduled: Math.min(100, ((totalScheduledHours - completedHours) / task.totalHoursNeeded) * 100)
    };
  };

  const getPriorityColor = (p: Priority) => {
    switch(p) {
        case 'High': return 'text-red-700 bg-red-50 border-red-200';
        case 'Medium': return 'text-amber-700 bg-amber-50 border-amber-200';
        case 'Low': return 'text-emerald-700 bg-emerald-50 border-emerald-200';
        default: return 'text-gray-700 bg-gray-50';
    }
  };

  if (tasks.length === 0) {
      return (
          <div className="flex flex-col items-center justify-center h-full py-20 text-center">
              <div className="bg-gray-100 p-6 rounded-full mb-4">
                  <span className="text-4xl">📝</span>
              </div>
              <h3 className="text-lg font-bold text-gray-900">No Tasks Yet</h3>
              <p className="text-gray-500 max-w-sm mt-2 mb-6">Start by adding a task, project, or exam study plan. The AI will help you schedule it.</p>
          </div>
      );
  }

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {tasks.map(task => {
            const stats = getProgress(task);
            const isOverdue = now > task.deadline && stats.percentCompleted < 100;
            const totalPlanned = stats.completed + stats.scheduledFuture;

            return (
                <div key={task.id} className="bg-white rounded-xl border border-gray-200 shadow-sm hover:shadow-md transition-all p-5 flex flex-col">
                    <div className="flex justify-between items-start mb-3">
                        <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider border ${getPriorityColor(task.priority)}`}>
                            {task.priority}
                        </span>
                        <div className="flex gap-2">
                             <button 
                                onClick={() => onEditTask(task)}
                                className="text-gray-400 hover:text-indigo-600 transition-colors"
                             >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                                </svg>
                             </button>
                             <button 
                                onClick={() => {
                                    if(confirm('Are you sure you want to delete this task? All scheduled sessions will be removed.')) {
                                        onDeleteTask(task.id);
                                    }
                                }}
                                className="text-gray-400 hover:text-red-600 transition-colors"
                             >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                </svg>
                             </button>
                        </div>
                    </div>

                    <h3 className="text-lg font-bold text-gray-900 mb-1 leading-tight">{task.title}</h3>

                    <div className="text-xs text-gray-500 mb-4 flex items-center">
                        <span className="mr-2">📅 Deadline:</span> 
                        <span className={`font-medium ${isOverdue ? 'text-red-600' : 'text-gray-700'}`}>
                            {task.deadline.toLocaleDateString(undefined, {month:'short', day:'numeric', hour:'numeric', minute:'2-digit'})}
                        </span>
                    </div>

                    {task.description && (
                        <p className="text-xs text-gray-600 mb-4 line-clamp-2">{task.description}</p>
                    )}

                    <div className="mt-auto">
                        <div className="flex justify-between items-end mb-1">
                            <span className="text-xs font-medium text-gray-500">
                                {stats.completed.toFixed(1)} hrs done
                            </span>
                            <span className="text-xs font-bold text-gray-700">
                                {totalPlanned.toFixed(1)} / {stats.totalNeeded} hrs planned
                            </span>
                        </div>

                        {/* Multi-colored Progress Bar */}
                        <div className="w-full bg-gray-100 rounded-full h-2.5 overflow-hidden flex">
                            {/* Completed Segment (Green) */}
                            <div 
                                className="h-full bg-emerald-500 transition-all duration-500"
                                style={{ width: `${stats.percentCompleted}%` }}
                                title="Completed"
                            ></div>
                            {/* Scheduled Future Segment (Indigo) */}
                            <div 
                                className="h-full bg-indigo-400 transition-all duration-500 opacity-60"
                                style={{ width: `${stats.percentScheduled}%` }}
                                title="Scheduled (Future)"
                            ></div>
                        </div>

                        <div className="mt-4 flex gap-2">
                             {task.files.length > 0 && (
                                <div className="text-[10px] bg-gray-50 border border-gray-200 px-2 py-1 rounded text-gray-600 flex items-center">
                                    📎 {task.files.length} Materials
                                </div>
                             )}
                        </div>
                    </div>
                </div>
            );
        })}
      </div>
    </div>
  );
};

export enum EventType {
  IMPORTED = 'IMPORTED', // From ICS or external
  MANUAL = 'MANUAL',     // User manually added
  AI_WORK_SESSION = 'AI_WORK_SESSION' // Generated by Engine
}

export type Priority = 'High' | 'Medium' | 'Low';
export type EnergyLevel = 'High' | 'Low';
export type TaskCategory = 'Task' | 'Meeting' | 'Habit';

export interface CalendarEvent {
  id: string;
  title: string;
  start: Date;
  end: Date;
  type: EventType;
  description?: string;
  relatedTaskId?: string; 
  color?: string;
  priority?: Priority;
  isClass?: boolean; // New property to identify classes
}

export interface TaskFile {
  name: string;
  size: number;
  type: string;
  url?: string; 
}

export interface Task {
  id: string;
  category: TaskCategory; // New: Distinguish between types
  title: string;
  description: string;

  // -- Task Specific --
  difficulty: number; 
  totalHoursNeeded: number;
  deadline: Date;

  // -- Habit Specific --
  recurrenceEndDate?: Date; // When the habit stops repeating

  // -- Meeting Specific --
  meetingDate?: string; // YYYY-MM-DD
  meetingStartTime?: string; // HH:mm
  meetingEndTime?: string; // HH:mm

  // -- Shared Scheduling Preferences --
  preferredDays: string[]; 
  preferredTimeStart: string; 
  preferredTimeEnd: string;
  preferredSessionDuration: number; 

  files: TaskFile[];
  isScheduled: boolean;
  priority: Priority;
  energyLevel: EnergyLevel;
}

export interface AIScheduleSuggestion {
  sessions: {
    startISO: string;
    endISO: string;
    summary: string;
    reasoning: string;
  }[];
}

export interface AIClassClassification {
  classEventIds: string[];
}

import React, { useState, useEffect } from 'react';
import { Task, CalendarEvent, Priority, TaskCategory } from '../types';

interface EventsViewProps {
  tasks: Task[];
  events: CalendarEvent[];
  onEditTask: (task: Task) => void;
  onDeleteTask: (taskId: string) => void;
}

export const EventsView: React.FC<EventsViewProps> = ({ tasks, events, onEditTask, onDeleteTask }) => {
  const [now, setNow] = useState(new Date());
  const [filter, setFilter] = useState<TaskCategory | 'All'>('All');

  useEffect(() => {
    const interval = setInterval(() => {
        setNow(new Date());
    }, 60000); 
    return () => clearInterval(interval);
  }, []);

  const getProgress = (task: Task) => {
    // If it's a meeting, it's binary: passed or not
    if (task.category === 'Meeting') {
        const start = new Date(`${task.meetingDate}T${task.meetingStartTime}`);
        const end = new Date(`${task.meetingDate}T${task.meetingEndTime}`);
        const isDone = now > end;
        return {
            completed: isDone ? 1 : 0,
            scheduledFuture: isDone ? 0 : 1,
            totalNeeded: 1,
            percentCompleted: isDone ? 100 : 0,
            percentScheduled: isDone ? 0 : 100
        };
    }

    const taskEvents = events.filter(e => e.relatedTaskId === task.id);
    let totalScheduledHours = 0;
    let completedHours = 0;

    taskEvents.forEach(e => {
        const durationHours = (e.end.getTime() - e.start.getTime()) / (1000 * 60 * 60);
        totalScheduledHours += durationHours;

        if (now >= e.end) {
            completedHours += durationHours;
        } else if (now > e.start) {
            const passedMs = now.getTime() - e.start.getTime();
            completedHours += passedMs / (1000 * 60 * 60);
        }
    });

    // For Habits, totalNeeded is dynamic based on how many were scheduled, 
    // but for the UI bar we can just show "Completed vs Planned so far".
    // For Tasks, we use the explicit totalHoursNeeded.
    const denominator = task.category === 'Task' ? task.totalHoursNeeded : totalScheduledHours || 1;

    return {
        completed: completedHours,
        scheduledFuture: Math.max(0, totalScheduledHours - completedHours),
        totalNeeded: task.category === 'Task' ? task.totalHoursNeeded : totalScheduledHours,
        percentCompleted: Math.min(100, (completedHours / denominator) * 100),
        percentScheduled: Math.min(100, ((totalScheduledHours - completedHours) / denominator) * 100)
    };
  };

  const getPriorityColor = (p: Priority) => {
    switch(p) {
        case 'High': return 'text-red-700 bg-red-50 border-red-200';
        case 'Medium': return 'text-amber-700 bg-amber-50 border-amber-200';
        case 'Low': return 'text-emerald-700 bg-emerald-50 border-emerald-200';
        default: return 'text-gray-700 bg-gray-50';
    }
  };

  const filteredTasks = filter === 'All' ? tasks : tasks.filter(t => t.category === filter);

  if (tasks.length === 0) {
      return (
          <div className="flex flex-col items-center justify-center h-full py-20 text-center">
              <div className="bg-gray-100 p-6 rounded-full mb-4">
                  <span className="text-4xl">📅</span>
              </div>
              <h3 className="text-lg font-bold text-gray-900">No Events Yet</h3>
              <p className="text-gray-500 max-w-sm mt-2 mb-6">Create Tasks, Meetings, or Habits to fill your schedule.</p>
          </div>
      );
  }

  return (
    <div className="space-y-6">
      {/* Filter Tabs */}
      <div className="flex space-x-2 border-b border-gray-200 pb-1">
          {(['All', 'Task', 'Meeting', 'Habit'] as const).map(cat => (
              <button
                key={cat}
                onClick={() => setFilter(cat)}
                className={`px-4 py-2 text-sm font-medium rounded-t-lg transition-colors ${
                    filter === cat 
                    ? 'bg-white text-indigo-600 border border-b-0 border-gray-200 shadow-sm' 
                    : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'
                }`}
              >
                  {cat === 'All' ? 'All Events' : `${cat}s`}
              </button>
          ))}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredTasks.map(task => {
            const stats = getProgress(task);
            const isOverdue = task.category === 'Task' && now > task.deadline && stats.percentCompleted < 100;
            const totalPlanned = stats.completed + stats.scheduledFuture;

            return (
                <div key={task.id} className="bg-white rounded-xl border border-gray-200 shadow-sm hover:shadow-md transition-all p-5 flex flex-col relative overflow-hidden">
                    {/* Category Badge Stripe */}
                    <div className={`absolute top-0 left-0 w-1 h-full ${
                        task.category === 'Meeting' ? 'bg-purple-500' :
                        task.category === 'Habit' ? 'bg-teal-500' : 'bg-indigo-500'
                    }`}></div>

                    <div className="flex justify-between items-start mb-3 pl-3">
                        <div className="flex flex-col">
                            <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider mb-1">{task.category}</span>
                            <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider border w-fit ${getPriorityColor(task.priority)}`}>
                                {task.priority}
                            </span>
                        </div>
                        <div className="flex gap-2">
                             <button 
                                onClick={() => onEditTask(task)}
                                className="text-gray-400 hover:text-indigo-600 transition-colors"
                             >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                                </svg>
                             </button>
                             <button 
                                onClick={() => {
                                    if(confirm('Are you sure you want to delete this?')) {
                                        onDeleteTask(task.id);
                                    }
                                }}
                                className="text-gray-400 hover:text-red-600 transition-colors"
                             >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                </svg>
                             </button>
                        </div>
                    </div>

                    <h3 className="text-lg font-bold text-gray-900 mb-1 leading-tight pl-3">{task.title}</h3>

                    <div className="pl-3 mb-4">
                        {task.category === 'Task' && (
                            <div className="text-xs text-gray-500 flex items-center">
                                <span className="mr-2">📅 Due:</span> 
                                <span className={`font-medium ${isOverdue ? 'text-red-600' : 'text-gray-700'}`}>
                                    {task.deadline.toLocaleDateString(undefined, {month:'short', day:'numeric'})}
                                </span>
                            </div>
                        )}
                        {task.category === 'Meeting' && (
                             <div className="text-xs text-gray-500 flex items-center">
                                <span className="mr-2">🕒 Time:</span> 
                                <span className="font-medium text-gray-700">
                                    {task.meetingDate} @ {task.meetingStartTime}
                                </span>
                            </div>
                        )}
                        {task.category === 'Habit' && (
                             <div className="text-xs text-gray-500 flex items-center">
                                <span className="mr-2">🔁 Repeats:</span> 
                                <span className="font-medium text-gray-700">
                                    {task.preferredDays.map(d => d.slice(0,3)).join(', ')}
                                </span>
                            </div>
                        )}
                    </div>

                    {task.description && (
                        <p className="text-xs text-gray-600 mb-4 line-clamp-2 pl-3">{task.description}</p>
                    )}

                    <div className="mt-auto pl-3">
                        {task.category !== 'Meeting' && (
                        <>
                            <div className="flex justify-between items-end mb-1">
                                <span className="text-xs font-medium text-gray-500">
                                    {stats.completed.toFixed(1)} hrs done
                                </span>
                                <span className="text-xs font-bold text-gray-700">
                                    {totalPlanned.toFixed(1)} hrs planned
                                </span>
                            </div>

                            <div className="w-full bg-gray-100 rounded-full h-2.5 overflow-hidden flex">
                                <div 
                                    className="h-full bg-emerald-500 transition-all duration-500"
                                    style={{ width: `${stats.percentCompleted}%` }}
                                ></div>
                                <div 
                                    className="h-full bg-indigo-400 transition-all duration-500 opacity-60"
                                    style={{ width: `${stats.percentScheduled}%` }}
                                ></div>
                            </div>
                        </>
                        )}

                        <div className="mt-4 flex gap-2">
                             {task.files.length > 0 && (
                                <div className="text-[10px] bg-gray-50 border border-gray-200 px-2 py-1 rounded text-gray-600 flex items-center">
                                    📎 {task.files.length} Materials
                                </div>
                             )}
                        </div>
                    </div>
                </div>
            );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Task, TaskFile, Priority, EnergyLevel, TaskCategory } from '../types';
import { Button } from './Button';

interface TaskFormProps {
  initialTask?: Task | null;
  onSubmit: (task: Task) => Promise<void>;
  onCancel: () => void;
}

const DAYS_OF_WEEK = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"];

export const TaskForm: React.FC<TaskFormProps> = ({ initialTask, onSubmit, onCancel }) => {
  // Mode Selection
  const [category, setCategory] = useState<TaskCategory>('Task');

  // Common Fields
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [priority, setPriority] = useState<Priority>('Medium');
  const [files, setFiles] = useState<TaskFile[]>([]);

  // Task Specific
  const [deadline, setDeadline] = useState("");
  const [totalHours, setTotalHours] = useState(2);
  const [energyLevel, setEnergyLevel] = useState<EnergyLevel>('High');

  // Meeting Specific
  const [meetingDate, setMeetingDate] = useState("");
  const [meetingStart, setMeetingStart] = useState("09:00");
  const [meetingEnd, setMeetingEnd] = useState("10:00");

  // Habit Specific
  const [recurrenceEndDate, setRecurrenceEndDate] = useState("");

  // Scheduling Preferences (Shared by Task & Habit)
  const [sessionDuration, setSessionDuration] = useState(1.0);
  const [selectedDays, setSelectedDays] = useState<string[]>([]);
  const [preferredTimeStart, setPreferredTimeStart] = useState("09:00");
  const [preferredTimeEnd, setPreferredTimeEnd] = useState("22:00");

  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    if (initialTask) {
        setCategory(initialTask.category);
        setTitle(initialTask.title);
        setDescription(initialTask.description);
        setPriority(initialTask.priority);
        setFiles(initialTask.files);
        setEnergyLevel(initialTask.energyLevel);

        if (initialTask.category === 'Task') {
            setTotalHours(initialTask.totalHoursNeeded);
            const d = new Date(initialTask.deadline);
            const pad = (n: number) => n < 10 ? '0'+n : n;
            setDeadline(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`);
        } else if (initialTask.category === 'Meeting') {
             setMeetingDate(initialTask.meetingDate || "");
             setMeetingStart(initialTask.meetingStartTime || "09:00");
             setMeetingEnd(initialTask.meetingEndTime || "10:00");
        } else if (initialTask.category === 'Habit') {
             if (initialTask.recurrenceEndDate) {
                const d = new Date(initialTask.recurrenceEndDate);
                const pad = (n: number) => n < 10 ? '0'+n : n;
                setRecurrenceEndDate(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`);
             }
        }

        // Shared
        setSessionDuration(initialTask.preferredSessionDuration || 1.0);
        setSelectedDays(initialTask.preferredDays || []);
        setPreferredTimeStart(initialTask.preferredTimeStart || "09:00");
        setPreferredTimeEnd(initialTask.preferredTimeEnd || "22:00");
    } else {
        // Defaults
        const tomorrow = new Date();
        tomorrow.setDate(tomorrow.getDate() + 1);
        tomorrow.setHours(17,0,0,0);
        // Default deadline
    }
  }, [initialTask]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: TaskFile[] = Array.from(e.target.files).map(f => ({
        name: f.name,
        size: f.size,
        type: f.type,
        url: URL.createObjectURL(f) 
      }));
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const toggleDay = (day: string) => {
    setSelectedDays(prev => 
      prev.includes(day) ? prev.filter(d => d !== day) : [...prev, day]
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    // Validation
    if (category === 'Task' && !deadline) { alert("Deadline required"); setIsSubmitting(false); return; }
    if (category === 'Meeting' && (!meetingDate || !meetingStart || !meetingEnd)) { alert("Meeting details required"); setIsSubmitting(false); return; }
    if (category === 'Habit' && selectedDays.length === 0) { alert("Select days for habit"); setIsSubmitting(false); return; }

    const taskToSave: Task = {
      id: initialTask ? initialTask.id : crypto.randomUUID(),
      category,
      title,
      description,
      priority,
      files,
      // Task fields
      difficulty: 5,
      totalHoursNeeded: totalHours,
      deadline: deadline ? new Date(deadline) : new Date(new Date().setFullYear(new Date().getFullYear() + 1)),
      energyLevel,
      // Habit fields
      recurrenceEndDate: recurrenceEndDate ? new Date(recurrenceEndDate) : undefined,
      // Meeting fields
      meetingDate,
      meetingStartTime: meetingStart,
      meetingEndTime: meetingEnd,
      // Scheduling
      preferredDays: selectedDays.length > 0 ? selectedDays : DAYS_OF_WEEK,
      preferredTimeStart,
      preferredTimeEnd,
      preferredSessionDuration: sessionDuration,
      isScheduled: initialTask ? initialTask.isScheduled : false
    };

    try {
      await onSubmit(taskToSave);
    } catch (err) {
      console.error(err);
      alert("Failed to save.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-xl max-w-2xl mx-auto border border-gray-200">
      <div className="mb-6">
          <h2 className="text-2xl font-bold text-gray-900 mb-4 flex items-center">
            <span className="bg-indigo-50 text-indigo-600 p-2 rounded-lg mr-3 border border-indigo-100">
                {initialTask ? '✏️' : '✦'}
            </span>
            {initialTask ? 'Edit Event' : 'New Event'}
          </h2>

          {/* Category Tabs */}
          {!initialTask && (
              <div className="flex bg-gray-100 p-1 rounded-lg mb-6">
                {(['Task', 'Meeting', 'Habit'] as TaskCategory[]).map(cat => (
                    <button
                        key={cat}
                        type="button"
                        onClick={() => setCategory(cat)}
                        className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${
                            category === cat 
                            ? 'bg-white text-indigo-600 shadow-sm' 
                            : 'text-gray-500 hover:text-gray-900'
                        }`}
                    >
                        {cat}
                    </button>
                ))}
              </div>
          )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Title & Desc */}
        <div>
            <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Title</label>
            <input 
              required
              type="text" 
              value={title}
              onChange={e => setTitle(e.target.value)}
              className="block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2.5 border bg-white text-gray-900"
              placeholder={category === 'Meeting' ? "e.g. Team Sync" : category === 'Habit' ? "e.g. Gym" : "e.g. Final Project"}
            />
        </div>

        {/* --- MEETING FIELDS --- */}
        {category === 'Meeting' && (
             <div className="grid grid-cols-3 gap-4 bg-purple-50 p-4 rounded-lg border border-purple-100">
                <div className="col-span-1">
                    <label className="block text-xs font-semibold text-purple-800 mb-1">Date</label>
                    <input type="date" required value={meetingDate} onChange={e => setMeetingDate(e.target.value)} className="w-full text-sm p-2 rounded border-gray-300" />
                </div>
                <div className="col-span-1">
                    <label className="block text-xs font-semibold text-purple-800 mb-1">Start</label>
                    <input type="time" required value={meetingStart} onChange={e => setMeetingStart(e.target.value)} className="w-full text-sm p-2 rounded border-gray-300" />
                </div>
                 <div className="col-span-1">
                    <label className="block text-xs font-semibold text-purple-800 mb-1">End</label>
                    <input type="time" required value={meetingEnd} onChange={e => setMeetingEnd(e.target.value)} className="w-full text-sm p-2 rounded border-gray-300" />
                </div>
             </div>
        )}

        {/* --- TASK FIELDS --- */}
        {category === 'Task' && (
             <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Deadline</label>
                    <input type="datetime-local" required value={deadline} onChange={e => setDeadline(e.target.value)} className="block w-full rounded-md border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 sm:text-sm" />
                 </div>
                 <div>
                     <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Total Hours</label>
                     <input type="number" min="0.5" step="0.5" value={totalHours} onChange={e => setTotalHours(parseFloat(e.target.value))} className="block w-full rounded-md border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 sm:text-sm" />
                 </div>

                 {/* Energy Level (Only relevant for flexible tasks) */}
                 <div className="col-span-2">
                     <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Best Time of Day</label>
                     <div className="flex rounded-md shadow-sm bg-gray-50 border border-gray-200 p-1">
                        {(['High', 'Low'] as EnergyLevel[]).map((e) => (
                            <button
                                key={e}
                                type="button"
                                onClick={() => setEnergyLevel(e)}
                                className={`flex-1 py-1 text-xs font-medium rounded transition-colors ${energyLevel === e ? 'bg-white text-indigo-600 shadow-sm border border-gray-100' : 'text-gray-500 hover:text-gray-700'}`}
                            >
                                {e === 'High' ? '☀️ Morning / Focus' : '🌙 Evening / Relax'}
                            </button>
                        ))}
                     </div>
                 </div>
             </div>
        )}

        {/* --- HABIT FIELDS --- */}
        {category === 'Habit' && (
             <div className="grid grid-cols-2 gap-4 bg-teal-50 p-4 rounded-lg border border-teal-100">
                <div>
                     <label className="block text-xs font-semibold text-teal-800 mb-1">Duration per session (hrs)</label>
                     <input type="number" min="0.5" step="0.5" value={sessionDuration} onChange={e => setSessionDuration(parseFloat(e.target.value))} className="w-full text-sm p-2 rounded border-gray-300" />
                </div>
                <div>
                     <label className="block text-xs font-semibold text-teal-800 mb-1">Repeat Until</label>
                     <input type="date" value={recurrenceEndDate} onChange={e => setRecurrenceEndDate(e.target.value)} className="w-full text-sm p-2 rounded border-gray-300" />
                </div>
             </div>
        )}

        {/* Description */}
        <div>
            <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Description</label>
            <textarea value={description} onChange={e => setDescription(e.target.value)} rows={2} className="block w-full rounded-md border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 sm:text-sm placeholder-gray-400" />
        </div>

        {/* --- SHARED: AVAILABILITY / RECURRENCE --- */}
        {category !== 'Meeting' && (
            <div className="border-t border-gray-200 pt-6">
                <h3 className="text-sm font-semibold text-gray-900 mb-4">
                    {category === 'Habit' ? 'Recurrence Pattern' : 'Availability'}
                </h3>

                <div className="flex flex-wrap gap-2 mb-4">
                    {DAYS_OF_WEEK.map(day => (
                        <button
                            key={day}
                            type="button"
                            onClick={() => toggleDay(day)}
                            className={`px-3 py-1.5 rounded text-xs font-medium border transition-colors ${
                                selectedDays.includes(day) 
                                    ? 'bg-indigo-600 text-white border-indigo-600' 
                                    : 'bg-white text-gray-500 border-gray-300 hover:border-gray-400'
                            }`}
                        >
                            {day.substring(0, 3)}
                        </button>
                    ))}
                </div>

                <div className="grid grid-cols-2 gap-6">
                    <div>
                        <label className="block text-xs text-gray-500 mb-1">Preferred Start</label>
                        <input type="time" value={preferredTimeStart} onChange={e => setPreferredTimeStart(e.target.value)} className="block w-full rounded-md border-gray-300 shadow-sm sm:text-sm p-2 border bg-white text-gray-900" />
                    </div>
                    <div>
                        <label className="block text-xs text-gray-500 mb-1">Preferred End</label>
                        <input type="time" value={preferredTimeEnd} onChange={e => setPreferredTimeEnd(e.target.value)} className="block w-full rounded-md border-gray-300 shadow-sm sm:text-sm p-2 border bg-white text-gray-900" />
                    </div>
                </div>
            </div>
        )}

        {/* Priority & Files */}
        <div className="grid grid-cols-2 gap-6 border-t border-gray-200 pt-6">
             <div>
                 <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Priority</label>
                 <select value={priority} onChange={(e) => setPriority(e.target.value as Priority)} className="block w-full rounded-md border-gray-300 shadow-sm p-2 border bg-white text-gray-900 sm:text-sm">
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                 </select>
             </div>

             <div>
                <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Materials</label>
                <label className="flex items-center justify-center w-full p-2 border border-gray-300 border-dashed rounded cursor-pointer hover:bg-gray-50">
                    <span className="text-xs text-indigo-600">+ Upload</span>
                    <input type="file" className="hidden" multiple onChange={handleFileChange} />
                </label>
             </div>
        </div>

        {files.length > 0 && (
            <ul className="space-y-1">
                {files.map((file, idx) => (
                    <li key={idx} className="flex justify-between items-center text-xs text-gray-600 bg-gray-50 p-1 rounded">
                        <span>{file.name}</span>
                        <button type="button" onClick={() => removeFile(idx)} className="text-red-500">×</button>
                    </li>
                ))}
            </ul>
        )}

        <div className="flex justify-end gap-3 pt-4 border-t border-gray-200">
            <Button variant="ghost" type="button" onClick={onCancel}>Cancel</Button>
            <Button type="submit" isLoading={isSubmitting}>
                {initialTask ? 'Save Changes' : `Add ${category}`}
            </Button>
        </div>
      </form>
    </div>
  );
};

import { CalendarEvent, Task, EventType, Priority } from '../types';

/**
 * Parses a time string (e.g. "14:30") and sets it on the given date object.
 */
const parseTimeOnDate = (timeStr: string, date: Date): Date => {
    const [hours, minutes] = timeStr.split(':').map(Number);
    const newDate = new Date(date);
    newDate.setHours(hours, minutes, 0, 0);
    return newDate;
};

/**
 * Checks if two date ranges overlap
 */
const isOverlapping = (start1: Date, end1: Date, start2: Date, end2: Date): boolean => {
    return start1 < end2 && end1 > start2;
};

interface TimeRange {
    start: Date;
    end: Date;
}

/**
 * Subtracts busy intervals from a time range to find free bins.
 */
const calculateFreeBins = (
    rangeStart: Date,
    rangeEnd: Date,
    busyEvents: CalendarEvent[]
): TimeRange[] => {
    const sortedBusy = [...busyEvents]
        .filter(e => isOverlapping(e.start, e.end, rangeStart, rangeEnd))
        .sort((a, b) => a.start.getTime() - b.start.getTime());

    const freeBins: TimeRange[] = [];
    let currentStart = new Date(rangeStart);

    for (const event of sortedBusy) {
        const eventStart = event.start < rangeStart ? rangeStart : event.start;
        const eventEnd = event.end > rangeEnd ? rangeEnd : event.end;

        if (eventStart > currentStart) {
            freeBins.push({ start: new Date(currentStart), end: new Date(eventStart) });
        }

        if (eventEnd > currentStart) {
            currentStart = new Date(eventEnd);
        }
    }

    if (currentStart < rangeEnd) {
        freeBins.push({ start: new Date(currentStart), end: new Date(rangeEnd) });
    }

    return freeBins;
};

const getEventColorByPriority = (priority: Priority) => {
    switch(priority) {
        case 'High': return 'bg-red-50 border-red-200 text-red-700';
        case 'Medium': return 'bg-amber-50 border-amber-200 text-amber-700';
        case 'Low': return 'bg-emerald-50 border-emerald-200 text-emerald-700';
        default: return 'bg-gray-50 border-gray-200 text-gray-700';
    }
};

/**
 * Core Scheduler
 */
export const scheduleTasks = (
    fixedEvents: CalendarEvent[],
    tasks: Task[]
): CalendarEvent[] => {
    const scheduledEvents: CalendarEvent[] = [];
    const now = new Date();

    // Separate Habits and Tasks
    const flexibleTasks = tasks.filter(t => t.category === 'Task' && t.isScheduled);
    const habits = tasks.filter(t => t.category === 'Habit' && t.isScheduled);

    // Helper: Apply buffers
    const getAllBusySlots = () => {
        const allEvents = [...fixedEvents, ...scheduledEvents];
        return allEvents.map(e => {
            const start = new Date(e.start);
            const end = new Date(e.end);
            // 15 min buffer for everything
            start.setMinutes(start.getMinutes() - 15);
            end.setMinutes(end.getMinutes() + 15);
            return { ...e, start, end };
        });
    };

    const startOfScheduling = new Date(now);
    const remainder = 15 - (startOfScheduling.getMinutes() % 15);
    startOfScheduling.setMinutes(startOfScheduling.getMinutes() + remainder, 0, 0);

    // --- PHASE 1: SCHEDULE HABITS ---
    // Habits are time-specific recurring events. We try to book them first.

    habits.forEach(habit => {
        let loopDate = new Date(startOfScheduling);
        const endDate = habit.recurrenceEndDate || new Date(now.getFullYear() + 1, 0, 1);

        while (loopDate < endDate) {
             const dayName = loopDate.toLocaleDateString('en-US', { weekday: 'long' });

             if (habit.preferredDays.includes(dayName)) {
                const windowStart = parseTimeOnDate(habit.preferredTimeStart, loopDate);
                const windowEnd = parseTimeOnDate(habit.preferredTimeEnd, loopDate);
                const effectiveStart = (windowStart < startOfScheduling) ? startOfScheduling : windowStart;

                if (effectiveStart < windowEnd) {
                    const busyEvents = getAllBusySlots();
                    const freeBins = calculateFreeBins(effectiveStart, windowEnd, busyEvents);

                    // Try to find *one* slot for this habit instance
                    for (const bin of freeBins) {
                        const binDurationHours = (bin.end.getTime() - bin.start.getTime()) / 36e5;
                        const needed = habit.preferredSessionDuration || 1.0;

                        if (binDurationHours >= needed) {
                             const sessionEnd = new Date(bin.start.getTime() + needed * 36e5);
                             scheduledEvents.push({
                                id: crypto.randomUUID(),
                                title: habit.title,
                                start: new Date(bin.start),
                                end: sessionEnd,
                                type: EventType.AI_WORK_SESSION,
                                relatedTaskId: habit.id,
                                description: "Recurring Habit",
                                color: "bg-teal-50 border-teal-200 text-teal-700",
                                priority: habit.priority
                             });
                             break; // Booked for this day
                        }
                    }
                }
             }
             loopDate.setDate(loopDate.getDate() + 1);
             loopDate.setHours(0,0,0,0);
        }
    });

    // --- PHASE 2: SCHEDULE FLEXIBLE TASKS (EDF) ---
    const sortedTasks = [...flexibleTasks].sort((a, b) => a.deadline.getTime() - b.deadline.getTime());
    const MIN_SESSION_DURATION_HOURS = 0.5;

    for (const task of sortedTasks) {
        let hoursRemaining = task.totalHoursNeeded;
        if (typeof hoursRemaining !== 'number' || isNaN(hoursRemaining) || hoursRemaining <= 0) continue;

        let currentDate = new Date(startOfScheduling);
        let dayCount = 0;
        const maxDays = 365;

        while (hoursRemaining > 0.05 && currentDate < task.deadline && dayCount < maxDays) {
            dayCount++;
            const dayName = currentDate.toLocaleDateString('en-US', { weekday: 'long' });

            if (task.preferredDays.includes(dayName)) {
                const windowStart = parseTimeOnDate(task.preferredTimeStart, currentDate);
                const windowEnd = parseTimeOnDate(task.preferredTimeEnd, currentDate);
                const effectiveStart = (windowStart < startOfScheduling) ? startOfScheduling : windowStart;

                if (effectiveStart < windowEnd) {
                    const busyEvents = getAllBusySlots();
                    let freeBins = calculateFreeBins(effectiveStart, windowEnd, busyEvents);

                    // Energy Heuristic
                    freeBins.sort((a, b) => {
                        const midA = (a.start.getHours() + a.end.getHours()) / 2;
                        const midB = (b.start.getHours() + b.end.getHours()) / 2;
                        return task.energyLevel === 'High' ? midA - midB : midB - midA;
                    });

                    for (const bin of freeBins) {
                        if (hoursRemaining <= 0.05) break;

                        const binDurationHours = (bin.end.getTime() - bin.start.getTime()) / 36e5;
                        if (binDurationHours < MIN_SESSION_DURATION_HOURS) continue;

                        const maxBlockSize = task.preferredSessionDuration || 2.0;
                        const timeToTake = Math.min(hoursRemaining, binDurationHours, maxBlockSize);

                        if (timeToTake < MIN_SESSION_DURATION_HOURS && Math.abs(timeToTake - hoursRemaining) > 0.05) continue;

                        const sessionEnd = new Date(bin.start.getTime() + timeToTake * 36e5);

                        scheduledEvents.push({
                            id: crypto.randomUUID(),
                            title: task.title,
                            start: new Date(bin.start),
                            end: sessionEnd,
                            type: EventType.AI_WORK_SESSION,
                            relatedTaskId: task.id,
                            description: `Priority: ${task.priority} | Energy: ${task.energyLevel}`,
                            color: getEventColorByPriority(task.priority),
                            priority: task.priority
                        });

                        hoursRemaining -= timeToTake;
                    }
                }
            }
            currentDate.setDate(currentDate.getDate() + 1);
            currentDate.setHours(0, 0, 0, 0);
        }
    }

    return scheduledEvents;
};

import React, { useState } from 'react';
import { Calendar } from './components/Calendar';
import { TaskForm } from './components/TaskForm';
import { ImportModal } from './components/ImportModal';
import { EventDetailsModal } from './components/EventDetailsModal';
import { EventsView } from './components/EventsView';
import { Button } from './components/Button';
import { scheduleTasks } from './services/scheduler';
import { identifyClasses, analyzeTaskSemantics } from './services/geminiService';
import { CalendarEvent, Task, EventType } from './types';

function App() {
  const [view, setView] = useState<'calendar' | 'events' | 'newEvent' | 'editEvent'>('calendar');
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const [currentDate, setCurrentDate] = useState(new Date());

  const handleNavigate = (direction: 'prev' | 'next' | 'today') => {
    const newDate = new Date(currentDate);
    if (direction === 'today') {
      setCurrentDate(new Date());
    } else if (direction === 'next') {
      newDate.setDate(newDate.getDate() + 7);
      setCurrentDate(newDate);
    } else {
      newDate.setDate(newDate.getDate() - 7);
      setCurrentDate(newDate);
    }
  };

  const runGlobalScheduler = (fixedEvents: CalendarEvent[], currentTasks: Task[]) => {
    // Only AI Work Sessions that haven't been manually moved (conceptually) are re-scheduled.
    const cleanFixedEvents = fixedEvents.filter(e => e.type !== EventType.AI_WORK_SESSION);
    const newSessions = scheduleTasks(cleanFixedEvents, currentTasks);
    return [...cleanFixedEvents, ...newSessions];
  };

  const handleImport = async (importedEvents: CalendarEvent[]) => {
    setIsImportModalOpen(false);
    setIsProcessing(true);
    try {
      const classIds = await identifyClasses(importedEvents);
      const taggedEvents = importedEvents.map(e => ({
        ...e,
        isClass: classIds.includes(e.id),
        color: classIds.includes(e.id) ? "bg-blue-50 border-blue-200 text-blue-700" : e.color
      }));

      const existingFixed = events.filter(e => e.type !== EventType.AI_WORK_SESSION);
      const allFixedEvents = [...existingFixed, ...taggedEvents];
      const optimizedSchedule = runGlobalScheduler(allFixedEvents, tasks);
      setEvents(optimizedSchedule);
    } catch (error) {
      console.error("Import error:", error);
      alert("Error processing schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCreateOrUpdateTask = async (taskInput: Task) => {
    setIsProcessing(true);
    try {
      let task = { ...taskInput };

      // AI Analysis only for flexible Tasks, not Meetings/Habits usually (but Habits could use it)
      if (task.category === 'Task') {
          const aiAnalysis = await analyzeTaskSemantics(task.title, task.description);
          task.energyLevel = aiAnalysis.energyLevel;
      }

      let updatedTasks;
      const isUpdate = tasks.some(t => t.id === task.id);

      // Determine if we need to schedule valid events
      // If MEETING: We create a Manual event immediately
      let newManualEvent: CalendarEvent | null = null;
      if (task.category === 'Meeting' && task.meetingDate && task.meetingStartTime && task.meetingEndTime) {
         const start = new Date(`${task.meetingDate}T${task.meetingStartTime}`);
         const end = new Date(`${task.meetingDate}T${task.meetingEndTime}`);
         newManualEvent = {
             id: `meeting-${task.id}`,
             title: task.title,
             start,
             end,
             type: EventType.MANUAL,
             relatedTaskId: task.id,
             color: "bg-purple-50 border-purple-200 text-purple-700",
             description: task.description
         };
         task.isScheduled = true; // Mark meeting task as done/scheduled
      } else {
         task.isScheduled = true; // Mark task/habit as ready for scheduler
      }

      if (isUpdate) {
        updatedTasks = tasks.map(t => t.id === task.id ? task : t);
      } else {
        updatedTasks = [...tasks, task];
      }

      // 1. Filter out old sessions related to this task if updating
      //    (Unless it's a manual meeting, in which case we might overwrite the specific one)
      let currentEvents = events.filter(e => e.relatedTaskId !== task.id || e.type !== EventType.AI_WORK_SESSION);

      // 2. Add the new Meeting event if applicable
      if (newManualEvent) {
          // Remove old meeting event if exists
          currentEvents = currentEvents.filter(e => e.relatedTaskId !== task.id);
          currentEvents.push(newManualEvent);
      }

      // 3. Re-run scheduler
      // Note: Meetings are now in 'currentEvents' as MANUAL, so scheduler sees them as busy slots.
      const fixedEvents = currentEvents.filter(e => e.type !== EventType.AI_WORK_SESSION);
      const optimizedSchedule = runGlobalScheduler(fixedEvents, updatedTasks);

      setEvents(optimizedSchedule);
      setTasks(updatedTasks);
      setView('calendar');
      setEditingTask(null);

    } catch (error) {
      console.error(error);
      alert("Error generating schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDeleteEvent = (id: string) => {
    const eventToDelete = events.find(e => e.id === id);
    if (!eventToDelete) return;

    // If deleting a Meeting event, we should probably delete the task too or mark it unscheduled?
    // For now, just delete the event block. 
    if (eventToDelete.type === EventType.AI_WORK_SESSION) {
        setEvents(prev => prev.filter(e => e.id !== id));
    } else {
        const remainingFixed = events.filter(e => e.id !== id && e.type !== EventType.AI_WORK_SESSION);
        const optimizedSchedule = runGlobalScheduler(remainingFixed, tasks);
        setEvents(optimizedSchedule);
    }
  };

  const handleDeleteTask = (taskId: string) => {
      const updatedTasks = tasks.filter(t => t.id !== taskId);
      setTasks(updatedTasks);
      const remainingEvents = events.filter(e => e.relatedTaskId !== taskId);
      const fixedEvents = remainingEvents.filter(e => e.type !== EventType.AI_WORK_SESSION);
      const optimizedSchedule = runGlobalScheduler(fixedEvents, updatedTasks);
      setEvents(optimizedSchedule);
  };

  const handleUpdateEvent = (updatedEvent: CalendarEvent) => {
    const finalEvent = {
        ...updatedEvent,
        type: updatedEvent.type === EventType.AI_WORK_SESSION ? EventType.MANUAL : updatedEvent.type,
    };
    setEvents(prevEvents => {
        const otherEvents = prevEvents.filter(e => e.id !== updatedEvent.id);
        const newEventList = [...otherEvents, finalEvent];
        return newEventList;
    });
  };

  const selectedTask = selectedEvent?.relatedTaskId 
    ? tasks.find(t => t.id === selectedEvent.relatedTaskId) 
    : undefined;

  return (
    <div className="min-h-screen flex flex-col relative bg-gray-50 text-gray-900 font-sans">
      <nav className="border-b border-gray-200 bg-white sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <span className="bg-indigo-600 text-white p-1.5 rounded mr-3 font-bold">SP</span>
              <h1 className="text-xl font-bold tracking-tight text-gray-900 hidden sm:block">SparkPlan AI</h1>

              <div className="ml-8 flex space-x-1">
                 <button 
                    onClick={() => setView('calendar')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'calendar' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Calendar
                 </button>
                 <button 
                    onClick={() => setView('events')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'events' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Events
                 </button>
              </div>
            </div>
            <div className="flex items-center space-x-4">
              <Button variant="ghost" onClick={() => setIsImportModalOpen(true)}>Import</Button>
              <Button onClick={() => { setEditingTask(null); setView('newEvent'); }} disabled={view === 'newEvent'}>
                + New Event
              </Button>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {view === 'calendar' && (
          <>
            <div className="mb-6 flex items-center justify-between">
              <div>
                <h2 className="text-xl font-bold text-gray-900 tracking-tight">Dashboard</h2>
                <p className="text-sm text-gray-500 mt-1">
                  {events.filter(e => e.type === EventType.AI_WORK_SESSION).length} active work sessions.
                </p>
              </div>
              <div className="flex gap-4 text-xs font-medium text-gray-600">
                 <div className="flex items-center"><div className="w-2 h-2 bg-blue-400 rounded-full mr-2"></div> Class</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-purple-400 rounded-full mr-2"></div> Meeting</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-teal-400 rounded-full mr-2"></div> Habit</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-indigo-600 rounded-full mr-2"></div> Task</div>
              </div>
            </div>
            <div className="h-[calc(100vh-200px)]">
               <Calendar 
                  events={events} 
                  currentDate={currentDate} 
                  onEventClick={setSelectedEvent}
                  onNavigate={handleNavigate}
                  onEventUpdate={handleUpdateEvent}
               />
            </div>
          </>
        )}

        {view === 'events' && (
            <EventsView 
                tasks={tasks} 
                events={events}
                onEditTask={(task) => {
                    setEditingTask(task);
                    setView('editEvent');
                }}
                onDeleteTask={handleDeleteTask}
            />
        )}

        {(view === 'newEvent' || view === 'editEvent') && (
          <div className="py-8">
            <TaskForm 
              initialTask={editingTask}
              onSubmit={handleCreateOrUpdateTask} 
              onCancel={() => {
                  setEditingTask(null);
                  setView('calendar');
              }} 
            />
          </div>
        )}
      </main>

      <ImportModal 
        isOpen={isImportModalOpen} 
        onClose={() => setIsImportModalOpen(false)} 
        onImport={handleImport} 
      />

      <EventDetailsModal 
        event={selectedEvent} 
        relatedTask={selectedTask}
        onClose={() => setSelectedEvent(null)}
        onDelete={handleDeleteEvent}
        onUpdate={handleUpdateEvent}
      />

      {isProcessing && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-900 bg-opacity-50 backdrop-blur-sm transition-opacity">
            <div className="flex flex-col items-center p-6 bg-white rounded-lg shadow-xl">
                <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
                <h3 className="text-lg font-bold text-gray-900 tracking-widest uppercase">Scheduling</h3>
                <p className="text-xs text-gray-500 mt-2">Balancing Tasks, Habits & Meetings...</p>
            </div>
        </div>
      )}

    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { CalendarEvent, EventType } from '../types';

interface CalendarProps {
  events: CalendarEvent[];
  currentDate: Date;
  onEventClick: (event: CalendarEvent) => void;
  onNavigate: (direction: 'prev' | 'next' | 'today') => void;
  onEventUpdate: (updatedEvent: CalendarEvent) => void;
}

export const Calendar: React.FC<CalendarProps> = ({ events, currentDate, onEventClick, onNavigate, onEventUpdate }) => {
  const [now, setNow] = useState(new Date());

  useEffect(() => {
    // Update 'now' every minute
    const interval = setInterval(() => setNow(new Date()), 60000);
    return () => clearInterval(interval);
  }, []);

  const daysOfWeek = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const startHour = 6;
  const hours = Array.from({ length: 18 }, (_, i) => i + startHour); 

  const getDayDates = () => {
    const dates = [];
    const startOfWeek = new Date(currentDate);
    const day = startOfWeek.getDay();
    startOfWeek.setDate(startOfWeek.getDate() - day);

    for (let i = 0; i < 7; i++) {
      const date = new Date(startOfWeek);
      date.setDate(startOfWeek.getDate() + i);
      dates.push(date);
    }
    return dates;
  };

  const weekDates = getDayDates();

  const formatHour = (h: number) => {
    const ampm = h >= 12 ? 'PM' : 'AM';
    const h12 = h % 12 || 12;
    return `${h12} ${ampm}`;
  };

  const getEventStyle = (event: CalendarEvent, colIndex: number) => {
    const eventStartHour = event.start.getHours() + event.start.getMinutes() / 60;
    const eventEndHour = event.end.getHours() + event.end.getMinutes() / 60;
    const duration = eventEndHour - eventStartHour;
    const top = (eventStartHour - startHour) * 60; 
    const height = duration * 60;

    return {
      top: `${top}px`,
      height: `${height}px`,
      left: '2px',
      right: '2px'
    };
  };

  const isSameDay = (d1: Date, d2: Date) => {
    return d1.getDate() === d2.getDate() && 
           d1.getMonth() === d2.getMonth() && 
           d1.getFullYear() === d2.getFullYear();
  };

  const formatWeekRange = (start: Date, end: Date) => {
    return `${start.toLocaleDateString('default', {month:'short', day:'numeric'})} - ${end.toLocaleDateString('default', {month:'short', day:'numeric'})}`;
  };

  // --- Heatmap Logic: Calculate Constraint Density ---
  const getHeatmapColor = (date: Date) => {
      const dayEvents = events.filter(e => isSameDay(e.start, date));
      let totalHours = 0;
      dayEvents.forEach(e => {
          totalHours += (e.end.getTime() - e.start.getTime()) / (1000 * 60 * 60);
      });

      const ratio = Math.min(totalHours / 12, 1);

      if (ratio < 0.2) return 'bg-emerald-50/50'; 
      if (ratio < 0.5) return 'bg-amber-50/50'; 
      return 'bg-red-50/50'; 
  };

  const getHeatmapHeight = (date: Date) => {
      const dayEvents = events.filter(e => isSameDay(e.start, date));
      let totalHours = 0;
      dayEvents.forEach(e => {
          totalHours += (e.end.getTime() - e.start.getTime()) / (1000 * 60 * 60);
      });
      const ratio = Math.min(totalHours / 14, 1);
      return `${ratio * 100}%`;
  }

  // --- Current Time Indicator Helper ---
  const getCurrentTimePosition = () => {
      const currentHour = now.getHours();
      const currentMin = now.getMinutes();
      // Calculate pixels from top: (Hours passed since startHour * 60) + minutes
      return ((currentHour - startHour) * 60) + currentMin;
  };

  const isTimeVisible = () => {
      const pos = getCurrentTimePosition();
      // Total height is 18 hours * 60px = 1080px
      return pos >= 0 && pos <= 1080;
  };

  // --- Drag and Drop Handlers ---

  const handleDragStart = (e: React.DragEvent, event: CalendarEvent) => {
    e.dataTransfer.setData('text/plain', event.id);
    e.dataTransfer.effectAllowed = 'move';

    // Calculate offset to prevent "jumping" when dragging starts
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const offsetY = e.clientY - rect.top;
    e.dataTransfer.setData('offsetY', offsetY.toString());
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault(); // Necessary to allow dropping
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, date: Date) => {
    e.preventDefault();
    const eventId = e.dataTransfer.getData('text/plain');
    const offsetY = parseFloat(e.dataTransfer.getData('offsetY'));

    const event = events.find(ev => ev.id === eventId);
    if (!event) return;

    const colRect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const dropY = e.clientY - colRect.top - offsetY; 

    // Snap to 15 min slots (15px)
    const snappedY = Math.round(dropY / 15) * 15;

    // Calculate new start time
    const hoursFromStart = snappedY / 60;
    const totalMinutes = (startHour * 60) + (hoursFromStart * 60);

    const newStart = new Date(date);
    newStart.setHours(Math.floor(totalMinutes / 60), Math.floor(totalMinutes % 60), 0, 0);

    // Calculate new end time (preserve duration)
    const durationMs = event.end.getTime() - event.start.getTime();
    const newEnd = new Date(newStart.getTime() + durationMs);

    onEventUpdate({ ...event, start: newStart, end: newEnd });
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-xl border border-gray-200 overflow-hidden shadow-sm">

      {/* Navigation Header */}
      <div className="flex items-center justify-between px-6 py-4 border-b border-gray-200 bg-white">
        <div className="flex items-center gap-6">
            <h2 className="text-lg font-bold text-gray-900 w-48 tracking-tight">
                {weekDates[0].toLocaleString('default', { month: 'long', year: 'numeric' })}
            </h2>
            <div className="flex items-center gap-2">
                <button onClick={() => onNavigate('prev')} className="p-2 text-gray-500 hover:text-gray-900 transition-colors">←</button>
                <span className="text-sm font-medium text-gray-600 w-32 text-center">
                    {formatWeekRange(weekDates[0], weekDates[6])}
                </span>
                <button onClick={() => onNavigate('next')} className="p-2 text-gray-500 hover:text-gray-900 transition-colors">→</button>

                <button 
                    onClick={() => onNavigate('today')} 
                    className="ml-4 px-3 py-1 text-xs font-medium text-gray-700 bg-gray-100 rounded hover:bg-gray-200 transition-colors border border-gray-200"
                >
                    Today
                </button>
            </div>
        </div>
      </div>

      {/* Days Header */}
      <div className="grid grid-cols-8 border-b border-gray-200 bg-gray-50">
        <div className="p-4 border-r border-gray-200 text-xs font-mono text-gray-500 uppercase text-center pt-8">
           GMT
        </div>
        {weekDates.map((date, i) => (
          <div key={i} className={`relative p-2 text-center border-r border-gray-200 ${isSameDay(date, new Date()) ? 'bg-blue-50' : ''}`}>
             <div className="absolute top-0 left-0 w-full opacity-30 pointer-events-none" 
                  style={{ 
                      height: '4px', 
                      background: `linear-gradient(90deg, transparent, ${getHeatmapHeight(date)} === '0%' ? 'transparent' : '#ef4444')`
                  }}>
             </div>
             <div className={`absolute inset-0 pointer-events-none ${getHeatmapColor(date)}`}></div>

            <div className="relative z-10">
                <div className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-1">{daysOfWeek[date.getDay()]}</div>
                <div className={`text-xl font-medium ${isSameDay(date, new Date()) ? 'text-indigo-600' : 'text-gray-900'}`}>
                {date.getDate()}
                </div>
            </div>
          </div>
        ))}
      </div>

      {/* Grid */}
      <div className="flex-1 overflow-y-auto relative custom-scrollbar">
        <div className="grid grid-cols-8 min-h-[1080px]">
          {/* Time Sidebar */}
          <div className="border-r border-gray-200 bg-white">
            {hours.map(hour => (
              <div key={hour} className="h-[60px] border-b border-gray-100 text-[10px] text-gray-400 text-right pr-3 pt-2 font-mono">
                 {formatHour(hour)}
              </div>
            ))}
          </div>

          {/* Days Columns */}
          {weekDates.map((date, colIndex) => {
            const dayEvents = events.filter(e => isSameDay(e.start, date));
            const isToday = isSameDay(date, now);

            return (
              <div 
                key={colIndex} 
                className="relative border-r border-gray-200 bg-white hover:bg-gray-50 transition-colors"
                onDragOver={handleDragOver}
                onDrop={(e) => handleDrop(e, date)}
              >
                {/* Current Time Indicator Line */}
                {isToday && isTimeVisible() && (
                    <div 
                        className="absolute w-full z-30 pointer-events-none flex items-center"
                        style={{ top: `${getCurrentTimePosition()}px` }}
                    >
                        <div className="w-2 h-2 rounded-full bg-red-500 -ml-1"></div>
                        <div className="flex-1 h-[2px] bg-red-500 opacity-80"></div>
                    </div>
                )}

                {hours.map(hour => (
                  <div key={hour} className="h-[60px] border-b border-gray-100 pointer-events-none"></div>
                ))}

                {dayEvents.map(event => {
                    const styles = getEventStyle(event, colIndex);
                    if (parseInt(styles.top) + parseInt(styles.height) < 0) return null;

                    return (
                      <div
                        key={event.id}
                        draggable
                        onDragStart={(e) => handleDragStart(e, event)}
                        onClick={(e) => { e.stopPropagation(); onEventClick(event); }}
                        className={`absolute rounded px-3 py-2 text-xs cursor-pointer border-l-4 shadow-sm transition-all hover:shadow-md hover:z-20 overflow-hidden group
                            ${event.color || 'bg-gray-100 border-gray-400 text-gray-700'}`}
                        style={styles}
                      >
                        <div className="font-semibold truncate tracking-tight">{event.title}</div>
                        <div className="opacity-0 group-hover:opacity-100 transition-opacity text-[9px] mt-1 font-mono">
                          {event.start.toLocaleTimeString([], {hour: 'numeric', minute:'2-digit', hour12: true})}
                        </div>
                      </div>
                    );
                })}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

export enum EventType {
  IMPORTED = 'IMPORTED', // From ICS or external
  MANUAL = 'MANUAL',     // User manually added
  AI_WORK_SESSION = 'AI_WORK_SESSION' // Generated by Engine
}

export type Priority = 'High' | 'Medium' | 'Low';
export type EnergyLevel = 'High' | 'Low';
export type TaskCategory = 'Task' | 'Meeting' | 'Habit';

export interface CalendarEvent {
  id: string;
  title: string;
  start: Date;
  end: Date;
  type: EventType;
  description?: string;
  relatedTaskId?: string; 
  color?: string;
  priority?: Priority;
  isClass?: boolean; // New property to identify classes
}

export interface TaskFile {
  name: string;
  size: number;
  type: string;
  url?: string; 
}

export interface Task {
  id: string;
  category: TaskCategory; // New: Distinguish between types
  title: string;
  description: string;

  // -- Task Specific --
  difficulty: number; 
  totalHoursNeeded: number;
  deadline: Date;
  isCompleted?: boolean; // New status field

  // -- Habit Specific --
  recurrenceEndDate?: Date; // When the habit stops repeating

  // -- Meeting Specific --
  meetingDate?: string; // YYYY-MM-DD
  meetingStartTime?: string; // HH:mm
  meetingEndTime?: string; // HH:mm

  // -- Shared Scheduling Preferences --
  preferredDays: string[]; 
  preferredTimeStart: string; 
  preferredTimeEnd: string;
  preferredSessionDuration: number; 

  files: TaskFile[];
  isScheduled: boolean;
  priority: Priority;
  energyLevel: EnergyLevel;
}

export interface AIScheduleSuggestion {
  sessions: {
    startISO: string;
    endISO: string;
    summary: string;
    reasoning: string;
  }[];
}

export interface AIClassClassification {
  classEventIds: string[];
}

import React, { useState, useEffect } from 'react';
import { Task, CalendarEvent, Priority, TaskCategory } from '../types';

interface EventsViewProps {
  tasks: Task[];
  events: CalendarEvent[];
  onEditTask: (task: Task) => void;
  onDeleteTask: (taskId: string) => void;
  onToggleComplete: (taskId: string, isComplete: boolean) => void;
}

export const EventsView: React.FC<EventsViewProps> = ({ tasks, events, onEditTask, onDeleteTask, onToggleComplete }) => {
  const [now, setNow] = useState(new Date());
  const [filter, setFilter] = useState<TaskCategory | 'All'>('All');

  useEffect(() => {
    const interval = setInterval(() => {
        setNow(new Date());
    }, 60000); 
    return () => clearInterval(interval);
  }, []);

  const getProgress = (task: Task) => {
    // If explicitly marked complete, return 100%
    if (task.isCompleted) {
        return {
            completed: task.totalHoursNeeded,
            scheduledFuture: 0,
            totalNeeded: task.totalHoursNeeded,
            percentCompleted: 100,
            percentScheduled: 0
        };
    }

    // If it's a meeting, it's binary: passed or not
    if (task.category === 'Meeting') {
        const start = new Date(`${task.meetingDate}T${task.meetingStartTime}`);
        const end = new Date(`${task.meetingDate}T${task.meetingEndTime}`);
        const isDone = now > end;
        return {
            completed: isDone ? 1 : 0,
            scheduledFuture: isDone ? 0 : 1,
            totalNeeded: 1,
            percentCompleted: isDone ? 100 : 0,
            percentScheduled: isDone ? 0 : 100
        };
    }

    const taskEvents = events.filter(e => e.relatedTaskId === task.id);
    let totalScheduledHours = 0;
    let completedHours = 0;

    taskEvents.forEach(e => {
        const durationHours = (e.end.getTime() - e.start.getTime()) / (1000 * 60 * 60);
        totalScheduledHours += durationHours;

        if (now >= e.end) {
            completedHours += durationHours;
        } else if (now > e.start) {
            const passedMs = now.getTime() - e.start.getTime();
            completedHours += passedMs / (1000 * 60 * 60);
        }
    });

    const denominator = task.category === 'Task' ? task.totalHoursNeeded : totalScheduledHours || 1;

    return {
        completed: completedHours,
        scheduledFuture: Math.max(0, totalScheduledHours - completedHours),
        totalNeeded: task.category === 'Task' ? task.totalHoursNeeded : totalScheduledHours,
        percentCompleted: Math.min(100, (completedHours / denominator) * 100),
        percentScheduled: Math.min(100, ((totalScheduledHours - completedHours) / denominator) * 100)
    };
  };

  const getPriorityColor = (p: Priority) => {
    switch(p) {
        case 'High': return 'text-red-700 bg-red-50 border-red-200';
        case 'Medium': return 'text-amber-700 bg-amber-50 border-amber-200';
        case 'Low': return 'text-emerald-700 bg-emerald-50 border-emerald-200';
        default: return 'text-gray-700 bg-gray-50';
    }
  };

  const filteredTasks = filter === 'All' ? tasks : tasks.filter(t => t.category === filter);

  if (tasks.length === 0) {
      return (
          <div className="flex flex-col items-center justify-center h-full py-20 text-center">
              <div className="bg-gray-100 p-6 rounded-full mb-4">
                  <span className="text-4xl">📅</span>
              </div>
              <h3 className="text-lg font-bold text-gray-900">No Events Yet</h3>
              <p className="text-gray-500 max-w-sm mt-2 mb-6">Create Tasks, Meetings, or Habits to fill your schedule.</p>
          </div>
      );
  }

  return (
    <div className="space-y-6">
      {/* Filter Tabs */}
      <div className="flex space-x-2 border-b border-gray-200 pb-1">
          {(['All', 'Task', 'Meeting', 'Habit'] as const).map(cat => (
              <button
                key={cat}
                onClick={() => setFilter(cat)}
                className={`px-4 py-2 text-sm font-medium rounded-t-lg transition-colors ${
                    filter === cat 
                    ? 'bg-white text-indigo-600 border border-b-0 border-gray-200 shadow-sm' 
                    : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'
                }`}
              >
                  {cat === 'All' ? 'All Events' : `${cat}s`}
              </button>
          ))}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredTasks.map(task => {
            const stats = getProgress(task);
            const isOverdue = !task.isCompleted && task.category === 'Task' && now > task.deadline && stats.percentCompleted < 100;
            const totalPlanned = stats.completed + stats.scheduledFuture;

            return (
                <div 
                    key={task.id} 
                    className={`bg-white rounded-xl border transition-all p-5 flex flex-col relative overflow-hidden group
                        ${task.isCompleted ? 'border-green-200 bg-green-50/30' : 'border-gray-200 shadow-sm hover:shadow-md'}
                    `}
                >
                    {/* Category Badge Stripe */}
                    <div className={`absolute top-0 left-0 w-1 h-full ${
                        task.isCompleted ? 'bg-green-500' :
                        task.category === 'Meeting' ? 'bg-purple-500' :
                        task.category === 'Habit' ? 'bg-teal-500' : 'bg-indigo-500'
                    }`}></div>

                    <div className="flex justify-between items-start mb-3 pl-3">
                        <div className="flex flex-col">
                            <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider mb-1">{task.category}</span>
                            {task.isCompleted ? (
                                <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider border bg-green-100 text-green-700 border-green-200 w-fit">
                                    Completed
                                </span>
                            ) : (
                                <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider border w-fit ${getPriorityColor(task.priority)}`}>
                                    {task.priority}
                                </span>
                            )}
                        </div>
                        <div className="flex gap-2">
                             {!task.isCompleted && (
                                <button 
                                    onClick={() => onEditTask(task)}
                                    className="text-gray-400 hover:text-indigo-600 transition-colors"
                                >
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                                    </svg>
                                </button>
                             )}
                             <button 
                                onClick={() => {
                                    if(confirm('Are you sure you want to delete this?')) {
                                        onDeleteTask(task.id);
                                    }
                                }}
                                className="text-gray-400 hover:text-red-600 transition-colors"
                             >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                </svg>
                             </button>
                        </div>
                    </div>

                    <h3 className={`text-lg font-bold mb-1 leading-tight pl-3 ${task.isCompleted ? 'text-gray-500 line-through' : 'text-gray-900'}`}>
                        {task.title}
                    </h3>

                    <div className="pl-3 mb-4">
                        {task.category === 'Task' && (
                            <div className="text-xs text-gray-500 flex items-center">
                                <span className="mr-2">📅 Due:</span> 
                                <span className={`font-medium ${isOverdue ? 'text-red-600' : 'text-gray-700'}`}>
                                    {task.deadline.toLocaleDateString(undefined, {month:'short', day:'numeric'})}
                                </span>
                            </div>
                        )}
                        {task.category === 'Meeting' && (
                             <div className="text-xs text-gray-500 flex items-center">
                                <span className="mr-2">🕒 Time:</span> 
                                <span className="font-medium text-gray-700">
                                    {task.meetingDate} @ {task.meetingStartTime}
                                </span>
                            </div>
                        )}
                        {task.category === 'Habit' && (
                             <div className="text-xs text-gray-500 flex items-center">
                                <span className="mr-2">🔁 Repeats:</span> 
                                <span className="font-medium text-gray-700">
                                    {task.preferredDays.map(d => d.slice(0,3)).join(', ')}
                                </span>
                            </div>
                        )}
                    </div>

                    {task.description && (
                        <p className={`text-xs mb-4 line-clamp-2 pl-3 ${task.isCompleted ? 'text-gray-400' : 'text-gray-600'}`}>
                            {task.description}
                        </p>
                    )}

                    <div className="mt-auto pl-3">
                        {task.category !== 'Meeting' && (
                        <>
                            <div className="flex justify-between items-end mb-1">
                                <span className="text-xs font-medium text-gray-500">
                                    {stats.completed.toFixed(1)} hrs done
                                </span>
                                <span className="text-xs font-bold text-gray-700">
                                    {totalPlanned.toFixed(1)} hrs planned
                                </span>
                            </div>

                            <div className="w-full bg-gray-100 rounded-full h-2.5 overflow-hidden flex">
                                <div 
                                    className="h-full bg-emerald-500 transition-all duration-500"
                                    style={{ width: `${stats.percentCompleted}%` }}
                                ></div>
                                {!task.isCompleted && (
                                    <div 
                                        className="h-full bg-indigo-400 transition-all duration-500 opacity-60"
                                        style={{ width: `${stats.percentScheduled}%` }}
                                    ></div>
                                )}
                            </div>
                        </>
                        )}

                        <div className="mt-4 flex items-center justify-between">
                             {task.files.length > 0 ? (
                                <div className="text-[10px] bg-gray-50 border border-gray-200 px-2 py-1 rounded text-gray-600 flex items-center">
                                    📎 {task.files.length} Materials
                                </div>
                             ) : <div></div>}

                             {/* Mark as Complete Button for Tasks */}
                             {task.category === 'Task' && (
                                 <button
                                    onClick={() => onToggleComplete(task.id, !task.isCompleted)}
                                    className={`text-xs px-3 py-1.5 rounded-full font-medium transition-colors border flex items-center gap-1 ${
                                        task.isCompleted 
                                        ? 'bg-white border-gray-300 text-gray-500 hover:bg-gray-50' 
                                        : 'bg-indigo-50 border-indigo-200 text-indigo-700 hover:bg-indigo-100'
                                    }`}
                                 >
                                    {task.isCompleted ? (
                                        <>↩ Undo Complete</>
                                    ) : (
                                        <>✓ Mark Complete</>
                                    )}
                                 </button>
                             )}
                        </div>
                    </div>
                </div>
            );
        })}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Calendar } from './components/Calendar';
import { TaskForm } from './components/TaskForm';
import { ImportModal } from './components/ImportModal';
import { EventDetailsModal } from './components/EventDetailsModal';
import { EventsView } from './components/EventsView';
import { Button } from './components/Button';
import { scheduleTasks } from './services/scheduler';
import { identifyClasses, analyzeTaskSemantics } from './services/geminiService';
import { CalendarEvent, Task, EventType } from './types';

function App() {
  const [view, setView] = useState<'calendar' | 'events' | 'newEvent' | 'editEvent'>('calendar');
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const [currentDate, setCurrentDate] = useState(new Date());

  const handleNavigate = (direction: 'prev' | 'next' | 'today') => {
    const newDate = new Date(currentDate);
    if (direction === 'today') {
      setCurrentDate(new Date());
    } else if (direction === 'next') {
      newDate.setDate(newDate.getDate() + 7);
      setCurrentDate(newDate);
    } else {
      newDate.setDate(newDate.getDate() - 7);
      setCurrentDate(newDate);
    }
  };

  const runGlobalScheduler = (fixedEvents: CalendarEvent[], currentTasks: Task[]) => {
    // Only AI Work Sessions that haven't been manually moved (conceptually) are re-scheduled.
    // However, if a task is marked completed, it's filtered out before it gets here or handled by not being in 'currentTasks' effectively?
    // Actually simpler: scheduleTasks ignores completed tasks if we filter or we can update scheduleTasks to ignore them.
    // But better to just manage the event list directly when toggling.
    const cleanFixedEvents = fixedEvents.filter(e => e.type !== EventType.AI_WORK_SESSION);
    const activeTasks = currentTasks.filter(t => !t.isCompleted); // Only schedule active tasks
    const newSessions = scheduleTasks(cleanFixedEvents, activeTasks);
    return [...cleanFixedEvents, ...newSessions];
  };

  const handleImport = async (importedEvents: CalendarEvent[]) => {
    setIsImportModalOpen(false);
    setIsProcessing(true);
    try {
      const classIds = await identifyClasses(importedEvents);
      const taggedEvents = importedEvents.map(e => ({
        ...e,
        isClass: classIds.includes(e.id),
        color: classIds.includes(e.id) ? "bg-blue-50 border-blue-200 text-blue-700" : e.color
      }));

      const existingFixed = events.filter(e => e.type !== EventType.AI_WORK_SESSION);
      const allFixedEvents = [...existingFixed, ...taggedEvents];
      const optimizedSchedule = runGlobalScheduler(allFixedEvents, tasks);
      setEvents(optimizedSchedule);
    } catch (error) {
      console.error("Import error:", error);
      alert("Error processing schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCreateOrUpdateTask = async (taskInput: Task) => {
    setIsProcessing(true);
    try {
      let task = { ...taskInput };

      // AI Analysis only for flexible Tasks
      if (task.category === 'Task') {
          const aiAnalysis = await analyzeTaskSemantics(task.title, task.description);
          task.energyLevel = aiAnalysis.energyLevel;
      }

      let updatedTasks;
      const isUpdate = tasks.some(t => t.id === task.id);

      let newManualEvent: CalendarEvent | null = null;
      if (task.category === 'Meeting' && task.meetingDate && task.meetingStartTime && task.meetingEndTime) {
         const start = new Date(`${task.meetingDate}T${task.meetingStartTime}`);
         const end = new Date(`${task.meetingDate}T${task.meetingEndTime}`);
         newManualEvent = {
             id: `meeting-${task.id}`,
             title: task.title,
             start,
             end,
             type: EventType.MANUAL,
             relatedTaskId: task.id,
             color: "bg-purple-50 border-purple-200 text-purple-700",
             description: task.description
         };
         task.isScheduled = true; 
      } else {
         task.isScheduled = true; 
      }

      if (isUpdate) {
        updatedTasks = tasks.map(t => t.id === task.id ? task : t);
      } else {
        updatedTasks = [...tasks, task];
      }

      let currentEvents = events.filter(e => e.relatedTaskId !== task.id || e.type !== EventType.AI_WORK_SESSION);

      if (newManualEvent) {
          currentEvents = currentEvents.filter(e => e.relatedTaskId !== task.id);
          currentEvents.push(newManualEvent);
      }

      const fixedEvents = currentEvents.filter(e => e.type !== EventType.AI_WORK_SESSION);
      const optimizedSchedule = runGlobalScheduler(fixedEvents, updatedTasks);

      setEvents(optimizedSchedule);
      setTasks(updatedTasks);
      setView('calendar');
      setEditingTask(null);

    } catch (error) {
      console.error(error);
      alert("Error generating schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDeleteEvent = (id: string) => {
    const eventToDelete = events.find(e => e.id === id);
    if (!eventToDelete) return;

    if (eventToDelete.type === EventType.AI_WORK_SESSION) {
        setEvents(prev => prev.filter(e => e.id !== id));
    } else {
        const remainingFixed = events.filter(e => e.id !== id && e.type !== EventType.AI_WORK_SESSION);
        const optimizedSchedule = runGlobalScheduler(remainingFixed, tasks);
        setEvents(optimizedSchedule);
    }
  };

  const handleDeleteTask = (taskId: string) => {
      const updatedTasks = tasks.filter(t => t.id !== taskId);
      setTasks(updatedTasks);
      const remainingEvents = events.filter(e => e.relatedTaskId !== taskId);
      const fixedEvents = remainingEvents.filter(e => e.type !== EventType.AI_WORK_SESSION);
      const optimizedSchedule = runGlobalScheduler(fixedEvents, updatedTasks);
      setEvents(optimizedSchedule);
  };

  const handleUpdateEvent = (updatedEvent: CalendarEvent) => {
    const finalEvent = {
        ...updatedEvent,
        type: updatedEvent.type === EventType.AI_WORK_SESSION ? EventType.MANUAL : updatedEvent.type,
    };
    setEvents(prevEvents => {
        const otherEvents = prevEvents.filter(e => e.id !== updatedEvent.id);
        const newEventList = [...otherEvents, finalEvent];
        return newEventList;
    });
  };

  const handleToggleTaskComplete = (taskId: string, isComplete: boolean) => {
      // 1. Update Task State
      const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, isCompleted: isComplete } : t);
      setTasks(updatedTasks);

      if (isComplete) {
          // 2. Remove future AI sessions for this task
          const now = new Date();
          const updatedEvents = events.filter(e => {
              // If event belongs to this task, is AI generated, and is in the future => REMOVE it
              if (e.relatedTaskId === taskId && e.type === EventType.AI_WORK_SESSION && e.start > now) {
                  return false; 
              }
              return true;
          });
          setEvents(updatedEvents);
      } else {
          // If un-completing, we don't automatically reschedule to avoid jarring UI shifts. 
          // The user can edit the task to re-trigger scheduling if needed, or we could run scheduler here.
          // For now, simple state toggle.
      }
  };

  const selectedTask = selectedEvent?.relatedTaskId 
    ? tasks.find(t => t.id === selectedEvent.relatedTaskId) 
    : undefined;

  return (
    <div className="min-h-screen flex flex-col relative bg-gray-50 text-gray-900 font-sans">
      <nav className="border-b border-gray-200 bg-white sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <span className="bg-indigo-600 text-white p-1.5 rounded mr-3 font-bold">SP</span>
              <h1 className="text-xl font-bold tracking-tight text-gray-900 hidden sm:block">SparkPlan AI</h1>

              <div className="ml-8 flex space-x-1">
                 <button 
                    onClick={() => setView('calendar')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'calendar' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Calendar
                 </button>
                 <button 
                    onClick={() => setView('events')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'events' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Events
                 </button>
              </div>
            </div>
            <div className="flex items-center space-x-4">
              <Button variant="ghost" onClick={() => setIsImportModalOpen(true)}>Import</Button>
              <Button onClick={() => { setEditingTask(null); setView('newEvent'); }} disabled={view === 'newEvent'}>
                + New Event
              </Button>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {view === 'calendar' && (
          <>
            <div className="mb-6 flex items-center justify-between">
              <div>
                <h2 className="text-xl font-bold text-gray-900 tracking-tight">Dashboard</h2>
                <p className="text-sm text-gray-500 mt-1">
                  {events.filter(e => e.type === EventType.AI_WORK_SESSION).length} active work sessions.
                </p>
              </div>
              <div className="flex gap-4 text-xs font-medium text-gray-600">
                 <div className="flex items-center"><div className="w-2 h-2 bg-blue-400 rounded-full mr-2"></div> Class</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-purple-400 rounded-full mr-2"></div> Meeting</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-teal-400 rounded-full mr-2"></div> Habit</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-indigo-600 rounded-full mr-2"></div> Task</div>
              </div>
            </div>
            <div className="h-[calc(100vh-200px)]">
               <Calendar 
                  events={events} 
                  currentDate={currentDate} 
                  onEventClick={setSelectedEvent}
                  onNavigate={handleNavigate}
                  onEventUpdate={handleUpdateEvent}
               />
            </div>
          </>
        )}

        {view === 'events' && (
            <EventsView 
                tasks={tasks} 
                events={events}
                onEditTask={(task) => {
                    setEditingTask(task);
                    setView('editEvent');
                }}
                onDeleteTask={handleDeleteTask}
                onToggleComplete={handleToggleTaskComplete}
            />
        )}

        {(view === 'newEvent' || view === 'editEvent') && (
          <div className="py-8">
            <TaskForm 
              initialTask={editingTask}
              onSubmit={handleCreateOrUpdateTask} 
              onCancel={() => {
                  setEditingTask(null);
                  setView('calendar');
              }} 
            />
          </div>
        )}
      </main>

      <ImportModal 
        isOpen={isImportModalOpen} 
        onClose={() => setIsImportModalOpen(false)} 
        onImport={handleImport} 
      />

      <EventDetailsModal 
        event={selectedEvent} 
        relatedTask={selectedTask}
        onClose={() => setSelectedEvent(null)}
        onDelete={handleDeleteEvent}
        onUpdate={handleUpdateEvent}
      />

      {isProcessing && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-900 bg-opacity-50 backdrop-blur-sm transition-opacity">
            <div className="flex flex-col items-center p-6 bg-white rounded-lg shadow-xl">
                <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
                <h3 className="text-lg font-bold text-gray-900 tracking-widest uppercase">Scheduling</h3>
                <p className="text-xs text-gray-500 mt-2">Balancing Tasks, Habits & Meetings...</p>
            </div>
        </div>
      )}

    </div>
  );
}

export default App;

