            <Button variant="ghost" type="button" onClick={onCancel}>Cancel</Button>
            <Button type="submit" isLoading={isSubmitting}>
                {isEditing ? 'Save Changes' : `Add ${category}`}
            </Button>
        </div>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { Calendar } from './components/Calendar';
import { TaskForm } from './components/TaskForm';
import { ImportModal } from './components/ImportModal';
import { EventDetailsModal } from './components/EventDetailsModal';
import { EventsView } from './components/EventsView';
import { Button } from './components/Button';
import { scheduleTasks } from './services/scheduler';
import { identifyClasses, analyzeTaskSemantics } from './services/geminiService';
import { CalendarEvent, Task, EventType } from './types';

function App() {
  const [view, setView] = useState<'calendar' | 'events' | 'newEvent' | 'editEvent'>('calendar');
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const [currentDate, setCurrentDate] = useState(new Date());

  const handleNavigate = (direction: 'prev' | 'next' | 'today') => {
    const newDate = new Date(currentDate);
    if (direction === 'today') {
      setCurrentDate(new Date());
    } else if (direction === 'next') {
      newDate.setDate(newDate.getDate() + 7);
      setCurrentDate(newDate);
    } else {
      newDate.setDate(newDate.getDate() - 7);
      setCurrentDate(newDate);
    }
  };

  // Helper: Re-runs the AI Scheduler
  // Preserves: Manual Events, Imported Events, and PAST AI Work Sessions (History)
  // Regenerates: FUTURE AI Work Sessions for active tasks
  const runGlobalScheduler = (currentEvents: CalendarEvent[], currentTasks: Task[]) => {
    const now = new Date();

    // 1. Keep non-AI events (Fixed)
    // 2. Keep AI events that have already ended (History)
    const preservedEvents = currentEvents.filter(e => 
        e.type !== EventType.AI_WORK_SESSION || e.end <= now
    );

    // 3. Identify tasks that need scheduling (Not completed)
    const activeTasks = currentTasks.filter(t => !t.isCompleted); 

    // 4. Generate new future sessions
    const newSessions = scheduleTasks(preservedEvents, activeTasks);

    return [...preservedEvents, ...newSessions];
  };

  const handleImport = async (importedEvents: CalendarEvent[]) => {
    setIsImportModalOpen(false);
    setIsProcessing(true);
    try {
      const classIds = await identifyClasses(importedEvents);
      const taggedEvents = importedEvents.map(e => ({
        ...e,
        isClass: classIds.includes(e.id),
        color: classIds.includes(e.id) ? "bg-blue-50 border-blue-200 text-blue-700" : e.color
      }));

      // Combine existing events with new imported ones, then reschedule
      const allEvents = [...events, ...taggedEvents];
      const optimizedSchedule = runGlobalScheduler(allEvents, tasks);
      setEvents(optimizedSchedule);
    } catch (error) {
      console.error("Import error:", error);
      alert("Error processing schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCreateOrUpdateTask = async (taskInput: Task) => {
    setIsProcessing(true);
    try {
      let task = { ...taskInput };

      // AI Analysis only for flexible Tasks
      if (task.category === 'Task') {
          const aiAnalysis = await analyzeTaskSemantics(task.title, task.description);
          task.energyLevel = aiAnalysis.energyLevel;
      }

      let updatedTasks;
      const isUpdate = tasks.some(t => t.id === task.id);

      let newManualEvent: CalendarEvent | null = null;
      // Only create manual event if user opted in via 'isScheduled'
      if (task.category === 'Meeting' && task.meetingDate && task.meetingStartTime && task.meetingEndTime && task.isScheduled) {
         const start = new Date(`${task.meetingDate}T${task.meetingStartTime}`);
         const end = new Date(`${task.meetingDate}T${task.meetingEndTime}`);
         newManualEvent = {
             id: `meeting-${task.id}`,
             title: task.title,
             start,
             end,
             type: EventType.MANUAL,
             relatedTaskId: task.id,
             color: "bg-purple-50 border-purple-200 text-purple-700",
             description: task.description
         };
      }

      if (isUpdate) {
        updatedTasks = tasks.map(t => t.id === task.id ? task : t);
      } else {
        updatedTasks = [...tasks, task];
      }

      // If updating, remove old FUTURE sessions for this specific task before rescheduling
      // to allow the scheduler to start fresh for this task.
      const now = new Date();
      let currentEvents = events.filter(e => {
          if (e.relatedTaskId === task.id) {
              // If it's AI session in future, remove it. 
              // If it's manual (meeting), remove it (we re-add below).
              // If it's past AI session, keep it (history).
              if (e.type === EventType.AI_WORK_SESSION && e.end <= now) return true;
              return false;
          }
          return true;
      });

      if (newManualEvent) {
          currentEvents.push(newManualEvent);
      }

      const optimizedSchedule = runGlobalScheduler(currentEvents, updatedTasks);

      setEvents(optimizedSchedule);
      setTasks(updatedTasks);
      setView('calendar');
      setEditingTask(null);

    } catch (error) {
      console.error(error);
      alert("Error generating schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDeleteEvent = (id: string) => {
    const eventToDelete = events.find(e => e.id === id);
    if (!eventToDelete) return;

    if (eventToDelete.type === EventType.AI_WORK_SESSION) {
        // Just delete the single session
        setEvents(prev => prev.filter(e => e.id !== id));
    } else {
        // If deleting a fixed event, we need to re-shuffle flexible tasks to fill the gap
        const remainingEvents = events.filter(e => e.id !== id);
        const optimizedSchedule = runGlobalScheduler(remainingEvents, tasks);
        setEvents(optimizedSchedule);
    }
  };

  const handleDeleteTask = (taskId: string) => {
      const updatedTasks = tasks.filter(t => t.id !== taskId);
      setTasks(updatedTasks);

      // Remove all events related to this task
      const remainingEvents = events.filter(e => e.relatedTaskId !== taskId);

      // Reschedule remaining tasks (in case gaps opened up)
      const optimizedSchedule = runGlobalScheduler(remainingEvents, updatedTasks);
      setEvents(optimizedSchedule);
  };

  const handleUpdateEvent = (updatedEvent: CalendarEvent) => {
    const finalEvent = {
        ...updatedEvent,
        type: updatedEvent.type === EventType.AI_WORK_SESSION ? EventType.MANUAL : updatedEvent.type,
    };
    setEvents(prevEvents => {
        const otherEvents = prevEvents.filter(e => e.id !== updatedEvent.id);
        const newEventList = [...otherEvents, finalEvent];
        return newEventList;
    });
  };

  const handleToggleTaskComplete = (taskId: string, isComplete: boolean) => {
      // 1. Update Task State
      const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, isCompleted: isComplete } : t);
      setTasks(updatedTasks);

      if (isComplete) {
          // 2. Completed: Remove FUTURE AI sessions for this task
          const now = new Date();
          const updatedEvents = events.filter(e => {
              if (e.relatedTaskId === taskId && e.type === EventType.AI_WORK_SESSION && e.start > now) {
                  return false; 
              }
              return true;
          });
          setEvents(updatedEvents);
      } else {
          // 3. Undo Complete: Re-activate and Schedule
          // runGlobalScheduler will see this task is no longer 'isCompleted', 
          // and will generate new sessions for it.
          const optimizedSchedule = runGlobalScheduler(events, updatedTasks);
          setEvents(optimizedSchedule);
      }
  };

  const handleCalendarSlotClick = (date: Date) => {
      const startStr = date.toTimeString().slice(0, 5); // HH:mm
      const end = new Date(date.getTime() + 60*60*1000); // +1 hour
      const endStr = end.toTimeString().slice(0, 5);

      const pad = (n: number) => n < 10 ? '0'+n : n;
      const dateStr = `${date.getFullYear()}-${pad(date.getMonth()+1)}-${pad(date.getDate())}`;

      // Create a "Draft" task with default values based on the click
      const draftTask: Task = {
          id: '', // Empty ID indicates new
          category: 'Meeting', // Default to meeting for calendar clicks
          title: '',
          description: '',
          priority: 'Medium',
          files: [],
          difficulty: 5,
          totalHoursNeeded: 2,
          deadline: new Date(date.getTime() + 7*24*60*60*1000), // Default deadline +1 week
          energyLevel: 'High',
          // Meeting specific defaults
          meetingDate: dateStr,
          meetingStartTime: startStr,
          meetingEndTime: endStr,
          // Shared
          preferredDays: [],
          preferredTimeStart: '09:00',
          preferredTimeEnd: '17:00',
          preferredSessionDuration: 1,
          isScheduled: false // Per user request: Default to no auto assign
      };

      setEditingTask(draftTask);
      setView('newEvent');
  };

  const selectedTask = selectedEvent?.relatedTaskId 
    ? tasks.find(t => t.id === selectedEvent.relatedTaskId) 
    : undefined;

  return (
    <div className="min-h-screen flex flex-col relative bg-gray-50 text-gray-900 font-sans">
      <nav className="border-b border-gray-200 bg-white sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <span className="bg-indigo-600 text-white p-1.5 rounded mr-3 font-bold">SP</span>
              <h1 className="text-xl font-bold tracking-tight text-gray-900 hidden sm:block">SparkPlan AI</h1>

              <div className="ml-8 flex space-x-1">
                 <button 
                    onClick={() => setView('calendar')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'calendar' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Calendar
                 </button>
                 <button 
                    onClick={() => setView('events')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'events' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Events
                 </button>
              </div>
            </div>
            <div className="flex items-center space-x-4">
              <Button variant="ghost" onClick={() => setIsImportModalOpen(true)}>Import</Button>
              <Button onClick={() => { setEditingTask(null); setView('newEvent'); }} disabled={view === 'newEvent'}>
                + New Event
              </Button>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {view === 'calendar' && (
          <>
            <div className="mb-6 flex items-center justify-between">
              <div>
                <h2 className="text-xl font-bold text-gray-900 tracking-tight">Dashboard</h2>
                <p className="text-sm text-gray-500 mt-1">
                  {events.filter(e => e.type === EventType.AI_WORK_SESSION).length} active work sessions.
                </p>
              </div>
              <div className="flex gap-4 text-xs font-medium text-gray-600">
                 <div className="flex items-center"><div className="w-2 h-2 bg-blue-400 rounded-full mr-2"></div> Class</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-purple-400 rounded-full mr-2"></div> Meeting</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-teal-400 rounded-full mr-2"></div> Habit</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-indigo-600 rounded-full mr-2"></div> Task</div>
              </div>
            </div>
            <div className="h-[calc(100vh-200px)]">
               <Calendar 
                  events={events} 
                  currentDate={currentDate} 
                  onEventClick={setSelectedEvent}
                  onNavigate={handleNavigate}
                  onEventUpdate={handleUpdateEvent}
                  onSlotClick={handleCalendarSlotClick}
               />
            </div>
          </>
        )}

        {view === 'events' && (
            <EventsView 
                tasks={tasks} 
                events={events}
                onEditTask={(task) => {
                    setEditingTask(task);
                    setView('editEvent');
                }}
                onDeleteTask={handleDeleteTask}
                onToggleComplete={handleToggleTaskComplete}
            />
        )}

        {(view === 'newEvent' || view === 'editEvent') && (
          <div className="py-8">
            <TaskForm 
              initialTask={editingTask}
              onSubmit={handleCreateOrUpdateTask} 
              onCancel={() => {
                  setEditingTask(null);
                  setView('calendar');
              }} 
            />
          </div>
        )}
      </main>

      <ImportModal 
        isOpen={isImportModalOpen} 
        onClose={() => setIsImportModalOpen(false)} 
        onImport={handleImport} 
      />

      <EventDetailsModal 
        event={selectedEvent} 
        relatedTask={selectedTask}
        onClose={() => setSelectedEvent(null)}
        onDelete={handleDeleteEvent}
        onUpdate={handleUpdateEvent}
      />

      {isProcessing && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-900 bg-opacity-50 backdrop-blur-sm transition-opacity">
            <div className="flex flex-col items-center p-6 bg-white rounded-lg shadow-xl">
                <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
                <h3 className="text-lg font-bold text-gray-900 tracking-widest uppercase">Scheduling</h3>
                <p className="text-xs text-gray-500 mt-2">Balancing Tasks, Habits & Meetings...</p>
            </div>
        </div>
      )}

    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { Task, TaskFile, Priority, EnergyLevel, TaskCategory } from '../types';
import { Button } from './Button';

interface TaskFormProps {
  initialTask?: Task | null;
  onSubmit: (task: Task) => Promise<void>;
  onCancel: () => void;
}

const DAYS_OF_WEEK = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"];

export const TaskForm: React.FC<TaskFormProps> = ({ initialTask, onSubmit, onCancel }) => {
  // Mode Selection
  const [category, setCategory] = useState<TaskCategory>('Task');

  // Common Fields
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [priority, setPriority] = useState<Priority>('Medium');
  const [files, setFiles] = useState<TaskFile[]>([]);

  // Task Specific
  const [deadline, setDeadline] = useState("");
  const [totalHours, setTotalHours] = useState(2);
  const [energyLevel, setEnergyLevel] = useState<EnergyLevel>('High');

  // Meeting Specific
  const [meetingDate, setMeetingDate] = useState("");
  const [meetingStart, setMeetingStart] = useState("09:00");
  const [meetingEnd, setMeetingEnd] = useState("10:00");

  // Habit Specific
  const [recurrenceEndDate, setRecurrenceEndDate] = useState("");

  // Scheduling Preferences (Shared by Task & Habit)
  const [sessionDuration, setSessionDuration] = useState(1.0);
  const [selectedDays, setSelectedDays] = useState<string[]>([]);
  const [preferredTimeStart, setPreferredTimeStart] = useState("09:00");
  const [preferredTimeEnd, setPreferredTimeEnd] = useState("22:00");

  // New: Auto-Assign / Scheduled state
  const [isScheduled, setIsScheduled] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    if (initialTask) {
        setCategory(initialTask.category);
        setTitle(initialTask.title);
        setDescription(initialTask.description);
        setPriority(initialTask.priority);
        setFiles(initialTask.files);
        setEnergyLevel(initialTask.energyLevel);
        setIsScheduled(initialTask.isScheduled);

        if (initialTask.category === 'Task') {
            setTotalHours(initialTask.totalHoursNeeded);
            const d = new Date(initialTask.deadline);
            // Handle invalid date in template
            if (!isNaN(d.getTime())) {
                const pad = (n: number) => n < 10 ? '0'+n : n;
                setDeadline(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`);
            }
        } else if (initialTask.category === 'Meeting') {
             setMeetingDate(initialTask.meetingDate || "");
             setMeetingStart(initialTask.meetingStartTime || "09:00");
             setMeetingEnd(initialTask.meetingEndTime || "10:00");
        } else if (initialTask.category === 'Habit') {
             if (initialTask.recurrenceEndDate) {
                const d = new Date(initialTask.recurrenceEndDate);
                if (!isNaN(d.getTime())) {
                    const pad = (n: number) => n < 10 ? '0'+n : n;
                    setRecurrenceEndDate(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`);
                }
             }
        }

        // Shared
        setSessionDuration(initialTask.preferredSessionDuration || 1.0);
        setSelectedDays(initialTask.preferredDays || []);
        setPreferredTimeStart(initialTask.preferredTimeStart || "09:00");
        setPreferredTimeEnd(initialTask.preferredTimeEnd || "22:00");
    } else {
        // Defaults if no task provided
        const tomorrow = new Date();
        tomorrow.setDate(tomorrow.getDate() + 1);
        tomorrow.setHours(17,0,0,0);
        setIsScheduled(false); // Default to NO auto assign
    }
  }, [initialTask]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: TaskFile[] = Array.from(e.target.files).map(f => ({
        name: f.name,
        size: f.size,
        type: f.type,
        url: URL.createObjectURL(f) 
      }));
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const toggleDay = (day: string) => {
    setSelectedDays(prev => 
      prev.includes(day) ? prev.filter(d => d !== day) : [...prev, day]
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    // Validation
    if (category === 'Task' && !deadline) { alert("Deadline required"); setIsSubmitting(false); return; }
    if (category === 'Meeting' && (!meetingDate || !meetingStart || !meetingEnd)) { alert("Meeting details required"); setIsSubmitting(false); return; }
    if (category === 'Habit' && selectedDays.length === 0) { alert("Select days for habit"); setIsSubmitting(false); return; }

    const taskToSave: Task = {
      // If initialTask has an ID, keep it. Otherwise (new or template), generate new UUID.
      id: (initialTask && initialTask.id) ? initialTask.id : crypto.randomUUID(),
      category,
      title,
      description,
      priority,
      files,
      // Task fields
      difficulty: 5,
      totalHoursNeeded: totalHours,
      deadline: deadline ? new Date(deadline) : new Date(new Date().setFullYear(new Date().getFullYear() + 1)),
      energyLevel,
      // Habit fields
      recurrenceEndDate: recurrenceEndDate ? new Date(recurrenceEndDate) : undefined,
      // Meeting fields
      meetingDate,
      meetingStartTime: meetingStart,
      meetingEndTime: meetingEnd,
      // Scheduling
      preferredDays: selectedDays.length > 0 ? selectedDays : DAYS_OF_WEEK,
      preferredTimeStart,
      preferredTimeEnd,
      preferredTimeEnd,
      preferredSessionDuration: sessionDuration,
      isScheduled: isScheduled // Use local state
    };

    try {
      await onSubmit(taskToSave);
    } catch (err) {
      console.error(err);
      alert("Failed to save.");
    } finally {
      setIsSubmitting(false);
    }
  };

  // Determine if we are editing an existing persisted task
  const isEditing = initialTask && initialTask.id !== '';

  return (
    <div className="bg-white p-6 rounded-lg shadow-xl max-w-2xl mx-auto border border-gray-200">
      <div className="mb-6">
          <h2 className="text-2xl font-bold text-gray-900 mb-4 flex items-center">
            <span className="bg-indigo-50 text-indigo-600 p-2 rounded-lg mr-3 border border-indigo-100">
                {isEditing ? '✏️' : '✦'}
            </span>
            {isEditing ? 'Edit Event' : 'New Event'}
          </h2>

          {/* Category Tabs: Show if creating new (including from template) */}
          {!isEditing && (
              <div className="flex bg-gray-100 p-1 rounded-lg mb-6">
                {(['Task', 'Meeting', 'Habit'] as TaskCategory[]).map(cat => (
                    <button
                        key={cat}
                        type="button"
                        onClick={() => setCategory(cat)}
                        className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${
                            category === cat 
                            ? 'bg-white text-indigo-600 shadow-sm' 
                            : 'text-gray-500 hover:text-gray-900'
                        }`}
                    >
                        {cat}
                    </button>
                ))}
              </div>
          )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Title & Desc */}
        <div>
            <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Title</label>
            <input 
              required
              type="text" 
              value={title}
              onChange={e => setTitle(e.target.value)}
              className="block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2.5 border bg-white text-gray-900"
              placeholder={category === 'Meeting' ? "e.g. Team Sync" : category === 'Habit' ? "e.g. Final Project" : "e.g. Final Project"}
            />
        </div>

        {/* --- MEETING FIELDS --- */}
        {category === 'Meeting' && (
             <div className="grid grid-cols-3 gap-4 bg-purple-50 p-4 rounded-lg border border-purple-100">
                <div className="col-span-1">
                    <label className="block text-xs font-semibold text-purple-800 mb-1">Date</label>
                    <input type="date" required value={meetingDate} onChange={e => setMeetingDate(e.target.value)} className="w-full text-sm p-2 rounded border-gray-300 bg-white text-gray-900 border" />
                </div>
                <div className="col-span-1">
                    <label className="block text-xs font-semibold text-purple-800 mb-1">Start</label>
                    <input type="time" required value={meetingStart} onChange={e => setMeetingStart(e.target.value)} className="w-full text-sm p-2 rounded border-gray-300 bg-white text-gray-900 border" />
                </div>
                 <div className="col-span-1">
                    <label className="block text-xs font-semibold text-purple-800 mb-1">End</label>
                    <input type="time" required value={meetingEnd} onChange={e => setMeetingEnd(e.target.value)} className="w-full text-sm p-2 rounded border-gray-300 bg-white text-gray-900 border" />
                </div>
             </div>
        )}

        {/* --- TASK FIELDS --- */}
        {category === 'Task' && (
             <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Deadline</label>
                    <input type="datetime-local" required value={deadline} onChange={e => setDeadline(e.target.value)} className="block w-full rounded-md border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 sm:text-sm" />
                 </div>
                 <div>
                     <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Total Hours</label>
                     <input type="number" min="0.5" step="0.5" value={totalHours} onChange={e => setTotalHours(parseFloat(e.target.value))} className="block w-full rounded-md border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 sm:text-sm" />
                 </div>

                 {/* Energy Level (Only relevant for flexible tasks) */}
                 <div className="col-span-2">
                     <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Best Time of Day</label>
                     <div className="flex rounded-md shadow-sm bg-gray-50 border border-gray-200 p-1">
                        {(['High', 'Low'] as EnergyLevel[]).map((e) => (
                            <button
                                key={e}
                                type="button"
                                onClick={() => setEnergyLevel(e)}
                                className={`flex-1 py-1 text-xs font-medium rounded transition-colors ${energyLevel === e ? 'bg-white text-indigo-600 shadow-sm border border-gray-100' : 'text-gray-500 hover:text-gray-700'}`}
                            >
                                {e === 'High' ? '☀️ Morning / Focus' : '🌙 Evening / Relax'}
                            </button>
                        ))}
                     </div>
                 </div>
             </div>
        )}

        {/* --- HABIT FIELDS --- */}
        {category === 'Habit' && (
             <div className="grid grid-cols-2 gap-4 bg-teal-50 p-4 rounded-lg border border-teal-100">
                <div>
                     <label className="block text-xs font-semibold text-teal-800 mb-1">Duration per session (hrs)</label>
                     <input type="number" min="0.5" step="0.5" value={sessionDuration} onChange={e => setSessionDuration(parseFloat(e.target.value))} className="w-full text-sm p-2 rounded border-gray-300 bg-white text-gray-900 border" />
                </div>
                <div>
                     <label className="block text-xs font-semibold text-teal-800 mb-1">Repeat Until</label>
                     <input type="date" value={recurrenceEndDate} onChange={e => setRecurrenceEndDate(e.target.value)} className="w-full text-sm p-2 rounded border-gray-300 bg-white text-gray-900 border" />
                </div>
             </div>
        )}

        {/* Description */}
        <div>
            <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Description</label>
            <textarea value={description} onChange={e => setDescription(e.target.value)} rows={2} className="block w-full rounded-md border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 sm:text-sm placeholder-gray-400" />
        </div>

        {/* --- SHARED: AVAILABILITY / RECURRENCE --- */}
        {category !== 'Meeting' && (
            <div className="border-t border-gray-200 pt-6">
                <h3 className="text-sm font-semibold text-gray-900 mb-4">
                    {category === 'Habit' ? 'Recurrence Pattern' : 'Availability'}
                </h3>

                <div className="flex flex-wrap gap-2 mb-4">
                    {DAYS_OF_WEEK.map(day => (
                        <button
                            key={day}
                            type="button"
                            onClick={() => toggleDay(day)}
                            className={`px-3 py-1.5 rounded text-xs font-medium border transition-colors ${
                                selectedDays.includes(day) 
                                    ? 'bg-indigo-600 text-white border-indigo-600' 
                                    : 'bg-white text-gray-500 border-gray-300 hover:border-gray-400'
                            }`}
                        >
                            {day.substring(0, 3)}
                        </button>
                    ))}
                </div>

                <div className="grid grid-cols-2 gap-6">
                    <div>
                        <label className="block text-xs text-gray-500 mb-1">Preferred Start</label>
                        <input type="time" value={preferredTimeStart} onChange={e => setPreferredTimeStart(e.target.value)} className="block w-full rounded-md border-gray-300 shadow-sm sm:text-sm p-2 border bg-white text-gray-900" />
                    </div>
                    <div>
                        <label className="block text-xs text-gray-500 mb-1">Preferred End</label>
                        <input type="time" value={preferredTimeEnd} onChange={e => setPreferredTimeEnd(e.target.value)} className="block w-full rounded-md border-gray-300 shadow-sm sm:text-sm p-2 border bg-white text-gray-900" />
                    </div>
                </div>
            </div>
        )}

        {/* Priority & Files */}
        <div className="grid grid-cols-2 gap-6 border-t border-gray-200 pt-6">
             <div>
                 <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Priority</label>
                 <div className="flex rounded-md shadow-sm bg-gray-50 border border-gray-200 p-1">
                    {(['High', 'Medium', 'Low'] as Priority[]).map((p) => {
                        let activeClass = '';
                        if (priority === p) {
                            if (p === 'High') activeClass = 'bg-white text-red-600 shadow-sm ring-1 ring-red-100 font-bold';
                            else if (p === 'Medium') activeClass = 'bg-white text-amber-600 shadow-sm ring-1 ring-amber-100 font-bold';
                            else activeClass = 'bg-white text-emerald-600 shadow-sm ring-1 ring-emerald-100 font-bold';
                        } else {
                            activeClass = 'text-gray-500 hover:text-gray-700 hover:bg-gray-100';
                        }

                        return (
                            <button
                                key={p}
                                type="button"
                                onClick={() => setPriority(p)}
                                className={`flex-1 py-2 text-xs font-medium rounded transition-all ${activeClass}`}
                            >
                                {p}
                            </button>
                        );
                    })}
                 </div>
             </div>

             <div>
                <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Materials</label>
                <label className="flex items-center justify-center w-full p-2 border border-gray-300 border-dashed rounded cursor-pointer hover:bg-gray-50">
                    <span className="text-xs text-indigo-600">+ Upload</span>
                    <input type="file" className="hidden" multiple onChange={handleFileChange} />
                </label>
             </div>
        </div>

        {/* Auto-Schedule Toggle */}
        <div className="flex items-center justify-between bg-gray-50 p-4 rounded-lg border border-gray-200 mt-6">
            <div className="flex flex-col">
                <span className="text-sm font-semibold text-gray-900">
                    {category === 'Task' || category === 'Habit' ? "Auto-Schedule" : "Add to Calendar"}
                </span>
                <span className="text-xs text-gray-500">
                    {category === 'Task' || category === 'Habit' 
                        ? "Let AI assign time slots automatically." 
                        : "Place this meeting on your schedule."}
                </span>
            </div>
            <button 
                type="button"
                onClick={() => setIsScheduled(!isScheduled)}
                className={`relative inline-flex h-6 w-11 flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out focus:outline-none ${isScheduled ? 'bg-indigo-600' : 'bg-gray-200'}`}
            >
                <span className={`pointer-events-none inline-block h-5 w-5 transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out ${isScheduled ? 'translate-x-5' : 'translate-x-0'}`} />
            </button>
        </div>

        <div className="flex justify-end gap-3 pt-4 border-t border-gray-200">
            <Button variant="ghost" type="button" onClick={onCancel}>Cancel</Button>
            <Button type="submit" isLoading={isSubmitting}>
                {isEditing ? 'Save Changes' : `Add ${category}`}
            </Button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Task, TaskFile, Priority, EnergyLevel, TaskCategory } from '../types';
import { Button } from './Button';

interface TaskFormProps {
  initialTask?: Task | null;
  onSubmit: (task: Task) => Promise<void>;
  onCancel: () => void;
}

const DAYS_OF_WEEK = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"];

export const TaskForm: React.FC<TaskFormProps> = ({ initialTask, onSubmit, onCancel }) => {
  // Mode Selection
  const [category, setCategory] = useState<TaskCategory>('Task');

  // Common Fields
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [priority, setPriority] = useState<Priority>('Medium');
  const [files, setFiles] = useState<TaskFile[]>([]);

  // Task Specific
  const [deadline, setDeadline] = useState("");
  const [totalHours, setTotalHours] = useState(2);
  const [energyLevel, setEnergyLevel] = useState<EnergyLevel>('High');

  // Meeting Specific
  const [meetingDate, setMeetingDate] = useState("");
  const [meetingStart, setMeetingStart] = useState("09:00");
  const [meetingEnd, setMeetingEnd] = useState("10:00");

  // Habit Specific
  const [recurrenceEndDate, setRecurrenceEndDate] = useState("");

  // Scheduling Preferences (Shared by Task & Habit)
  const [sessionDuration, setSessionDuration] = useState(1.0);
  const [selectedDays, setSelectedDays] = useState<string[]>([]);
  const [preferredTimeStart, setPreferredTimeStart] = useState("09:00");
  const [preferredTimeEnd, setPreferredTimeEnd] = useState("22:00");

  // New: Auto-Assign / Scheduled state
  const [isScheduled, setIsScheduled] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    if (initialTask) {
        setCategory(initialTask.category);
        setTitle(initialTask.title);
        setDescription(initialTask.description);
        setPriority(initialTask.priority);
        setFiles(initialTask.files);
        setEnergyLevel(initialTask.energyLevel);
        setIsScheduled(initialTask.isScheduled);

        if (initialTask.category === 'Task') {
            setTotalHours(initialTask.totalHoursNeeded);
            const d = new Date(initialTask.deadline);
            // Handle invalid date in template
            if (!isNaN(d.getTime())) {
                const pad = (n: number) => n < 10 ? '0'+n : n;
                setDeadline(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`);
            }
        } else if (initialTask.category === 'Meeting') {
             setMeetingDate(initialTask.meetingDate || "");
             setMeetingStart(initialTask.meetingStartTime || "09:00");
             setMeetingEnd(initialTask.meetingEndTime || "10:00");
        } else if (initialTask.category === 'Habit') {
             if (initialTask.recurrenceEndDate) {
                const d = new Date(initialTask.recurrenceEndDate);
                if (!isNaN(d.getTime())) {
                    const pad = (n: number) => n < 10 ? '0'+n : n;
                    setRecurrenceEndDate(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`);
                }
             }
        }

        // Shared
        setSessionDuration(initialTask.preferredSessionDuration || 1.0);
        setSelectedDays(initialTask.preferredDays || []);
        setPreferredTimeStart(initialTask.preferredTimeStart || "09:00");
        setPreferredTimeEnd(initialTask.preferredTimeEnd || "22:00");
    } else {
        // Defaults if no task provided
        const tomorrow = new Date();
        tomorrow.setDate(tomorrow.getDate() + 1);
        tomorrow.setHours(17,0,0,0);
        setIsScheduled(false); // Default to NO auto assign
    }
  }, [initialTask]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: TaskFile[] = Array.from(e.target.files).map(f => ({
        name: f.name,
        size: f.size,
        type: f.type,
        url: URL.createObjectURL(f) 
      }));
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const toggleDay = (day: string) => {
    setSelectedDays(prev => 
      prev.includes(day) ? prev.filter(d => d !== day) : [...prev, day]
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    // Validation
    if (category === 'Task' && !deadline) { alert("Deadline required"); setIsSubmitting(false); return; }
    if (category === 'Meeting' && (!meetingDate || !meetingStart || !meetingEnd)) { alert("Meeting details required"); setIsSubmitting(false); return; }
    if (category === 'Habit' && selectedDays.length === 0) { alert("Select days for habit"); setIsSubmitting(false); return; }

    const taskToSave: Task = {
      // If initialTask has an ID, keep it. Otherwise (new or template), generate new UUID.
      id: (initialTask && initialTask.id) ? initialTask.id : crypto.randomUUID(),
      category,
      title,
      description,
      priority,
      files,
      // Task fields
      difficulty: 5,
      totalHoursNeeded: totalHours,
      deadline: deadline ? new Date(deadline) : new Date(new Date().setFullYear(new Date().getFullYear() + 1)),
      energyLevel,
      // Habit fields
      recurrenceEndDate: recurrenceEndDate ? new Date(recurrenceEndDate) : undefined,
      // Meeting fields
      meetingDate,
      meetingStartTime: meetingStart,
      meetingEndTime: meetingEnd,
      // Scheduling
      preferredDays: selectedDays.length > 0 ? selectedDays : DAYS_OF_WEEK,
      preferredTimeStart,
      preferredTimeEnd,
      preferredSessionDuration: sessionDuration,
      isScheduled: isScheduled // Use local state
    };

    try {
      await onSubmit(taskToSave);
    } catch (err) {
      console.error(err);
      alert("Failed to save.");
    } finally {
      setIsSubmitting(false);
    }
  };

  // Determine if we are editing an existing persisted task
  const isEditing = initialTask && initialTask.id !== '';

  return (
    <div className="bg-white p-6 rounded-lg shadow-xl max-w-2xl mx-auto border border-gray-200">
      <div className="mb-6">
          <h2 className="text-2xl font-bold text-gray-900 mb-4 flex items-center">
            <span className="bg-indigo-50 text-indigo-600 p-2 rounded-lg mr-3 border border-indigo-100">
                {isEditing ? '✏️' : '✦'}
            </span>
            {isEditing ? 'Edit Event' : 'New Event'}
          </h2>

          {/* Category Tabs: Show if creating new (including from template) */}
          {!isEditing && (
              <div className="flex bg-gray-100 p-1 rounded-lg mb-6">
                {(['Task', 'Meeting', 'Habit'] as TaskCategory[]).map(cat => (
                    <button
                        key={cat}
                        type="button"
                        onClick={() => setCategory(cat)}
                        className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${
                            category === cat 
                            ? 'bg-white text-indigo-600 shadow-sm' 
                            : 'text-gray-500 hover:text-gray-900'
                        }`}
                    >
                        {cat}
                    </button>
                ))}
              </div>
          )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Title & Desc */}
        <div>
            <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Title</label>
            <input 
              required
              type="text" 
              value={title}
              onChange={e => setTitle(e.target.value)}
              className="block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2.5 border bg-white text-gray-900"
              placeholder={category === 'Meeting' ? "e.g. Team Sync" : category === 'Habit' ? "e.g. Final Project" : "e.g. Final Project"}
            />
        </div>

        {/* --- MEETING FIELDS --- */}
        {category === 'Meeting' && (
             <div className="grid grid-cols-3 gap-4 bg-purple-50 p-4 rounded-lg border border-purple-100">
                <div className="col-span-1">
                    <label className="block text-xs font-semibold text-purple-800 mb-1">Date</label>
                    <input type="date" required value={meetingDate} onChange={e => setMeetingDate(e.target.value)} className="w-full text-sm p-2 rounded border-gray-300 bg-white text-gray-900 border" />
                </div>
                <div className="col-span-1">
                    <label className="block text-xs font-semibold text-purple-800 mb-1">Start</label>
                    <input type="time" required value={meetingStart} onChange={e => setMeetingStart(e.target.value)} className="w-full text-sm p-2 rounded border-gray-300 bg-white text-gray-900 border" />
                </div>
                 <div className="col-span-1">
                    <label className="block text-xs font-semibold text-purple-800 mb-1">End</label>
                    <input type="time" required value={meetingEnd} onChange={e => setMeetingEnd(e.target.value)} className="w-full text-sm p-2 rounded border-gray-300 bg-white text-gray-900 border" />
                </div>
             </div>
        )}

        {/* --- TASK FIELDS --- */}
        {category === 'Task' && (
             <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Deadline</label>
                    <input type="datetime-local" required value={deadline} onChange={e => setDeadline(e.target.value)} className="block w-full rounded-md border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 sm:text-sm" />
                 </div>
                 <div>
                     <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Total Hours</label>
                     <input type="number" min="0.5" step="0.5" value={totalHours} onChange={e => setTotalHours(parseFloat(e.target.value))} className="block w-full rounded-md border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 sm:text-sm" />
                 </div>

                 {/* Energy Level (Only relevant for flexible tasks) */}
                 <div className="col-span-2">
                     <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Best Time of Day</label>
                     <div className="flex rounded-md shadow-sm bg-gray-50 border border-gray-200 p-1">
                        {(['High', 'Low'] as EnergyLevel[]).map((e) => (
                            <button
                                key={e}
                                type="button"
                                onClick={() => setEnergyLevel(e)}
                                className={`flex-1 py-1 text-xs font-medium rounded transition-colors ${energyLevel === e ? 'bg-white text-indigo-600 shadow-sm border border-gray-100' : 'text-gray-500 hover:text-gray-700'}`}
                            >
                                {e === 'High' ? '☀️ Morning / Focus' : '🌙 Evening / Relax'}
                            </button>
                        ))}
                     </div>
                 </div>
             </div>
        )}

        {/* --- HABIT FIELDS --- */}
        {category === 'Habit' && (
             <div className="grid grid-cols-2 gap-4 bg-teal-50 p-4 rounded-lg border border-teal-100">
                <div>
                     <label className="block text-xs font-semibold text-teal-800 mb-1">Duration per session (hrs)</label>
                     <input type="number" min="0.5" step="0.5" value={sessionDuration} onChange={e => setSessionDuration(parseFloat(e.target.value))} className="w-full text-sm p-2 rounded border-gray-300 bg-white text-gray-900 border" />
                </div>
                <div>
                     <label className="block text-xs font-semibold text-teal-800 mb-1">Repeat Until</label>
                     <input type="date" value={recurrenceEndDate} onChange={e => setRecurrenceEndDate(e.target.value)} className="w-full text-sm p-2 rounded border-gray-300 bg-white text-gray-900 border" />
                </div>
             </div>
        )}

        {/* Description */}
        <div>
            <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Description</label>
            <textarea value={description} onChange={e => setDescription(e.target.value)} rows={2} className="block w-full rounded-md border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 sm:text-sm placeholder-gray-400" />
        </div>

        {/* --- SHARED: AVAILABILITY / RECURRENCE --- */}
        {category !== 'Meeting' && (
            <div className="border-t border-gray-200 pt-6">
                <h3 className="text-sm font-semibold text-gray-900 mb-4">
                    {category === 'Habit' ? 'Recurrence Pattern' : 'Availability'}
                </h3>

                <div className="flex flex-wrap gap-2 mb-4">
                    {DAYS_OF_WEEK.map(day => (
                        <button
                            key={day}
                            type="button"
                            onClick={() => toggleDay(day)}
                            className={`px-3 py-1.5 rounded text-xs font-medium border transition-colors ${
                                selectedDays.includes(day) 
                                    ? 'bg-indigo-600 text-white border-indigo-600' 
                                    : 'bg-white text-gray-500 border-gray-300 hover:border-gray-400'
                            }`}
                        >
                            {day.substring(0, 3)}
                        </button>
                    ))}
                </div>

                <div className="grid grid-cols-2 gap-6">
                    <div>
                        <label className="block text-xs text-gray-500 mb-1">Preferred Start</label>
                        <input type="time" value={preferredTimeStart} onChange={e => setPreferredTimeStart(e.target.value)} className="block w-full rounded-md border-gray-300 shadow-sm sm:text-sm p-2 border bg-white text-gray-900" />
                    </div>
                    <div>
                        <label className="block text-xs text-gray-500 mb-1">Preferred End</label>
                        <input type="time" value={preferredTimeEnd} onChange={e => setPreferredTimeEnd(e.target.value)} className="block w-full rounded-md border-gray-300 shadow-sm sm:text-sm p-2 border bg-white text-gray-900" />
                    </div>
                </div>
            </div>
        )}

        {/* Priority & Files */}
        <div className="grid grid-cols-2 gap-6 border-t border-gray-200 pt-6">
             <div>
                 <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Priority</label>
                 <div className="flex rounded-md shadow-sm bg-gray-50 border border-gray-200 p-1">
                    {(['High', 'Medium', 'Low'] as Priority[]).map((p) => {
                        let activeClass = '';
                        if (priority === p) {
                            if (p === 'High') activeClass = 'bg-white text-red-600 shadow-sm ring-1 ring-red-100 font-bold';
                            else if (p === 'Medium') activeClass = 'bg-white text-amber-600 shadow-sm ring-1 ring-amber-100 font-bold';
                            else activeClass = 'bg-white text-emerald-600 shadow-sm ring-1 ring-emerald-100 font-bold';
                        } else {
                            activeClass = 'text-gray-500 hover:text-gray-700 hover:bg-gray-100';
                        }

                        return (
                            <button
                                key={p}
                                type="button"
                                onClick={() => setPriority(p)}
                                className={`flex-1 py-2 text-xs font-medium rounded transition-all ${activeClass}`}
                            >
                                {p}
                            </button>
                        );
                    })}
                 </div>
             </div>

             <div>
                <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Materials</label>
                <label className="flex items-center justify-center w-full p-2 border border-gray-300 border-dashed rounded cursor-pointer hover:bg-gray-50">
                    <span className="text-xs text-indigo-600">+ Upload</span>
                    <input type="file" className="hidden" multiple onChange={handleFileChange} />
                </label>
             </div>
        </div>

        {/* Auto-Schedule Toggle */}
        <div className="flex items-center justify-between bg-gray-50 p-4 rounded-lg border border-gray-200 mt-6">
            <div className="flex flex-col">
                <span className="text-sm font-semibold text-gray-900">
                    {category === 'Task' || category === 'Habit' ? "Auto-Schedule" : "Add to Calendar"}
                </span>
                <span className="text-xs text-gray-500">
                    {category === 'Task' || category === 'Habit' 
                        ? "Let AI assign time slots automatically." 
                        : "Place this meeting on your schedule."}
                </span>
            </div>
            <button 
                type="button"
                onClick={() => setIsScheduled(!isScheduled)}
                className={`relative inline-flex h-6 w-11 flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out focus:outline-none ${isScheduled ? 'bg-indigo-600' : 'bg-gray-200'}`}
            >
                <span className={`pointer-events-none inline-block h-5 w-5 transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out ${isScheduled ? 'translate-x-5' : 'translate-x-0'}`} />
            </button>
        </div>

        <div className="flex justify-end gap-3 pt-4 border-t border-gray-200">
            <Button variant="ghost" type="button" onClick={onCancel}>Cancel</Button>
            <Button type="submit" isLoading={isSubmitting}>
                {isEditing ? 'Save Changes' : `Add ${category}`}
            </Button>
        </div>
      </form>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { CalendarEvent, Task, EventType, AIScheduleSuggestion, EnergyLevel } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = "gemini-3-flash-preview";

export const identifyClasses = async (events: CalendarEvent[]): Promise<string[]> => {
  if (events.length === 0) return [];

  const uniqueEvents = new Map<string, { title: string; description: string }>();

  events.forEach(e => {
    if (!uniqueEvents.has(e.title)) {
        uniqueEvents.set(e.title, {
            title: e.title,
            description: e.description || ""
        });
    }
  });

  const distinctEventList = Array.from(uniqueEvents.values()).slice(0, 150);

  const prompt = `
    Analyze the following list of unique event titles and descriptions.
    Identify which ones represent University Classes, Lectures, Labs, or Recitations.
    Return a list of the *Exact Titles* that are classes.
    Ignore social events, work, clubs, or general reminders.

    Unique Events:
    ${JSON.stringify(distinctEventList)}
  `;

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      classTitles: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "List of exact titles identified as academic classes."
      }
    }
  };

  try {
    const timeout = new Promise<never>((_, reject) => 
        setTimeout(() => reject(new Error("Timeout")), 8000)
    );

    const apiCall = ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.1,
      },
    });

    const response: any = await Promise.race([apiCall, timeout]);

    const outputText = response.text;
    if (!outputText) return [];

    const result = JSON.parse(outputText) as { classTitles: string[] };
    const classTitles = new Set(result.classTitles || []);

    const classEventIds = events
        .filter(e => classTitles.has(e.title))
        .map(e => e.id);

    return classEventIds;

  } catch (error) {
    console.warn("AI Classification skipped or failed:", error);
    return []; 
  }
};

export const analyzeTaskSemantics = async (title: string, description: string): Promise<{ energyLevel: EnergyLevel }> => {
    const prompt = `
        Analyze the following task title and description.
        Determine the implicit time-of-day preference based on the semantics.

        Rules:
        - If the task implies "morning", "start of day", "breakfast", "intense focus", "urgent", return 'High'.
        - If the task implies "night", "before sleep", "evening", "relax", "review", "chill", return 'Low'.
        - Default to 'High' if ambiguous, as most tasks are better done earlier.

        Task Title: "${title}"
        Task Description: "${description}"
    `;

    const responseSchema = {
        type: Type.OBJECT,
        properties: {
            energyLevel: {
                type: Type.STRING,
                enum: ["High", "Low"],
                description: "High for Morning/Focus, Low for Evening/Relax"
            }
        }
    };

    try {
        const response = await ai.models.generateContent({
            model: MODEL_NAME,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
                temperature: 0.1
            }
        });

        const result = JSON.parse(response.text || '{}');
        return { energyLevel: result.energyLevel || 'High' };
    } catch (e) {
        console.warn("Semantics analysis failed", e);
        return { energyLevel: 'High' };
    }
};

/**
 * NEW: Pure AI Scheduler
 * Replaces the algorithmic approach in scheduler.ts
 */
export const generateFullSchedule = async (
    fixedEvents: CalendarEvent[], 
    tasksToSchedule: Task[]
): Promise<CalendarEvent[]> => {

    if (tasksToSchedule.length === 0) return [];

    const now = new Date();
    // Context: Get schedule for next 7 days or up to furthest deadline
    const contextEnd = new Date(now);
    contextEnd.setDate(contextEnd.getDate() + 7);

    // Filter relevant fixed events to reduce token count
    const relevantFixed = fixedEvents.filter(e => e.start >= now && e.start <= contextEnd).map(e => ({
        title: e.title,
        start: e.start.toLocaleString(),
        end: e.end.toLocaleString()
    }));

    const taskContext = tasksToSchedule.map(t => ({
        id: t.id,
        title: t.title,
        description: t.description, // This is the user's "Prompt"
        totalHours: t.totalHoursNeeded,
        deadline: t.deadline.toLocaleString(),
        priority: t.priority,
        energyLevel: t.energyLevel,
        preferences: {
            days: t.preferredDays.join(", "),
            startTime: t.preferredTimeStart,
            endTime: t.preferredTimeEnd,
            sessionDuration: t.preferredSessionDuration
        }
    }));

    const prompt = `
        You are an intelligent scheduler. I need you to assign "Work Sessions" for my tasks into my existing calendar.

        Current Time: ${now.toLocaleString()}

        --- EXISTING BUSY SLOTS (DO NOT OVERLAP) ---
        ${JSON.stringify(relevantFixed)}

        --- TASKS TO SCHEDULE ---
        ${JSON.stringify(taskContext)}

        --- RULES ---
        1. **15-Minute Rule**: Do not schedule a task within 15 minutes of an existing busy slot. Leave a buffer.
        2. **User Instructions**: Read the "description" of each task carefully. It contains specific instructions (e.g., "Do this after lunch", "Review in the evening"). Plan accordingly.
        3. **Working Hours**: Respect the "startTime" and "endTime" preferences for each task.
        4. **Fragmentation**: Break large tasks into multiple sessions based on "sessionDuration".
        5. **Completeness**: Try to schedule ALL needed hours before the deadline. If the deadline is close, prioritize finding ANY slot.
        6. **Conflicts**: If a task cannot be fully scheduled due to lack of time, schedule as much as possible.

        Return a JSON object containing the list of new sessions.
    `;

    const responseSchema = {
        type: Type.OBJECT,
        properties: {
            sessions: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        taskId: { type: Type.STRING, description: "The ID of the task this session belongs to" },
                        startISO: { type: Type.STRING, description: "ISO 8601 Start Time" },
                        endISO: { type: Type.STRING, description: "ISO 8601 End Time" },
                        reasoning: { type: Type.STRING, description: "Why this slot was chosen based on the user's description/instruction." }
                    },
                    required: ["taskId", "startISO", "endISO", "reasoning"]
                }
            }
        }
    };

    try {
        const response = await ai.models.generateContent({
            model: MODEL_NAME,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
                temperature: 0.2, // Slightly higher creativity to solve packing problems
            }
        });

        const outputText = response.text;
        if (!outputText) return [];

        const result = JSON.parse(outputText) as { sessions: any[] };

        // Convert back to CalendarEvents
        const newEvents: CalendarEvent[] = [];

        for (const session of result.sessions) {
            const task = tasksToSchedule.find(t => t.id === session.taskId);
            if (!task) continue;

            const start = new Date(session.startISO);
            const end = new Date(session.endISO);

            // Basic sanity check on dates
            if (isNaN(start.getTime()) || isNaN(end.getTime())) continue;

            newEvents.push({
                id: crypto.randomUUID(),
                title: task.title,
                start: start,
                end: end,
                type: EventType.AI_WORK_SESSION,
                relatedTaskId: task.id,
                description: session.reasoning, // Use the AI's reasoning as the description
                priority: task.priority,
                color: task.priority === 'High' ? "bg-red-50 border-red-200 text-red-700" : 
                       task.priority === 'Medium' ? "bg-amber-50 border-amber-200 text-amber-700" : 
                       "bg-emerald-50 border-emerald-200 text-emerald-700"
            });
        }

        return newEvents;

    } catch (e) {
        console.error("Full AI Schedule Generation Failed:", e);
        // Fallback: return empty list, do not crash app
        return [];
    }
};

