                        if (priority === p) {
                            if (p === 'High') activeClass = 'bg-white text-red-600 shadow-sm ring-1 ring-red-100 font-bold';
                            else if (p === 'Medium') activeClass = 'bg-white text-amber-600 shadow-sm ring-1 ring-amber-100 font-bold';
