            </button>
        </div>

        <div className="flex justify-end gap-3 pt-4 border-t border-gray-200">
            <Button variant="ghost" type="button" onClick={onCancel}>Cancel</Button>
            <Button type="submit" isLoading={isSubmitting}>
                {isEditing ? 'Save Changes' : `Add ${category}`}
            </Button>
        </div>
      </form>
    </div>
  );
};

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { CalendarEvent, Task, EventType, AIScheduleSuggestion, EnergyLevel } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MODEL_NAME = "gemini-3-flash-preview";

/**
 * Helper to strip markdown code blocks from JSON response
 */
const cleanJsonOutput = (text: string): string => {
    if (!text) return "{}";
    // Remove ```json and ``` markers if present
    let cleaned = text.replace(/^```json\s*/, "").replace(/\s*```$/, "");
    // Fallback: sometimes it might just be ``` without json
    cleaned = cleaned.replace(/^```\s*/, "").replace(/\s*```$/, "");
    return cleaned.trim();
};

/**
 * Helper to wrap promises with a timeout
 */
const callWithTimeout = async <T>(promise: Promise<T>, ms: number): Promise<T> => {
    let timeoutId: any;
    const timeoutPromise = new Promise<T>((_, reject) => {
        timeoutId = setTimeout(() => reject(new Error(`AI Request timed out after ${ms}ms`)), ms);
    });
    try {
        const result = await Promise.race([promise, timeoutPromise]);
        clearTimeout(timeoutId);
        return result;
    } catch (e) {
        clearTimeout(timeoutId);
        throw e;
    }
};

export const identifyClasses = async (events: CalendarEvent[]): Promise<string[]> => {
  if (events.length === 0) return [];

  const uniqueEvents = new Map<string, { title: string; description: string }>();

  events.forEach(e => {
    if (!uniqueEvents.has(e.title)) {
        uniqueEvents.set(e.title, {
            title: e.title,
            description: e.description || ""
        });
    }
  });

  const distinctEventList = Array.from(uniqueEvents.values()).slice(0, 150);

  const prompt = `
    Analyze the following list of unique event titles and descriptions.
    Identify which ones represent University Classes, Lectures, Labs, or Recitations.
    Return a list of the *Exact Titles* that are classes.
    Ignore social events, work, clubs, or general reminders.

    Unique Events:
    ${JSON.stringify(distinctEventList)}
  `;

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      classTitles: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "List of exact titles identified as academic classes."
      }
    }
  };

  try {
    const apiCall = ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.1,
      },
    });

    const response = await callWithTimeout<GenerateContentResponse>(apiCall, 15000); // 15s Timeout

    const outputText = response.text;
    if (!outputText) return [];

    const cleanedText = cleanJsonOutput(outputText);
    const result = JSON.parse(cleanedText) as { classTitles: string[] };
    const classTitles = new Set(result.classTitles || []);

    const classEventIds = events
        .filter(e => classTitles.has(e.title))
        .map(e => e.id);

    return classEventIds;

  } catch (error) {
    console.warn("AI Classification skipped or failed:", error);
    return []; 
  }
};

export const analyzeTaskSemantics = async (title: string, description: string): Promise<{ energyLevel: EnergyLevel }> => {
    const prompt = `
        Analyze the following task title and description.
        Determine the implicit time-of-day preference based on the semantics.

        Rules:
        - If the task implies "morning", "start of day", "breakfast", "intense focus", "urgent", return 'High'.
        - If the task implies "night", "before sleep", "evening", "relax", "review", "chill", return 'Low'.
        - Default to 'High' if ambiguous, as most tasks are better done earlier.

        Task Title: "${title}"
        Task Description: "${description}"
    `;

    const responseSchema = {
        type: Type.OBJECT,
        properties: {
            energyLevel: {
                type: Type.STRING,
                enum: ["High", "Low"],
                description: "High for Morning/Focus, Low for Evening/Relax"
            }
        }
    };

    try {
        const apiCall = ai.models.generateContent({
            model: MODEL_NAME,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
                temperature: 0.1
            }
        });

        const response = await callWithTimeout<GenerateContentResponse>(apiCall, 10000); // 10s timeout

        const cleanedText = cleanJsonOutput(response.text || '{}');
        const result = JSON.parse(cleanedText);
        return { energyLevel: result.energyLevel || 'High' };
    } catch (e) {
        console.warn("Semantics analysis failed", e);
        return { energyLevel: 'High' };
    }
};

/**
 * NEW: Pure AI Scheduler
 */
export const generateFullSchedule = async (
    fixedEvents: CalendarEvent[], 
    tasksToSchedule: Task[]
): Promise<CalendarEvent[]> => {

    if (tasksToSchedule.length === 0) return [];

    const now = new Date();
    const contextEnd = new Date(now);
    contextEnd.setDate(contextEnd.getDate() + 7);

    // OPTIMIZATION: Compact string representation for busy slots to reduce tokens & latency
    const relevantFixed = fixedEvents
        .filter(e => e.start >= now && e.start <= contextEnd)
        .map(e => {
            const day = e.start.toLocaleDateString('en-US', { weekday: 'short', month: 'numeric', day: 'numeric' });
            const startStr = `${e.start.getHours().toString().padStart(2, '0')}:${e.start.getMinutes().toString().padStart(2, '0')}`;
            const endStr = `${e.end.getHours().toString().padStart(2, '0')}:${e.end.getMinutes().toString().padStart(2, '0')}`;
            return `"${e.title}" (${day}): ${startStr}-${endStr}`;
        });

    // OPTIMIZATION: Compact task representation
    const taskContext = tasksToSchedule.map(t => ({
        id: t.id,
        title: t.title,
        desc: t.description || "None", 
        hrs: t.totalHoursNeeded,
        due: t.deadline.toLocaleString('en-US', { weekday: 'short', month: 'numeric', day: 'numeric', hour: 'numeric' }),
        prio: t.priority,
        energy: t.energyLevel,
        prefs: {
            days: t.preferredDays.join(", "),
            start: t.preferredTimeStart,
            end: t.preferredTimeEnd,
            sessionLen: t.preferredSessionDuration
        }
    }));

    const prompt = `
        Scheduler Agent. Assign work sessions for tasks into gaps in the calendar.

        Current Time: ${now.toLocaleString()}

        BUSY SLOTS (Fixed, Do Not Overlap):
        ${JSON.stringify(relevantFixed)}

        TASKS TO SCHEDULE:
        ${JSON.stringify(taskContext)}

        RULES:
        1. NO OVERLAPS with Busy Slots.
        2. 15-min buffer between events.
        3. **CRITICAL**: 'desc' (Description) overrides 'prefs'. If 'desc' specifies a time (e.g. "at 11pm"), IGNORE 'prefs.end' and schedule it then.
        4. Respect "prefs" (working hours, days) ONLY IF 'desc' does not specify otherwise.
        5. Split tasks into "sessionLen" blocks.
        6. Return JSON.

        Output Schema:
        { "sessions": [{ "taskId": "id", "startISO": "iso-date", "endISO": "iso-date", "reasoning": "reason" }] }
    `;

    const responseSchema = {
        type: Type.OBJECT,
        properties: {
            sessions: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        taskId: { type: Type.STRING, description: "The ID of the task this session belongs to" },
                        startISO: { type: Type.STRING, description: "ISO 8601 Start Time" },
                        endISO: { type: Type.STRING, description: "ISO 8601 End Time" },
                        reasoning: { type: Type.STRING, description: "Why this slot was chosen." }
                    },
                    required: ["taskId", "startISO", "endISO", "reasoning"]
                }
            }
        }
    };

    try {
        const apiCall = ai.models.generateContent({
            model: MODEL_NAME,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: responseSchema,
                temperature: 0.2,
            }
        });

        // INCREASED TIMEOUT: 60 seconds (up from 25s)
        const response = await callWithTimeout<GenerateContentResponse>(apiCall, 60000); 

        const outputText = response.text;
        if (!outputText) return [];

        const cleanedText = cleanJsonOutput(outputText);
        const result = JSON.parse(cleanedText) as { sessions: any[] };

        // Convert back to CalendarEvents
        const newEvents: CalendarEvent[] = [];

        if (result.sessions) {
            for (const session of result.sessions) {
                const task = tasksToSchedule.find(t => t.id === session.taskId);
                if (!task) continue;

                const start = new Date(session.startISO);
                const end = new Date(session.endISO);

                if (isNaN(start.getTime()) || isNaN(end.getTime())) continue;

                newEvents.push({
                    id: crypto.randomUUID(),
                    title: task.title,
                    start: start,
                    end: end,
                    type: EventType.AI_WORK_SESSION,
                    relatedTaskId: task.id,
                    description: session.reasoning,
                    priority: task.priority,
                    color: task.priority === 'High' ? "bg-red-50 border-red-200 text-red-700" : 
                           task.priority === 'Medium' ? "bg-amber-50 border-amber-200 text-amber-700" : 
                           "bg-emerald-50 border-emerald-200 text-emerald-700"
                });
            }
        }

        return newEvents;

    } catch (e) {
        console.error("Full AI Schedule Generation Failed or Timed Out:", e);
        // Fail gracefully so the app doesn't hang
        return [];
    }
};

