import React, { useState, useEffect } from 'react';
import { Task, TaskFile, Priority, EnergyLevel, TaskCategory, CalendarEvent } from '../types';
import { Button } from './Button';

interface TaskFormProps {
  initialTask?: Task | null;
  existingEvents?: CalendarEvent[]; // Added for conflict detection
  onSubmit: (task: Task) => Promise<void>;
  onCancel: () => void;
}

const DAYS_OF_WEEK = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"];

type ScheduleMode = 'AI' | 'MANUAL';

export const TaskForm: React.FC<TaskFormProps> = ({ initialTask, existingEvents = [], onSubmit, onCancel }) => {
  // Top Level Mode
  const [mode, setMode] = useState<ScheduleMode>('AI');

  // AI Sub-Mode
  const [aiType, setAiType] = useState<'Task' | 'Habit'>('Task');

  // Common Fields
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState(""); // Acts as AI Prompt in AI mode
  const [priority, setPriority] = useState<Priority>('Medium');
  const [files, setFiles] = useState<TaskFile[]>([]);

  // AI - Task Specific
  const [deadline, setDeadline] = useState("");
  const [totalHours, setTotalHours] = useState(2);
  const [energyLevel, setEnergyLevel] = useState<EnergyLevel>('High');

  // AI - Habit Specific
  const [sessionDuration, setSessionDuration] = useState(1.0);
  const [selectedDays, setSelectedDays] = useState<string[]>([]);
  const [recurrenceEndDate, setRecurrenceEndDate] = useState("");
  const [preferredTimeStart, setPreferredTimeStart] = useState("09:00");
  const [preferredTimeEnd, setPreferredTimeEnd] = useState("22:00");

  // Manual Specific
  const [manualDate, setManualDate] = useState("");
  const [manualStart, setManualStart] = useState("09:00");
  const [manualEnd, setManualEnd] = useState("10:00");

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [manualConflict, setManualConflict] = useState<string | null>(null);

  // Initialize form
  useEffect(() => {
    if (initialTask) {
        // Infer mode from category
        if (initialTask.category === 'Meeting') {
            setMode('MANUAL');
            setManualDate(initialTask.meetingDate || "");
            setManualStart(initialTask.meetingStartTime || "09:00");
            setManualEnd(initialTask.meetingEndTime || "10:00");
        } else {
            setMode('AI');
            setAiType(initialTask.category as 'Task' | 'Habit');

            // AI Fields
            if (initialTask.category === 'Task') {
                setTotalHours(initialTask.totalHoursNeeded);
                const d = new Date(initialTask.deadline);
                if (!isNaN(d.getTime())) {
                    const pad = (n: number) => n < 10 ? '0'+n : n;
                    setDeadline(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`);
                }
            } else {
                // Habit
                setSessionDuration(initialTask.preferredSessionDuration || 1.0);
                setSelectedDays(initialTask.preferredDays || []);
                if (initialTask.recurrenceEndDate) {
                    const d = new Date(initialTask.recurrenceEndDate);
                    if (!isNaN(d.getTime())) {
                        const pad = (n: number) => n < 10 ? '0'+n : n;
                        setRecurrenceEndDate(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`);
                    }
                }
                setPreferredTimeStart(initialTask.preferredTimeStart || "09:00");
                setPreferredTimeEnd(initialTask.preferredTimeEnd || "22:00");
            }
        }

        // Common
        setTitle(initialTask.title);
        setDescription(initialTask.description);
        setPriority(initialTask.priority);
        setFiles(initialTask.files);
        setEnergyLevel(initialTask.energyLevel);

    } else {
        // Default Defaults
        const tomorrow = new Date();
        tomorrow.setDate(tomorrow.getDate() + 1);
        tomorrow.setHours(17,0,0,0);

        const todayStr = new Date().toISOString().split('T')[0];
        setManualDate(todayStr);
    }
  }, [initialTask]);

  // Conflict Detection for Manual Mode
  useEffect(() => {
      if (mode === 'MANUAL' && manualDate && manualStart && manualEnd) {
          const start = new Date(`${manualDate}T${manualStart}`);
          const end = new Date(`${manualDate}T${manualEnd}`);

          if (start >= end) {
              setManualConflict("End time must be after start time.");
              return;
          }

          const hasConflict = existingEvents.some(e => {
              // Ignore self if editing (though ID isn't easily avail here, we usually don't block edit save unless explicit)
              // Ideally check against all events EXCEPT the one being edited.
              // For simplicity, we just warn.
              if (initialTask && e.relatedTaskId === initialTask.id) return false;

              return (start < e.end && end > e.start);
          });

          if (hasConflict) {
              setManualConflict("This time slot conflicts with an existing event.");
          } else {
              setManualConflict(null);
          }
      } else {
          setManualConflict(null);
      }
  }, [mode, manualDate, manualStart, manualEnd, existingEvents, initialTask]);


  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: TaskFile[] = Array.from(e.target.files).map(f => ({
        name: f.name,
        size: f.size,
        type: f.type,
        url: URL.createObjectURL(f) 
      }));
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const toggleDay = (day: string) => {
    setSelectedDays(prev => 
      prev.includes(day) ? prev.filter(d => d !== day) : [...prev, day]
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    // Validation
    if (mode === 'AI') {
        if (aiType === 'Task' && !deadline) { alert("Deadline required"); setIsSubmitting(false); return; }
        if (aiType === 'Habit' && selectedDays.length === 0) { alert("Select days for habit"); setIsSubmitting(false); return; }
    } else {
        if (!manualDate || !manualStart || !manualEnd) { alert("Date and times required"); setIsSubmitting(false); return; }
        if (manualConflict) { alert(manualConflict); setIsSubmitting(false); return; }
    }

    const category: TaskCategory = mode === 'MANUAL' ? 'Meeting' : aiType;

    const taskToSave: Task = {
      id: (initialTask && initialTask.id) ? initialTask.id : crypto.randomUUID(),
      category,
      title,
      description,
      priority,
      files,
      // Default / Placeholder values for unused fields based on mode
      difficulty: 5,
      energyLevel: mode === 'AI' && aiType === 'Task' ? energyLevel : 'High',

      // Task Specifics
      totalHoursNeeded: (mode === 'AI' && aiType === 'Task') ? totalHours : 0,
      deadline: (mode === 'AI' && aiType === 'Task' && deadline) 
        ? new Date(deadline) 
        : new Date(new Date().setFullYear(new Date().getFullYear() + 1)),

      // Habit Specifics
      recurrenceEndDate: (mode === 'AI' && aiType === 'Habit' && recurrenceEndDate) ? new Date(recurrenceEndDate) : undefined,
      preferredDays: (mode === 'AI' && aiType === 'Habit') ? selectedDays : DAYS_OF_WEEK,
      preferredTimeStart: (mode === 'AI' && aiType === 'Habit') ? preferredTimeStart : "09:00",
      preferredTimeEnd: (mode === 'AI' && aiType === 'Habit') ? preferredTimeEnd : "22:00",
      preferredSessionDuration: (mode === 'AI' && aiType === 'Habit') ? sessionDuration : 1.0,

      // Manual Specifics
      meetingDate: mode === 'MANUAL' ? manualDate : undefined,
      meetingStartTime: mode === 'MANUAL' ? manualStart : undefined,
      meetingEndTime: mode === 'MANUAL' ? manualEnd : undefined,

      // Flags
      isScheduled: true // Always true now: AI schedules AI tasks, App logic schedules Manual meetings
    };

    try {
      await onSubmit(taskToSave);
    } catch (err) {
      console.error(err);
      alert("Failed to save.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const isEditing = initialTask && initialTask.id !== '';

  return (
    <div className="bg-white p-6 rounded-lg shadow-xl max-w-2xl mx-auto border border-gray-200">

      {/* Header & Mode Switcher */}
      <div className="mb-8">
          <div className="flex items-center justify-between mb-6">
              <h2 className="text-2xl font-bold text-gray-900 flex items-center">
                <span className="bg-indigo-50 text-indigo-600 p-2 rounded-lg mr-3 border border-indigo-100">
                    {isEditing ? '✏️' : '✦'}
                </span>
                {isEditing ? 'Edit Event' : 'New Event'}
              </h2>
          </div>

          {!isEditing && (
              <div className="grid grid-cols-2 gap-4 p-1 bg-gray-100 rounded-lg">
                  <button
                    type="button"
                    onClick={() => setMode('AI')}
                    className={`flex items-center justify-center py-3 px-4 rounded-md text-sm font-semibold transition-all ${
                        mode === 'AI' 
                        ? 'bg-white text-indigo-600 shadow-sm ring-1 ring-black/5' 
                        : 'text-gray-500 hover:text-gray-900'
                    }`}
                  >
                      <span className="mr-2">✨</span> AI Powered
                  </button>
                  <button
                    type="button"
                    onClick={() => setMode('MANUAL')}
                    className={`flex items-center justify-center py-3 px-4 rounded-md text-sm font-semibold transition-all ${
                        mode === 'MANUAL' 
                        ? 'bg-white text-gray-900 shadow-sm ring-1 ring-black/5' 
                        : 'text-gray-500 hover:text-gray-900'
                    }`}
                  >
                      <span className="mr-2">📅</span> Manual Schedule
                  </button>
              </div>
          )}
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Title */}
        <div>
            <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Title</label>
            <input 
              required
              type="text" 
              value={title}
              onChange={e => setTitle(e.target.value)}
              className="block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-3 border bg-white text-gray-900"
              placeholder={mode === 'AI' ? "e.g. Study for Calculus" : "e.g. Team Meeting"}
            />
        </div>

        {/* --- AI MODE FIELDS --- */}
        {mode === 'AI' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-top-4 duration-300">
                {/* Sub-type Selector */}
                {!isEditing && (
                    <div className="flex gap-4 border-b border-gray-200 pb-4">
                        <label className="flex items-center cursor-pointer">
                            <input type="radio" checked={aiType === 'Task'} onChange={() => setAiType('Task')} className="h-4 w-4 text-indigo-600 focus:ring-indigo-500 border-gray-300" />
                            <span className="ml-2 text-sm font-medium text-gray-900">One-time Task</span>
