                            <input type="radio" checked={aiType === 'Habit'} onChange={() => setAiType('Habit')} className="h-4 w-4 text-indigo-600 focus:ring-indigo-500 border-gray-300" />
                            <span className="ml-2 text-sm font-medium text-gray-900">Recurring Habit</span>
