                     <div className="grid grid-cols-2 gap-4">
                        <div>
                           <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Deadline</label>
                           <input type="datetime-local" required value={deadline} onChange={e => setDeadline(e.target.value)} className="block w-full rounded-md border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 sm:text-sm" />
                        </div>
                        <div>
                            <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Hours Needed</label>
                            <input type="number" min="0.5" step="0.5" value={totalHours} onChange={e => setTotalHours(parseFloat(e.target.value))} className="block w-full rounded-md border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 sm:text-sm" />
