import React, { useState, useEffect } from 'react';
import { Task, TaskFile, Priority, TaskCategory, CalendarEvent } from '../types';
import { Button } from './Button';

interface TaskFormProps {
  initialTask?: Task | null;
  existingEvents?: CalendarEvent[];
  onSubmit: (task: Task) => Promise<void>;
  onCancel: () => void;
}

type ScheduleMode = 'AI' | 'MANUAL';

export const TaskForm: React.FC<TaskFormProps> = ({ initialTask, existingEvents = [], onSubmit, onCancel }) => {
  // Mode Selection
  const [mode, setMode] = useState<ScheduleMode>('AI');

  // Common Fields
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [category, setCategory] = useState<TaskCategory>('Task');

  // AI Specific
  const [deadline, setDeadline] = useState("");
  const [totalHours, setTotalHours] = useState(1);

  // Manual Specific
  const [priority, setPriority] = useState<Priority>('Medium');
  const [files, setFiles] = useState<TaskFile[]>([]);

  // Manual Meeting/Habit
  const [manualDate, setManualDate] = useState("");
  const [manualStart, setManualStart] = useState("09:00");
  const [manualEnd, setManualEnd] = useState("10:00");

  // Manual Task
  const [manualDueTime, setManualDueTime] = useState("");

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [manualConflict, setManualConflict] = useState<string | null>(null);

  useEffect(() => {
    if (initialTask) {
        setCategory(initialTask.category);
        setTitle(initialTask.title);
        setDescription(initialTask.description);
        setFiles(initialTask.files);
        setPriority(initialTask.priority);

        if (initialTask.meetingDate) {
            // Manual Meeting
            setMode('MANUAL');
            setManualDate(initialTask.meetingDate || "");
            setManualStart(initialTask.meetingStartTime || "09:00");
            setManualEnd(initialTask.meetingEndTime || "10:00");
        } else if (initialTask.totalHoursNeeded > 0 && initialTask.isScheduled) {
            // AI Task
            setMode('AI');
            setTotalHours(initialTask.totalHoursNeeded);
            const d = new Date(initialTask.deadline);
            if (!isNaN(d.getTime())) {
                const pad = (n: number) => n < 10 ? '0'+n : n;
                setDeadline(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`);
            }
        } else {
            // Manual Task (No meeting date, no AI scheduling)
            setMode('MANUAL');
            const d = new Date(initialTask.deadline);
            if (!isNaN(d.getTime())) {
                const pad = (n: number) => n < 10 ? '0'+n : n;
                setManualDate(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`);
                // Extract time if it wasn't default EOD
                if (d.getHours() !== 23 || d.getMinutes() !== 59) {
                     setManualDueTime(`${pad(d.getHours())}:${pad(d.getMinutes())}`);
                }
            }
        }
    } else {
        // Default
        setMode('AI');
        const now = new Date();
        const tomorrow = new Date(now);
        tomorrow.setDate(tomorrow.getDate() + 1);
        tomorrow.setHours(23, 59, 0, 0); 

        const pad = (n: number) => n < 10 ? '0'+n : n;
        setDeadline(`${tomorrow.getFullYear()}-${pad(tomorrow.getMonth()+1)}-${pad(tomorrow.getDate())}T${pad(tomorrow.getHours())}:${pad(tomorrow.getMinutes())}`);

        const todayStr = new Date().toISOString().split('T')[0];
        setManualDate(todayStr);
    }
  }, [initialTask]);

  // Conflict Detection for Manual Mode (Only for Meetings)
  useEffect(() => {
      if (mode === 'MANUAL' && category !== 'Task' && manualDate && manualStart && manualEnd) {
          const start = new Date(`${manualDate}T${manualStart}`);
          const end = new Date(`${manualDate}T${manualEnd}`);

          if (start >= end) {
              setManualConflict("End time must be after start time.");
              return;
          }

          const hasConflict = existingEvents.some(e => {
              if (initialTask && e.relatedTaskId === initialTask.id) return false;
              return (start < e.end && end > e.start);
          });

          if (hasConflict) {
              setManualConflict("⚠ Time slot conflicts with existing event.");
          } else {
              setManualConflict(null);
          }
      } else {
          setManualConflict(null);
      }
  }, [mode, category, manualDate, manualStart, manualEnd, existingEvents, initialTask]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: TaskFile[] = Array.from(e.target.files).map(f => ({
        name: f.name,
        size: f.size,
        type: f.type,
        url: URL.createObjectURL(f) 
      }));
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    // Validation
    if (mode === 'AI') {
        if (!deadline) { alert("Date is required."); setIsSubmitting(false); return; }
        if (totalHours <= 0) { alert("Hours needed must be greater than 0."); setIsSubmitting(false); return; }
    } else {
        // Manual Mode
        if (!manualDate) { alert("Date is required."); setIsSubmitting(false); return; }

        if (category !== 'Task') {
            // Meeting needs start/end
            if (!manualStart || !manualEnd) { alert("Start and End times required for meetings."); setIsSubmitting(false); return; }
            if (manualConflict) { alert(manualConflict); setIsSubmitting(false); return; }
        }
    }

    let calculatedDeadline = new Date();
    // Calculate Deadline based on mode
    if (mode === 'AI') {
        calculatedDeadline = new Date(deadline);
    } else {
        if (category === 'Task') {
            // Manual Task: Use manualDate + manualDueTime (or EOD)
            if (manualDueTime) {
                calculatedDeadline = new Date(`${manualDate}T${manualDueTime}`);
            } else {
                calculatedDeadline = new Date(`${manualDate}T23:59:00`);
            }
        } else {
            // Manual Meeting: Deadline isn't really used logically, but we set it to end time
            calculatedDeadline = new Date(`${manualDate}T${manualEnd}`);
        }
    }

    const taskToSave: Task = {
      id: (initialTask && initialTask.id) ? initialTask.id : crypto.randomUUID(),
      category,
      title,
      description,

      // AI Fields
      totalHoursNeeded: mode === 'AI' ? totalHours : 0,
      deadline: calculatedDeadline,

      // Manual Fields
      priority: mode === 'MANUAL' ? priority : 'Medium',
      files: mode === 'MANUAL' ? files : [],

      // Meeting Specifics (Only set if Manual Meeting)
      meetingDate: (mode === 'MANUAL' && category !== 'Task') ? manualDate : undefined,
      meetingStartTime: (mode === 'MANUAL' && category !== 'Task') ? manualStart : undefined,
      meetingEndTime: (mode === 'MANUAL' && category !== 'Task') ? manualEnd : undefined,

      // Defaults
      difficulty: 5,
      energyLevel: 'High',
      preferredDays: [],
      preferredTimeStart: "00:00",
      preferredTimeEnd: "23:59",
      preferredSessionDuration: totalHours,

      // If AI mode -> Scheduled=true (to trigger AI)
      // If Manual Meeting -> Scheduled=true (to show on calendar)
      // If Manual Task -> Scheduled=false (just a todo list item)
      isScheduled: mode === 'AI' || (mode === 'MANUAL' && category !== 'Task') 
    };

    try {
      await onSubmit(taskToSave);
    } catch (err) {
      console.error(err);
      alert("Failed to save.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const isEditing = initialTask && initialTask.id !== '';

  return (
    <div className="bg-white p-6 rounded-lg shadow-xl max-w-xl mx-auto border border-gray-200">

      <div className="mb-6">
          <div className="flex items-center justify-between mb-4">
              <h2 className="text-2xl font-bold text-gray-900 flex items-center">
                {isEditing ? 'Edit Event' : 'New Event'}
              </h2>
          </div>

          <div className="grid grid-cols-2 gap-4 p-1 bg-gray-100 rounded-lg mb-6">
              <button
                type="button"
                onClick={() => setMode('AI')}
                className={`flex items-center justify-center py-3 px-4 rounded-md text-sm font-bold transition-all ${
                    mode === 'AI' 
                    ? 'bg-white text-indigo-600 shadow-sm ring-1 ring-black/5' 
                    : 'text-gray-500 hover:text-gray-900'
                }`}
              >
                  ✨ AI Powered
              </button>
              <button
                type="button"
                onClick={() => setMode('MANUAL')}
                className={`flex items-center justify-center py-3 px-4 rounded-md text-sm font-bold transition-all ${
                    mode === 'MANUAL' 
                    ? 'bg-white text-gray-900 shadow-sm ring-1 ring-black/5' 
                    : 'text-gray-500 hover:text-gray-900'
                }`}
              >
                  📅 Manual
              </button>
          </div>

          {/* Category Selector */}
          <div>
            <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">Category</label>
            <div className="flex gap-2">
                {(['Task', 'Meeting', 'Habit'] as TaskCategory[]).map(cat => (
                    <button
                        key={cat}
                        type="button"
                        onClick={() => setCategory(cat)}
                        className={`flex-1 py-2 px-3 text-sm font-medium rounded-lg border transition-all ${
                            category === cat 
                            ? 'bg-indigo-50 border-indigo-200 text-indigo-700 ring-1 ring-indigo-200' 
                            : 'bg-white border-gray-200 text-gray-600 hover:bg-gray-50'
                        }`}
                    >
                        {cat}
                    </button>
                ))}
            </div>
          </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Title */}
        <div>
            <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">Title</label>
            <input 
              required
              type="text" 
              value={title}
              onChange={e => setTitle(e.target.value)}
              className="block w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 text-base p-3 border bg-white text-gray-900"
              placeholder={mode === 'AI' ? "e.g. Work on Project" : "e.g. Client Meeting"}
            />
        </div>

        {/* AI Mode: Strictly Minimal */}
        {mode === 'AI' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-top-4 duration-300">

                <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-lg">
                    <label className="block text-sm font-bold text-indigo-900 mb-2">
                        AI Instructions
                    </label>
                    <textarea 
                        value={description} 
                        onChange={e => setDescription(e.target.value)} 
                        rows={3} 
                        className="block w-full rounded-md border-indigo-200 shadow-sm p-3 border bg-white text-gray-900 text-sm placeholder-indigo-300 focus:border-indigo-500 focus:ring-indigo-500" 
                        placeholder={category === 'Habit' ? "e.g. Every day at 8am" : "e.g. Schedule this at 11pm tonight."} 
                    />
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">
                            {category === 'Habit' ? 'End Date' : 'Deadline'}
                        </label>
                        <input 
                            type="datetime-local" 
                            required 
                            value={deadline} 
                            onChange={e => setDeadline(e.target.value)} 
                            className="block w-full rounded-lg border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 text-sm" 
                        />
                    </div>
                    <div>
                        <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">
                            {category === 'Habit' ? 'Hours Per Day' : 'Hours Needed'}
                        </label>
                        <input 
                            type="number" 
                            min="0.25" 
                            step="0.25" 
                            value={totalHours} 
                            onChange={e => setTotalHours(parseFloat(e.target.value))} 
                            className="block w-full rounded-lg border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 text-sm" 
                        />
                    </div>
                </div>
            </div>
        )}

        {/* Manual Mode: Split between Task and Meeting */}
        {mode === 'MANUAL' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-top-4 duration-300">
                <div>
                    <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">Notes</label>
                    <textarea value={description} onChange={e => setDescription(e.target.value)} rows={2} className="block w-full rounded-md border-gray-300 shadow-sm p-3 border bg-white text-gray-900 text-sm" placeholder="Details..." />
                </div>

                <div className="bg-gray-50 p-4 rounded-lg border border-gray-200">
                    {category === 'Task' ? (
                        /* Manual Task: Date and Optional Time */
                        <div className="grid grid-cols-2 gap-4">
                             <div>
                                <label className="block text-xs font-bold text-gray-700 mb-1">Due Date</label>
                                <input type="date" required value={manualDate} onChange={e => setManualDate(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                             </div>
                             <div>
                                <label className="block text-xs font-bold text-gray-700 mb-1">Due Time (Optional)</label>
                                <input type="time" value={manualDueTime} onChange={e => setManualDueTime(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                             </div>
                             <div className="col-span-2 text-xs text-gray-500 italic">
                                * This task will appear in your list but won't be blocked on the calendar.
                             </div>
                        </div>
                    ) : (
                        /* Manual Meeting/Habit: Date and Time Range */
                        <div className="grid grid-cols-1 gap-4">
                            <div>
                                <label className="block text-xs font-bold text-gray-700 mb-1">Date</label>
                                <input type="date" required value={manualDate} onChange={e => setManualDate(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-xs font-bold text-gray-700 mb-1">Start Time</label>
                                    <input type="time" required value={manualStart} onChange={e => setManualStart(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-gray-700 mb-1">End Time</label>
                                    <input type="time" required value={manualEnd} onChange={e => setManualEnd(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                                </div>
                            </div>
                            {manualConflict && (
                                <div className="mt-2 flex items-center text-sm text-red-700 bg-red-100 p-2 rounded border border-red-200 font-medium">
                                    <svg className="w-5 h-5 mr-2" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                                    {manualConflict}
                                </div>
                            )}
                        </div>
                    )}
                </div>

                <div className="grid grid-cols-2 gap-6 border-t border-gray-200 pt-6">
                    <div>
                        <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Priority</label>
                        <div className="flex rounded-md shadow-sm bg-gray-50 border border-gray-200 p-1">
                            {(['High', 'Medium', 'Low'] as Priority[]).map((p) => (
                                <button
                                    key={p}
                                    type="button"
                                    onClick={() => setPriority(p)}
                                    className={`flex-1 py-2 text-xs font-medium rounded transition-all ${priority === p ? 'bg-white text-indigo-600 shadow-sm font-bold' : 'text-gray-500'}`}
                                >
                                    {p}
                                </button>
                            ))}
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Materials</label>
                        <label className="flex items-center justify-center w-full p-2 border border-gray-300 border-dashed rounded cursor-pointer hover:bg-gray-50">
                            <span className="text-xs text-indigo-600">+ Upload</span>
                            <input type="file" className="hidden" multiple onChange={handleFileChange} />
                        </label>
                    </div>
                </div>
            </div>
        )}

        <div className="flex justify-end gap-3 pt-6 border-t border-gray-200">
            <Button variant="ghost" type="button" onClick={onCancel}>Cancel</Button>
            <Button type="submit" isLoading={isSubmitting} disabled={!!manualConflict && mode === 'MANUAL' && category !== 'Task'}>
                {isEditing ? 'Save Changes' : (mode === 'AI' ? 'Auto-Schedule' : (category === 'Task' ? 'Add Task' : 'Add to Calendar'))}
            </Button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Task, TaskFile, Priority, TaskCategory, CalendarEvent } from '../types';
import { Button } from './Button';

interface TaskFormProps {
  initialTask?: Task | null;
  existingEvents?: CalendarEvent[];
  onSubmit: (task: Task) => Promise<void>;
  onCancel: () => void;
}

type ScheduleMode = 'AI' | 'MANUAL';

const DAYS_OF_WEEK = [
    { label: 'S', value: 'Sunday' },
    { label: 'M', value: 'Monday' },
    { label: 'T', value: 'Tuesday' },
    { label: 'W', value: 'Wednesday' },
    { label: 'T', value: 'Thursday' },
    { label: 'F', value: 'Friday' },
    { label: 'S', value: 'Saturday' },
];

export const TaskForm: React.FC<TaskFormProps> = ({ initialTask, existingEvents = [], onSubmit, onCancel }) => {
  // Mode Selection
  const [mode, setMode] = useState<ScheduleMode>('AI');

  // Common Fields
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [category, setCategory] = useState<TaskCategory>('Task');

  // AI Specific
  const [deadline, setDeadline] = useState("");
  const [totalHours, setTotalHours] = useState(1);

  // Manual Specific
  const [priority, setPriority] = useState<Priority>('Medium');
  const [files, setFiles] = useState<TaskFile[]>([]);

  // Manual Meeting/Habit
  const [manualDate, setManualDate] = useState("");
  const [manualRecurrenceEnd, setManualRecurrenceEnd] = useState(""); // For Habits
  const [manualStart, setManualStart] = useState("09:00");
  const [manualEnd, setManualEnd] = useState("10:00");
  const [selectedDays, setSelectedDays] = useState<string[]>(['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday']);

  // Manual Task
  const [manualDueTime, setManualDueTime] = useState("");

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [manualConflict, setManualConflict] = useState<string | null>(null);

  useEffect(() => {
    if (initialTask) {
        setCategory(initialTask.category);
        setTitle(initialTask.title);
        setDescription(initialTask.description);
        setFiles(initialTask.files);
        setPriority(initialTask.priority);

        if (initialTask.meetingDate) {
            // Manual Meeting or Habit Start
            setMode('MANUAL');
            setManualDate(initialTask.meetingDate || "");
            setManualStart(initialTask.meetingStartTime || "09:00");
            setManualEnd(initialTask.meetingEndTime || "10:00");

            if (initialTask.category === 'Habit') {
                setSelectedDays(initialTask.preferredDays || []);
                if (initialTask.recurrenceEndDate) {
                    const d = new Date(initialTask.recurrenceEndDate);
                    const pad = (n: number) => n < 10 ? '0'+n : n;
                    setManualRecurrenceEnd(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`);
                }
            }
        } else if (initialTask.totalHoursNeeded > 0 && initialTask.isScheduled) {
            // AI Task
            setMode('AI');
            setTotalHours(initialTask.totalHoursNeeded);
            const d = new Date(initialTask.deadline);
            if (!isNaN(d.getTime())) {
                const pad = (n: number) => n < 10 ? '0'+n : n;
                setDeadline(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`);
            }
        } else {
            // Manual Task (No meeting date, no AI scheduling)
            setMode('MANUAL');
            const d = new Date(initialTask.deadline);
            if (!isNaN(d.getTime())) {
                const pad = (n: number) => n < 10 ? '0'+n : n;
                setManualDate(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`);
                // Extract time if it wasn't default EOD
                if (d.getHours() !== 23 || d.getMinutes() !== 59) {
                     setManualDueTime(`${pad(d.getHours())}:${pad(d.getMinutes())}`);
                }
            }
        }
    } else {
        // Default
        setMode('AI');
        const now = new Date();
        const tomorrow = new Date(now);
        tomorrow.setDate(tomorrow.getDate() + 1);
        tomorrow.setHours(23, 59, 0, 0); 

        const pad = (n: number) => n < 10 ? '0'+n : n;
        setDeadline(`${tomorrow.getFullYear()}-${pad(tomorrow.getMonth()+1)}-${pad(tomorrow.getDate())}T${pad(tomorrow.getHours())}:${pad(tomorrow.getMinutes())}`);

        const todayStr = new Date().toISOString().split('T')[0];
        setManualDate(todayStr);

        // Default Habit End Date (1 month later)
        const nextMonth = new Date();
        nextMonth.setMonth(nextMonth.getMonth() + 1);
        setManualRecurrenceEnd(nextMonth.toISOString().split('T')[0]);
    }
  }, [initialTask]);

  // Conflict Detection for Manual Mode (Only for Meetings/Habits)
  useEffect(() => {
      if (mode === 'MANUAL' && category !== 'Task' && manualDate && manualStart && manualEnd) {
          const start = new Date(`${manualDate}T${manualStart}`);
          const end = new Date(`${manualDate}T${manualEnd}`);

          if (start >= end) {
              setManualConflict("End time must be after start time.");
              return;
          }

          if (category === 'Meeting') {
            // Only check single day conflict for meetings
            const hasConflict = existingEvents.some(e => {
                if (initialTask && e.relatedTaskId === initialTask.id) return false;
                return (start < e.end && end > e.start);
            });

            if (hasConflict) {
                setManualConflict("⚠ Time slot conflicts with existing event.");
            } else {
                setManualConflict(null);
            }
          } else {
             // For habits, conflict checking is complex (recurrence), skip for now
             setManualConflict(null);
          }
      } else {
          setManualConflict(null);
      }
  }, [mode, category, manualDate, manualStart, manualEnd, existingEvents, initialTask]);

  const toggleDay = (day: string) => {
      if (selectedDays.includes(day)) {
          setSelectedDays(prev => prev.filter(d => d !== day));
      } else {
          setSelectedDays(prev => [...prev, day]);
      }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: TaskFile[] = Array.from(e.target.files).map(f => ({
        name: f.name,
        size: f.size,
        type: f.type,
        url: URL.createObjectURL(f) 
      }));
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    // Validation
    if (mode === 'AI') {
        if (!deadline) { alert("Date is required."); setIsSubmitting(false); return; }
        if (totalHours <= 0) { alert("Hours needed must be greater than 0."); setIsSubmitting(false); return; }
    } else {
        // Manual Mode
        if (!manualDate) { alert("Date is required."); setIsSubmitting(false); return; }

        if (category !== 'Task') {
            // Meeting/Habit needs start/end
            if (!manualStart || !manualEnd) { alert("Start and End times required."); setIsSubmitting(false); return; }
            if (manualConflict) { alert(manualConflict); setIsSubmitting(false); return; }

            if (category === 'Habit') {
                if (!manualRecurrenceEnd) { alert("End Date is required for habits."); setIsSubmitting(false); return; }
                if (new Date(manualRecurrenceEnd) < new Date(manualDate)) { alert("End Date must be after Start Date."); setIsSubmitting(false); return; }
                if (selectedDays.length === 0) { alert("Please select at least one day for the habit."); setIsSubmitting(false); return; }
            }
        }
    }

    let calculatedDeadline = new Date();
    // Calculate Deadline based on mode
    if (mode === 'AI') {
        calculatedDeadline = new Date(deadline);
    } else {
        if (category === 'Task') {
            if (manualDueTime) {
                calculatedDeadline = new Date(`${manualDate}T${manualDueTime}`);
            } else {
                calculatedDeadline = new Date(`${manualDate}T23:59:00`);
            }
        } else {
            // Manual Meeting/Habit
            calculatedDeadline = new Date(`${manualDate}T${manualEnd}`);
        }
    }

    const taskToSave: Task = {
      id: (initialTask && initialTask.id) ? initialTask.id : crypto.randomUUID(),
      category,
      title,
      description,

      // AI Fields
      totalHoursNeeded: mode === 'AI' ? totalHours : 0,
      deadline: calculatedDeadline,

      // Manual Fields
      priority: mode === 'MANUAL' ? priority : 'Medium',
      files: mode === 'MANUAL' ? files : [],

      // Meeting/Habit Specifics
      meetingDate: (mode === 'MANUAL' && category !== 'Task') ? manualDate : undefined,
      meetingStartTime: (mode === 'MANUAL' && category !== 'Task') ? manualStart : undefined,
      meetingEndTime: (mode === 'MANUAL' && category !== 'Task') ? manualEnd : undefined,

      // Habit Specifics
      recurrenceEndDate: (mode === 'MANUAL' && category === 'Habit') ? new Date(manualRecurrenceEnd) : undefined,
      preferredDays: (mode === 'MANUAL' && category === 'Habit') ? selectedDays : [],

      // Defaults
      difficulty: 5,
      energyLevel: 'High',
      preferredTimeStart: "00:00",
      preferredTimeEnd: "23:59",
      preferredSessionDuration: totalHours,

      isScheduled: mode === 'AI' || (mode === 'MANUAL' && category !== 'Task') 
    };

    try {
      await onSubmit(taskToSave);
    } catch (err) {
      console.error(err);
      alert("Failed to save.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const isEditing = initialTask && initialTask.id !== '';

  return (
    <div className="bg-white p-6 rounded-lg shadow-xl max-w-xl mx-auto border border-gray-200">

      <div className="mb-6">
          <div className="flex items-center justify-between mb-4">
              <h2 className="text-2xl font-bold text-gray-900 flex items-center">
                {isEditing ? 'Edit Event' : 'New Event'}
              </h2>
          </div>

          <div className="grid grid-cols-2 gap-4 p-1 bg-gray-100 rounded-lg mb-6">
              <button
                type="button"
                onClick={() => setMode('AI')}
                className={`flex items-center justify-center py-3 px-4 rounded-md text-sm font-bold transition-all ${
                    mode === 'AI' 
                    ? 'bg-white text-indigo-600 shadow-sm ring-1 ring-black/5' 
                    : 'text-gray-500 hover:text-gray-900'
                }`}
              >
                  ✨ AI Powered
              </button>
              <button
                type="button"
                onClick={() => setMode('MANUAL')}
                className={`flex items-center justify-center py-3 px-4 rounded-md text-sm font-bold transition-all ${
                    mode === 'MANUAL' 
                    ? 'bg-white text-gray-900 shadow-sm ring-1 ring-black/5' 
                    : 'text-gray-500 hover:text-gray-900'
                }`}
              >
                  📅 Manual
              </button>
          </div>

          {/* Category Selector */}
          <div>
            <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">Category</label>
            <div className="flex gap-2">
                {(['Task', 'Meeting', 'Habit'] as TaskCategory[]).map(cat => (
                    <button
                        key={cat}
                        type="button"
                        onClick={() => setCategory(cat)}
                        className={`flex-1 py-2 px-3 text-sm font-medium rounded-lg border transition-all ${
                            category === cat 
                            ? 'bg-indigo-50 border-indigo-200 text-indigo-700 ring-1 ring-indigo-200' 
                            : 'bg-white border-gray-200 text-gray-600 hover:bg-gray-50'
                        }`}
                    >
                        {cat}
                    </button>
                ))}
            </div>
          </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Title */}
        <div>
            <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">Title</label>
            <input 
              required
              type="text" 
              value={title}
              onChange={e => setTitle(e.target.value)}
              className="block w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 text-base p-3 border bg-white text-gray-900"
              placeholder={mode === 'AI' ? "e.g. Work on Project" : "e.g. Client Meeting"}
            />
        </div>

        {/* AI Mode: Strictly Minimal */}
        {mode === 'AI' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-top-4 duration-300">

                <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-lg">
                    <label className="block text-sm font-bold text-indigo-900 mb-2">
                        AI Instructions
                    </label>
                    <textarea 
                        value={description} 
                        onChange={e => setDescription(e.target.value)} 
                        rows={3} 
                        className="block w-full rounded-md border-indigo-200 shadow-sm p-3 border bg-white text-gray-900 text-sm placeholder-indigo-300 focus:border-indigo-500 focus:ring-indigo-500" 
                        placeholder={category === 'Habit' ? "e.g. Every day at 8am" : "e.g. Schedule this at 11pm tonight."} 
                    />
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">
                            {category === 'Habit' ? 'End Date' : 'Deadline'}
                        </label>
                        <input 
                            type="datetime-local" 
                            required 
                            value={deadline} 
                            onChange={e => setDeadline(e.target.value)} 
                            className="block w-full rounded-lg border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 text-sm" 
                        />
                    </div>
                    <div>
                        <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">
                            {category === 'Habit' ? 'Hours Per Day' : 'Hours Needed'}
                        </label>
                        <input 
                            type="number" 
                            min="0.25" 
                            step="0.25" 
                            value={totalHours} 
                            onChange={e => setTotalHours(parseFloat(e.target.value))} 
                            className="block w-full rounded-lg border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 text-sm" 
                        />
                    </div>
                </div>
            </div>
        )}

        {/* Manual Mode: Split between Task and Meeting/Habit */}
        {mode === 'MANUAL' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-top-4 duration-300">
                <div>
                    <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">Notes</label>
                    <textarea value={description} onChange={e => setDescription(e.target.value)} rows={2} className="block w-full rounded-md border-gray-300 shadow-sm p-3 border bg-white text-gray-900 text-sm" placeholder="Details..." />
                </div>

                <div className="bg-gray-50 p-4 rounded-lg border border-gray-200">
                    {category === 'Task' ? (
                        /* Manual Task: Date and Optional Time */
                        <div className="grid grid-cols-2 gap-4">
                             <div>
                                <label className="block text-xs font-bold text-gray-700 mb-1">Due Date</label>
                                <input type="date" required value={manualDate} onChange={e => setManualDate(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                             </div>
                             <div>
                                <label className="block text-xs font-bold text-gray-700 mb-1">Due Time (Optional)</label>
                                <input type="time" value={manualDueTime} onChange={e => setManualDueTime(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                             </div>
                             <div className="col-span-2 text-xs text-gray-500 italic">
                                * This task will appear in your list but won't be blocked on the calendar.
                             </div>
                        </div>
                    ) : (
                        /* Manual Meeting or Habit */
                        <div className="grid grid-cols-1 gap-4">
                            {category === 'Habit' ? (
                                <div className="grid grid-cols-2 gap-4">
                                     <div>
                                        <label className="block text-xs font-bold text-gray-700 mb-1">Start Date</label>
                                        <input type="date" required value={manualDate} onChange={e => setManualDate(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold text-gray-700 mb-1">End Date</label>
                                        <input type="date" required value={manualRecurrenceEnd} onChange={e => setManualRecurrenceEnd(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                                    </div>
                                    <div className="col-span-2">
                                        <label className="block text-xs font-bold text-gray-700 mb-1">Repeat On</label>
                                        <div className="flex justify-between gap-1">
                                            {DAYS_OF_WEEK.map(d => (
                                                <button
                                                    key={d.value}
                                                    type="button"
                                                    onClick={() => toggleDay(d.value)}
                                                    className={`w-9 h-9 rounded-full text-xs font-bold flex items-center justify-center transition-all ${
                                                        selectedDays.includes(d.value) 
                                                        ? 'bg-indigo-600 text-white shadow-md transform scale-105' 
                                                        : 'bg-white border border-gray-200 text-gray-500 hover:bg-gray-50'
                                                    }`}
                                                >
                                                    {d.label}
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                            ) : (
                                <div>
                                    <label className="block text-xs font-bold text-gray-700 mb-1">Date</label>
                                    <input type="date" required value={manualDate} onChange={e => setManualDate(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                                </div>
                            )}

                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-xs font-bold text-gray-700 mb-1">Start Time</label>
                                    <input type="time" required value={manualStart} onChange={e => setManualStart(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-gray-700 mb-1">End Time</label>
                                    <input type="time" required value={manualEnd} onChange={e => setManualEnd(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                                </div>
                            </div>

                            {manualConflict && (
                                <div className="mt-2 flex items-center text-sm text-red-700 bg-red-100 p-2 rounded border border-red-200 font-medium">
                                    <svg className="w-5 h-5 mr-2" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                                    {manualConflict}
                                </div>
                            )}
                        </div>
                    )}
                </div>

                <div className="grid grid-cols-2 gap-6 border-t border-gray-200 pt-6">
                    <div>
                        <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Priority</label>
                        <div className="flex rounded-md shadow-sm bg-gray-50 border border-gray-200 p-1">
                            {(['High', 'Medium', 'Low'] as Priority[]).map((p) => (
                                <button
                                    key={p}
                                    type="button"
                                    onClick={() => setPriority(p)}
                                    className={`flex-1 py-2 text-xs font-medium rounded transition-all ${priority === p ? 'bg-white text-indigo-600 shadow-sm font-bold' : 'text-gray-500'}`}
                                >
                                    {p}
                                </button>
                            ))}
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Materials</label>
                        <label className="flex items-center justify-center w-full p-2 border border-gray-300 border-dashed rounded cursor-pointer hover:bg-gray-50">
                            <span className="text-xs text-indigo-600">+ Upload</span>
                            <input type="file" className="hidden" multiple onChange={handleFileChange} />
                        </label>
                    </div>
                </div>
            </div>
        )}

        <div className="flex justify-end gap-3 pt-6 border-t border-gray-200">
            <Button variant="ghost" type="button" onClick={onCancel}>Cancel</Button>
            <Button type="submit" isLoading={isSubmitting} disabled={!!manualConflict && mode === 'MANUAL' && category === 'Meeting'}>
                {isEditing ? 'Save Changes' : (mode === 'AI' ? 'Auto-Schedule' : (category === 'Task' ? 'Add Task' : 'Add to Calendar'))}
            </Button>
        </div>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { Calendar } from './components/Calendar';
import { TaskForm } from './components/TaskForm';
import { ImportModal } from './components/ImportModal';
import { EventDetailsModal } from './components/EventDetailsModal';
import { EventsView } from './components/EventsView';
import { Button } from './components/Button';
import { identifyClasses, analyzeTaskSemantics, generateFullSchedule } from './services/geminiService';
import { CalendarEvent, Task, EventType } from './types';

function App() {
  const [view, setView] = useState<'calendar' | 'events' | 'newEvent' | 'editEvent'>('calendar');
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const [currentDate, setCurrentDate] = useState(new Date());

  const handleNavigate = (direction: 'prev' | 'next' | 'today') => {
    const newDate = new Date(currentDate);
    if (direction === 'today') {
      setCurrentDate(new Date());
    } else if (direction === 'next') {
      newDate.setDate(newDate.getDate() + 7);
      setCurrentDate(newDate);
    } else {
      newDate.setDate(newDate.getDate() - 7);
      setCurrentDate(newDate);
    }
  };

  // REPLACEMENT: Async AI Scheduler
  const runGlobalScheduler = async (currentEvents: CalendarEvent[], currentTasks: Task[]) => {
    const now = new Date();

    // 1. Keep non-AI events (Fixed)
    // 2. Keep AI events that have already ended (History)
    const preservedEvents = currentEvents.filter(e => 
        e.type !== EventType.AI_WORK_SESSION || e.end <= now
    );

    // 3. Identify tasks that need scheduling (Not completed AND isScheduled=true AND has hours needed)
    // Removed category filter to allow AI to schedule Meetings/Habits if requested via AI mode.
    const tasksToSchedule = currentTasks.filter(t => !t.isCompleted && t.isScheduled && t.totalHoursNeeded > 0); 

    // 4. Generate new future sessions using AI
    let newSessions: CalendarEvent[] = [];
    if (tasksToSchedule.length > 0) {
        newSessions = await generateFullSchedule(preservedEvents, tasksToSchedule);
    }

    return [...preservedEvents, ...newSessions];
  };

  const handleImport = async (importedEvents: CalendarEvent[]) => {
    setIsImportModalOpen(false);
    setIsProcessing(true);
    try {
      const classIds = await identifyClasses(importedEvents);
      const taggedEvents = importedEvents.map(e => ({
        ...e,
        isClass: classIds.includes(e.id),
        color: classIds.includes(e.id) ? "bg-blue-50 border-blue-200 text-blue-700" : e.color
      }));

      // Combine existing events with new imported ones, then reschedule
      const allEvents = [...events, ...taggedEvents];
      const optimizedSchedule = await runGlobalScheduler(allEvents, tasks); // Await AI
      setEvents(optimizedSchedule);
    } catch (error) {
      console.error("Import error:", error);
      alert("Error processing schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCreateOrUpdateTask = async (taskInput: Task) => {
    setIsProcessing(true);
    try {
      let task = { ...taskInput };

      // AI Analysis only for flexible Tasks if not provided and in AI mode
      if (task.category === 'Task' && task.totalHoursNeeded > 0) {
          const aiAnalysis = await analyzeTaskSemantics(task.title, task.description);
          task.energyLevel = aiAnalysis.energyLevel;
      }

      let updatedTasks;
      const isUpdate = tasks.some(t => t.id === task.id);

      const newManualEvents: CalendarEvent[] = [];

      // Check for Manual Time fields
      if (task.meetingDate && task.meetingStartTime && task.meetingEndTime) {
         if (task.category === 'Habit' && task.recurrenceEndDate && task.preferredDays.length > 0) {
             // Recurring Manual Habit
             const start = new Date(task.meetingDate);
             const end = new Date(task.recurrenceEndDate);
             const loopDate = new Date(start);

             // Safety cap: Max 365 days of events
             let safety = 0;
             while (loopDate <= end && safety < 365) {
                 const dayName = loopDate.toLocaleDateString('en-US', { weekday: 'long' });

                 if (task.preferredDays.includes(dayName)) {
                     const dateStr = loopDate.toISOString().split('T')[0];
                     const s = new Date(`${dateStr}T${task.meetingStartTime}`);
                     const e = new Date(`${dateStr}T${task.meetingEndTime}`);

                     newManualEvents.push({
                         id: `manual-${task.id}-${dateStr}`,
                         title: task.title,
                         start: s,
                         end: e,
                         type: EventType.MANUAL,
                         relatedTaskId: task.id,
                         color: "bg-teal-50 border-teal-200 text-teal-700",
                         description: task.description
                     });
                 }
                 loopDate.setDate(loopDate.getDate() + 1);
                 safety++;
             }

         } else {
             // Single Manual Meeting/Event
             const start = new Date(`${task.meetingDate}T${task.meetingStartTime}`);
             const end = new Date(`${task.meetingDate}T${task.meetingEndTime}`);
             newManualEvents.push({
                 id: `manual-${task.id}`,
                 title: task.title,
                 start,
                 end,
                 type: EventType.MANUAL,
                 relatedTaskId: task.id,
                 color: task.category === 'Meeting' 
                    ? "bg-purple-50 border-purple-200 text-purple-700" 
                    : "bg-gray-50 border-gray-200 text-gray-700",
                 description: task.description
             });
         }
      }

      if (isUpdate) {
        updatedTasks = tasks.map(t => t.id === task.id ? task : t);
      } else {
        updatedTasks = [...tasks, task];
      }

      // If updating, remove old FUTURE sessions for this specific task before rescheduling
      // ALSO remove old manual events for this task if we are updating it (so we don't duplicate or leave ghosts)
      const now = new Date();
      let currentEvents = events.filter(e => {
          if (e.relatedTaskId === task.id) {
              if (e.type === EventType.AI_WORK_SESSION && e.end <= now) return true; // Keep history
              return false; // Remove future AI or old Manual events
          }
          return true;
      });

      // Add all new manual events
      currentEvents = [...currentEvents, ...newManualEvents];

      const optimizedSchedule = await runGlobalScheduler(currentEvents, updatedTasks);

      setEvents(optimizedSchedule);
      setTasks(updatedTasks);
      setView('calendar');
      setEditingTask(null);

    } catch (error) {
      console.error(error);
      alert("Error generating schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDeleteEvent = async (id: string) => {
    const eventToDelete = events.find(e => e.id === id);
    if (!eventToDelete) return;

    if (eventToDelete.type === EventType.AI_WORK_SESSION) {
        // Just delete the single session locally
        setEvents(prev => prev.filter(e => e.id !== id));
    } else {
        // If deleting a fixed event, we need to re-shuffle flexible tasks to fill the gap
        setIsProcessing(true);
        try {
            const remainingEvents = events.filter(e => e.id !== id);
            const optimizedSchedule = await runGlobalScheduler(remainingEvents, tasks);
            setEvents(optimizedSchedule);
        } finally {
            setIsProcessing(false);
        }
    }
  };

  const handleDeleteTask = async (taskId: string) => {
      // Optimistic update: Remove immediately from UI
      const updatedTasks = tasks.filter(t => t.id !== taskId);
      setTasks(updatedTasks);
      const remainingEvents = events.filter(e => e.relatedTaskId !== taskId);
      setEvents(remainingEvents);

      setIsProcessing(true);
      try {
          // Reschedule remaining tasks in background to fill any gaps left
          const optimizedSchedule = await runGlobalScheduler(remainingEvents, updatedTasks);
          setEvents(optimizedSchedule);
      } catch(e) {
          console.error("Failed to reschedule after delete", e);
          // Note: We don't revert the delete because user intent was clear.
      } finally {
          setIsProcessing(false);
      }
  };

  const handleUpdateEvent = (updatedEvent: CalendarEvent) => {
    const finalEvent = {
        ...updatedEvent,
        type: updatedEvent.type === EventType.AI_WORK_SESSION ? EventType.MANUAL : updatedEvent.type,
    };
    setEvents(prevEvents => {
        const otherEvents = prevEvents.filter(e => e.id !== updatedEvent.id);
        const newEventList = [...otherEvents, finalEvent];
        return newEventList;
    });
  };

  const handleToggleTaskComplete = async (taskId: string, isComplete: boolean) => {
      setIsProcessing(true);
      try {
          const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, isCompleted: isComplete } : t);
          setTasks(updatedTasks);

          if (isComplete) {
              // Completed: Remove FUTURE AI sessions for this task
              const now = new Date();
              const updatedEvents = events.filter(e => {
                  if (e.relatedTaskId === taskId && e.type === EventType.AI_WORK_SESSION && e.start > now) {
                      return false; 
                  }
                  return true;
              });
              setEvents(updatedEvents);
          } else {
              // Undo Complete: Re-activate and Schedule using AI
              const optimizedSchedule = await runGlobalScheduler(events, updatedTasks);
              setEvents(optimizedSchedule);
          }
      } finally {
          setIsProcessing(false);
      }
  };

  const handleCalendarSlotClick = (date: Date) => {
      const startStr = date.toTimeString().slice(0, 5); // HH:mm
      const end = new Date(date.getTime() + 60*60*1000); // +1 hour
      const endStr = end.toTimeString().slice(0, 5);

      const pad = (n: number) => n < 10 ? '0'+n : n;
      const dateStr = `${date.getFullYear()}-${pad(date.getMonth()+1)}-${pad(date.getDate())}`;

      const draftTask: Task = {
          id: '', 
          category: 'Meeting', 
          title: '',
          description: '',
          priority: 'Medium',
          files: [],
          difficulty: 5,
          totalHoursNeeded: 0, // Manual = 0 hours needed for AI
          deadline: new Date(date.getTime() + 7*24*60*60*1000), 
          energyLevel: 'High',
          meetingDate: dateStr,
          meetingStartTime: startStr,
          meetingEndTime: endStr,
          preferredDays: [],
          preferredTimeStart: '09:00',
          preferredTimeEnd: '17:00',
          preferredSessionDuration: 1,
          isScheduled: true 
      };

      setEditingTask(draftTask);
      setView('newEvent');
  };

  const selectedTask = selectedEvent?.relatedTaskId 
    ? tasks.find(t => t.id === selectedEvent.relatedTaskId) 
    : undefined;

  return (
    <div className="min-h-screen flex flex-col relative bg-gray-50 text-gray-900 font-sans">
      <nav className="border-b border-gray-200 bg-white sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <span className="bg-indigo-600 text-white p-1.5 rounded mr-3 font-bold">SP</span>
              <h1 className="text-xl font-bold tracking-tight text-gray-900 hidden sm:block">SparkPlan AI</h1>

              <div className="ml-8 flex space-x-1">
                 <button 
                    onClick={() => setView('calendar')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'calendar' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Calendar
                 </button>
                 <button 
                    onClick={() => setView('events')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'events' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Events
                 </button>
              </div>
            </div>
            <div className="flex items-center space-x-4">
              <Button variant="ghost" onClick={() => setIsImportModalOpen(true)}>Import</Button>
              <Button onClick={() => { setEditingTask(null); setView('newEvent'); }} disabled={view === 'newEvent'}>
                + New Event
              </Button>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {view === 'calendar' && (
          <>
            <div className="mb-6 flex items-center justify-between">
              <div>
                <h2 className="text-xl font-bold text-gray-900 tracking-tight">Dashboard</h2>
                <p className="text-sm text-gray-500 mt-1">
                  {events.filter(e => e.type === EventType.AI_WORK_SESSION).length} active work sessions.
                </p>
              </div>
              <div className="flex gap-4 text-xs font-medium text-gray-600">
                 <div className="flex items-center"><div className="w-2 h-2 bg-blue-400 rounded-full mr-2"></div> Class</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-gray-400 rounded-full mr-2"></div> Manual</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-teal-400 rounded-full mr-2"></div> Habit</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-indigo-600 rounded-full mr-2"></div> Task</div>
              </div>
            </div>
            <div className="h-[calc(100vh-200px)]">
               <Calendar 
                  events={events} 
                  currentDate={currentDate} 
                  onEventClick={setSelectedEvent}
                  onNavigate={handleNavigate}
                  onEventUpdate={handleUpdateEvent}
                  onSlotClick={handleCalendarSlotClick}
               />
            </div>
          </>
        )}

        {view === 'events' && (
            <EventsView 
                tasks={tasks} 
                events={events}
                onEditTask={(task) => {
                    setEditingTask(task);
                    setView('editEvent');
                }}
                onDeleteTask={handleDeleteTask}
                onToggleComplete={handleToggleTaskComplete}
            />
        )}

        {(view === 'newEvent' || view === 'editEvent') && (
          <div className="py-8">
            <TaskForm 
              initialTask={editingTask}
              existingEvents={events}
              onSubmit={handleCreateOrUpdateTask} 
              onCancel={() => {
                  setEditingTask(null);
                  setView('calendar');
              }} 
            />
          </div>
        )}
      </main>

      <ImportModal 
        isOpen={isImportModalOpen} 
        onClose={() => setIsImportModalOpen(false)} 
        onImport={handleImport} 
      />

      <EventDetailsModal 
        event={selectedEvent} 
        relatedTask={selectedTask}
        onClose={() => setSelectedEvent(null)}
        onDelete={handleDeleteEvent}
        onUpdate={handleUpdateEvent}
      />

      {isProcessing && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-900 bg-opacity-50 backdrop-blur-sm transition-opacity">
            <div className="flex flex-col items-center p-6 bg-white rounded-lg shadow-xl">
                <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
                <h3 className="text-lg font-bold text-gray-900 tracking-widest uppercase">AI Planning</h3>
                <p className="text-xs text-gray-500 mt-2">Consulting the AI for the best slots...</p>
            </div>
        </div>
      )}

    </div>
  );
}

