        {/* AI Mode: Strictly Minimal */}
        {mode === 'AI' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-top-4 duration-300">

                <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-lg">
