const callWithTimeout = async <T>(promise: Promise<T>, ms: number): Promise<T> => {
    let timeoutId: any;
    const timeoutPromise = new Promise<T>((_, reject) => {
        timeoutId = setTimeout(() => reject(new Error(`AI Request timed out after ${ms}ms`)), ms);
    });
    try {
        const result = await Promise.race([promise, timeoutPromise]);
        clearTimeout(timeoutId);
        return result;
    } catch (e) {
        clearTimeout(timeoutId);
        throw e;
    }
};

export const identifyClasses = async (events: CalendarEvent[]): Promise<string[]> => {
  if (events.length === 0) return [];
  const uniqueEvents = new Map<string, { title: string; description: string }>();
  events.forEach(e => {
    if (!uniqueEvents.has(e.title)) uniqueEvents.set(e.title, { title: e.title, description: e.description || "" });
  });
  const distinctEventList = Array.from(uniqueEvents.values()).slice(0, 150);
  const prompt = `Identify University Classes in list: ${JSON.stringify(distinctEventList)}. Return {"classTitles": ["Exact Title"]}.`;
  try {
    const apiCall = ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: { responseMimeType: "application/json", temperature: 0.1 },
    });
    const response = await callWithTimeout<GenerateContentResponse>(apiCall, 15000);
    const result = JSON.parse(response.text || '{}') as { classTitles: string[] };
    const classTitles = new Set(result.classTitles || []);
    return events.filter(e => classTitles.has(e.title)).map(e => e.id);
  } catch (error) { return []; }
};

export const analyzeTaskSemantics = async (title: string, description: string): Promise<{ energyLevel: EnergyLevel }> => {
    if (!title && !description) return { energyLevel: 'High' };
    const prompt = `Classify task energy: "${title} ${description}". Return {"energyLevel": "High" or "Low"}. High=Morning/Focus, Low=Evening/Relax.`;
    try {
        const apiCall = ai.models.generateContent({
            model: MODEL_NAME,
            contents: prompt,
            config: { responseMimeType: "application/json", temperature: 0.1 }
        });
        const response = await callWithTimeout<GenerateContentResponse>(apiCall, 8000);
        const result = JSON.parse(response.text || '{}');
        return { energyLevel: result.energyLevel || 'High' };
    } catch (e) { return { energyLevel: 'High' }; }
};

export const generateFullSchedule = async (fixedEvents: CalendarEvent[], tasksToSchedule: Task[]): Promise<CalendarEvent[]> => {
    if (tasksToSchedule.length === 0) return [];
    const now = new Date();

    // Provide a 10-day lookahead context for scheduling
    const contextEnd = new Date(now);
    contextEnd.setDate(contextEnd.getDate() + 10);

    const relevantFixed = fixedEvents
        .filter(e => e.start >= now && e.start <= contextEnd && !e.isGhost) // Ignore ghost events for backend logic
        .map(e => ({
            title: e.title,
            start: e.start.toISOString(),
            end: e.end.toISOString()
        }));

    const tasksContext = tasksToSchedule.map(t => ({
        id: t.id,
        category: t.category,
        title: t.title,
        instructions: t.description, 
        durationHours: t.totalHoursNeeded,
        deadline: t.deadline.toISOString()
    }));

    // Detect User Timezone Information
    const timeZone = Intl.DateTimeFormat().resolvedOptions().timeZone;
    const localTime = now.toLocaleString('en-US', { timeZone, hour12: false });

    const systemPrompt = `You are a high-performance scheduling engine. 
    You DO NOT speak. You DO NOT output conversational text. 
    You ONLY output valid JSON.

    CRITICAL INSTRUCTION:
    Your output must be a single JSON object containing a 'sessions' array.
    This mimics a parallel function call to schedule multiple tasks at once.

    INPUT DATA:
    - User Timezone: ${timeZone}
    - Local Time: ${localTime}
    - Fixed Slots (Busy): Array of start/end times.
    - Tasks: Array of tasks to schedule.

    LOGIC:
    1. Find gaps in Fixed Slots.
    2. Place Tasks in gaps before their deadline.
    3. Convert User Local Time instructions (e.g. "at 5pm") to UTC ISO8601.
    4. Return strict JSON.
    `;

    const userContent = JSON.stringify({
        fixedSlots: relevantFixed,
        tasks: tasksContext
    });

    try {
        const apiCall = ai.models.generateContent({
            model: MODEL_NAME,
            contents: userContent,
            config: { 
                systemInstruction: systemPrompt,
                responseMimeType: "application/json", 
                temperature: 0.2 
            }
        });
        const response = await callWithTimeout<GenerateContentResponse>(apiCall, 45000); 
        const result = JSON.parse(response.text || '{}') as { sessions: any[] };

        return (result.sessions || []).map(s => {
            const task = tasksToSchedule.find(t => t.id === s.taskId);
            if (!task) return null;
            return {
                id: crypto.randomUUID(),
                title: task.title,
                start: new Date(s.start),
                end: new Date(s.end),
                type: EventType.AI_WORK_SESSION,
                relatedTaskId: task.id,
                description: s.reasoning,
                color: task.category === 'Habit' ? "bg-teal-50 border-teal-200 text-teal-700" : (task.category === 'Meeting' ? "bg-purple-50 border-purple-200 text-purple-700" : "bg-indigo-50 border-indigo-200 text-indigo-700"),
                priority: task.priority
            };
        }).filter(e => e !== null) as CalendarEvent[];

    } catch (e) {
        console.error("AI Scheduler Error:", e);
        return [];
    }
};

import React, { useState } from 'react';
import { Calendar } from './components/Calendar';
import { TaskForm } from './components/TaskForm';
import { ImportModal } from './components/ImportModal';
import { EventDetailsModal } from './components/EventDetailsModal';
import { EventsView } from './components/EventsView';
import { Button } from './components/Button';
import { identifyClasses, analyzeTaskSemantics, generateFullSchedule } from './services/geminiService';
import { CalendarEvent, Task, EventType } from './types';

function App() {
  const [view, setView] = useState<'calendar' | 'events' | 'newEvent' | 'editEvent'>('calendar');
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const [currentDate, setCurrentDate] = useState(new Date());

  const handleNavigate = (direction: 'prev' | 'next' | 'today') => {
    const newDate = new Date(currentDate);
    if (direction === 'today') {
      setCurrentDate(new Date());
    } else if (direction === 'next') {
      newDate.setDate(newDate.getDate() + 7);
      setCurrentDate(newDate);
    } else {
      newDate.setDate(newDate.getDate() - 7);
      setCurrentDate(newDate);
    }
  };

  // REPLACEMENT: Async AI Scheduler
  const runGlobalScheduler = async (currentEvents: CalendarEvent[], currentTasks: Task[]) => {
    const now = new Date();

    // 1. Keep non-AI events (Fixed)
    // 2. Keep AI events that have already ended (History)
    // 3. IMPORTANT: Ignore Ghost events when calculating busy slots for the backend
    const preservedEvents = currentEvents.filter(e => 
        (e.type !== EventType.AI_WORK_SESSION || e.end <= now) && !e.isGhost
    );

    // 3. Identify tasks that need scheduling (Not completed AND isScheduled=true AND has hours needed)
    // Removed category filter to allow AI to schedule Meetings/Habits if requested via AI mode.
    const tasksToSchedule = currentTasks.filter(t => !t.isCompleted && t.isScheduled && t.totalHoursNeeded > 0); 

    // 4. Generate new future sessions using AI
    let newSessions: CalendarEvent[] = [];
    if (tasksToSchedule.length > 0) {
        newSessions = await generateFullSchedule(preservedEvents, tasksToSchedule);
    }

    return [...preservedEvents, ...newSessions];
  };

  const handleImport = async (importedEvents: CalendarEvent[]) => {
    setIsImportModalOpen(false);
    setIsProcessing(true);
    try {
      const classIds = await identifyClasses(importedEvents);
      const taggedEvents = importedEvents.map(e => ({
        ...e,
        isClass: classIds.includes(e.id),
        color: classIds.includes(e.id) ? "bg-blue-50 border-blue-200 text-blue-700" : e.color
      }));

      // Combine existing events with new imported ones, then reschedule
      const allEvents = [...events, ...taggedEvents];
      const optimizedSchedule = await runGlobalScheduler(allEvents, tasks); // Await AI
      setEvents(optimizedSchedule);
    } catch (error) {
      console.error("Import error:", error);
      alert("Error processing schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCreateOrUpdateTask = async (taskInput: Task) => {
    // Note: We do NOT set isProcessing(true) here for AI tasks anymore because we use Optimistic UI
    try {
      let task = { ...taskInput };

      // AI Analysis only for flexible Tasks if not provided and in AI mode
      if (task.category === 'Task' && task.totalHoursNeeded > 0) {
          // This is fast enough to await, or we could optimistic this too, but for now we await classification
          // If we wanted true sub-second for everything, we'd skip this or mock it.
          // Let's assume this is fast enough (Flash model).
          const aiAnalysis = await analyzeTaskSemantics(task.title, task.description);
          task.energyLevel = aiAnalysis.energyLevel;
      }

      let updatedTasks;
      const isUpdate = tasks.some(t => t.id === task.id);

      const newManualEvents: CalendarEvent[] = [];

      // Check for Manual Time fields
      if (task.meetingDate && task.meetingStartTime && task.meetingEndTime) {
         // ... (Manual Habit Logic - kept same) ...
         if (task.category === 'Habit' && task.recurrenceEndDate && task.preferredDays.length > 0) {
             const [sYear, sMonth, sDay] = task.meetingDate.split('-').map(Number);
             const loopDate = new Date(sYear, sMonth - 1, sDay); 

             const eD = new Date(task.recurrenceEndDate);
             const finalDate = new Date(eD.getFullYear(), eD.getMonth(), eD.getDate());
             finalDate.setHours(23, 59, 59, 999);

             let safety = 0;
             while (loopDate <= finalDate && safety < 365) {
                 const dayName = loopDate.toLocaleDateString('en-US', { weekday: 'long' });

                 if (task.preferredDays.includes(dayName)) {
                     const pad = (n: number) => n < 10 ? '0'+n : n;
                     const dateStr = `${loopDate.getFullYear()}-${pad(loopDate.getMonth()+1)}-${pad(loopDate.getDate())}`;

                     const s = new Date(`${dateStr}T${task.meetingStartTime}`);
                     const e = new Date(`${dateStr}T${task.meetingEndTime}`);

                     newManualEvents.push({
                         id: `manual-${task.id}-${dateStr}`,
                         title: task.title,
                         start: s,
                         end: e,
                         type: EventType.MANUAL,
                         relatedTaskId: task.id,
                         color: "bg-teal-50 border-teal-200 text-teal-700",
                         description: task.description
                     });
                 }
                 loopDate.setDate(loopDate.getDate() + 1);
                 safety++;
             }

         } else {
             // Single Manual Meeting/Event
             const start = new Date(`${task.meetingDate}T${task.meetingStartTime}`);
             const end = new Date(`${task.meetingDate}T${task.meetingEndTime}`);
             newManualEvents.push({
                 id: `manual-${task.id}`,
                 title: task.title,
                 start,
                 end,
                 type: EventType.MANUAL,
                 relatedTaskId: task.id,
                 color: task.category === 'Meeting' 
                    ? "bg-purple-50 border-purple-200 text-purple-700" 
                    : "bg-gray-50 border-gray-200 text-gray-700",
                 description: task.description
             });
         }
      }

      if (isUpdate) {
        updatedTasks = tasks.map(t => t.id === task.id ? task : t);
      } else {
        updatedTasks = [...tasks, task];
      }

      // --- OPTIMISTIC UI LOGIC ---

      // 1. Close Modal Immediately
      setView('calendar');
      setEditingTask(null);
      setTasks(updatedTasks);

      // 2. Prepare Events (remove old future AI events for this task)
      const now = new Date();
      let currentEvents = events.filter(e => {
          if (e.relatedTaskId === task.id) {
              if (e.type === EventType.AI_WORK_SESSION && e.end <= now) return true; // Keep history
              return false; // Remove future
          }
          return true;
      });
      currentEvents = [...currentEvents, ...newManualEvents];

      // 3. Inject Ghost Event if it's an AI task
      if (task.isScheduled && task.totalHoursNeeded > 0 && newManualEvents.length === 0) {
          const ghostStart = new Date();
          ghostStart.setHours(ghostStart.getHours() + 1, 0, 0, 0); // Tentative: Next hour
          const ghostEnd = new Date(ghostStart.getTime() + (task.totalHoursNeeded * 60 * 60 * 1000));

          const ghostEvent: CalendarEvent = {
              id: `ghost-${task.id}`,
              title: `Scheduling: ${task.title}...`,
              start: ghostStart,
              end: ghostEnd,
              type: EventType.AI_WORK_SESSION,
              relatedTaskId: task.id,
              color: "bg-gray-100",
              isGhost: true // Triggers Skeleton UI
          };

          // Show ghost immediately
          setEvents([...currentEvents, ghostEvent]);
      } else {
          // Manual events are shown immediately
          setEvents(currentEvents);
      }

      // 4. Run AI Backend (Parallel/Async)
      // This will overwrite the ghost event when it returns
      runGlobalScheduler(currentEvents, updatedTasks).then((optimizedSchedule) => {
          setEvents(optimizedSchedule);
      }).catch((err) => {
          console.error("Scheduling failed", err);
          alert("Automatic scheduling failed. Please try again.");
          // Rollback ghost
          setEvents(currentEvents);
      });

    } catch (error) {
      console.error(error);
      alert("Error saving task.");
      setIsProcessing(false);
    }
  };

  const handleDeleteEvent = async (id: string) => {
    const eventToDelete = events.find(e => e.id === id);
    if (!eventToDelete) return;

    if (eventToDelete.type === EventType.AI_WORK_SESSION) {
        // Just delete the single session locally
        setEvents(prev => prev.filter(e => e.id !== id));
    } else {
        // If deleting a fixed event, we need to re-shuffle flexible tasks to fill the gap
        setIsProcessing(true);
        try {
            const remainingEvents = events.filter(e => e.id !== id);
            const optimizedSchedule = await runGlobalScheduler(remainingEvents, tasks);
            setEvents(optimizedSchedule);
        } finally {
            setIsProcessing(false);
        }
    }
  };

  const handleDeleteTask = async (taskId: string) => {
      // Optimistic update: Remove immediately from UI
      const updatedTasks = tasks.filter(t => t.id !== taskId);
      setTasks(updatedTasks);
      const remainingEvents = events.filter(e => e.relatedTaskId !== taskId);
      setEvents(remainingEvents);

      setIsProcessing(true);
      try {
          // Reschedule remaining tasks in background to fill any gaps left
          const optimizedSchedule = await runGlobalScheduler(remainingEvents, updatedTasks);
          setEvents(optimizedSchedule);
      } catch(e) {
          console.error("Failed to reschedule after delete", e);
          // Note: We don't revert the delete because user intent was clear.
      } finally {
          setIsProcessing(false);
      }
  };

  const handleUpdateEvent = (updatedEvent: CalendarEvent) => {
    const finalEvent = {
        ...updatedEvent,
        type: updatedEvent.type === EventType.AI_WORK_SESSION ? EventType.MANUAL : updatedEvent.type,
    };
    setEvents(prevEvents => {
        const otherEvents = prevEvents.filter(e => e.id !== updatedEvent.id);
        const newEventList = [...otherEvents, finalEvent];
        return newEventList;
    });
  };

  const handleToggleTaskComplete = async (taskId: string, isComplete: boolean) => {
      // Optimistic Update
      const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, isCompleted: isComplete } : t);
      setTasks(updatedTasks);

      if (isComplete) {
          const now = new Date();
          setEvents(prev => prev.filter(e => {
              if (e.relatedTaskId === taskId && e.type === EventType.AI_WORK_SESSION && e.start > now) return false;
              return true;
          }));
      } else {
          // Re-schedule in background
          runGlobalScheduler(events, updatedTasks).then(setEvents);
      }
  };

  const handleCalendarSlotClick = (date: Date) => {
      const startStr = date.toTimeString().slice(0, 5); // HH:mm
      const end = new Date(date.getTime() + 60*60*1000); // +1 hour
      const endStr = end.toTimeString().slice(0, 5);

      const pad = (n: number) => n < 10 ? '0'+n : n;
      const dateStr = `${date.getFullYear()}-${pad(date.getMonth()+1)}-${pad(date.getDate())}`;

      const draftTask: Task = {
          id: '', 
          category: 'Meeting', 
          title: '',
          description: '',
          priority: 'Medium',
          files: [],
          difficulty: 5,
          totalHoursNeeded: 0, // Manual = 0 hours needed for AI
          deadline: new Date(date.getTime() + 7*24*60*60*1000), 
          energyLevel: 'High',
          meetingDate: dateStr,
          meetingStartTime: startStr,
          meetingEndTime: endStr,
          preferredDays: [],
          preferredTimeStart: '09:00',
          preferredTimeEnd: '17:00',
          preferredSessionDuration: 1,
          isScheduled: true 
      };

      setEditingTask(draftTask);
      setView('newEvent');
  };

  const selectedTask = selectedEvent?.relatedTaskId 
    ? tasks.find(t => t.id === selectedEvent.relatedTaskId) 
    : undefined;

  return (
    <div className="min-h-screen flex flex-col relative bg-gray-50 text-gray-900 font-sans">
      <nav className="border-b border-gray-200 bg-white sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <span className="bg-indigo-600 text-white p-1.5 rounded mr-3 font-bold">SP</span>
              <h1 className="text-xl font-bold tracking-tight text-gray-900 hidden sm:block">SparkPlan AI</h1>

              <div className="ml-8 flex space-x-1">
                 <button 
                    onClick={() => setView('calendar')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'calendar' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Calendar
                 </button>
                 <button 
                    onClick={() => setView('events')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'events' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Events
                 </button>
              </div>
            </div>
            <div className="flex items-center space-x-4">
              <Button variant="ghost" onClick={() => setIsImportModalOpen(true)}>Import</Button>
              <Button onClick={() => { setEditingTask(null); setView('newEvent'); }} disabled={view === 'newEvent'}>
                + New Event
              </Button>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {view === 'calendar' && (
          <>
            <div className="mb-6 flex items-center justify-between">
              <div>
                <h2 className="text-xl font-bold text-gray-900 tracking-tight">Dashboard</h2>
                <p className="text-sm text-gray-500 mt-1">
                  {events.filter(e => e.type === EventType.AI_WORK_SESSION && !e.isGhost).length} active work sessions.
                </p>
              </div>
              <div className="flex gap-4 text-xs font-medium text-gray-600">
                 <div className="flex items-center"><div className="w-2 h-2 bg-blue-400 rounded-full mr-2"></div> Class</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-gray-400 rounded-full mr-2"></div> Manual</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-teal-400 rounded-full mr-2"></div> Habit</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-indigo-600 rounded-full mr-2"></div> Task</div>
              </div>
            </div>
            <div className="h-[calc(100vh-200px)]">
               <Calendar 
                  events={events} 
                  currentDate={currentDate} 
                  onEventClick={setSelectedEvent}
                  onNavigate={handleNavigate}
                  onEventUpdate={handleUpdateEvent}
                  onSlotClick={handleCalendarSlotClick}
               />
            </div>
          </>
        )}

        {view === 'events' && (
            <EventsView 
                tasks={tasks} 
                events={events}
                onEditTask={(task) => {
                    setEditingTask(task);
                    setView('editEvent');
                }}
                onDeleteTask={handleDeleteTask}
                onToggleComplete={handleToggleTaskComplete}
            />
        )}

        {(view === 'newEvent' || view === 'editEvent') && (
          <div className="py-8">
            <TaskForm 
              initialTask={editingTask}
              existingEvents={events}
              onSubmit={handleCreateOrUpdateTask} 
              onCancel={() => {
                  setEditingTask(null);
                  setView('calendar');
              }} 
            />
          </div>
        )}
      </main>

      <ImportModal 
        isOpen={isImportModalOpen} 
        onClose={() => setIsImportModalOpen(false)} 
        onImport={handleImport} 
      />

      <EventDetailsModal 
        event={selectedEvent} 
        relatedTask={selectedTask}
        onClose={() => setSelectedEvent(null)}
        onDelete={handleDeleteEvent}
        onUpdate={handleUpdateEvent}
      />

      {isProcessing && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-900 bg-opacity-50 backdrop-blur-sm transition-opacity">
            <div className="flex flex-col items-center p-6 bg-white rounded-lg shadow-xl">
                <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
                <h3 className="text-lg font-bold text-gray-900 tracking-widest uppercase">AI Planning</h3>
                <p className="text-xs text-gray-500 mt-2">Consulting the AI for the best slots...</p>
            </div>
        </div>
      )}

    </div>
  );
}

export default App;

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { CalendarEvent, Task, EventType, EnergyLevel } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Using Flash model for speed/intent extraction as requested
const MODEL_NAME = "gemini-3-flash-preview";

const callWithTimeout = async <T>(promise: Promise<T>, ms: number): Promise<T> => {
    let timeoutId: any;
    const timeoutPromise = new Promise<T>((_, reject) => {
        timeoutId = setTimeout(() => reject(new Error(`AI Request timed out after ${ms}ms`)), ms);
    });
    try {
        const result = await Promise.race([promise, timeoutPromise]);
        clearTimeout(timeoutId);
        return result;
    } catch (e) {
        clearTimeout(timeoutId);
        throw e;
    }
};

export const identifyClasses = async (events: CalendarEvent[]): Promise<string[]> => {
  if (events.length === 0) return [];
  const uniqueEvents = new Map<string, { title: string; description: string }>();
  events.forEach(e => {
    if (!uniqueEvents.has(e.title)) uniqueEvents.set(e.title, { title: e.title, description: e.description || "" });
  });
  const distinctEventList = Array.from(uniqueEvents.values()).slice(0, 150);
  const prompt = `Identify University Classes in list: ${JSON.stringify(distinctEventList)}. Return {"classTitles": ["Exact Title"]}.`;
  try {
    const apiCall = ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: { responseMimeType: "application/json", temperature: 0.1 },
    });
    const response = await callWithTimeout<GenerateContentResponse>(apiCall, 15000);
    const result = JSON.parse(response.text || '{}') as { classTitles: string[] };
    const classTitles = new Set(result.classTitles || []);
    return events.filter(e => classTitles.has(e.title)).map(e => e.id);
  } catch (error) { return []; }
};

export const analyzeTaskSemantics = async (title: string, description: string): Promise<{ energyLevel: EnergyLevel }> => {
    if (!title && !description) return { energyLevel: 'High' };
    const prompt = `Classify task energy: "${title} ${description}". Return {"energyLevel": "High" or "Low"}. High=Morning/Focus, Low=Evening/Relax.`;
    try {
        const apiCall = ai.models.generateContent({
            model: MODEL_NAME,
            contents: prompt,
            config: { responseMimeType: "application/json", temperature: 0.1 }
        });
        const response = await callWithTimeout<GenerateContentResponse>(apiCall, 8000);
        const result = JSON.parse(response.text || '{}');
        return { energyLevel: result.energyLevel || 'High' };
    } catch (e) { return { energyLevel: 'High' }; }
};

export const generateFullSchedule = async (fixedEvents: CalendarEvent[], tasksToSchedule: Task[]): Promise<CalendarEvent[]> => {
    if (tasksToSchedule.length === 0) return [];
    const now = new Date();

    // Provide a 10-day lookahead context for scheduling
    const contextEnd = new Date(now);
    contextEnd.setDate(contextEnd.getDate() + 10);

    const relevantFixed = fixedEvents
        .filter(e => e.start >= now && e.start <= contextEnd && !e.isGhost) // Ignore ghost events for backend logic
        .map(e => {
            // APPLY BUFFER LOGIC:
            // Pad existing events by 15 minutes on both ends.
            // This forces the AI to see the adjacent time as "busy", ensuring 
            // the next task starts at least 15 minutes later.
            const bufferedStart = new Date(e.start);
            bufferedStart.setMinutes(bufferedStart.getMinutes() - 15);

            const bufferedEnd = new Date(e.end);
            bufferedEnd.setMinutes(bufferedEnd.getMinutes() + 15);

            return {
                title: e.title,
                start: bufferedStart.toISOString(),
                end: bufferedEnd.toISOString()
            };
        });

    const tasksContext = tasksToSchedule.map(t => ({
        id: t.id,
        category: t.category,
        title: t.title,
        instructions: t.description, 
        durationHours: t.totalHoursNeeded,
        deadline: t.deadline.toISOString()
    }));

    // Detect User Timezone Information
    const timeZone = Intl.DateTimeFormat().resolvedOptions().timeZone;
    const localTime = now.toLocaleString('en-US', { timeZone, hour12: false });

    const systemPrompt = `You are a high-performance scheduling engine. 
    You DO NOT speak. You DO NOT output conversational text. 
    You ONLY output valid JSON.

    CRITICAL INSTRUCTION:
    Your output must be a single JSON object containing a 'sessions' array.
    This mimics a parallel function call to schedule multiple tasks at once.

    INPUT DATA:
    - User Timezone: ${timeZone}
    - Local Time: ${localTime}
    - Fixed Slots (Busy): Array of start/end times (includes safety buffers).
    - Tasks: Array of tasks to schedule.

    LOGIC:
    1. Find gaps in Fixed Slots.
    2. Place Tasks in gaps before their deadline.
    3. Convert User Local Time instructions (e.g. "at 5pm") to UTC ISO8601.
    4. CONSTRAINT: You MUST leave at least 15 minutes of gap between any two generated sessions. Do not schedule tasks strictly back-to-back.
    5. Return strict JSON.
    `;

    const userContent = JSON.stringify({
        fixedSlots: relevantFixed,
        tasks: tasksContext
    });

    try {
        const apiCall = ai.models.generateContent({
            model: MODEL_NAME,
            contents: userContent,
            config: { 
                systemInstruction: systemPrompt,
                responseMimeType: "application/json", 
                temperature: 0.2 
            }
        });
        const response = await callWithTimeout<GenerateContentResponse>(apiCall, 45000); 
        const result = JSON.parse(response.text || '{}') as { sessions: any[] };

        return (result.sessions || []).map(s => {
            const task = tasksToSchedule.find(t => t.id === s.taskId);
            if (!task) return null;
            return {
                id: crypto.randomUUID(),
                title: task.title,
                start: new Date(s.start),
                end: new Date(s.end),
                type: EventType.AI_WORK_SESSION,
                relatedTaskId: task.id,
                description: s.reasoning,
                color: task.category === 'Habit' ? "bg-teal-50 border-teal-200 text-teal-700" : (task.category === 'Meeting' ? "bg-purple-50 border-purple-200 text-purple-700" : "bg-indigo-50 border-indigo-200 text-indigo-700"),
                priority: task.priority
            };
        }).filter(e => e !== null) as CalendarEvent[];

    } catch (e) {
        console.error("AI Scheduler Error:", e);
        return [];
    }
};

export enum EventType {
  IMPORTED = 'IMPORTED', // From ICS or external
  MANUAL = 'MANUAL',     // User manually added
  AI_WORK_SESSION = 'AI_WORK_SESSION' // Generated by Engine
}

