export const generateFullSchedule = async (fixedEvents: CalendarEvent[], tasksToSchedule: Task[]): Promise<CalendarEvent[]> => {
    if (tasksToSchedule.length === 0) return [];
    const now = new Date();

    // Provide a 120-day lookahead context for scheduling
    const contextEnd = new Date(now);
    contextEnd.setDate(contextEnd.getDate() + 120);

    const relevantFixed = fixedEvents
        .filter(e => e.start >= now && e.start <= contextEnd && !e.isGhost) // Ignore ghost events for backend logic
        .map(e => {
            // APPLY BUFFER LOGIC:
            // Pad existing events by 15 minutes on both ends.
            // This forces the AI to see the adjacent time as "busy", ensuring 
            // the next task starts at least 15 minutes later.
            const bufferedStart = new Date(e.start);
            bufferedStart.setMinutes(bufferedStart.getMinutes() - 15);

            const bufferedEnd = new Date(e.end);
            bufferedEnd.setMinutes(bufferedEnd.getMinutes() + 15);

            return {
                title: e.title,
                start: bufferedStart.toISOString(),
                end: bufferedEnd.toISOString()
            };
        });

    const tasksContext = tasksToSchedule.map(t => ({
        id: t.id,
        category: t.category,
        title: t.title,
        instructions: t.description, 
        durationHours: t.totalHoursNeeded,
        deadline: t.deadline.toISOString()
    }));

    // Detect User Timezone Information
    const timeZone = Intl.DateTimeFormat().resolvedOptions().timeZone;
    const localTime = now.toLocaleString('en-US', { timeZone, hour12: false });

    const systemPrompt = `You are a high-performance scheduling engine. 
    You DO NOT speak. You DO NOT output conversational text. 
    You ONLY output valid JSON.

    CRITICAL INSTRUCTION:
    Your output must be a single JSON object containing a 'sessions' array.
    This mimics a parallel function call to schedule multiple tasks at once.

    INPUT DATA:
    - User Timezone: ${timeZone}
    - Local Time: ${localTime}
    - Fixed Slots (Busy): Array of start/end times (includes safety buffers).
    - Tasks: Array of tasks to schedule.

    LOGIC:
    1. Find gaps in Fixed Slots between ${localTime} and ${contextEnd.toISOString()}.
    2. Place Tasks in gaps before their deadline.
    3. Convert User Local Time instructions (e.g. "at 5pm") to UTC ISO8601.
    4. CONSTRAINT: You MUST leave at least 15 minutes of gap between any two generated sessions. Do not schedule tasks strictly back-to-back.
    5. CRITICAL FOR HABITS: If a task category is 'Habit', you MUST schedule it REPEATEDLY (e.g. daily, or as instructed) across the ENTIRE provided context window (up to 120 days). Do not just schedule it once. Fill the calendar.
    6. Return strict JSON.
    `;

    const userContent = JSON.stringify({
        fixedSlots: relevantFixed,
        tasks: tasksContext
    });

    try {
        const apiCall = ai.models.generateContent({
            model: MODEL_NAME,
            contents: userContent,
            config: { 
                systemInstruction: systemPrompt,
                responseMimeType: "application/json", 
                temperature: 0.2 
            }
        });
        // Increased timeout to 120s to handle the large generation volume for 120-day schedules
        const response = await callWithTimeout<GenerateContentResponse>(apiCall, 120000); 
        const result = JSON.parse(response.text || '{}') as { sessions: any[] };

        return (result.sessions || []).map(s => {
            const task = tasksToSchedule.find(t => t.id === s.taskId);
            if (!task) return null;
            return {
                id: crypto.randomUUID(),
                title: task.title,
                start: new Date(s.start),
                end: new Date(s.end),
                type: EventType.AI_WORK_SESSION,
                relatedTaskId: task.id,
                description: s.reasoning,
                location: task.location, // Pass location if available
                color: task.category === 'Habit' ? "bg-teal-50 border-teal-200 text-teal-700" : (task.category === 'Meeting' ? "bg-purple-50 border-purple-200 text-purple-700" : "bg-indigo-50 border-indigo-200 text-indigo-700"),
                priority: task.priority
            };
        }).filter(e => e !== null) as CalendarEvent[];

    } catch (e) {
        console.error("AI Scheduler Error:", e);
        return [];
    }
};

import React, { useState } from 'react';
import { Calendar } from './components/Calendar';
import { TaskForm } from './components/TaskForm';
import { ImportModal } from './components/ImportModal';
import { EventDetailsModal } from './components/EventDetailsModal';
import { EventsView } from './components/EventsView';
import { Button } from './components/Button';
import { identifyClasses, analyzeTaskSemantics, generateFullSchedule } from './services/geminiService';
import { CalendarEvent, Task, EventType } from './types';

function App() {
  const [view, setView] = useState<'calendar' | 'events' | 'newEvent' | 'editEvent'>('calendar');
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const [currentDate, setCurrentDate] = useState(new Date());

  const handleNavigate = (direction: 'prev' | 'next' | 'today') => {
    const newDate = new Date(currentDate);
    if (direction === 'today') {
      setCurrentDate(new Date());
    } else if (direction === 'next') {
      newDate.setDate(newDate.getDate() + 7);
      setCurrentDate(newDate);
    } else {
      newDate.setDate(newDate.getDate() - 7);
      setCurrentDate(newDate);
    }
  };

  // REPLACEMENT: Async AI Scheduler
  const runGlobalScheduler = async (currentEvents: CalendarEvent[], currentTasks: Task[]) => {
    const now = new Date();

    // 1. Keep non-AI events (Fixed)
    // 2. Keep AI events that have already ended (History)
    // 3. IMPORTANT: Ignore Ghost events when calculating busy slots for the backend
    const preservedEvents = currentEvents.filter(e => 
        (e.type !== EventType.AI_WORK_SESSION || e.end <= now) && !e.isGhost
    );

    // 3. Identify tasks that need scheduling (Not completed AND isScheduled=true AND has hours needed)
    // Removed category filter to allow AI to schedule Meetings/Habits if requested via AI mode.
    const tasksToSchedule = currentTasks.filter(t => !t.isCompleted && t.isScheduled && t.totalHoursNeeded > 0); 

    // 4. Generate new future sessions using AI
    let newSessions: CalendarEvent[] = [];
    if (tasksToSchedule.length > 0) {
        newSessions = await generateFullSchedule(preservedEvents, tasksToSchedule);
    }

    return [...preservedEvents, ...newSessions];
  };

  const handleImport = async (importedEvents: CalendarEvent[]) => {
    setIsImportModalOpen(false);
    setIsProcessing(true);
    try {
      const classIds = await identifyClasses(importedEvents);
      const taggedEvents = importedEvents.map(e => ({
        ...e,
        isClass: classIds.includes(e.id),
        // Solid Blue Block with White Text for best legibility
        color: classIds.includes(e.id) ? "bg-blue-600 border-blue-700 text-white shadow-sm" : e.color
      }));

      // Combine existing events with new imported ones, then reschedule
      const allEvents = [...events, ...taggedEvents];
      const optimizedSchedule = await runGlobalScheduler(allEvents, tasks); // Await AI
      setEvents(optimizedSchedule);
    } catch (error) {
      console.error("Import error:", error);
      alert("Error processing schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCreateOrUpdateTask = async (taskInput: Task) => {
    // Note: We do NOT set isProcessing(true) here for AI tasks anymore because we use Optimistic UI
    try {
      let task = { ...taskInput };

      // AI Analysis only for flexible Tasks if not provided and in AI mode
      if (task.category === 'Task' && task.totalHoursNeeded > 0) {
          // This is fast enough to await, or we could optimistic this too, but for now we await classification
          // If we wanted true sub-second for everything, we'd skip this or mock it.
          // Let's assume this is fast enough (Flash model).
          const aiAnalysis = await analyzeTaskSemantics(task.title, task.description);
          task.energyLevel = aiAnalysis.energyLevel;
      }

      let updatedTasks;
      const isUpdate = tasks.some(t => t.id === task.id);

      const newManualEvents: CalendarEvent[] = [];

      // Check for Manual Time fields
      if (task.meetingDate && task.meetingStartTime && task.meetingEndTime) {
         // ... (Manual Habit Logic - kept same) ...
         if (task.category === 'Habit' && task.recurrenceEndDate && task.preferredDays.length > 0) {
             const [sYear, sMonth, sDay] = task.meetingDate.split('-').map(Number);
             const loopDate = new Date(sYear, sMonth - 1, sDay); 

             const eD = new Date(task.recurrenceEndDate);
             const finalDate = new Date(eD.getFullYear(), eD.getMonth(), eD.getDate());
             finalDate.setHours(23, 59, 59, 999);

             let safety = 0;
             while (loopDate <= finalDate && safety < 365) {
                 const dayName = loopDate.toLocaleDateString('en-US', { weekday: 'long' });

                 if (task.preferredDays.includes(dayName)) {
                     const pad = (n: number) => n < 10 ? '0'+n : n;
                     const dateStr = `${loopDate.getFullYear()}-${pad(loopDate.getMonth()+1)}-${pad(loopDate.getDate())}`;

                     const s = new Date(`${dateStr}T${task.meetingStartTime}`);
                     const e = new Date(`${dateStr}T${task.meetingEndTime}`);

                     newManualEvents.push({
                         id: `manual-${task.id}-${dateStr}`,
                         title: task.title,
                         start: s,
                         end: e,
                         type: EventType.MANUAL,
                         relatedTaskId: task.id,
                         color: "bg-teal-50 border-teal-200 text-teal-700",
                         description: task.description,
                         location: task.location // Pass Location
                     });
                 }
                 loopDate.setDate(loopDate.getDate() + 1);
                 safety++;
             }

         } else {
             // Single Manual Meeting/Event
             const start = new Date(`${task.meetingDate}T${task.meetingStartTime}`);
             const end = new Date(`${task.meetingDate}T${task.meetingEndTime}`);
             newManualEvents.push({
                 id: `manual-${task.id}`,
                 title: task.title,
                 start,
                 end,
                 type: EventType.MANUAL,
                 relatedTaskId: task.id,
                 color: task.category === 'Meeting' 
                    ? "bg-purple-50 border-purple-200 text-purple-700" 
                    : "bg-gray-50 border-gray-200 text-gray-700",
                 description: task.description,
                 location: task.location // Pass Location
             });
         }
      }

      if (isUpdate) {
        updatedTasks = tasks.map(t => t.id === task.id ? task : t);
      } else {
        updatedTasks = [...tasks, task];
      }

      // --- OPTIMISTIC UI LOGIC ---

      // 1. Close Modal Immediately
      setView('calendar');
      setEditingTask(null);
      setTasks(updatedTasks);

      // 2. Prepare Events (remove old future AI events for this task)
      const now = new Date();
      let currentEvents = events.filter(e => {
          if (e.relatedTaskId === task.id) {
              if (e.type === EventType.AI_WORK_SESSION && e.end <= now) return true; // Keep history
              return false; // Remove future
          }
          return true;
      });
      currentEvents = [...currentEvents, ...newManualEvents];

      // 3. Inject Ghost Event if it's an AI task
      if (task.isScheduled && task.totalHoursNeeded > 0 && newManualEvents.length === 0) {
          const ghostStart = new Date();
          ghostStart.setHours(ghostStart.getHours() + 1, 0, 0, 0); // Tentative: Next hour
          const ghostEnd = new Date(ghostStart.getTime() + (task.totalHoursNeeded * 60 * 60 * 1000));

          const ghostEvent: CalendarEvent = {
              id: `ghost-${task.id}`,
              title: `Scheduling: ${task.title}...`,
              start: ghostStart,
              end: ghostEnd,
              type: EventType.AI_WORK_SESSION,
              relatedTaskId: task.id,
              color: "bg-gray-100",
              isGhost: true, // Triggers Skeleton UI
              location: task.location // Pass location to ghost
          };

          // Show ghost immediately
          setEvents([...currentEvents, ghostEvent]);
      } else {
          // Manual events are shown immediately
          setEvents(currentEvents);
      }

      // 4. Run AI Backend (Parallel/Async)
      // This will overwrite the ghost event when it returns
      runGlobalScheduler(currentEvents, updatedTasks).then((optimizedSchedule) => {
          setEvents(optimizedSchedule);
      }).catch((err) => {
          console.error("Scheduling failed", err);
          alert("Automatic scheduling failed. Please try again.");
          // Rollback ghost
          setEvents(currentEvents);
      });

    } catch (error) {
      console.error(error);
      alert("Error saving task.");
      setIsProcessing(false);
    }
  };

  const handleDeleteEvent = async (id: string) => {
    // Simply delete the event locally.
    // We do NOT trigger a full AI reschedule here anymore to avoid "ridiculous" wait times for simple deletions.
    setEvents(prev => prev.filter(e => e.id !== id));
  };

  const handleDeleteTask = async (taskId: string) => {
      // Remove task immediately
      const updatedTasks = tasks.filter(t => t.id !== taskId);
      setTasks(updatedTasks);

      // Remove associated events immediately
      setEvents(prev => prev.filter(e => e.relatedTaskId !== taskId));

      // We do NOT trigger AI rescheduling here. Gaps will simply remain empty until the next manual or AI action.
  };

  const handleUpdateEvent = (updatedEvent: CalendarEvent) => {
    const finalEvent = {
        ...updatedEvent,
        type: updatedEvent.type === EventType.AI_WORK_SESSION ? EventType.MANUAL : updatedEvent.type,
    };
    setEvents(prevEvents => {
        const otherEvents = prevEvents.filter(e => e.id !== updatedEvent.id);
        const newEventList = [...otherEvents, finalEvent];
        return newEventList;
    });
  };

  const handleToggleTaskComplete = async (taskId: string, isComplete: boolean) => {
      // Optimistic Update
      const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, isCompleted: isComplete } : t);
      setTasks(updatedTasks);

      if (isComplete) {
          const now = new Date();
          setEvents(prev => prev.filter(e => {
              if (e.relatedTaskId === taskId && e.type === EventType.AI_WORK_SESSION && e.start > now) return false;
              return true;
          }));
      } else {
          // Re-schedule in background (Uncompleting a task usually implies intent to do it, so we allow rescheduling here)
          runGlobalScheduler(events, updatedTasks).then(setEvents);
      }
  };

  const handleCalendarSlotClick = (date: Date) => {
      const startStr = date.toTimeString().slice(0, 5); // HH:mm
      const end = new Date(date.getTime() + 60*60*1000); // +1 hour
      const endStr = end.toTimeString().slice(0, 5);

      const pad = (n: number) => n < 10 ? '0'+n : n;
      const dateStr = `${date.getFullYear()}-${pad(date.getMonth()+1)}-${pad(date.getDate())}`;

      const draftTask: Task = {
          id: '', 
          category: 'Meeting', 
          title: '',
          description: '',
          priority: 'Medium',
          files: [],
          difficulty: 5,
          totalHoursNeeded: 0, // Manual = 0 hours needed for AI
          deadline: new Date(date.getTime() + 7*24*60*60*1000), 
          energyLevel: 'High',
          meetingDate: dateStr,
          meetingStartTime: startStr,
          meetingEndTime: endStr,
          preferredDays: [],
          preferredTimeStart: '09:00',
          preferredTimeEnd: '17:00',
          preferredSessionDuration: 1,
          isScheduled: true 
      };

      setEditingTask(draftTask);
      setView('newEvent');
  };

  const selectedTask = selectedEvent?.relatedTaskId 
    ? tasks.find(t => t.id === selectedEvent.relatedTaskId) 
    : undefined;

  return (
    <div className="min-h-screen flex flex-col relative bg-gray-50 text-gray-900 font-sans">
      <nav className="border-b border-gray-200 bg-white sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <span className="bg-indigo-600 text-white p-1.5 rounded mr-3 font-bold">SP</span>
              <h1 className="text-xl font-bold tracking-tight text-gray-900 hidden sm:block">SparkPlan AI</h1>

              <div className="ml-8 flex space-x-1">
                 <button 
                    onClick={() => setView('calendar')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'calendar' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Calendar
                 </button>
                 <button 
                    onClick={() => setView('events')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'events' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Events
                 </button>
              </div>
            </div>
            <div className="flex items-center space-x-4">
              <Button variant="ghost" onClick={() => setIsImportModalOpen(true)}>Import</Button>
              <Button onClick={() => { setEditingTask(null); setView('newEvent'); }} disabled={view === 'newEvent'}>
                + New Event
              </Button>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {view === 'calendar' && (
          <>
            <div className="mb-6 flex items-center justify-between">
              <div>
                <h2 className="text-xl font-bold text-gray-900 tracking-tight">Dashboard</h2>
                <p className="text-sm text-gray-500 mt-1">
                  {events.filter(e => e.type === EventType.AI_WORK_SESSION && !e.isGhost).length} active work sessions.
                </p>
              </div>
              <div className="flex gap-4 text-xs font-medium text-gray-600">
                 <div className="flex items-center"><div className="w-2 h-2 bg-blue-600 rounded-full mr-2"></div> Class</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-gray-400 rounded-full mr-2"></div> Manual</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-teal-400 rounded-full mr-2"></div> Habit</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-indigo-600 rounded-full mr-2"></div> Task</div>
              </div>
            </div>
            <div className="h-[calc(100vh-200px)]">
               <Calendar 
                  events={events} 
                  currentDate={currentDate} 
                  onEventClick={setSelectedEvent}
                  onNavigate={handleNavigate}
                  onEventUpdate={handleUpdateEvent}
                  onSlotClick={handleCalendarSlotClick}
               />
            </div>
          </>
        )}

        {view === 'events' && (
            <EventsView 
                tasks={tasks} 
                events={events}
                onEditTask={(task) => {
                    setEditingTask(task);
                    setView('editEvent');
                }}
                onDeleteTask={handleDeleteTask}
                onToggleComplete={handleToggleTaskComplete}
            />
        )}

        {(view === 'newEvent' || view === 'editEvent') && (
          <div className="py-8">
            <TaskForm 
              initialTask={editingTask}
              existingEvents={events}
              onSubmit={handleCreateOrUpdateTask} 
              onCancel={() => {
                  setEditingTask(null);
                  setView('calendar');
              }} 
            />
          </div>
        )}
      </main>

      <ImportModal 
        isOpen={isImportModalOpen} 
        onClose={() => setIsImportModalOpen(false)} 
        onImport={handleImport} 
      />

      <EventDetailsModal 
        event={selectedEvent} 
        relatedTask={selectedTask}
        onClose={() => setSelectedEvent(null)}
        onDelete={handleDeleteEvent}
        onUpdate={handleUpdateEvent}
      />

      {isProcessing && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-900 bg-opacity-50 backdrop-blur-sm transition-opacity">
            <div className="flex flex-col items-center p-6 bg-white rounded-lg shadow-xl">
                <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
                <h3 className="text-lg font-bold text-gray-900 tracking-widest uppercase">AI Planning</h3>
                <p className="text-xs text-gray-500 mt-2">Consulting the AI for the best slots...</p>
            </div>
        </div>
      )}

    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { Task, TaskFile, Priority, TaskCategory, CalendarEvent } from '../types';
import { Button } from './Button';

interface TaskFormProps {
  initialTask?: Task | null;
  existingEvents?: CalendarEvent[];
  onSubmit: (task: Task) => Promise<void>;
  onCancel: () => void;
}

type ScheduleMode = 'AI' | 'MANUAL';

const DAYS_OF_WEEK = [
    { label: 'S', value: 'Sunday' },
    { label: 'M', value: 'Monday' },
    { label: 'T', value: 'Tuesday' },
    { label: 'W', value: 'Wednesday' },
    { label: 'T', value: 'Thursday' },
    { label: 'F', value: 'Friday' },
    { label: 'S', value: 'Saturday' },
];

export const TaskForm: React.FC<TaskFormProps> = ({ initialTask, existingEvents = [], onSubmit, onCancel }) => {
  // Mode Selection
  const [mode, setMode] = useState<ScheduleMode>('AI');

  // Common Fields
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [location, setLocation] = useState(""); // Added Location
  const [category, setCategory] = useState<TaskCategory>('Task');

  // AI Specific
  const [deadline, setDeadline] = useState("");
  const [totalHours, setTotalHours] = useState(1);

  // Manual Specific
  const [priority, setPriority] = useState<Priority>('Medium');
  const [files, setFiles] = useState<TaskFile[]>([]);

  // Manual Meeting/Habit
  const [manualDate, setManualDate] = useState("");
  const [manualRecurrenceEnd, setManualRecurrenceEnd] = useState(""); // For Habits
  const [manualStart, setManualStart] = useState("09:00");
  const [manualEnd, setManualEnd] = useState("10:00");
  const [selectedDays, setSelectedDays] = useState<string[]>(['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday']);

  // Manual Task
  const [manualDueTime, setManualDueTime] = useState("");

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [manualConflict, setManualConflict] = useState<string | null>(null);

  useEffect(() => {
    if (initialTask) {
        setCategory(initialTask.category);
        setTitle(initialTask.title);
        setDescription(initialTask.description);
        setLocation(initialTask.location || "");
        setFiles(initialTask.files);
        setPriority(initialTask.priority);

        if (initialTask.meetingDate) {
            // Manual Meeting or Habit Start
            setMode('MANUAL');
            setManualDate(initialTask.meetingDate || "");
            setManualStart(initialTask.meetingStartTime || "09:00");
            setManualEnd(initialTask.meetingEndTime || "10:00");

            if (initialTask.category === 'Habit') {
                setSelectedDays(initialTask.preferredDays || []);
                // If recurring end date exists, use it, otherwise leave blank (indefinite)
                if (initialTask.recurrenceEndDate) {
                    const d = new Date(initialTask.recurrenceEndDate);
                    // If it's very far in the future, treat as empty (indefinite)
                    if (d.getFullYear() < new Date().getFullYear() + 2) {
                        const pad = (n: number) => n < 10 ? '0'+n : n;
                        setManualRecurrenceEnd(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`);
                    }
                }
            }
        } else if (initialTask.totalHoursNeeded > 0 && initialTask.isScheduled) {
            // AI Task
            setMode('AI');
            setTotalHours(initialTask.totalHoursNeeded);
            const d = new Date(initialTask.deadline);
            if (!isNaN(d.getTime())) {
                const pad = (n: number) => n < 10 ? '0'+n : n;
                setDeadline(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`);
            }
        } else {
            // Manual Task
            setMode('MANUAL');
            const d = new Date(initialTask.deadline);
            if (!isNaN(d.getTime())) {
                const pad = (n: number) => n < 10 ? '0'+n : n;
                setManualDate(`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`);
                if (d.getHours() !== 23 || d.getMinutes() !== 59) {
                     setManualDueTime(`${pad(d.getHours())}:${pad(d.getMinutes())}`);
                }
            }
        }
    } else {
        // Default
        setMode('AI');
        const now = new Date();
        const tomorrow = new Date(now);
        tomorrow.setDate(tomorrow.getDate() + 1);
        tomorrow.setHours(23, 59, 0, 0); 

        const pad = (n: number) => n < 10 ? '0'+n : n;
        setDeadline(`${tomorrow.getFullYear()}-${pad(tomorrow.getMonth()+1)}-${pad(tomorrow.getDate())}T${pad(tomorrow.getHours())}:${pad(tomorrow.getMinutes())}`);

        const todayStr = new Date().toISOString().split('T')[0];
        setManualDate(todayStr);
    }
  }, [initialTask]);

  // Conflict Detection
  useEffect(() => {
      if (mode === 'MANUAL' && category !== 'Task' && manualDate && manualStart && manualEnd) {
          const start = new Date(`${manualDate}T${manualStart}`);
          const end = new Date(`${manualDate}T${manualEnd}`);

          if (start >= end) {
              setManualConflict("End time must be after start time.");
              return;
          }

          if (category === 'Meeting') {
            const hasConflict = existingEvents.some(e => {
                if (initialTask && e.relatedTaskId === initialTask.id) return false;
                return (start < e.end && end > e.start);
            });

            if (hasConflict) {
                setManualConflict("⚠ Time slot conflicts with existing event.");
            } else {
                setManualConflict(null);
            }
          } else {
             setManualConflict(null);
          }
      } else {
          setManualConflict(null);
      }
  }, [mode, category, manualDate, manualStart, manualEnd, existingEvents, initialTask]);

  const toggleDay = (day: string) => {
      if (selectedDays.includes(day)) {
          setSelectedDays(prev => prev.filter(d => d !== day));
      } else {
          setSelectedDays(prev => [...prev, day]);
      }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles: TaskFile[] = Array.from(e.target.files).map((f: File) => ({
        name: f.name,
        size: f.size,
        type: f.type,
        url: URL.createObjectURL(f) 
      }));
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    if (mode === 'AI') {
        // For Habits in AI mode, we don't require the deadline input, we auto-set it later.
        if (category !== 'Habit' && !deadline) { alert("Date is required."); setIsSubmitting(false); return; }
        if (totalHours <= 0) { alert("Hours needed must be greater than 0."); setIsSubmitting(false); return; }
    } else {
        if (!manualDate) { alert("Date is required."); setIsSubmitting(false); return; }

        if (category !== 'Task') {
            if (!manualStart || !manualEnd) { alert("Start and End times required."); setIsSubmitting(false); return; }
            if (manualConflict) { alert(manualConflict); setIsSubmitting(false); return; }

            if (category === 'Habit') {
                // Habit End Date is now optional (Indefinite)
                if (manualRecurrenceEnd && new Date(manualRecurrenceEnd) < new Date(manualDate)) { alert("End Date must be after Start Date."); setIsSubmitting(false); return; }
                if (selectedDays.length === 0) { alert("Please select at least one day for the habit."); setIsSubmitting(false); return; }
            }
        }
    }

    let calculatedDeadline = new Date();
    if (mode === 'AI') {
        if (category === 'Habit') {
             // For AI Habits, default to 1 year out to effectively be "indefinite" in the short-term context
             calculatedDeadline = new Date(Date.now() + 365 * 24 * 60 * 60 * 1000);
        } else {
             calculatedDeadline = new Date(deadline);
        }
    } else {
        if (category === 'Task') {
            if (manualDueTime) {
                calculatedDeadline = new Date(`${manualDate}T${manualDueTime}`);
            } else {
                calculatedDeadline = new Date(`${manualDate}T23:59:00`);
            }
        } else {
            calculatedDeadline = new Date(`${manualDate}T${manualEnd}`);
        }
    }

    if (calculatedDeadline < new Date()) {
         if (category === 'Task' || (mode === 'AI' && category !== 'Habit')) {
             alert("The date cannot be in the past.");
             setIsSubmitting(false);
             return;
         }
    }

    // Handle Indefinite Habit logic
    let recurrenceEnd = undefined;
    if (mode === 'MANUAL' && category === 'Habit') {
        if (manualRecurrenceEnd) {
            recurrenceEnd = new Date(manualRecurrenceEnd);
        } else {
            // Indefinite: Set to 5 years from now for backend logic
            const future = new Date();
            future.setFullYear(future.getFullYear() + 5);
            recurrenceEnd = future;
        }
    }

    const taskToSave: Task = {
      id: (initialTask && initialTask.id) ? initialTask.id : crypto.randomUUID(),
      category,
      title,
      description,
      location, // Save Location

      // AI Fields
      totalHoursNeeded: mode === 'AI' ? totalHours : 0,
      deadline: calculatedDeadline,

      // Manual Fields
      priority: mode === 'MANUAL' ? priority : 'Medium',
      files: mode === 'MANUAL' ? files : [],

      // Meeting/Habit Specifics
      meetingDate: (mode === 'MANUAL' && category !== 'Task') ? manualDate : undefined,
      meetingStartTime: (mode === 'MANUAL' && category !== 'Task') ? manualStart : undefined,
      meetingEndTime: (mode === 'MANUAL' && category !== 'Task') ? manualEnd : undefined,

      // Habit Specifics
      recurrenceEndDate: recurrenceEnd,
      preferredDays: (mode === 'MANUAL' && category === 'Habit') ? selectedDays : [],

      // Defaults
      difficulty: 5,
      energyLevel: 'High',
      preferredTimeStart: "00:00",
      preferredTimeEnd: "23:59",
      preferredSessionDuration: totalHours,

      isScheduled: mode === 'AI' || (mode === 'MANUAL' && category !== 'Task') 
    };

    try {
      await onSubmit(taskToSave);
    } catch (err) {
      console.error(err);
      alert("Failed to save.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const isEditing = initialTask && initialTask.id !== '';

  return (
    <div className="bg-white p-6 rounded-lg shadow-xl max-w-xl mx-auto border border-gray-200">

      <div className="mb-6">
          <div className="flex items-center justify-between mb-4">
              <h2 className="text-2xl font-bold text-gray-900 flex items-center">
                {isEditing ? 'Edit Event' : 'New Event'}
              </h2>
          </div>

          <div className="grid grid-cols-2 gap-4 p-1 bg-gray-100 rounded-lg mb-6">
              <button
                type="button"
                onClick={() => setMode('AI')}
                className={`flex items-center justify-center py-3 px-4 rounded-md text-sm font-bold transition-all ${
                    mode === 'AI' 
                    ? 'bg-white text-indigo-600 shadow-sm ring-1 ring-black/5' 
                    : 'text-gray-500 hover:text-gray-900'
                }`}
              >
                  ✨ AI Powered
              </button>
              <button
                type="button"
                onClick={() => setMode('MANUAL')}
                className={`flex items-center justify-center py-3 px-4 rounded-md text-sm font-bold transition-all ${
                    mode === 'MANUAL' 
                    ? 'bg-white text-gray-900 shadow-sm ring-1 ring-black/5' 
                    : 'text-gray-500 hover:text-gray-900'
                }`}
              >
                  📅 Manual
              </button>
          </div>

          {/* Category Selector */}
          <div>
            <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">Category</label>
            <div className="flex gap-2">
                {(['Task', 'Meeting', 'Habit'] as TaskCategory[]).map(cat => (
                    <button
                        key={cat}
                        type="button"
                        onClick={() => setCategory(cat)}
                        className={`flex-1 py-2 px-3 text-sm font-medium rounded-lg border transition-all ${
                            category === cat 
                            ? 'bg-indigo-50 border-indigo-200 text-indigo-700 ring-1 ring-indigo-200' 
                            : 'bg-white border-gray-200 text-gray-600 hover:bg-gray-50'
                        }`}
                    >
                        {cat === 'Habit' ? 'Habit / Recurring' : cat}
                    </button>
                ))}
            </div>
          </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Title & Location */}
        <div className="grid grid-cols-1 gap-4">
            <div>
                <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">Title</label>
                <input 
                  required
                  type="text" 
                  value={title}
                  onChange={e => setTitle(e.target.value)}
                  className="block w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 text-base p-3 border bg-white text-gray-900"
                  placeholder={mode === 'AI' ? "e.g. Work on Project" : "e.g. Client Meeting"}
                />
            </div>
            <div>
                <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">Location (Optional)</label>
                <input 
                  type="text" 
                  value={location}
                  onChange={e => setLocation(e.target.value)}
                  className="block w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 text-sm p-3 border bg-white text-gray-900"
                  placeholder="e.g. Room 101, Zoom, Starbucks"
                />
            </div>
        </div>

        {/* AI Mode: Strictly Minimal */}
        {mode === 'AI' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-top-4 duration-300">

                <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-lg">
                    <label className="block text-sm font-bold text-indigo-900 mb-2">
                        AI Instructions
                    </label>
                    <textarea 
                        value={description} 
                        onChange={e => setDescription(e.target.value)} 
                        rows={3} 
                        className="block w-full rounded-md border-indigo-200 shadow-sm p-3 border bg-white text-gray-900 text-sm placeholder-indigo-300 focus:border-indigo-500 focus:ring-indigo-500" 
                        placeholder={category === 'Habit' ? "e.g. Every day at 8am" : "e.g. Schedule this at 11pm tonight."} 
                    />
                </div>

                <div className="grid grid-cols-2 gap-4">
                    {/* Hide Date for Habits (Indefinite) */}
                    {category !== 'Habit' && (
                        <div>
                            <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">
                                Deadline
                            </label>
                            <input 
                                type="datetime-local" 
                                required 
                                value={deadline} 
                                onChange={e => setDeadline(e.target.value)} 
                                className="block w-full rounded-lg border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 text-sm" 
                            />
                        </div>
                    )}
                    <div className={category === 'Habit' ? 'col-span-2' : ''}>
                        <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">
                            {category === 'Habit' ? 'Hours Per Day' : 'Hours Needed'}
                        </label>
                        <input 
                            type="number" 
                            min="0.25" 
                            step="0.25" 
                            value={totalHours} 
                            onChange={e => setTotalHours(parseFloat(e.target.value))} 
                            className="block w-full rounded-lg border-gray-300 shadow-sm p-2.5 border bg-white text-gray-900 text-sm" 
                        />
                    </div>
                </div>
            </div>
        )}

        {/* Manual Mode: Split between Task and Meeting/Habit */}
        {mode === 'MANUAL' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-top-4 duration-300">
                <div>
                    <label className="block text-xs uppercase tracking-wider font-bold text-gray-500 mb-2">Notes</label>
                    <textarea value={description} onChange={e => setDescription(e.target.value)} rows={2} className="block w-full rounded-md border-gray-300 shadow-sm p-3 border bg-white text-gray-900 text-sm" placeholder="Details..." />
                </div>

                <div className="bg-gray-50 p-4 rounded-lg border border-gray-200">
                    {category === 'Task' ? (
                        /* Manual Task: Date and Optional Time */
                        <div className="grid grid-cols-2 gap-4">
                             <div>
                                <label className="block text-xs font-bold text-gray-700 mb-1">Due Date</label>
                                <input type="date" required value={manualDate} onChange={e => setManualDate(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                             </div>
                             <div>
                                <label className="block text-xs font-bold text-gray-700 mb-1">Due Time (Optional)</label>
                                <input type="time" value={manualDueTime} onChange={e => setManualDueTime(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                             </div>
                             <div className="col-span-2 text-xs text-gray-500 italic">
                                * This task will appear in your list but won't be blocked on the calendar.
                             </div>
                        </div>
                    ) : (
                        /* Manual Meeting or Habit */
                        <div className="grid grid-cols-1 gap-4">
                            {category === 'Habit' ? (
                                <div className="grid grid-cols-1 gap-4">
                                     <div>
                                        <label className="block text-xs font-bold text-gray-700 mb-1">Start Date</label>
                                        <input type="date" required value={manualDate} onChange={e => setManualDate(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                                    </div>
                                    {/* Removed End Date for Habits to allow indefinite */}

                                    <div className="col-span-1">
                                        <label className="block text-xs font-bold text-gray-700 mb-1">Repeat On</label>
                                        <div className="flex justify-between gap-1">
                                            {DAYS_OF_WEEK.map(d => (
                                                <button
                                                    key={d.value}
                                                    type="button"
                                                    onClick={() => toggleDay(d.value)}
                                                    className={`w-9 h-9 rounded-full text-xs font-bold flex items-center justify-center transition-all ${
                                                        selectedDays.includes(d.value) 
                                                        ? 'bg-indigo-600 text-white shadow-md transform scale-105' 
                                                        : 'bg-white border border-gray-200 text-gray-500 hover:bg-gray-50'
                                                    }`}
                                                >
                                                    {d.label}
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                            ) : (
                                <div>
                                    <label className="block text-xs font-bold text-gray-700 mb-1">Date</label>
                                    <input type="date" required value={manualDate} onChange={e => setManualDate(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                                </div>
                            )}

                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-xs font-bold text-gray-700 mb-1">Start Time</label>
                                    <input type="time" required value={manualStart} onChange={e => setManualStart(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-gray-700 mb-1">End Time</label>
                                    <input type="time" required value={manualEnd} onChange={e => setManualEnd(e.target.value)} className="w-full text-sm p-2.5 rounded border-gray-300 bg-white text-gray-900 border shadow-sm" />
                                </div>
                            </div>

                            {manualConflict && (
                                <div className="mt-2 flex items-center text-sm text-red-700 bg-red-100 p-2 rounded border border-red-200 font-medium">
                                    <svg className="w-5 h-5 mr-2" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                                    {manualConflict}
                                </div>
                            )}
                        </div>
                    )}
                </div>

                <div className="grid grid-cols-2 gap-6 border-t border-gray-200 pt-6">
                    <div>
                        <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Priority</label>
                        <div className="flex rounded-md shadow-sm bg-gray-50 border border-gray-200 p-1">
                            {(['High', 'Medium', 'Low'] as Priority[]).map((p) => (
                                <button
                                    key={p}
                                    type="button"
                                    onClick={() => setPriority(p)}
                                    className={`flex-1 py-2 text-xs font-medium rounded transition-all ${priority === p ? 'bg-white text-indigo-600 shadow-sm font-bold' : 'text-gray-500'}`}
                                >
                                    {p}
                                </button>
                            ))}
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs uppercase tracking-wider font-semibold text-gray-500 mb-2">Materials</label>
                        <label className="flex items-center justify-center w-full p-2 border border-gray-300 border-dashed rounded cursor-pointer hover:bg-gray-50">
                            <span className="text-xs text-indigo-600">+ Upload</span>
                            <input type="file" className="hidden" multiple onChange={handleFileChange} />
                        </label>
                    </div>
                </div>
            </div>
        )}

        <div className="flex justify-end gap-3 pt-6 border-t border-gray-200">
            <Button variant="ghost" type="button" onClick={onCancel}>Cancel</Button>
            <Button type="submit" isLoading={isSubmitting} disabled={!!manualConflict && mode === 'MANUAL' && category === 'Meeting'}>
                {isEditing ? 'Save Changes' : (mode === 'AI' ? 'Auto-Schedule' : (category === 'Task' ? 'Add Task' : 'Add to Calendar'))}
            </Button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Task, CalendarEvent, Priority, TaskCategory } from '../types';

interface EventsViewProps {
  tasks: Task[];
  events: CalendarEvent[];
  onEditTask: (task: Task) => void;
  onDeleteTask: (taskId: string) => void;
  onToggleComplete: (taskId: string, isComplete: boolean) => void;
}

export const EventsView: React.FC<EventsViewProps> = ({ tasks, events, onEditTask, onDeleteTask, onToggleComplete }) => {
  const [now, setNow] = useState(new Date());
  const [filter, setFilter] = useState<TaskCategory | 'All'>('All');

  useEffect(() => {
    const interval = setInterval(() => {
        setNow(new Date());
    }, 60000); 
    return () => clearInterval(interval);
  }, []);

  const getProgress = (task: Task) => {
    if (task.isCompleted) {
        return {
            completed: task.totalHoursNeeded,
            scheduledFuture: 0,
            totalNeeded: task.totalHoursNeeded,
            percentCompleted: 100,
            percentScheduled: 0
        };
    }

    if (task.category === 'Meeting') {
        const start = new Date(`${task.meetingDate}T${task.meetingStartTime}`);
        const end = new Date(`${task.meetingDate}T${task.meetingEndTime}`);
        const isDone = now > end;
        return {
            completed: isDone ? 1 : 0,
            scheduledFuture: isDone ? 0 : 1,
            totalNeeded: 1,
            percentCompleted: isDone ? 100 : 0,
            percentScheduled: isDone ? 0 : 100
        };
    }

    const taskEvents = events.filter(e => e.relatedTaskId === task.id);
    let totalScheduledHours = 0;
    let completedHours = 0;

    taskEvents.forEach(e => {
        const durationHours = (e.end.getTime() - e.start.getTime()) / (1000 * 60 * 60);
        totalScheduledHours += durationHours;

        if (now >= e.end) {
            completedHours += durationHours;
        } else if (now > e.start) {
            const passedMs = now.getTime() - e.start.getTime();
            completedHours += passedMs / (1000 * 60 * 60);
        }
    });

    const denominator = task.category === 'Task' ? task.totalHoursNeeded : totalScheduledHours || 1;

    return {
        completed: completedHours,
        scheduledFuture: Math.max(0, totalScheduledHours - completedHours),
        totalNeeded: task.category === 'Task' ? task.totalHoursNeeded : totalScheduledHours,
        percentCompleted: Math.min(100, (completedHours / denominator) * 100),
        percentScheduled: Math.min(100, ((totalScheduledHours - completedHours) / denominator) * 100)
    };
  };

  const getPriorityColor = (p: Priority) => {
    switch(p) {
        case 'High': return 'text-red-700 bg-red-50 border-red-200';
        case 'Medium': return 'text-amber-700 bg-amber-50 border-amber-200';
        case 'Low': return 'text-emerald-700 bg-emerald-50 border-emerald-200';
        default: return 'text-gray-700 bg-gray-50';
    }
  };

  const filteredTasks = filter === 'All' ? tasks : tasks.filter(t => t.category === filter);

  if (tasks.length === 0) {
      return (
          <div className="flex flex-col items-center justify-center h-full py-20 text-center">
              <div className="bg-gray-100 p-6 rounded-full mb-4">
                  <span className="text-4xl">📅</span>
              </div>
              <h3 className="text-lg font-bold text-gray-900">No Events Yet</h3>
              <p className="text-gray-500 max-w-sm mt-2 mb-6">Create Tasks, Meetings, or Habits to fill your schedule.</p>
          </div>
      );
  }

  return (
    <div className="space-y-6">
      {/* Filter Tabs */}
      <div className="flex space-x-2 border-b border-gray-200 pb-1">
          {(['All', 'Task', 'Meeting', 'Habit'] as const).map(cat => (
              <button
                key={cat}
                onClick={() => setFilter(cat)}
                className={`px-4 py-2 text-sm font-medium rounded-t-lg transition-colors ${
                    filter === cat 
                    ? 'bg-white text-indigo-600 border border-b-0 border-gray-200 shadow-sm' 
                    : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'
                }`}
              >
                  {cat === 'All' ? 'All Events' : (cat === 'Habit' ? 'Habits / Recurring' : `${cat}s`)}
              </button>
          ))}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredTasks.map(task => {
            const stats = getProgress(task);
            const isOverdue = !task.isCompleted && task.category === 'Task' && now > task.deadline && stats.percentCompleted < 100;
            const totalPlanned = stats.completed + stats.scheduledFuture;

            return (
                <div 
                    key={task.id} 
                    className={`bg-white rounded-xl border transition-all p-5 flex flex-col relative overflow-hidden group
                        ${task.isCompleted ? 'border-green-200 bg-green-50/30' : 'border-gray-200 shadow-sm hover:shadow-md'}
                    `}
                >
                    {/* Category Badge Stripe */}
                    <div className={`absolute top-0 left-0 w-1 h-full ${
                        task.isCompleted ? 'bg-green-500' :
                        task.category === 'Meeting' ? 'bg-purple-500' :
                        task.category === 'Habit' ? 'bg-teal-500' : 'bg-indigo-500'
                    }`}></div>

                    <div className="flex justify-between items-start mb-3 pl-3">
                        <div className="flex flex-col">
                            <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider mb-1">
                                {task.category === 'Habit' ? 'Habit / Recurring' : task.category}
                            </span>
                            {task.isCompleted ? (
                                <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider border bg-green-100 text-green-700 border-green-200 w-fit">
                                    Completed
                                </span>
                            ) : (
                                <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider border w-fit ${getPriorityColor(task.priority)}`}>
                                    {task.priority}
                                </span>
                            )}
                        </div>
                        <div className="flex gap-2 relative z-20">
                             {!task.isCompleted && (
                                <button 
                                    type="button"
                                    onClick={(e) => { 
                                        e.stopPropagation(); 
                                        onEditTask(task); 
                                    }}
                                    className="text-gray-400 hover:text-indigo-600 transition-colors p-2 rounded-full hover:bg-indigo-50"
                                    title="Edit"
                                >
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                                    </svg>
                                </button>
                             )}
                             <button 
                                type="button"
                                onClick={(e) => {
                                    e.stopPropagation();
                                    onDeleteTask(task.id);
                                }}
                                className="text-gray-400 hover:text-red-600 transition-colors p-2 rounded-full hover:bg-red-50"
                                title="Delete Task"
                             >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                </svg>
                             </button>
                        </div>
                    </div>

                    <h3 className={`text-lg font-bold mb-1 leading-tight pl-3 ${task.isCompleted ? 'text-gray-500 line-through' : 'text-gray-900'}`}>
                        {task.title}
                    </h3>

                    <div className="pl-3 mb-4">
                        {task.category === 'Task' && (
                            <div className="text-xs text-gray-500 flex items-center">
                                <span className="mr-2">📅 Due:</span> 
                                <span className={`font-medium ${isOverdue ? 'text-red-600' : 'text-gray-700'}`}>
                                    {task.deadline.toLocaleDateString(undefined, {month:'short', day:'numeric'})}
                                </span>
                            </div>
                        )}
                        {task.category === 'Meeting' && (
                             <div className="text-xs text-gray-500 flex items-center">
                                <span className="mr-2">🕒 Time:</span> 
                                <span className="font-medium text-gray-700">
                                    {task.meetingDate} @ {task.meetingStartTime}
                                </span>
                            </div>
                        )}
                        {task.category === 'Habit' && (
                             <div className="text-xs text-gray-500 flex items-center">
                                <span className="mr-2">🔁 Repeats:</span> 
                                <span className="font-medium text-gray-700">
                                    {task.preferredDays.map(d => d.slice(0,3)).join(', ')}
                                </span>
                            </div>
                        )}
                    </div>

                    {task.description && (
                        <p className={`text-xs mb-4 line-clamp-2 pl-3 ${task.isCompleted ? 'text-gray-400' : 'text-gray-600'}`}>
                            {task.description}
                        </p>
                    )}

                    <div className="mt-auto pl-3">
                        {task.category !== 'Meeting' && (
                        <>
                            <div className="flex justify-between items-end mb-1">
                                <span className="text-xs font-medium text-gray-500">
                                    {stats.completed.toFixed(1)} hrs done
                                </span>
                                <span className="text-xs font-bold text-gray-700">
                                    {totalPlanned.toFixed(1)} hrs planned
                                </span>
                            </div>

                            <div className="w-full bg-gray-100 rounded-full h-2.5 overflow-hidden flex">
                                <div 
                                    className="h-full bg-emerald-500 transition-all duration-500"
                                    style={{ width: `${stats.percentCompleted}%` }}
                                ></div>
                                {!task.isCompleted && (
                                    <div 
                                        className="h-full bg-indigo-400 transition-all duration-500 opacity-60"
                                        style={{ width: `${stats.percentScheduled}%` }}
                                    ></div>
                                )}
                            </div>
                        </>
                        )}

                        <div className="mt-4 flex items-center justify-between">
                             {task.files.length > 0 ? (
                                <div className="text-[10px] bg-gray-50 border border-gray-200 px-2 py-1 rounded text-gray-600 flex items-center">
                                    📎 {task.files.length} Materials
                                </div>
                             ) : <div></div>}

                             {/* Mark as Complete Button for Tasks */}
                             {task.category === 'Task' && (
                                 <button
                                    type="button"
                                    onClick={(e) => { e.stopPropagation(); onToggleComplete(task.id, !task.isCompleted); }}
                                    className={`text-xs px-3 py-1.5 rounded-full font-medium transition-colors border flex items-center gap-1 ${
                                        task.isCompleted 
                                        ? 'bg-white border-gray-300 text-gray-500 hover:bg-gray-50' 
                                        : 'bg-indigo-50 border-indigo-200 text-indigo-700 hover:bg-indigo-100'
                                    }`}
                                 >
                                    {task.isCompleted ? (
                                        <>↩ Undo Complete</>
                                    ) : (
                                        <>✓ Mark Complete</>
                                    )}
                                 </button>
                             )}
                        </div>
                    </div>
                </div>
            );
        })}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Calendar } from './components/Calendar';
import { TaskForm } from './components/TaskForm';
import { ImportModal } from './components/ImportModal';
import { EventDetailsModal } from './components/EventDetailsModal';
import { EventsView } from './components/EventsView';
import { Button } from './components/Button';
import { identifyClasses, analyzeTaskSemantics, generateFullSchedule } from './services/geminiService';
import { CalendarEvent, Task, EventType } from './types';

function App() {
  const [view, setView] = useState<'calendar' | 'events' | 'newEvent' | 'editEvent'>('calendar');
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const [currentDate, setCurrentDate] = useState(new Date());

  const handleNavigate = (direction: 'prev' | 'next' | 'today') => {
    const newDate = new Date(currentDate);
    if (direction === 'today') {
      setCurrentDate(new Date());
    } else if (direction === 'next') {
      newDate.setDate(newDate.getDate() + 7);
      setCurrentDate(newDate);
    } else {
      newDate.setDate(newDate.getDate() - 7);
      setCurrentDate(newDate);
    }
  };

  // REPLACEMENT: Async AI Scheduler
  const runGlobalScheduler = async (currentEvents: CalendarEvent[], currentTasks: Task[]) => {
    const now = new Date();

    // 1. Keep non-AI events (Fixed)
    // 2. Keep AI events that have already ended (History)
    // 3. IMPORTANT: Ignore Ghost events when calculating busy slots for the backend
    const preservedEvents = currentEvents.filter(e => 
        (e.type !== EventType.AI_WORK_SESSION || e.end <= now) && !e.isGhost
    );

    // 3. Identify tasks that need scheduling (Not completed AND isScheduled=true AND has hours needed)
    // Removed category filter to allow AI to schedule Meetings/Habits if requested via AI mode.
    const tasksToSchedule = currentTasks.filter(t => !t.isCompleted && t.isScheduled && t.totalHoursNeeded > 0); 

    // 4. Generate new future sessions using AI
    let newSessions: CalendarEvent[] = [];
    if (tasksToSchedule.length > 0) {
        newSessions = await generateFullSchedule(preservedEvents, tasksToSchedule);
    }

    return [...preservedEvents, ...newSessions];
  };

  const handleImport = async (importedEvents: CalendarEvent[]) => {
    setIsImportModalOpen(false);
    setIsProcessing(true);
    try {
      const classIds = await identifyClasses(importedEvents);
      const taggedEvents = importedEvents.map(e => ({
        ...e,
        isClass: classIds.includes(e.id),
        // Solid Blue Block with White Text for best legibility
        color: classIds.includes(e.id) ? "bg-blue-600 border-blue-700 text-white shadow-sm" : e.color
      }));

      // Combine existing events with new imported ones, then reschedule
      const allEvents = [...events, ...taggedEvents];
      const optimizedSchedule = await runGlobalScheduler(allEvents, tasks); // Await AI
      setEvents(optimizedSchedule);
    } catch (error) {
      console.error("Import error:", error);
      alert("Error processing schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCreateOrUpdateTask = async (taskInput: Task) => {
    // Note: We do NOT set isProcessing(true) here for AI tasks anymore because we use Optimistic UI
    try {
      let task = { ...taskInput };

      // AI Analysis only for flexible Tasks if not provided and in AI mode
      if (task.category === 'Task' && task.totalHoursNeeded > 0) {
          // This is fast enough to await, or we could optimistic this too, but for now we await classification
          // If we wanted true sub-second for everything, we'd skip this or mock it.
          // Let's assume this is fast enough (Flash model).
          const aiAnalysis = await analyzeTaskSemantics(task.title, task.description);
          task.energyLevel = aiAnalysis.energyLevel;
      }

      let updatedTasks;
      const isUpdate = tasks.some(t => t.id === task.id);

      const newManualEvents: CalendarEvent[] = [];

      // Check for Manual Time fields
      if (task.meetingDate && task.meetingStartTime && task.meetingEndTime) {
         // ... (Manual Habit Logic - kept same) ...
         if (task.category === 'Habit' && task.recurrenceEndDate && task.preferredDays.length > 0) {
             const [sYear, sMonth, sDay] = task.meetingDate.split('-').map(Number);
             const loopDate = new Date(sYear, sMonth - 1, sDay); 

             const eD = new Date(task.recurrenceEndDate);
             const finalDate = new Date(eD.getFullYear(), eD.getMonth(), eD.getDate());
             finalDate.setHours(23, 59, 59, 999);

             let safety = 0;
             while (loopDate <= finalDate && safety < 365) {
                 const dayName = loopDate.toLocaleDateString('en-US', { weekday: 'long' });

                 if (task.preferredDays.includes(dayName)) {
                     const pad = (n: number) => n < 10 ? '0'+n : n;
                     const dateStr = `${loopDate.getFullYear()}-${pad(loopDate.getMonth()+1)}-${pad(loopDate.getDate())}`;

                     const s = new Date(`${dateStr}T${task.meetingStartTime}`);
                     const e = new Date(`${dateStr}T${task.meetingEndTime}`);

                     newManualEvents.push({
                         id: `manual-${task.id}-${dateStr}`,
                         title: task.title,
                         start: s,
                         end: e,
                         type: EventType.MANUAL,
                         relatedTaskId: task.id,
                         color: "bg-teal-50 border-teal-200 text-teal-700",
                         description: task.description,
                         location: task.location // Pass Location
                     });
                 }
                 loopDate.setDate(loopDate.getDate() + 1);
                 safety++;
             }

         } else {
             // Single Manual Meeting/Event
             const start = new Date(`${task.meetingDate}T${task.meetingStartTime}`);
             const end = new Date(`${task.meetingDate}T${task.meetingEndTime}`);
             newManualEvents.push({
                 id: `manual-${task.id}`,
                 title: task.title,
                 start,
                 end,
                 type: EventType.MANUAL,
                 relatedTaskId: task.id,
                 color: task.category === 'Meeting' 
                    ? "bg-purple-50 border-purple-200 text-purple-700" 
                    : "bg-gray-50 border-gray-200 text-gray-700",
                 description: task.description,
                 location: task.location // Pass Location
             });
         }
      }

      if (isUpdate) {
        updatedTasks = tasks.map(t => t.id === task.id ? task : t);
      } else {
        updatedTasks = [...tasks, task];
      }

      // --- OPTIMISTIC UI LOGIC ---

      // 1. Close Modal Immediately
      setView('calendar');
      setEditingTask(null);
      setTasks(updatedTasks);

      // 2. Prepare Events (remove old future AI events for this task)
      const now = new Date();
      let currentEvents = events.filter(e => {
          if (e.relatedTaskId === task.id) {
              if (e.type === EventType.AI_WORK_SESSION && e.end <= now) return true; // Keep history
              return false; // Remove future
          }
          return true;
      });
      currentEvents = [...currentEvents, ...newManualEvents];

      // 3. Inject Ghost Event if it's an AI task
      if (task.isScheduled && task.totalHoursNeeded > 0 && newManualEvents.length === 0) {
          const ghostStart = new Date();
          ghostStart.setHours(ghostStart.getHours() + 1, 0, 0, 0); // Tentative: Next hour
          const ghostEnd = new Date(ghostStart.getTime() + (task.totalHoursNeeded * 60 * 60 * 1000));

          const ghostEvent: CalendarEvent = {
              id: `ghost-${task.id}`,
              title: `Scheduling: ${task.title}...`,
              start: ghostStart,
              end: ghostEnd,
              type: EventType.AI_WORK_SESSION,
              relatedTaskId: task.id,
              color: "bg-gray-100",
              isGhost: true, // Triggers Skeleton UI
              location: task.location // Pass location to ghost
          };

          // Show ghost immediately
          setEvents([...currentEvents, ghostEvent]);
      } else {
          // Manual events are shown immediately
          setEvents(currentEvents);
      }

      // 4. Run AI Backend (Parallel/Async)
      // This will overwrite the ghost event when it returns
      runGlobalScheduler(currentEvents, updatedTasks).then((optimizedSchedule) => {
          setEvents(optimizedSchedule);
      }).catch((err) => {
          console.error("Scheduling failed", err);
          alert("Automatic scheduling failed. Please try again.");
          // Rollback ghost
          setEvents(currentEvents);
      });

    } catch (error) {
      console.error(error);
      alert("Error saving task.");
      setIsProcessing(false);
    }
  };

  const handleDeleteEvent = async (id: string) => {
    // Simply delete the event locally.
    // We do NOT trigger a full AI reschedule here anymore to avoid "ridiculous" wait times for simple deletions.
    setEvents(prev => prev.filter(e => e.id !== id));
  };

  const handleDeleteTask = async (taskId: string) => {
      // Remove task immediately
      const updatedTasks = tasks.filter(t => t.id !== taskId);
      setTasks(updatedTasks);

      // Remove associated events immediately
      setEvents(prev => prev.filter(e => e.relatedTaskId !== taskId));

      // We do NOT trigger AI rescheduling here. Gaps will simply remain empty until the next manual or AI action.
  };

  const handleUpdateEvent = (updatedEvent: CalendarEvent) => {
    const finalEvent = {
        ...updatedEvent,
        type: updatedEvent.type === EventType.AI_WORK_SESSION ? EventType.MANUAL : updatedEvent.type,
    };
    setEvents(prevEvents => {
        const otherEvents = prevEvents.filter(e => e.id !== updatedEvent.id);
        const newEventList = [...otherEvents, finalEvent];
        return newEventList;
    });
  };

  const handleToggleTaskComplete = async (taskId: string, isComplete: boolean) => {
      // Optimistic Update
      const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, isCompleted: isComplete } : t);
      setTasks(updatedTasks);

      if (isComplete) {
          const now = new Date();
          setEvents(prev => prev.filter(e => {
              if (e.relatedTaskId === taskId && e.type === EventType.AI_WORK_SESSION && e.start > now) return false;
              return true;
          }));
      } else {
          // Re-schedule in background (Uncompleting a task usually implies intent to do it, so we allow rescheduling here)
          runGlobalScheduler(events, updatedTasks).then(setEvents);
      }
  };

  const handleCalendarSlotClick = (date: Date) => {
      const startStr = date.toTimeString().slice(0, 5); // HH:mm
      const end = new Date(date.getTime() + 60*60*1000); // +1 hour
      const endStr = end.toTimeString().slice(0, 5);

      const pad = (n: number) => n < 10 ? '0'+n : n;
      const dateStr = `${date.getFullYear()}-${pad(date.getMonth()+1)}-${pad(date.getDate())}`;

      const draftTask: Task = {
          id: '', 
          category: 'Meeting', 
          title: '',
          description: '',
          priority: 'Medium',
          files: [],
          difficulty: 5,
          totalHoursNeeded: 0, // Manual = 0 hours needed for AI
          deadline: new Date(date.getTime() + 7*24*60*60*1000), 
          energyLevel: 'High',
          meetingDate: dateStr,
          meetingStartTime: startStr,
          meetingEndTime: endStr,
          preferredDays: [],
          preferredTimeStart: '09:00',
          preferredTimeEnd: '17:00',
          preferredSessionDuration: 1,
          isScheduled: true 
      };

      setEditingTask(draftTask);
      setView('newEvent');
  };

  const selectedTask = selectedEvent?.relatedTaskId 
    ? tasks.find(t => t.id === selectedEvent.relatedTaskId) 
    : undefined;

  return (
    <div className="min-h-screen flex flex-col relative bg-gray-50 text-gray-900 font-sans">
      <nav className="border-b border-gray-200 bg-white sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <span className="bg-indigo-600 text-white p-1.5 rounded mr-3 font-bold">SP</span>
              <h1 className="text-xl font-bold tracking-tight text-gray-900 hidden sm:block">SparkPlan AI</h1>

              <div className="ml-8 flex space-x-1">
                 <button 
                    onClick={() => setView('calendar')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'calendar' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Calendar
                 </button>
                 <button 
                    onClick={() => setView('events')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'events' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Events
                 </button>
              </div>
            </div>
            <div className="flex items-center space-x-4">
              <Button variant="ghost" onClick={() => setIsImportModalOpen(true)}>Import</Button>
              <Button onClick={() => { setEditingTask(null); setView('newEvent'); }} disabled={view === 'newEvent'}>
                + New Event
              </Button>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {view === 'calendar' && (
          <>
            <div className="mb-6 flex items-center justify-between">
              <div>
                <h2 className="text-xl font-bold text-gray-900 tracking-tight">Dashboard</h2>
                <p className="text-sm text-gray-500 mt-1">
                  {events.filter(e => e.type === EventType.AI_WORK_SESSION && !e.isGhost).length} active work sessions.
                </p>
              </div>
              <div className="flex gap-4 text-xs font-medium text-gray-600">
                 <div className="flex items-center"><div className="w-2 h-2 bg-blue-600 rounded-full mr-2"></div> Class</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-gray-400 rounded-full mr-2"></div> Manual</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-teal-400 rounded-full mr-2"></div> Habit / Recurring</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-indigo-600 rounded-full mr-2"></div> Task</div>
              </div>
            </div>
            <div className="h-[calc(100vh-200px)]">
               <Calendar 
                  events={events} 
                  currentDate={currentDate} 
                  onEventClick={setSelectedEvent}
                  onNavigate={handleNavigate}
                  onEventUpdate={handleUpdateEvent}
                  onSlotClick={handleCalendarSlotClick}
               />
            </div>
          </>
        )}

        {view === 'events' && (
            <EventsView 
                tasks={tasks} 
                events={events}
                onEditTask={(task) => {
                    setEditingTask(task);
                    setView('editEvent');
                }}
                onDeleteTask={handleDeleteTask}
                onToggleComplete={handleToggleTaskComplete}
            />
        )}

        {(view === 'newEvent' || view === 'editEvent') && (
          <div className="py-8">
            <TaskForm 
              initialTask={editingTask}
              existingEvents={events}
              onSubmit={handleCreateOrUpdateTask} 
              onCancel={() => {
                  setEditingTask(null);
                  setView('calendar');
              }} 
            />
          </div>
        )}
      </main>

      <ImportModal 
        isOpen={isImportModalOpen} 
        onClose={() => setIsImportModalOpen(false)} 
        onImport={handleImport} 
      />

      <EventDetailsModal 
        event={selectedEvent} 
        relatedTask={selectedTask}
        onClose={() => setSelectedEvent(null)}
        onDelete={handleDeleteEvent}
        onUpdate={handleUpdateEvent}
      />

      {isProcessing && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-900 bg-opacity-50 backdrop-blur-sm transition-opacity">
            <div className="flex flex-col items-center p-6 bg-white rounded-lg shadow-xl">
                <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
                <h3 className="text-lg font-bold text-gray-900 tracking-widest uppercase">AI Planning</h3>
                <p className="text-xs text-gray-500 mt-2">Consulting the AI for the best slots...</p>
            </div>
        </div>
      )}

    </div>
  );
}

export default App;

