import React, { useState } from 'react';
import { Button } from './Button';
import { CalendarEvent, EventType } from '../types';

interface ImportModalProps {
  isOpen: boolean;
  onClose: () => void;
  onImport: (events: CalendarEvent[]) => void;
}

type TabType = 'upload' | 'url' | 'text';

export const ImportModal: React.FC<ImportModalProps> = ({ isOpen, onClose, onImport }) => {
  const [activeTab, setActiveTab] = useState<TabType>('upload');
  const [icsContent, setIcsContent] = useState('');
  const [urlInput, setUrlInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  if (!isOpen) return null;

  const generateId = () => Date.now().toString(36) + Math.random().toString(36).substring(2);

  const parseICSDate = (str: string): Date | null => {
    try {
        if (!str) return null;
        const isUTC = str.endsWith('Z');
        const cleanStr = str.replace('Z', '');
        if (cleanStr.length < 8) return null;
        const year = parseInt(cleanStr.substring(0, 4));
        const month = parseInt(cleanStr.substring(4, 6)) - 1;
        const day = parseInt(cleanStr.substring(6, 8));
        if (isNaN(year) || isNaN(month) || isNaN(day)) return null;
        if (cleanStr.length === 8) return new Date(year, month, day);
        const hour = parseInt(cleanStr.substring(9, 11));
        const min = parseInt(cleanStr.substring(11, 13));
        const sec = cleanStr.length >= 15 ? parseInt(cleanStr.substring(13, 15)) : 0;
        if (isNaN(hour) || isNaN(min)) return null;
        if (isUTC) return new Date(Date.UTC(year, month, day, hour, min, sec));
        return new Date(year, month, day, hour, min, sec);
    } catch (e) { return null; }
  };

  const expandRecurringEvent = (originalEvent: CalendarEvent, rruleStr: string): CalendarEvent[] => {
      try {
        const rules: any = {};
        rruleStr.split(';').forEach(part => {
            const [key, val] = part.split('=');
            rules[key] = val;
        });
        if (rules.FREQ !== 'WEEKLY') return [originalEvent]; 
        const expanded: CalendarEvent[] = [];
        const duration = originalEvent.end.getTime() - originalEvent.start.getTime();
        let until = rules.UNTIL ? parseICSDate(rules.UNTIL) : null;
        const count = rules.COUNT ? parseInt(rules.COUNT) : Infinity;
        const interval = rules.INTERVAL ? parseInt(rules.INTERVAL) : 1;
        if (!until && count === Infinity) {
            const d = new Date(originalEvent.start);
            d.setMonth(d.getMonth() + 4);
            until = d;
        }
        const dayMap: {[key: string]: number} = { 'SU': 0, 'MO': 1, 'TU': 2, 'WE': 3, 'TH': 4, 'FR': 5, 'SA': 6 };
        const byDay = rules.BYDAY ? rules.BYDAY.split(',').map((d: string) => dayMap[d.length > 2 ? d.slice(-2) : d]) : null;
        const anchor = new Date(originalEvent.start);
        anchor.setDate(anchor.getDate() - anchor.getDay()); 
        anchor.setHours(originalEvent.start.getHours(), originalEvent.start.getMinutes(), 0, 0);
        let addedCount = 0;
        for (let w = 0; w < 52; w++) { 
            if (addedCount >= count) break;
            if (!byDay) {
                const date = new Date(originalEvent.start);
                date.setDate(date.getDate() + (w * 7 * interval));
                if (until && date > until) break;
                expanded.push({ ...originalEvent, id: `${originalEvent.id}_${w}`, start: date, end: new Date(date.getTime() + duration) });
                addedCount++;
                continue;
            }
            if (w % interval !== 0) continue;
            for (const dayIdx of byDay) {
                if (dayIdx === undefined) continue;
                const date = new Date(anchor);
                date.setDate(date.getDate() + (w * 7) + dayIdx);
                date.setHours(originalEvent.start.getHours(), originalEvent.start.getMinutes(), originalEvent.start.getSeconds(), 0);
                if (date < originalEvent.start) continue; 
                if (until && date > until) { } else {
                    expanded.push({ ...originalEvent, id: `${originalEvent.id}_${w}_${dayIdx}`, start: date, end: new Date(date.getTime() + duration) });
                    addedCount++;
                }
            }
            if (until && expanded.length > 0 && expanded[expanded.length-1].start > until) break;
        }
        return expanded.length > 0 ? expanded : [originalEvent];
    } catch (e) { return [originalEvent]; }
  };

  const processICSContent = (content: string) => {
      try {
      if (!content.trim()) return;
      const events: CalendarEvent[] = [];
      const lines = content.split(/\r\n|\n|\r/);
      let currentEvent: Partial<CalendarEvent> | null = null;
      let currentEventRRule: string | null = null;
      let inEvent = false;

      for (let i = 0; i < lines.length; i++) {
        const line = lines[i].trim();
        if (!line) continue;
        if (line === 'BEGIN:VEVENT') {
          inEvent = true;
          currentEvent = { id: generateId(), type: EventType.IMPORTED, color: "bg-gray-100 border-gray-300 text-gray-700" }; 
          currentEventRRule = null;
          continue;
        } 
        if (line === 'END:VEVENT') {
          inEvent = false;
          if (currentEvent && currentEvent.title && currentEvent.start && currentEvent.end) {
            if (!isNaN(currentEvent.start.getTime()) && !isNaN(currentEvent.end.getTime())) {
                if (currentEventRRule) {
                    events.push(...expandRecurringEvent(currentEvent as CalendarEvent, currentEventRRule));
                } else {
                    events.push(currentEvent as CalendarEvent);
                }
            }
          }
          currentEvent = null; continue;
        }
        if (inEvent && currentEvent) {
          if (line.startsWith('SUMMARY:')) currentEvent.title = line.substring(8).trim();
          if (line.startsWith('RRULE:')) currentEventRRule = line.substring(6).trim();
          if (line.startsWith('DTSTART')) {
             const val = line.substring(line.indexOf(':') + 1).trim();
             const date = parseICSDate(val);
             if (date) currentEvent.start = date;
          }
          if (line.startsWith('DTEND')) {
             const val = line.substring(line.indexOf(':') + 1).trim();
             const date = parseICSDate(val);
             if (date) currentEvent.end = date;
          }
        }
      }
      onImport(events);
      setIcsContent(''); setUrlInput(''); onClose();
    } catch (e) { console.error(e); }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      processICSContent(event.target?.result as string);
      setIsProcessing(false);
    };
    reader.readAsText(file);
  };

  const handleUrlImport = async () => {
    if (!urlInput) return;
    setIsProcessing(true);
    try {
        const targetUrl = urlInput.trim();
        let response;
        let error;

        // Strategy 1: corsproxy.io
        try {
            response = await fetch(`https://corsproxy.io/?${encodeURIComponent(targetUrl)}`);
            if (!response.ok) throw new Error("Proxy 1 failed");
        } catch (e) {
            console.warn("Primary proxy failed, trying fallback...");
            error = e;
        }

        // Strategy 2: allorigins.win (Fallback)
        if (!response || !response.ok) {
            try {
                // allorigins returns JSON by default, need 'raw' for ICS text
                response = await fetch(`https://api.allorigins.win/raw?url=${encodeURIComponent(targetUrl)}`);
                if (!response.ok) throw new Error("Fallback proxy failed");
            } catch (e) {
                console.error("All proxies failed", e);
                throw error || e;
            }
        }

        const text = await response.text();

        // Basic validation to check if we actually got ICS content
        if (!text.includes("BEGIN:VCALENDAR")) {
             throw new Error("Invalid ICS content received. The URL might be protected or incorrect.");
        }

        processICSContent(text);
    } catch (e) { 
        console.error(e);
        alert("Import failed. Please ensure:\n1. The URL is a direct link to an .ics file.\n2. For Google Calendar, use the 'Secret address in iCal format'.\n3. Your calendar is publicly accessible or you are using the secret link."); 
    } finally { setIsProcessing(false); }
  };

  const handleSimulateImport = () => {
    setIsProcessing(true);
    setTimeout(() => {
      const today = new Date();
      const mockEvents: CalendarEvent[] = [];
      for(let i=0; i<4; i++) { 
         [1, 3, 5].forEach(dayOffset => { 
             const start = new Date(today);
             start.setDate(today.getDate() - today.getDay() + dayOffset + (i*7));
             start.setHours(10, 0, 0, 0);
             const end = new Date(start);
             end.setHours(11, 30, 0, 0);
             mockEvents.push({
                id: generateId(),
                title: "Calculus II",
                start: start,
                end: end,
                type: EventType.IMPORTED,
                color: "bg-gray-100 border-gray-300 text-gray-700"
             });
         });
      }
      onImport(mockEvents);
      setIsProcessing(false);
      onClose();
    }, 800);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-500 bg-opacity-75 backdrop-blur-sm p-4">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6 border border-gray-200">
        <h2 className="text-xl font-bold mb-6 text-gray-900 tracking-tight">Import Calendar</h2>

        <div className="flex border-b border-gray-200 mb-6">
            {(['upload', 'url', 'text'] as TabType[]).map(tab => (
                 <button 
                    key={tab}
                    onClick={() => setActiveTab(tab)}
                    className={`flex-1 py-2 text-xs font-medium border-b-2 uppercase tracking-wide transition-colors ${activeTab === tab ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
                >
                    {tab}
                </button>
            ))}
        </div>

        <div className="min-h-[160px]">
            {activeTab === 'upload' && (
                <div className="text-center py-4">
                    <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-gray-300 border-dashed rounded-lg cursor-pointer bg-gray-50 hover:bg-gray-100 transition-colors">
                        <span className="text-sm text-gray-500">Click to upload .ics file</span>
                        <input type="file" accept=".ics,text/calendar" className="hidden" onChange={handleFileUpload} />
                    </label>
                </div>
            )}
            {activeTab === 'url' && (
                <div className="py-2">
                    <input 
                        type="url"
                        placeholder="https://calendar.google.com/calendar/ical/..."
                        value={urlInput}
                        onChange={(e) => setUrlInput(e.target.value)}
                        className="w-full p-2 bg-white border border-gray-300 rounded text-gray-900 focus:ring-1 focus:ring-indigo-500 text-sm"
                    />
                    <p className="text-[10px] text-gray-400 mt-2">
                        For Google Calendar, use the "Secret address in iCal format" from Settings.
                    </p>
                    <div className="mt-4 flex justify-end">
                        <Button onClick={handleUrlImport} isLoading={isProcessing} disabled={!urlInput} variant="secondary">Sync</Button>
                    </div>
                </div>
            )}
            {activeTab === 'text' && (
                <div className="py-2">
                    <textarea 
                        className="w-full h-32 p-2 bg-white border border-gray-300 rounded text-gray-900 font-mono text-xs focus:ring-1 focus:ring-indigo-500"
                        placeholder="BEGIN:VCALENDAR..."
                        value={icsContent}
                        onChange={(e) => setIcsContent(e.target.value)}
                    />
                    <div className="mt-2 flex justify-end">
                        <Button onClick={() => icsContent && processICSContent(icsContent)} disabled={!icsContent} variant="secondary">Parse</Button>
                    </div>
                </div>
            )}
        </div>

        <div className="mt-6 flex justify-between items-center pt-4 border-t border-gray-100">
             <button onClick={handleSimulateImport} className="text-xs text-gray-400 hover:text-indigo-600 underline">
                Simulate (Dev)
             </button>
             <div className="flex gap-2">
                <Button variant="ghost" onClick={onClose}>Cancel</Button>
             </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Calendar } from './components/Calendar';
import { TaskForm } from './components/TaskForm';
import { ImportModal } from './components/ImportModal';
import { EventDetailsModal } from './components/EventDetailsModal';
import { EventsView } from './components/EventsView';
import { Button } from './components/Button';
import { identifyClasses, analyzeTaskSemantics, generateFullSchedule } from './services/geminiService';
import { CalendarEvent, Task, EventType } from './types';

// --- Persistence Helpers ---
const STORAGE_EVENTS_KEY = 'better_calendar_events_v1';
const STORAGE_TASKS_KEY = 'better_calendar_tasks_v1';

const dateReviver = (key: string, value: any) => {
  // Convert date strings back to Date objects during JSON parse
  if (['start', 'end', 'deadline', 'recurrenceEndDate'].includes(key) && value) {
    return new Date(value);
  }
  return value;
};

const loadFromStorage = <T,>(key: string, defaultValue: T): T => {
  try {
    const item = localStorage.getItem(key);
    return item ? JSON.parse(item, dateReviver) : defaultValue;
  } catch (error) {
    console.error(`Error loading ${key} from storage:`, error);
    return defaultValue;
  }
};

function App() {
  const [view, setView] = useState<'calendar' | 'events' | 'newEvent' | 'editEvent'>('calendar');

  // Initialize state from LocalStorage
  const [events, setEvents] = useState<CalendarEvent[]>(() => loadFromStorage(STORAGE_EVENTS_KEY, []));
  const [tasks, setTasks] = useState<Task[]>(() => loadFromStorage(STORAGE_TASKS_KEY, []));

  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const [currentDate, setCurrentDate] = useState(new Date());

  // --- Persistence Effects ---
  useEffect(() => {
    localStorage.setItem(STORAGE_EVENTS_KEY, JSON.stringify(events));
  }, [events]);

  useEffect(() => {
    localStorage.setItem(STORAGE_TASKS_KEY, JSON.stringify(tasks));
  }, [tasks]);

  const handleNavigate = (direction: 'prev' | 'next' | 'today') => {
    const newDate = new Date(currentDate);
    if (direction === 'today') {
      setCurrentDate(new Date());
    } else if (direction === 'next') {
      newDate.setDate(newDate.getDate() + 7);
      setCurrentDate(newDate);
    } else {
      newDate.setDate(newDate.getDate() - 7);
      setCurrentDate(newDate);
    }
  };

  // REPLACEMENT: Async AI Scheduler
  const runGlobalScheduler = async (currentEvents: CalendarEvent[], currentTasks: Task[]) => {
    const now = new Date();

    // 1. Keep non-AI events (Fixed)
    // 2. Keep AI events that have already ended (History)
    // 3. IMPORTANT: Ignore Ghost events when calculating busy slots for the backend
    const preservedEvents = currentEvents.filter(e => 
        (e.type !== EventType.AI_WORK_SESSION || e.end <= now) && !e.isGhost
    );

    // 3. Identify tasks that need scheduling (Not completed AND isScheduled=true AND has hours needed)
    // Removed category filter to allow AI to schedule Meetings/Habits if requested via AI mode.
    const tasksToSchedule = currentTasks.filter(t => !t.isCompleted && t.isScheduled && t.totalHoursNeeded > 0); 

    // 4. Generate new future sessions using AI
    let newSessions: CalendarEvent[] = [];
    if (tasksToSchedule.length > 0) {
        newSessions = await generateFullSchedule(preservedEvents, tasksToSchedule);
    }

    return [...preservedEvents, ...newSessions];
  };

  const handleImport = async (importedEvents: CalendarEvent[]) => {
    setIsImportModalOpen(false);
    setIsProcessing(true);
    try {
      const classIds = await identifyClasses(importedEvents);
      const taggedEvents = importedEvents.map(e => ({
        ...e,
        isClass: classIds.includes(e.id),
        // Solid Blue Block with White Text for best legibility
        color: classIds.includes(e.id) ? "bg-blue-600 border-blue-700 text-white shadow-sm" : e.color
      }));

      // Combine existing events with new imported ones, then reschedule
      const allEvents = [...events, ...taggedEvents];
      const optimizedSchedule = await runGlobalScheduler(allEvents, tasks); // Await AI
      setEvents(optimizedSchedule);
    } catch (error) {
      console.error("Import error:", error);
      alert("Error processing schedule.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleCreateOrUpdateTask = async (taskInput: Task) => {
    // Note: We do NOT set isProcessing(true) here for AI tasks anymore because we use Optimistic UI
    try {
      let task = { ...taskInput };

      // AI Analysis only for flexible Tasks if not provided and in AI mode
      if (task.category === 'Task' && task.totalHoursNeeded > 0) {
          // This is fast enough to await, or we could optimistic this too, but for now we await classification
          // If we wanted true sub-second for everything, we'd skip this or mock it.
          // Let's assume this is fast enough (Flash model).
          const aiAnalysis = await analyzeTaskSemantics(task.title, task.description);
          task.energyLevel = aiAnalysis.energyLevel;
      }

      let updatedTasks;
      const isUpdate = tasks.some(t => t.id === task.id);

      const newManualEvents: CalendarEvent[] = [];

      // Check for Manual Time fields
      if (task.meetingDate && task.meetingStartTime && task.meetingEndTime) {
         // ... (Manual Habit Logic - kept same) ...
         if (task.category === 'Habit' && task.recurrenceEndDate && task.preferredDays.length > 0) {
             const [sYear, sMonth, sDay] = task.meetingDate.split('-').map(Number);
             const loopDate = new Date(sYear, sMonth - 1, sDay); 

             const eD = new Date(task.recurrenceEndDate);
             const finalDate = new Date(eD.getFullYear(), eD.getMonth(), eD.getDate());
             finalDate.setHours(23, 59, 59, 999);

             let safety = 0;
             while (loopDate <= finalDate && safety < 365) {
                 const dayName = loopDate.toLocaleDateString('en-US', { weekday: 'long' });

                 if (task.preferredDays.includes(dayName)) {
                     const pad = (n: number) => n < 10 ? '0'+n : n;
                     const dateStr = `${loopDate.getFullYear()}-${pad(loopDate.getMonth()+1)}-${pad(loopDate.getDate())}`;

                     const s = new Date(`${dateStr}T${task.meetingStartTime}`);
                     const e = new Date(`${dateStr}T${task.meetingEndTime}`);

                     newManualEvents.push({
                         id: `manual-${task.id}-${dateStr}`,
                         title: task.title,
                         start: s,
                         end: e,
                         type: EventType.MANUAL,
                         relatedTaskId: task.id,
                         color: "bg-teal-50 border-teal-200 text-teal-700",
                         description: task.description,
                         location: task.location // Pass Location
                     });
                 }
                 loopDate.setDate(loopDate.getDate() + 1);
                 safety++;
             }

         } else {
             // Single Manual Meeting/Event
             const start = new Date(`${task.meetingDate}T${task.meetingStartTime}`);
             const end = new Date(`${task.meetingDate}T${task.meetingEndTime}`);
             newManualEvents.push({
                 id: `manual-${task.id}`,
                 title: task.title,
                 start,
                 end,
                 type: EventType.MANUAL,
                 relatedTaskId: task.id,
                 color: task.category === 'Meeting' 
                    ? "bg-purple-50 border-purple-200 text-purple-700" 
                    : "bg-gray-50 border-gray-200 text-gray-700",
                 description: task.description,
                 location: task.location // Pass Location
             });
         }
      }

      if (isUpdate) {
        updatedTasks = tasks.map(t => t.id === task.id ? task : t);
      } else {
        updatedTasks = [...tasks, task];
      }

      // --- OPTIMISTIC UI LOGIC ---

      // 1. Close Modal Immediately
      setView('calendar');
      setEditingTask(null);
      setTasks(updatedTasks);

      // 2. Prepare Events (remove old future AI events for this task)
      const now = new Date();
      let currentEvents = events.filter(e => {
          if (e.relatedTaskId === task.id) {
              if (e.type === EventType.AI_WORK_SESSION && e.end <= now) return true; // Keep history
              return false; // Remove future
          }
          return true;
      });
      currentEvents = [...currentEvents, ...newManualEvents];

      // 3. Inject Ghost Event if it's an AI task
      if (task.isScheduled && task.totalHoursNeeded > 0 && newManualEvents.length === 0) {
          const ghostStart = new Date();
          ghostStart.setHours(ghostStart.getHours() + 1, 0, 0, 0); // Tentative: Next hour
          const ghostEnd = new Date(ghostStart.getTime() + (task.totalHoursNeeded * 60 * 60 * 1000));

          const ghostEvent: CalendarEvent = {
              id: `ghost-${task.id}`,
              title: `Scheduling: ${task.title}...`,
              start: ghostStart,
              end: ghostEnd,
              type: EventType.AI_WORK_SESSION,
              relatedTaskId: task.id,
              color: "bg-gray-100",
              isGhost: true, // Triggers Skeleton UI
              location: task.location // Pass location to ghost
          };

          // Show ghost immediately
          setEvents([...currentEvents, ghostEvent]);
      } else {
          // Manual events are shown immediately
          setEvents(currentEvents);
      }

      // 4. Run AI Backend (Parallel/Async)
      // This will overwrite the ghost event when it returns
      runGlobalScheduler(currentEvents, updatedTasks).then((optimizedSchedule) => {
          setEvents(optimizedSchedule);
      }).catch((err) => {
          console.error("Scheduling failed", err);
          alert("Automatic scheduling failed. Please try again.");
          // Rollback ghost
          setEvents(currentEvents);
      });

    } catch (error) {
      console.error(error);
      alert("Error saving task.");
      setIsProcessing(false);
    }
  };

  const handleDeleteEvent = async (id: string) => {
    // Simply delete the event locally.
    // We do NOT trigger a full AI reschedule here anymore to avoid "ridiculous" wait times for simple deletions.
    setEvents(prev => prev.filter(e => e.id !== id));
  };

  const handleDeleteTask = async (taskId: string) => {
      // Remove task immediately
      const updatedTasks = tasks.filter(t => t.id !== taskId);
      setTasks(updatedTasks);

      // Remove associated events immediately
      setEvents(prev => prev.filter(e => e.relatedTaskId !== taskId));

      // We do NOT trigger AI rescheduling here. Gaps will simply remain empty until the next manual or AI action.
  };

  const handleUpdateEvent = (updatedEvent: CalendarEvent) => {
    const finalEvent = {
        ...updatedEvent,
        type: updatedEvent.type === EventType.AI_WORK_SESSION ? EventType.MANUAL : updatedEvent.type,
    };
    setEvents(prevEvents => {
        const otherEvents = prevEvents.filter(e => e.id !== updatedEvent.id);
        const newEventList = [...otherEvents, finalEvent];
        return newEventList;
    });
  };

  const handleToggleTaskComplete = async (taskId: string, isComplete: boolean) => {
      // Optimistic Update
      const updatedTasks = tasks.map(t => t.id === taskId ? { ...t, isCompleted: isComplete } : t);
      setTasks(updatedTasks);

      if (isComplete) {
          const now = new Date();
          setEvents(prev => prev.filter(e => {
              if (e.relatedTaskId === taskId && e.type === EventType.AI_WORK_SESSION && e.start > now) return false;
              return true;
          }));
      } else {
          // Re-schedule in background (Uncompleting a task usually implies intent to do it, so we allow rescheduling here)
          runGlobalScheduler(events, updatedTasks).then(setEvents);
      }
  };

  const handleCalendarSlotClick = (date: Date) => {
      const startStr = date.toTimeString().slice(0, 5); // HH:mm
      const end = new Date(date.getTime() + 60*60*1000); // +1 hour
      const endStr = end.toTimeString().slice(0, 5);

      const pad = (n: number) => n < 10 ? '0'+n : n;
      const dateStr = `${date.getFullYear()}-${pad(date.getMonth()+1)}-${pad(date.getDate())}`;

      const draftTask: Task = {
          id: '', 
          category: 'Meeting', 
          title: '',
          description: '',
          priority: 'Medium',
          files: [],
          difficulty: 5,
          totalHoursNeeded: 0, // Manual = 0 hours needed for AI
          deadline: new Date(date.getTime() + 7*24*60*60*1000), 
          energyLevel: 'High',
          meetingDate: dateStr,
          meetingStartTime: startStr,
          meetingEndTime: endStr,
          preferredDays: [],
          preferredTimeStart: '09:00',
          preferredTimeEnd: '17:00',
          preferredSessionDuration: 1,
          isScheduled: true 
      };

      setEditingTask(draftTask);
      setView('newEvent');
  };

  const selectedTask = selectedEvent?.relatedTaskId 
    ? tasks.find(t => t.id === selectedEvent.relatedTaskId) 
    : undefined;

  return (
    <div className="min-h-screen flex flex-col relative bg-gray-50 text-gray-900 font-sans">
      <nav className="border-b border-gray-200 bg-white sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <span className="bg-indigo-600 text-white p-1.5 rounded mr-3 font-bold">BC</span>
              <h1 className="text-xl font-bold tracking-tight text-gray-900 hidden sm:block">BetterCalendar</h1>

              <div className="ml-8 flex space-x-1">
                 <button 
                    onClick={() => setView('calendar')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'calendar' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Calendar
                 </button>
                 <button 
                    onClick={() => setView('events')}
                    className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${view === 'events' ? 'bg-gray-100 text-indigo-700' : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'}`}
                 >
                    Events
                 </button>
              </div>
            </div>
            <div className="flex items-center space-x-4">
              <Button variant="ghost" onClick={() => setIsImportModalOpen(true)}>Import</Button>
              <Button onClick={() => { setEditingTask(null); setView('newEvent'); }} disabled={view === 'newEvent'}>
                + New Event
              </Button>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {view === 'calendar' && (
          <>
            <div className="mb-6 flex items-center justify-between">
              <div>
                <h2 className="text-xl font-bold text-gray-900 tracking-tight">Dashboard</h2>
                <p className="text-sm text-gray-500 mt-1">
                  {events.filter(e => e.type === EventType.AI_WORK_SESSION && !e.isGhost).length} active work sessions.
                </p>
              </div>
              <div className="flex gap-4 text-xs font-medium text-gray-600">
                 <div className="flex items-center"><div className="w-2 h-2 bg-blue-600 rounded-full mr-2"></div> Class</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-gray-400 rounded-full mr-2"></div> Manual</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-teal-400 rounded-full mr-2"></div> Habit / Recurring</div>
                 <div className="flex items-center"><div className="w-2 h-2 bg-indigo-600 rounded-full mr-2"></div> Task</div>
              </div>
            </div>
            <div className="h-[calc(100vh-200px)]">
               <Calendar 
                  events={events} 
                  currentDate={currentDate} 
                  onEventClick={setSelectedEvent}
                  onNavigate={handleNavigate}
                  onEventUpdate={handleUpdateEvent}
                  onSlotClick={handleCalendarSlotClick}
               />
            </div>
          </>
        )}

        {view === 'events' && (
            <EventsView 
                tasks={tasks} 
                events={events}
                onEditTask={(task) => {
                    setEditingTask(task);
                    setView('editEvent');
                }}
                onDeleteTask={handleDeleteTask}
                onToggleComplete={handleToggleTaskComplete}
            />
        )}

        {(view === 'newEvent' || view === 'editEvent') && (
          <div className="py-8">
            <TaskForm 
              initialTask={editingTask}
              existingEvents={events}
              onSubmit={handleCreateOrUpdateTask} 
              onCancel={() => {
                  setEditingTask(null);
                  setView('calendar');
              }} 
            />
          </div>
        )}
      </main>

      <ImportModal 
        isOpen={isImportModalOpen} 
        onClose={() => setIsImportModalOpen(false)} 
        onImport={handleImport} 
      />

      <EventDetailsModal 
        event={selectedEvent} 
        relatedTask={selectedTask}
        onClose={() => setSelectedEvent(null)}
        onDelete={handleDeleteEvent}
        onUpdate={handleUpdateEvent}
      />

      {isProcessing && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-900 bg-opacity-50 backdrop-blur-sm transition-opacity">
            <div className="flex flex-col items-center p-6 bg-white rounded-lg shadow-xl">
                <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
                <h3 className="text-lg font-bold text-gray-900 tracking-widest uppercase">AI Planning</h3>
                <p className="text-xs text-gray-500 mt-2">Consulting the AI for the best slots...</p>
            </div>
        </div>
      )}

    </div>
  );
}

export default App;

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { CalendarEvent, Task, EventType, EnergyLevel } from "../types";

// Lazy initialization to allow checking for the key at runtime
let ai: GoogleGenAI | null = null;

const getAIClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        console.error("❌ API_KEY is missing! Make sure you have a .env file locally or environment variables set in Netlify.");
        alert("API Key is missing. AI features will not work.\n\nIf running locally, create a .env file with API_KEY=AIza...");
        throw new Error("API Key missing");
    }
    if (!ai) {
        ai = new GoogleGenAI({ apiKey });
    }
    return ai;
};

// Using Flash model for speed/intent extraction as requested
const MODEL_NAME = "gemini-3-flash-preview";

const callWithTimeout = async <T>(promise: Promise<T>, ms: number): Promise<T> => {
    let timeoutId: any;
    const timeoutPromise = new Promise<T>((_, reject) => {
        timeoutId = setTimeout(() => reject(new Error(`AI Request timed out after ${ms}ms`)), ms);
    });
    try {
        const result = await Promise.race([promise, timeoutPromise]);
        clearTimeout(timeoutId);
        return result;
    } catch (e) {
        clearTimeout(timeoutId);
        throw e;
    }
};

export const identifyClasses = async (events: CalendarEvent[]): Promise<string[]> => {
  if (events.length === 0) return [];
  console.log("🔍 identifying classes via AI...");

  const uniqueEvents = new Map<string, { title: string; description: string }>();
  events.forEach(e => {
    if (!uniqueEvents.has(e.title)) uniqueEvents.set(e.title, { title: e.title, description: e.description || "" });
  });
  const distinctEventList = Array.from(uniqueEvents.values()).slice(0, 150);
  const prompt = `Identify University Classes in list: ${JSON.stringify(distinctEventList)}. Return {"classTitles": ["Exact Title"]}.`;

  try {
    const client = getAIClient();
    const apiCall = client.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: { responseMimeType: "application/json", temperature: 0.1 },
    });
    const response = await callWithTimeout<GenerateContentResponse>(apiCall, 15000);
    const result = JSON.parse(response.text || '{}') as { classTitles: string[] };
    const classTitles = new Set(result.classTitles || []);
    return events.filter(e => classTitles.has(e.title)).map(e => e.id);
  } catch (error) { 
      console.error("❌ Class Identification Failed:", error);
      return []; 
  }
};

export const analyzeTaskSemantics = async (title: string, description: string): Promise<{ energyLevel: EnergyLevel }> => {
    if (!title && !description) return { energyLevel: 'High' };
    console.log(`⚡ Analyzing task energy: ${title}`);

    const prompt = `Classify task energy: "${title} ${description}". Return {"energyLevel": "High" or "Low"}. High=Morning/Focus, Low=Evening/Relax.`;
    try {
        const client = getAIClient();
        const apiCall = client.models.generateContent({
            model: MODEL_NAME,
            contents: prompt,
            config: { responseMimeType: "application/json", temperature: 0.1 }
        });
        const response = await callWithTimeout<GenerateContentResponse>(apiCall, 8000);
        const result = JSON.parse(response.text || '{}');
        return { energyLevel: result.energyLevel || 'High' };
    } catch (e) { 
        console.error("❌ Task Analysis Failed:", e);
        return { energyLevel: 'High' }; 
    }
};

export const generateFullSchedule = async (fixedEvents: CalendarEvent[], tasksToSchedule: Task[]): Promise<CalendarEvent[]> => {
    if (tasksToSchedule.length === 0) return [];
    console.log(`🤖 Generating schedule for ${tasksToSchedule.length} tasks...`);

    const now = new Date();

    // Provide a 120-day lookahead context for scheduling
    const contextEnd = new Date(now);
    contextEnd.setDate(contextEnd.getDate() + 120);

    const relevantFixed = fixedEvents
        .filter(e => e.start >= now && e.start <= contextEnd && !e.isGhost) // Ignore ghost events for backend logic
        .map(e => {
            // APPLY BUFFER LOGIC:
            // Pad existing events by 15 minutes on both ends.
            // This forces the AI to see the adjacent time as "busy", ensuring 
            // the next task starts at least 15 minutes later.
            const bufferedStart = new Date(e.start);
            bufferedStart.setMinutes(bufferedStart.getMinutes() - 15);

            const bufferedEnd = new Date(e.end);
            bufferedEnd.setMinutes(bufferedEnd.getMinutes() + 15);

            return {
                title: e.title,
                start: bufferedStart.toISOString(),
                end: bufferedEnd.toISOString()
            };
        });

    const tasksContext = tasksToSchedule.map(t => ({
        id: t.id,
        category: t.category,
        title: t.title,
        instructions: t.description, 
        durationHours: t.totalHoursNeeded,
        deadline: t.deadline.toISOString()
    }));

    // Detect User Timezone Information
    const timeZone = Intl.DateTimeFormat().resolvedOptions().timeZone;
    const localTime = now.toLocaleString('en-US', { timeZone, hour12: false });

    const systemPrompt = `You are a high-performance scheduling engine. 
    You DO NOT speak. You DO NOT output conversational text. 
    You ONLY output valid JSON.

    CRITICAL INSTRUCTION:
    Your output must be a single JSON object containing a 'sessions' array.
    This mimics a parallel function call to schedule multiple tasks at once.

    INPUT DATA:
    - User Timezone: ${timeZone}
    - Local Time: ${localTime}
    - Fixed Slots (Busy): Array of start/end times (includes safety buffers).
    - Tasks: Array of tasks to schedule.

    LOGIC:
    1. Find gaps in Fixed Slots between ${localTime} and ${contextEnd.toISOString()}.
    2. Place Tasks in gaps before their deadline.
    3. Convert User Local Time instructions (e.g. "at 5pm") to UTC ISO8601.
    4. CONSTRAINT: You MUST leave at least 15 minutes of gap between any two generated sessions. Do not schedule tasks strictly back-to-back.
    5. CRITICAL FOR HABITS: If a task category is 'Habit', you MUST schedule it REPEATEDLY (e.g. daily, or as instructed) across the ENTIRE provided context window (up to 120 days). Do not just schedule it once. Fill the calendar.
    6. Return strict JSON.
    `;

    const userContent = JSON.stringify({
        fixedSlots: relevantFixed,
        tasks: tasksContext
    });

    try {
        const client = getAIClient();
        const apiCall = client.models.generateContent({
            model: MODEL_NAME,
            contents: userContent,
            config: { 
                systemInstruction: systemPrompt,
                responseMimeType: "application/json", 
                temperature: 0.2 
            }
        });
        // Increased timeout to 120s to handle the large generation volume for 120-day schedules
        const response = await callWithTimeout<GenerateContentResponse>(apiCall, 120000); 
        console.log("✅ AI Response received");

        const result = JSON.parse(response.text || '{}') as { sessions: any[] };

        return (result.sessions || []).map(s => {
            const task = tasksToSchedule.find(t => t.id === s.taskId);
            if (!task) return null;
            return {
                id: crypto.randomUUID(),
                title: task.title,
                start: new Date(s.start),
                end: new Date(s.end),
                type: EventType.AI_WORK_SESSION,
                relatedTaskId: task.id,
                description: s.reasoning,
                location: task.location, // Pass location if available
                color: task.category === 'Habit' ? "bg-teal-50 border-teal-200 text-teal-700" : (task.category === 'Meeting' ? "bg-purple-50 border-purple-200 text-purple-700" : "bg-indigo-50 border-indigo-200 text-indigo-700"),
                priority: task.priority
            };
        }).filter(e => e !== null) as CalendarEvent[];

    } catch (e) {
        console.error("❌ AI Scheduler Error:", e);
        // Throwing here so the UI knows it failed
        throw e;
    }
};
